-- Poems batch 259
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('546eb1db-3f33-4668-8b0a-4bc9ccb12361','贈硯工楊全','方回','宋','宋诗','song-poetry','','[]','人間漸少老書生，真贋誰能別舊坑。',32,'全唐诗/poet.song.231000.json','["人間漸少老書生，真贋誰能別舊坑。", "磨墨揮毫自奇怪，可須一硯苦求精。"]'),
('7db1426e-cdf6-459b-a9b8-2b5ef69c2553','再贈硯工楊全長句','方回','宋','宋诗','song-poetry','','[]','誰鑿山中龍尾石，遍與人間供翰墨。',192,'全唐诗/poet.song.231000.json','["誰鑿山中龍尾石，遍與人間供翰墨。", "蛟螭妬嫉互盤踞，鬼神守護勤呵叱。", "苟非其人不輕出，似覺天公深愛惜。", "磨硯輕寫俗文章，豈不青蠅污白璧。", "硯工具眼如玉工，千巖夜見月貫虹。", "懸崖深淵致巨璞，氈包席裹箱奩中。", "深藏不敢褻天賜，脅取豈無王與公。", "脫使捐金動至百，卒未肯售寧固窮。", "客行何來身突兀，作字不媚詩有骨。", "此翁謂是謫仙人，開匣再拜獻此物。", "乃知楊翁亦奇崛，氣高肯爲勢力屈。", "劍與烈士得所歸，天下之寶不可忽。"]'),
('e51f5dcb-8c14-4c5c-946a-97a52abce87d','題黄君以發擬文公書院梁文及賦','方回','宋','宋诗','song-poetry','','[]','滔天筆勢百川東，小待清霜萬壑空。',32,'全唐诗/poet.song.231000.json','["滔天筆勢百川東，小待清霜萬壑空。", "能草子虛上林賦，更須收斂入檀弓。"]'),
('8aa885bd-d99b-4876-9622-2b412e7ee0d5','追和艮軒俞同年題程一甫詩卷','方回','宋','宋诗','song-poetry','','[]','人物真高絕，何徒上下床。',48,'全唐诗/poet.song.231000.json','["人物真高絕，何徒上下床。", "轉頭異今古，翻手變炎凉。", "應候禽蟲語，知時草樹香。", "吾曹能不朽，宇宙與俱長。"]'),
('f3b95144-0806-45b0-8c40-b86a3f3c6312','文公故居有懷','方回','宋','宋诗','song-poetry','','[]','慷慨懷人獨倚樓，定應故國此神遊。',64,'全唐诗/poet.song.231000.json','["慷慨懷人獨倚樓，定應故國此神遊。", "共知道派傳洙泗，猶覺文星貫斗牛。", "八佾舞移誰有魯，兩楹夢斷已無周。", "先生不遇關何事，更作離騷一段愁。"]'),
('c93f5a9f-26e6-408b-ae2b-2e71bd22f15e','文公書院新創','方回','宋','宋诗','song-poetry','','[]','新堂育士煥榱椽，突起文公故宅邊。',64,'全唐诗/poet.song.231000.json','["新堂育士煥榱椽，突起文公故宅邊。", "孟子向來推亞聖，鄒人誰不企先賢。", "遺書會萃垂千古，缺典因循近百年。", "爲問杏壇舊鄰里，顔曾以後豈無傳。"]'),
('b55c3bf1-03fa-4dae-b0a8-40607fe5bcb9','婺源邑中','方回','宋','宋诗','song-poetry','','[]','天地初開孰結融，一溪千折萬山重。',64,'全唐诗/poet.song.231000.json','["天地初開孰結融，一溪千折萬山重。", "縣城似繞流觴水，郡路多由對鏡峰。", "祠廟駿奔乾竺會，鄉邦鴻碩兖鄒封。", "版圖三萬東南有，二事無能可比蹤。"]'),
('fd168da1-230c-4801-80e8-beaf0f11e39d','離婺源過古薦注口張村三渡遂登五嶺','方回','宋','宋诗','song-poetry','','[]','卧聞鄰客曉先發，亦束寢衣辭旅榻。',128,'全唐诗/poet.song.231000.json','["卧聞鄰客曉先發，亦束寢衣辭旅榻。", "急雨頓止風稍動，空山微凉路不滑。", "溪流向西吾適東，舟渡者三更橫縱。", "人心最險天自易，左路欲窮須右通。", "蠶放三眠大麥熟，含桃爛紅豌豆綠。", "野次思之不可致，七日菜食市無肉。", "南山之北歸去來，摘菊剪韭手所栽。", "說詩命酒花當開，焉用拾是登崔嵬。"]'),
('7273594f-144f-4303-88b7-a9cfa4e3186c','過芙蓉嶺對鏡嶺羊鬬嶺新嶺塔嶺賦短歌五首  其一','方回','宋','宋诗','song-poetry','','[]','平生所聞芙蓉嶺，上如攀天下入井。',92,'全唐诗/poet.song.231000.json','["平生所聞芙蓉嶺，上如攀天下入井。", "老乃來遊殊不然，褰裳頃刻升絕頂。", "南踰大庾鷓鴣啼，北度居庸朔風緊。", "客行到彼例凄酸，我已恍惚夢中景。", "視險如夷兮要深省。", "君不見芙蓉一嶺今已過，我但慢行君奈何。"]'),
('357275fc-1569-47c8-8283-ebe82a7e4067','過芙蓉嶺對鏡嶺羊鬬嶺新嶺塔嶺賦短歌五首  其二','方回','宋','宋诗','song-poetry','','[]','千鈞巨石百十萬，亂堆橫峙塞山澗。',92,'全唐诗/poet.song.231000.json','["千鈞巨石百十萬，亂堆橫峙塞山澗。", "故今流水作嗚咽，行人厭聞猶喜闞。", "芙蓉非花鏡非鏡，無可充君耳目玩。", "第一嶺望二三嶺，蜿蜒似作長蛇緩。", "努力向前兮不須嘆。", "君不見老夫足垠半天下，臨危豈是趦趄者。"]'),
('a6d8636f-2d09-4f2b-ad4b-566d4cedfa33','過芙蓉嶺對鏡嶺羊鬬嶺新嶺塔嶺賦短歌五首  其三','方回','宋','宋诗','song-poetry','','[]','客謂老夫今老矣，胡爲尚落空山裏。',92,'全唐诗/poet.song.231000.json','["客謂老夫今老矣，胡爲尚落空山裏。", "千艱百難萬不平，上嶺下嶺不肯已。", "此嶺第三未爲險，人面獸心險於此。", "乾坤一紀戰旗紅，偶脫亂離身不死。", "流可無行兮坎即止。", "君不見羊化爲石鬬即休，兩角蝸爭何所求。"]'),
('158a7496-cfb4-4a17-b2c0-077dda9460ca','過芙蓉嶺對鏡嶺羊鬬嶺新嶺塔嶺賦短歌五首  其四','方回','宋','宋诗','song-poetry','','[]','第四嶺頭分兩邑，相背無情水流急。',92,'全唐诗/poet.song.231000.json','["第四嶺頭分兩邑，相背無情水流急。", "浙河東下彭蠡西，到海終須合爲一。", "海東聞有沃焦石，萬國之水不供吸。", "世故人心千百岐，有生必死終無迹。", "焉用皇皇兮仍汲汲。", "君不見塔嶺之塔焉在哉，不如有酒斟一杯。"]'),
('a8d972ac-8437-4aea-92c3-4a43222ea95c','過芙蓉嶺對鏡嶺羊鬬嶺新嶺塔嶺賦短歌五首  其五','方回','宋','宋诗','song-poetry','','[]','混沌何年分宇宙，天地日月常如舊。',92,'全唐诗/poet.song.231000.json','["混沌何年分宇宙，天地日月常如舊。", "如舊之中却常新，何曾一點受塵垢。", "誰鑿此山爲捷徑，爭利奔名足馳驟。", "新嶺終無可舊時，燠不加肥寒不瘦。", "行人自無兮百年壽。", "君不見嶺頭日日吹征塵，剩有新人無舊人。"]'),
('1216be5c-5f7a-4e0a-a98f-faee5620e159','留吳田霜崖吳居士宅予仲女許其孫姻','方回','宋','宋诗','song-poetry','','[]','衆山環如規，中有一川水。',288,'全唐诗/poet.song.231000.json','["衆山環如規，中有一川水。", "山腴翠樹圓，水潔玉石峙。", "居人近百家，耕餘習文史。", "此翁獨能詩，早充賓貢士。", "平生宦情薄，一試倉庾氏。", "中年厭兵革，肥遯白雲裏。", "時時吟一篇，自教孫與子。", "滿屋讀書聲，萬事不到耳。", "問途訪幽居，曲折十餘里。", "麥天小雨霽，初夏風日美。", "遠迓携飲壺，劇談並宴几。", "門帖句句佳，字畫亦勁偉。", "盡出名畫掛，頻共高閣倚。", "烹煎茗笋良，飣餖蔬果旨。", "鼓吹聒深夜，酒酣未容起。", "寒薄攀華盛，兩姓合嘉禮。", "東床向志學，骨相良可喜。", "積德貽後人，方興未云已。", "發稟濟青黄，垂紳曳朱紫。", "天人幽顯間，施報有茲理。", "略窺宅邊園，培芳茂花卉。", "黄鶑殆無數，白鷗不知幾。", "山茶及巖桂，葉葉瑩如洗。", "間氣鍾人物，吾故卜諸此。"]'),
('8a28c2f0-6de9-4b87-995e-b8ee1c0554c4','乍歸呈許君公度','方回','宋','宋诗','song-poetry','','[]','東南天地早聞名，三載吾邦沸頌聲。',64,'全唐诗/poet.song.231000.json','["東南天地早聞名，三載吾邦沸頌聲。", "山好更饒詩句好，江清未抵使君清。", "涓涓流水秧田足，細細吹風麥隴晴。", "客子歸來問耕穫，故園似可養殘生。"]'),
('44212cd4-3577-41db-b378-a30c26a3685f','同金漢臣徐蜚英小飲傍溪寺二首  其一','方回','宋','宋诗','song-poetry','','[]','萬峰奇峭一川平，四月清和十日晴。',32,'全唐诗/poet.song.231000.json','["萬峰奇峭一川平，四月清和十日晴。", "蠶麥豐登宜把酒，山城只欠艷歌聲。"]'),
('0e359318-0406-4e1e-b3f3-2d3a5c94db66','同金漢臣徐蜚英小飲傍溪寺二首  其二','方回','宋','宋诗','song-poetry','','[]','高憑遠眺酒頻斟，誰識風前快飲心。',32,'全唐诗/poet.song.231000.json','["高憑遠眺酒頻斟，誰識風前快飲心。", "州縣長官勝鄰境，秧疇水滿樹林陰。"]'),
('3dcae8eb-e7e0-4b75-a85c-47f62fedf285','送胡子游學正','方回','宋','宋诗','song-poetry','','[]','俗徒紛云云，章甫殊不競。',288,'全唐诗/poet.song.231000.json','["俗徒紛云云，章甫殊不競。", "不競何以故，無奈二氏橫。", "予曰實不然，請各言其行。", "開闢古至今，儒道獨也正。", "柱史玄牝門，專氣保清凈。", "末流詭長生，妄欲奪天命。", "靈山見作用，誤認氣爲性。", "輪迴豈有之，怪繆莫究竟。", "兩俱可鄙者，巫覡事禳禜。", "愚氓惑幻說，往往墮坑穽。", "既曰身出家，粉黛侈婚娉。", "豈不交鬼神，酒肉厭羶蒏。", "此曹浪夸毗，內衰外徒盛。", "吾儕讀何書，堯舜至孔孟。", "搶攘干戈後，學校幸未屏。", "窮者伏閭閻，甘忍饑寒併。", "仕或爲冷官，官冷亦何病。", "甯戚半夜歌，曾點暮春詠。", "求己勝求人，自重豈容輕。", "東家子朱子，述作貫百聖。", "遺言一一在，足可雪几映。", "省察中爲和，存養義由敬。", "上泝周程張，例不顓宰柄。", "乃有功斯文，如揭日月鏡。"]'),
('d7faa1a1-ffb7-4b17-baa0-c1f0adb4f603','次韻徐贊府蜚英八首  其一','方回','宋','宋诗','song-poetry','','[]','長官行縣課農書，耕叟治田賈趁虛。',32,'全唐诗/poet.song.231000.json','["長官行縣課農書，耕叟治田賈趁虛。", "上到嶺頭望應喜，人煙今密舊時疏。"]'),
('58f44fc2-0762-4c5e-8d53-b5fb69fcb83e','次韻徐贊府蜚英八首  其二','方回','宋','宋诗','song-poetry','','[]','高低田水入溪流，溪岸閒橫野渡舟。',32,'全唐诗/poet.song.231000.json','["高低田水入溪流，溪岸閒橫野渡舟。", "麥飯家家甑中有，永無犢佩起山頭。"]'),
('a1ebce91-85d4-45e3-8d04-42b0b4256e00','次韻徐贊府蜚英八首  其三','方回','宋','宋诗','song-poetry','','[]','樹形萬怪石千奇，我亦曾行亦有詩。',32,'全唐诗/poet.song.231000.json','["樹形萬怪石千奇，我亦曾行亦有詩。", "焉得一官如長吏，出郊長是看山時。"]'),
('2fe0a72e-d26a-47ae-bbc7-56567aa36401','次韻徐贊府蜚英八首  其四','方回','宋','宋诗','song-poetry','','[]','懸崖複嶺間岡坡，如此天邊遠碧何。',32,'全唐诗/poet.song.231000.json','["懸崖複嶺間岡坡，如此天邊遠碧何。", "誰道此中曾得句，道傍老樹閲人多。"]'),
('598c5bc0-d38c-43eb-a56a-45864213a8b4','次韻徐贊府蜚英八首  其五','方回','宋','宋诗','song-poetry','','[]','騎入州城出縣城，不須人送不須迎。',32,'全唐诗/poet.song.231000.json','["騎入州城出縣城，不須人送不須迎。", "連峰峻嶺崎嶇極，政自胸中掌樣平。"]'),
('e2443e29-0087-4e47-86e7-919b6d159b35','次韻徐贊府蜚英八首  其六','方回','宋','宋诗','song-poetry','','[]','摩拊惸嫠達下情，領州作縣總書生。',32,'全唐诗/poet.song.231000.json','["摩拊惸嫠達下情，領州作縣總書生。", "清詩要自清心出，比自新安水更清。"]'),
('30968568-5261-407b-98a8-4f22d4610d1e','次韻徐贊府蜚英八首  其七','方回','宋','宋诗','song-poetry','','[]','屏除呵殿少人知，隨馬囊詩更有誰。',32,'全唐诗/poet.song.231000.json','["屏除呵殿少人知，隨馬囊詩更有誰。", "五百不來村落靜，自然生齒似螽斯。"]'),
('f5733508-df8b-4548-8bee-955b74a79470','次韻徐贊府蜚英八首  其八','方回','宋','宋诗','song-poetry','','[]','老農持底報君公，十日甘霖五日風。',32,'全唐诗/poet.song.231000.json','["老農持底報君公，十日甘霖五日風。", "夜靜山中看天象，福星偏許照江東。"]'),
('66ba37fe-e443-4141-b7aa-85fb08d420c8','次韻金漢臣喜雨','方回','宋','宋诗','song-poetry','','[]','山高田易旱，已過一旬晴。',48,'全唐诗/poet.song.231000.json','["山高田易旱，已過一旬晴。", "豈止商饑飽，真成决死生。", "甘霖三尺透，病體十分輕。", "想見琴堂老，催詩意倍清。"]'),
('acbc214f-0390-4758-b3d1-6c3589a16de7','夏日小園','方回','宋','宋诗','song-poetry','','[]','山中豈不樂，奈無田可耕。',96,'全唐诗/poet.song.231000.json','["山中豈不樂，奈無田可耕。", "傍宅蒔荒圃，長夏日閒行。", "行倦即獨坐，時聞幽鳥鳴。", "剪花汰葵冗，護筍觀竹成。", "詩就意偶到，事罕心無營。", "忽復佳客至，取酒相與傾。", "熟醉徑高卧，頹然忘送迎。", "餘齡能幾何，聊用遨此生。"]'),
('9c85567f-e0de-4ea5-8215-34b948198707','戊子生日','方回','宋','宋诗','song-poetry','','["\u897f\u6e56"]','去年苦雨客西湖，湯餠經營至午無。',64,'全唐诗/poet.song.231000.json','["去年苦雨客西湖，湯餠經營至午無。", "窮老復能逢順境，歸林聊得保殘軀。", "親情飲食煩相問，朋友歌詩似稍腴。", "永感情懷更衰病，可憐兒輩事庖厨。"]'),
('0a937185-7919-4259-92f3-b20c63256f24','生日病腹疾書事','方回','宋','宋诗','song-poetry','','[]','今年六十二，棄官八年矣。',288,'全唐诗/poet.song.231000.json','["今年六十二，棄官八年矣。", "生世業已休，來日凜無幾。", "孰謂嘗作郡，旦暮窘薪米。", "少時頗豪宕，晚乃窮如此。", "此事非所憂，所憂學業圮。", "孤卧僅一榻，疾讀動千紙。", "積迷如望洋，頓悟不違咫。", "深井朱夏寒，自汲洗手水。", "心更潔於手，時以理趣洗。", "平生大繆誤，豈不習經史。", "搜覽浪該博，著述墮浮靡。", "詩雖稍得名，往往語多綺。", "夙愆奚庸追，舊嗜差可止。", "迴車遵大路，千聖同一軌。", "茲晨記吾降，益復感髪齒。", "忽虛苦下泄，乍實結中痞。", "道在果何懼，朝聞夕可死。", "朋友挾壺酒，卒爵强告旨。", "敦篤謝親姻，輯睦頼鄰里。", "人情不容拒，羔雁間豆篚。", "酢賓有故常，勿藥姑少俟。", "清庖作湯餠，霑丐兒女子。", "菲饌徹餕餘，稍亦及僕使。", "老夫且伏枕，萬事莫掛耳。"]'),
('795f2f11-2922-41c1-ae80-365ec7298231','五月十四日梅雨始通走筆二十韻','方回','宋','宋诗','song-poetry','','[]','邇日豈無雨，東有西或無。',240,'全唐诗/poet.song.231000.json','["邇日豈無雨，東有西或無。", "有亦僅鳴瓦，不肯鳴庭除。", "簷聲尚難滴，况望浮溝渠。", "滂沱靡後繼，霹靂空先驅。", "山田半未蒔，蒔早青苗枯。", "切慮旱勢迫，莫辦暑氣甦。", "去歲當此際，浙鄉渺爲湖。", "窮冬六十日，所至雪塞途。", "無乃天力竭，有如酒家壚。", "甕盎夙傾倒，遂絕來者沽。", "或謂帝有赫，豈忍氓畢屠。", "久蓄必大泄，勿遽宜少須。", "鄰寺鐘鼓晦，頓與常時殊。", "果即驟傾注，屋漏衣巾濡。", "平明視荒園，破鞋涉泥途。", "詎惜葵卉仆，但喜豆葉腴。", "西溪報橋斷，渡舫若小紆。", "遥想農出野，蓑笠爭奔趨。", "吾雖乏良疇，窘饑意已紓。", "天下免溝瘠，敢嘆瓶無儲。"]'),
('e9661663-214f-46ab-8093-e52ffb7216ca','五月二十八日塘頭小集呈同遊劉元煇楊復之','方回','宋','宋诗','song-poetry','','[]','山中五日寒，霖雨久不止。',204,'全唐诗/poet.song.231000.json','["山中五日寒，霖雨久不止。", "稍稍雲意開，駸駸日色美。", "駕言出東城，道傍玩流水。", "胸次積滯悶，一見似可洗。", "問訊元方兄，太息雍端子。", "養性在知命，制事當達理。", "病乃老人常，貧非志士恥。", "時運縱衰謝，見趣肯卑鄙。", "荒野叩槿楥，幽軒俯蓮沚。", "吾友跫然來，君子有酒旨。", "青甘剖嘉瓜，碧脆摘新李。", "加籩何必多，真率故佳爾。", "學道氣臭合，成文笑談綺。", "鳴禽窺林間，跳魚出波底。", "驚見我輩人，未有客如此。", "良晤匪易得，淺醉彌可喜。", "會當時盍簪，斯樂未云已。"]'),
('a078fb7b-6fd7-45aa-b651-948fa20be1ae','六月初一日次韻酬元煇','方回','宋','宋诗','song-poetry','','[]','吾不及淵明，愛酒未能止。',204,'全唐诗/poet.song.231000.json','["吾不及淵明，愛酒未能止。", "不仕亦有祿，頼此天之美。", "年年攪饑腸，憂旱復憂水。", "邇來甘雨調，惡况已一洗。", "□□佳人葠，古綿真附子。", "服藥焉用多，寡欲即將理。", "固窮豈無說，屢空詎足恥。", "彼以盜賊富，乃茲所深鄙。", "懷人渴儀刑，秉芳在中沚。", "心賞於焉臻，酌水味亦旨。", "况有杯中物，侑以來禽李。", "清談有餘韻，草木亦側耳。", "雲霄自旦奭，丘壑且園綺。", "向來榮進念，腐泥沉井底。", "相與賡醉吟，所樂不過此。", "寄語亨衢人，可弔不可喜。", "猗嗟楚子文，庸肯慍三已。"]'),
('5ecd2e7b-26bf-4db3-b494-58e6883a0b64','送嚴陵汪學正巽元併寄趙賓暘','方回','宋','宋诗','song-poetry','','[]','子去桐江路，諸生迓水濱。',48,'全唐诗/poet.song.231000.json','["子去桐江路，諸生迓水濱。", "爲言前郡守，獨憶老詩人。", "揖拜衣冠古，歌游棟宇新。", "故吾誰見念，辛苦戰場塵。"]'),
('14e557e8-8de1-4bbc-bb0b-640a9d6bcf65','次韻元煇昨游','方回','宋','宋诗','song-poetry','','[]','藕花茭葉忽明眼，此地聊乘解慍風。',64,'全唐诗/poet.song.231000.json','["藕花茭葉忽明眼，此地聊乘解慍風。", "無酒尚堪翻作有，蒼顔終不變爲紅。", "虛聲浪漫盈天下，急景奔騰過日中。", "萬事可容著心力，邇來詩句亦怱怱。"]'),
('c6f14b41-dee7-400d-937a-76c097c054c3','贈程山人','方回','宋','宋诗','song-poetry','','[]','青囊遺論究幾深，屋宅爲陽墓宅陰。',64,'全唐诗/poet.song.231000.json','["青囊遺論究幾深，屋宅爲陽墓宅陰。", "元出易中後天卦，更憑心上指南針。", "故知形勝從來有，難必榮華此處尋。", "周洛秦函倏興廢，豈虞山水喚之今。"]'),
('972fb668-de17-4de5-b028-6b7ad0c8f1a7','五月六月雨寒二十餘日','方回','宋','宋诗','song-poetry','','[]','五月今年更索裘，窮山積雨冷於秋。',64,'全唐诗/poet.song.231000.json','["五月今年更索裘，窮山積雨冷於秋。", "斯須變化真難料，宿昔沉綿幸少瘳。", "老强讀書猶有益，貧因知道故無憂。", "葵花零落渾閒事，且望田家早稻收。"]'),
('233804a9-ab52-446a-a695-7a7535cbb3d0','慵起','方回','宋','宋诗','song-poetry','','[]','慵起披衣出戶遲，今年最喜免招醫。',64,'全唐诗/poet.song.231000.json','["慵起披衣出戶遲，今年最喜免招醫。", "粗容破竈炊雲子，可用芳筵佐雪兒。", "醉後作詩多不記，夢中讀易了無疑。", "雨晴風爽園林密，獨立清陰過午時。"]'),
('49c408d8-ea5b-47eb-bca2-e6a36a909df5','次韻金漢臣雨後病起見寄','方回','宋','宋诗','song-poetry','','[]','一自蒲盃弔楚湘，倏成炎溽乍陰凉。',64,'全唐诗/poet.song.231000.json','["一自蒲盃弔楚湘，倏成炎溽乍陰凉。", "恨無櫪上如飛馬，往問齋中獨宿牀。", "病起精神如雨止，懷歸愁思與天長。", "何時共□□詩說，直上高峰看夕陽。"]'),
('fa1f6f9c-4196-45bc-87df-919b84139415','暑天','方回','宋','宋诗','song-poetry','','[]','暑天無暑荷天公，似覺吾家亦未窮。',64,'全唐诗/poet.song.231000.json','["暑天無暑荷天公，似覺吾家亦未窮。", "蔭傍漢朝名將樹，凉分楚澤大王風。", "洛遺書訂三焦誤，河負圖觀一點中。", "忽藉流螢足詩句，黄昏燁熠起林叢。"]'),
('238878b3-7a55-4e4f-8a77-bb5cdbc24ff7','次韻金漢臣喜晴','方回','宋','宋诗','song-poetry','','[]','雨足秧疇始放晴，鄉鄰所至有歡聲。',64,'全唐诗/poet.song.231000.json','["雨足秧疇始放晴，鄉鄰所至有歡聲。", "宰公明察無冤獄，太守辛勤自勸耕。", "我昔黄童成白首，誰今赤子視蒼生。", "定知米價秋來減，遍買村醪處處行。"]'),
('1c66be24-a56c-4433-91db-65644cd96d55','夜望','方回','宋','宋诗','song-poetry','','[]','夕陽已下月初生，小暑纔交雨漸晴。',64,'全唐诗/poet.song.231000.json','["夕陽已下月初生，小暑纔交雨漸晴。", "南北斗杓雙向直，乾坤卦位八方明。", "古人已往言猶在，末俗何爲路未平。", "似覺草蟲亦多事，爲予凄楚和吟聲。"]'),
('6f17ba87-e0b1-480f-a7ba-8bbc04c1bf0e','早起','方回','宋','宋诗','song-poetry','','[]','萬事崢嶸入夜思，稍欣無病且無饑。',64,'全唐诗/poet.song.231000.json','["萬事崢嶸入夜思，稍欣無病且無饑。", "山田望稔秋收近，暑月乘凉早起宜。", "暗撚鬚髯驚露濕，倦爬疥癬喜風吹。", "買薪汲水營蔬茹，草草盤餐了一炊。"]'),
('f2631e98-450a-4159-9a7c-bbcb480d45e5','次韻送胡教諭炳文如金陵二首  其一','方回','宋','宋诗','song-poetry','','[]','子有山中田，何不力自耕。',96,'全唐诗/poet.song.231000.json','["子有山中田，何不力自耕。", "曰予抱奇志，犯軷爲此行。", "於茲匏瓜繫，曷若鳳凰鳴。", "徒步未可料，一日秉國成。", "老夫察時義，不待易四營。", "大物苦難運，高位防易傾。", "苟且忝一命，奔走疲送迎。", "鄉里政自佳，歸來訓諸生。"]'),
('2d34a29e-64e7-446a-ab8b-978e53cfbd9f','次韻送胡教諭炳文如金陵二首  其二','方回','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','治郡愧坐嘯，歸田服躬耕。',96,'全唐诗/poet.song.231000.json','["治郡愧坐嘯，歸田服躬耕。", "始覺少年誤，浪作萬里行。", "書傳極古汲，詞藝爭先鳴。", "豈知老欲死，一事終無成。", "之子初遊遠，物務思經營。", "北望中原闊，東視長江傾。", "金陵冠蓋地，豈無倒屣迎。", "心賞少不至，謹無負平生。"]'),
('c411273e-b0c3-4a48-88ed-63a47e00caa9','送金漢臣明府徐蜚英贊府還婺源','方回','宋','宋诗','song-poetry','','[]','星源長貳兩賢者，丰采精神玉不如。',64,'全唐诗/poet.song.231000.json','["星源長貳兩賢者，丰采精神玉不如。", "詩外更工長短句，腹中何限古今書。", "平生事可心無愧，我輩人常氣有餘。", "記取孚舟亭上語，定應時復寄魚書。"]'),
('cfa3b975-ba83-4789-905b-0ec59cae7dc5','哭從兄良遇','方回','宋','宋诗','song-poetry','','[]','先祖五男子，其下八男孫。',288,'全唐诗/poet.song.231000.json','["先祖五男子，其下八男孫。", "白首涉患難，僅餘二老存。", "兄昔健如虎，行步疾飛奔。", "長眉具壽相，脩髯當風掀。", "千丈聳巨棟，一朝成枯根。", "强者尚若此，弱又其奚論。", "惟兄負剛勁，臨事簡不煩。", "可否率正色，臧否多直言。", "談笑無城府，其實春和溫。", "憸壬有弗察，平地生讎冤。", "惟揚赴逮對，乃用怨報恩。", "十年歸來乎，下帷董生園。", "此死幸無愧，彼生非游魂。", "春官一再上，科名合高騫。", "世事既鼎革，何如偃丘樊。", "百里許起家，性終不耐喧。", "軍馬塵未已，朝夕常閉門。", "劣弟解彫郡，生理古井眢。", "時復造兄室，釃酒崇盤餐。", "二月近生日，爛漫傾芳樽。", "豈謂三四月，醫藥昧病源。", "平生無妾侍，寡欲培真元。", "焉用艾與附，內外加炮燔。", "五月二十八，了了語不昏。"]'),
('d6aa49e5-5e88-4dbd-8e5a-777cdcc647cd','坐看南山雲二首  其一','方回','宋','宋诗','song-poetry','','[]','晨起無一事，坐看南山雲。',96,'全唐诗/poet.song.231000.json','["晨起無一事，坐看南山雲。", "爲雨殆可必，盎然心自欣。", "耕疇已久捐，稔歲猶願聞。", "匪惟救阨餒，兼足蘇惔焚。", "升降地天泰，兌艮通氤氳。", "高能以虛受，能下斯爲君。", "宇宙儻非爾，函靈焉不僨。", "吾生與草木，幸茲同芳芬。"]'),
('0c8ea4a2-a5f0-4689-8b7d-c58a105d6d74','坐看南山雲二首  其二','方回','宋','宋诗','song-poetry','','[]','幽林響欲滴，夜色始欲分。',96,'全唐诗/poet.song.231000.json','["幽林響欲滴，夜色始欲分。", "扶桑定已紅，星象收其文。", "尚復有飛鼠，撲擊空中蚊。", "須臾兩滅迹，寂然藏紛紜。", "鄰煙氣稍上，谷禽聲漸聞。", "七月入伏末，未減炎暑熏。", "皇后漏雨意，似閔黎庶勤。", "此心誰予知，坐看南山雲。"]'),
('acff0a25-89a2-44c7-9667-d73194cca528','早起','方回','宋','宋诗','song-poetry','','[]','調和風雨順星辰，幸是人間自有人。',64,'全唐诗/poet.song.231000.json','["調和風雨順星辰，幸是人間自有人。", "老頼獨眠無疾病，閒能早起更精神。", "胸中羲后先天易，物外無懷太古民。", "頗怪吾廬舊山色，不隨時世與俱新。"]'),
('34f03a63-f7e4-43ab-b9a5-f608b466b28e','野趣居士楊公遠令其子依竹似孫爲予寫真贈以長句','方回','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','爾來畫工工畫花，俗眼所識惟紛華。',320,'全唐诗/poet.song.231000.json','["爾來畫工工畫花，俗眼所識惟紛華。", "牡丹百卉鬨蜂蝶，芙蓉鴛鴦相交加。", "大爲屏帳小卷軸，堆紅積綠供□奢。", "高人瞥見付一笑，婦女小兒爭驚誇。", "我愛楊君畫山水，要自胸中有妙理。", "巴東巫峽猿夜鳴，洞庭瀟湘雁秋起。", "皓月明河萬里天，淡墨掃成頃刻耳。", "舊與結交三十年，今老而歸識其子。", "是父是子皆詩人，每一相逢佳句新。", "西風蕭寺父謂子，寫此前朝朝士真。", "自言畫是作詩法，狀貌之外觀精神。", "忽似老夫對明鏡，翛然雪鬢烏紗巾。", "野態愁容本難畫，問言何得此奇怪。", "得諸苦心熟在手，郢人斤斧由基射。", "腰圍不用黄金带，象笏紫袍貧已賣。", "只消結束作樵翁，看山獨立長松下。", "大楊居士醉曰然，小楊居士呼來前。", "眉間更著□毫一，縹緲詩仙仍酒仙。", "汝不逢我作郡年，此直當酬百萬錢。", "今既無此無可言，聊復贈之歌一篇。"]'),
('3b4ff123-32d2-4bf5-8d80-d92a04aa5faa','守孫滿歲','方回','宋','宋诗','song-poetry','','[]','升沉榮瘁可須論，古鏡當空了不昏。',64,'全唐诗/poet.song.231000.json','["升沉榮瘁可須論，古鏡當空了不昏。", "莫笑今踰六旬叟，頗欣已有兩男孫。", "特牲與子羞家廟，聯騎何人叩圃門。", "急掃秋亭具殽果，凉邊爛漫倒清樽。"]'),
('94b3e31d-8680-4e49-8925-7b568e991424','贈刊印朱才俊','方回','宋','宋诗','song-poetry','','[]','科斗何年變篆字，至秦程邈翻爲隸。',160,'全唐诗/poet.song.231000.json','["科斗何年變篆字，至秦程邈翻爲隸。", "今人但習真草行，誰會六書三耦意。", "篆所最難柱與圈，學打一圈費三年。", "豈容臆决蔑師授，汩沒形象迷傍偏。", "九江法帖鐘鼎刻，兵火以來猶可得。", "人間亦有說文本，臣翱反切臣鍇釋。", "朱生贈我古印章，奎躔壁度森開張。", "自言少小嗜此藝，意欲徑上陽冰堂。", "細觀刀筆最佳處，頗識傳箋通訓故。", "苟焉餬口棲此身，元來亦是知書人。"]'),
('57ca633e-34a9-4c9d-a5fb-d5e8ee35b1dc','不寐','方回','宋','宋诗','song-poetry','','[]','孤燈獨榻夜難晨，秋氣初寒展轉頻。',64,'全唐诗/poet.song.231000.json','["孤燈獨榻夜難晨，秋氣初寒展轉頻。", "每怪未嘗成夢寐，自憐何苦費精神。", "非關世事兼身事，欲學賢人與聖人。", "更著冰霜當七十，向來虛費幾青春。"]'),
('41a6fd08-458f-4f60-9ff2-75648a7577de','中秋前一日雨送罌粟戎葵子與劉元煇','方回','宋','宋诗','song-poetry','','[]','小雨翻鋤土带沙，戎葵罌粟送詩家。',64,'全唐诗/poet.song.231000.json','["小雨翻鋤土带沙，戎葵罌粟送詩家。", "敢爭天上中秋月，且種人間隔歲花。", "小稔米今猶未賤，固窮酒可不須賒。", "乘閒儻肯來相過，有水吾能自煮茶。"]'),
('9d9190d1-f972-4e16-b214-d820b7ada03c','次韻元煇中秋雨','方回','宋','宋诗','song-poetry','','[]','良辰合與一樽酬，有酒無朋也自愁。',64,'全唐诗/poet.song.231000.json','["良辰合與一樽酬，有酒無朋也自愁。", "萬事只堪花老眼，一年又過雨中秋。", "鳴砧處處凄鄰巷，擊柝相望起戍樓。", "更著亂蛩環獨榻，平生天地付神遊。"]'),
('8b123323-a9f4-40b8-9588-0b7475a2791f','題汪氏孝節堂','方回','宋','宋诗','song-poetry','','[]','三從分定付之天，捧案曾無月再圓。',64,'全唐诗/poet.song.231000.json','["三從分定付之天，捧案曾無月再圓。", "萊子方同綵衣舞，鄘風忽賦柏舟篇。", "頻年兵革經多難，奕世門閭喜獨全。", "孝節從來足陰相，兒孫衮衮壽眉前。"]'),
('766b2b64-f3b2-4dc2-8d9b-5c207b8d131e','喜馮伯田至','方回','宋','宋诗','song-poetry','','[]','扁舟相送浙河濱，又向苕溪住幾春。',64,'全唐诗/poet.song.231000.json','["扁舟相送浙河濱，又向苕溪住幾春。", "雨路遠來應跋涉，雪眉聞說尚精神。", "山城風物非他日，詩社交朋不數人。", "略遣後生識前輩，揮犀爲洗庾郎塵。"]'),
('273673d8-1198-4251-8608-a6f8113a1e18','夜思','方回','宋','宋诗','song-poetry','','[]','夜氣侵寒薄寢衣，迴頭六十二年非。',64,'全唐诗/poet.song.231000.json','["夜氣侵寒薄寢衣，迴頭六十二年非。", "直能欹枕思時透，始覺挑燈得處微。", "百蛬漸侵床畔語，一螢忽入帳前飛。", "研朱點墨皆陳迹，見道元來自有機。"]'),
('44bf2d60-7f9f-4c69-9fcd-d35a28a2eae9','次韻伯田見酬四首  其一','方回','宋','宋诗','song-poetry','','[]','久缺牋筒到霅濱，相逢依舊氣如春。',64,'全唐诗/poet.song.231000.json','["久缺牋筒到霅濱，相逢依舊氣如春。", "深藏尺璧元無價，時擊圓蓍尚有神。", "桑梓兵戈三峽路，衣冠文物五朝人。", "片時略得陪清話，一掃胸中萬斛塵。"]'),
('e2838bab-4578-4059-be4f-438dce9a70e0','次韻伯田見酬四首  其二','方回','宋','宋诗','song-poetry','','[]','世故吾其問水濱，向來不合典班春。',64,'全唐诗/poet.song.231000.json','["世故吾其問水濱，向來不合典班春。", "一從去作滄浪客，幾度重題鬰壘神。", "垂死豈堪思往事，忍窮方欲作閒人。", "喜公强健猶如故，未有清樽可祓塵。"]'),
('16dfcca3-aac5-49e5-9794-343498bb5071','次韻伯田見酬四首  其三','方回','宋','宋诗','song-poetry','','[]','半年洄泝越江濱，每愧羊裘老富春。',64,'全唐诗/poet.song.231000.json','["半年洄泝越江濱，每愧羊裘老富春。", "歸隠尚能聯比長，出遊復肯祭行神。", "枯腸近飽三爻夢，宿齒宜肩四豆人。", "能顧寒齋共芳茗，蠹編時爲拂蛛塵。"]'),
('b7359fc5-17d0-4bfb-a7bc-23d8ba7908f9','次韻伯田見酬四首  其四','方回','宋','宋诗','song-poetry','','[]','六橋久客舊湖濱，春日花開不似春。',64,'全唐诗/poet.song.231000.json','["六橋久客舊湖濱，春日花開不似春。", "游學頓無福建子，科名更說梓潼神。", "暗驚淵實丘夷事，枉作書癡傳癖人。", "辛苦湘纍辨蘭艾，莊生齊物等埃塵。"]'),
('cca9dcb2-55ca-48a2-96b8-b3e201a2a3e3','次韻仇仁近有懷見寄十首  其一','方回','宋','宋诗','song-poetry','','[]','我能納祿君辭聘，大覺蓑衣勝衮衣。',64,'全唐诗/poet.song.231000.json','["我能納祿君辭聘，大覺蓑衣勝衮衣。", "有徑弗行緣畏險，無形可見要研幾。", "就令枵腹常亡頼，儘勝枯骸永不歸。", "何限戟門委荒草，高堂猶記舊巍巍。"]'),
('5937042f-8c5a-4a00-81ad-9fd809b8eef3','次韻仇仁近有懷見寄十首  其二','方回','宋','宋诗','song-poetry','','[]','誰識虛翁此一虛，歸來不歎食無魚。',64,'全唐诗/poet.song.231000.json','["誰識虛翁此一虛，歸來不歎食無魚。", "早聞曾撰異三子，近喜陶詩賦二疏。", "但苦老身多疾痛，時呼醫士問方書。", "君知湖海元龍否，豪氣年來已盡除。"]'),
('5e191990-3181-464c-9b9a-bc987ad2b24b','次韻仇仁近有懷見寄十首  其三','方回','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','老玩韋編尚可爲，復能吃口對期期。',64,'全唐诗/poet.song.231000.json','["老玩韋編尚可爲，復能吃口對期期。", "離明偶剔書燈見，坎止因斟硯水知。", "豈厭微塵裨泰嶽，只愁殘照近咸池。", "兒曹未悟侯王夢，不了邯鄲黍一炊。"]'),
('6da251da-083d-444a-8980-573004ae4595','次韻仇仁近有懷見寄十首  其四','方回','宋','宋诗','song-poetry','','[]','身歷干戈百戰塵，休官仍似布衣貧。',64,'全唐诗/poet.song.231000.json','["身歷干戈百戰塵，休官仍似布衣貧。", "每看事有難行處，未見心無不愧人。", "秋稔粥饘猶可繼，夜凉燈火已堪親。", "閉門讀易吾謀决，莫用蓍龜問鬼神。"]'),
('da4ac89d-9f95-4eaf-8e9e-818f4d5f808b','次韻仇仁近有懷見寄十首  其五','方回','宋','宋诗','song-poetry','','[]','寄來詩卷了無塵，想見家貧道不貧。',64,'全唐诗/poet.song.231000.json','["寄來詩卷了無塵，想見家貧道不貧。", "真復遠追前輩味，頗驚頓異去來人。", "驅車蕩蕩行須至，破的遥遥見已親。", "換骨得仙內丹熟，可須浮海望三神。"]'),
('e2f00ed3-c09c-4538-b7e8-b955c8625efe','次韻仇仁近有懷見寄十首  其六','方回','宋','宋诗','song-poetry','','[]','少年忽作白頭人，慷慨悲歌豈爲身。',64,'全唐诗/poet.song.231000.json','["少年忽作白頭人，慷慨悲歌豈爲身。", "屈子獨醒天可問，重華久去士常貧。", "瓶無儲粟陶元亮，馬似乘船賀季真。", "此味孰能相識察，隕霜碩果有餘春。"]'),
('04687ce2-283e-4d3c-b9eb-7387ebd24217','次韻仇仁近有懷見寄十首  其七','方回','宋','宋诗','song-poetry','','[]','漢廷簪紱簉金張，初服逡巡返士鄉。',64,'全唐诗/poet.song.231000.json','["漢廷簪紱簉金張，初服逡巡返士鄉。", "勇退能爲疏傅去，過剛似勝次公狂。", "庭梧隕葉元非死，秋燕辭巢不待凉。", "玩物察時遠災咎，不須空熱九迴腸。"]'),
('4709ed6c-50de-43ee-a99c-75d5ddee27b9','次韻仇仁近有懷見寄十首  其八','方回','宋','宋诗','song-poetry','','[]','守雌甘似不鳴將，靜看無庸手脚忙。',64,'全唐诗/poet.song.231000.json','["守雌甘似不鳴將，靜看無庸手脚忙。", "沮溺故難同孔子，綺園何獨避高皇。", "星移斗轉光陰疾，林密山深氣味長。", "萬事灰心如嚼蠟，唯餘杯酒未相忘。"]'),
('f249880e-9528-44fe-bad5-f168280efa72','次韻仇仁近有懷見寄十首  其九','方回','宋','宋诗','song-poetry','','[]','猶喜看書懶作詩，暮年自合省云爲。',64,'全唐诗/poet.song.231000.json','["猶喜看書懶作詩，暮年自合省云爲。", "預知陰雨骨骸痛，怯上好山筋力罷。", "不寐有時忘數息，無疑焉用扣歸奇。", "寄聲爲報仇香道，近日交朋獨爾思。"]'),
('ffc3d8ec-4c8e-497e-a364-e5bdcafb8fce','次韻仇仁近有懷見寄十首  其一○','方回','宋','宋诗','song-poetry','','[]','相從汩沒走泥塗，忽又還家半載餘。',64,'全唐诗/poet.song.231000.json','["相從汩沒走泥塗，忽又還家半載餘。", "把盞何由嘗我酒，典錢猶憶借君書。", "兒孫十輩娛詩老，梅竹千株護野廬。", "東望懷人屢搔首，能來相訪定何如。"]'),
('ae19f2ba-e9e5-48a7-bf79-1f91b967d3a1','訪臨川楊仲權于天慶','方回','宋','宋诗','song-poetry','','[]','隠居何所爲，性懶絕造請。',156,'全唐诗/poet.song.231000.json','["隠居何所爲，性懶絕造請。", "駕言東城東，恍兮異人境。", "脩廊寂無聲，未忍踐竹影。", "獨立味玄澹，徐步入深冷。", "秋光照虛庭，拱揖冠服整。", "中有專氣翁，學道早脫穎。", "誠極語謝飾，幾動意潜領。", "煮茶雜椒榝，案酒粲梨梬。", "悅神良會稀，遺物閒晷永。", "休官陶元亮，遯世陸脩靜。", "異代復同調，霞外茲可騁。", "研幽挹高致，探妙發遐省。", "何言壺中天，心遠塵自辟。"]'),
('fafa1b39-cb14-4421-9f8d-4acded1b0161','九日約馮伯田王俊甫劉元煇','方回','宋','宋诗','song-poetry','','[]','山雨初開一望之，似無筋力可登危。',64,'全唐诗/poet.song.231000.json','["山雨初開一望之，似無筋力可登危。", "每重九日例凄苦，垂七十年更亂離。", "今歲江南猶有酒，吾曹天下謂能詩。", "肯來弔古酣歌否，恰放黄花一兩枝。"]'),
('3c4017bd-cce2-4a7d-a7e0-566636ca8a8d','次韻王俊甫山長九日登烏聊二首  其一','方回','宋','宋诗','song-poetry','','[]','山色初明小雨開，可容無地拓襟懷。',64,'全唐诗/poet.song.231000.json','["山色初明小雨開，可容無地拓襟懷。", "荒寒試與登臨去，奇崛能隨感慨來。", "何限詩愁關世故，終憑爛醉了生涯。", "風流二謝猶堪恨，俯首劉郎戲馬臺。"]'),
('cd0138aa-f8da-4b8b-934c-e7da07d82679','次韻王俊甫山長九日登烏聊二首  其二','方回','宋','宋诗','song-poetry','','[]','江邊危阜俯江臯，去馬來牛細若毛。',64,'全唐诗/poet.song.231000.json','["江邊危阜俯江臯，去馬來牛細若毛。", "古道向來元寂寂，俗流何處不滔滔。", "漫拈老筆雕空闊，徑命芳樽洗鬰陶。", "天地年年有摇落，悲秋端謝楚人騷。"]'),
('8a1db89e-961f-48e4-adaf-af5ec177a25f','次韻孫元京見過言詩  其一','方回','宋','宋诗','song-poetry','','[]','騷壇爭長各稱兵，未卜誰歟霸業成。',64,'全唐诗/poet.song.231000.json','["騷壇爭長各稱兵，未卜誰歟霸業成。", "欲療左盲治穀廢，合除白俗掃元輕。", "屢更落落心猶壯，常恐空空氣驟盈。", "據險作難終未是，頼公指示軌圖平。"]'),
('45f855fe-6d66-427e-80b4-95a98ac270da','次韻孫元京見過言詩  其二','方回','宋','宋诗','song-poetry','','[]','眼底驚嗟見此流，祇嫌接對未云稠。',64,'全唐诗/poet.song.231000.json','["眼底驚嗟見此流，祇嫌接對未云稠。", "蘇門逸響追長嘯，湘浦餘情續遠遊。", "新息今須乘果下，襄陽誰漫釣槎頭。", "吾衰久矣公猶健，好控飛車跨九州。"]'),
('0c9953aa-27fc-466f-943b-d996aceb5c58','九日詩馮伯田王俊甫劉元煇楊泰之見和復次韻二首  其一','方回','宋','宋诗','song-poetry','','[]','空經虛緯費來之，弦急常由瑟柱危。',64,'全唐诗/poet.song.231000.json','["空經虛緯費來之，弦急常由瑟柱危。", "壯似陰山歌敕勒，悲於易水和漸離。", "崎嶇萬古無窮事，酩酊重陽幾句詩。", "剩喜故人會吾意，東籬何日酹殘枝。"]'),
('fb23e744-3037-4920-bd71-ef18b46271ea','九日詩馮伯田王俊甫劉元煇楊泰之見和復次韻二首  其二','方回','宋','宋诗','song-poetry','','[]','歸來誓墓學羲之，政坐機張觸處危。',64,'全唐诗/poet.song.231000.json','["歸來誓墓學羲之，政坐機張觸處危。", "久已光芒韜巨闕，更能文采眩長離。", "奏書方朔三千牘，飲酒淵明二十詩。", "索米長安饑欲死，何如終保傲霜枝。"]'),
('d1ac677e-9e9b-4597-9f38-4393e302eb79','寄還程道益道大昆季詩卷','方回','宋','宋诗','song-poetry','','[]','山水吾州稱絕奇，間生傑出當如之。',64,'全唐诗/poet.song.231000.json','["山水吾州稱絕奇，間生傑出當如之。", "不行天上五嶺路，焉識人間二程詩。", "無逸幼槃金華似，才翁子美歐陽知。", "怒流洶湧各分派，萬折到海夫奚疑。"]'),
('62641bf1-2c31-49e6-9298-fb67e88cea83','爲黄仲宣賦山中四章章四句  其一','方回','宋','宋诗','song-poetry','','[]','山中之朝，有溪可瓢。',20,'全唐诗/poet.song.231000.json','["山中之朝，有溪可瓢。", "飲我之水，亦逍以遥。"]'),
('7dbb4fda-2b58-4a80-ae8a-3e0a09f61844','爲黄仲宣賦山中四章章四句  其二','方回','宋','宋诗','song-poetry','','[]','山中之暮，豈不風雨。',20,'全唐诗/poet.song.231000.json','["山中之暮，豈不風雨。", "心與一燈，耿耿千古。"]'),
('025b0d3f-90bb-4e54-8d27-082b4320f7d8','爲黄仲宣賦山中四章章四句  其三','方回','宋','宋诗','song-poetry','','[]','山中之人，耘夫耕民。',20,'全唐诗/poet.song.231000.json','["山中之人，耘夫耕民。", "鯖厥五侯，其如子真。"]'),
('cc8ee910-5ec6-4dcf-be6d-f7fdf1babe22','爲黄仲宣賦山中四章章四句  其四','方回','宋','宋诗','song-poetry','','[]','于疏于蹻，朋來其學。',20,'全唐诗/poet.song.231000.json','["于疏于蹻，朋來其學。", "彼惡知茲，山中之樂。"]'),
('5e61e5e1-29bc-45d0-8c0c-fa80d0be4417','承金漢臣寄詩將及一月次韻奉酬併呈徐蜚英','方回','宋','宋诗','song-poetry','','[]','千里秋光一倚欄，危樓四望碧雲寬。',64,'全唐诗/poet.song.231000.json','["千里秋光一倚欄，危樓四望碧雲寬。", "遥知對壘分詩將，未覺同舟怯縣灘。", "九日與誰同把酒，八年如我倦彈冠。", "會難別易駒陰迅，時展來篇細細看。"]'),
('c5b778e5-e000-4756-ae3d-5a064ade5b49','張滁州挽詞二首  其一','方回','宋','宋诗','song-poetry','','[]','世變古來有，人才時豈無。',48,'全唐诗/poet.song.231000.json','["世變古來有，人才時豈無。", "已移甄井璽，猶握釀泉符。", "壽及周三老，名成漢八厨。", "彼哉武斷者，盜起欲全軀。"]'),
('21e2f0d4-39e3-45c3-86dd-c3b9ca67fa3a','張滁州挽詞二首  其二','方回','宋','宋诗','song-poetry','','[]','上庠同補處，祖父昔通家。',48,'全唐诗/poet.song.231000.json','["上庠同補處，祖父昔通家。", "書在燈俱續，舟移劍共差。", "故都箕子麥，晚憶邵平瓜。", "五福公無恨，吾生自可嗟。"]'),
('66189ad0-4cdd-4295-be8b-e3fc2930af09','漢臣明府與公度使君話吾州山水之勝有詩次韻二首  其一','方回','宋','宋诗','song-poetry','','[]','繡作羣峰玉作川，筆端秋思浩無邊。',32,'全唐诗/poet.song.231000.json','["繡作羣峰玉作川，筆端秋思浩無邊。", "賜金增秩從民借，會費將軍九萬牋。"]'),
('bf3c09bd-75d4-42bb-a361-add8a3b8cb1b','漢臣明府與公度使君話吾州山水之勝有詩次韻二首  其二','方回','宋','宋诗','song-poetry','','[]','秋容洗雨雁浮空，牛斗之南江以東。',64,'全唐诗/poet.song.231000.json','["秋容洗雨雁浮空，牛斗之南江以東。", "是處皆爲群玉府，誰家不似水晶宮。", "君侯總是文章伯，文物差宜錦繡胸。", "緩馬倚樓隨所適，高情長在醉吟中。"]'),
('8a257539-8639-4c4f-a8d3-69a1684ba4a9','次韻金漢臣五城道中','方回','宋','宋诗','song-poetry','','[]','郊行胸次爽於秋，歲稔天寬百姓憂。',64,'全唐诗/poet.song.231000.json','["郊行胸次爽於秋，歲稔天寬百姓憂。", "但有樵人歌隴上，永無廷尉望山頭。", "最宜曠野開詩思，未覺他鄉動客愁。", "想見霜林疏更好，綠陰時節憶曾遊。"]'),
('11f2dcf8-5481-44bf-ba8e-3902d98368d4','次韻漢臣閔口渡','方回','宋','宋诗','song-poetry','','[]','歲月匆匆雁往迴，馬頭西去又東來。',32,'全唐诗/poet.song.231000.json','["歲月匆匆雁往迴，馬頭西去又東來。", "不知自有乾坤後，幾度蘆花謝復開。"]'),
('db4d97bc-bafe-46aa-a6a2-3d6db04f821b','九月三十日漢臣置酒次日有詩次韻','方回','宋','宋诗','song-poetry','','[]','槁梧策策晚風秋，始覺天邊雨意休。',64,'全唐诗/poet.song.231000.json','["槁梧策策晚風秋，始覺天邊雨意休。", "掃盡陰霾供一醉，豁開空闊慰雙眸。", "青銅未至無王老，紅袖何嫌有莫愁。", "我亦放顛插殘菊，不羞衰老雪盈頭。"]'),
('aed851d3-18aa-4353-a91b-213532145501','贈壽昌墨客葉實甫','方回','宋','宋诗','song-poetry','','[]','古人削竹以爲筆，木板爲方竹爲策。',344,'全唐诗/poet.song.231000.json','["古人削竹以爲筆，木板爲方竹爲策。", "其字科斗或鳥迹，或篆或籀煤傅漆。", "未有今人所謂墨，晉發汲冢尚可識。", "地中間獲鐘鼎刻，文爲之具未爲極。", "何其妙哉善摹畫，束縛毫管備肸飾。", "鶴眼鳳咮鑿湍石，黟楮剡藤擣成足。", "松煙魚胞和堅密，誇精鬬巧不遺力。", "隸真行草最後出，萬乃不能及古一。", "有良弓矢無良射，器利工拙繆繩尺。", "風頹俗降嘆近日，四寶往往俱難得，尤艱得者墨一物。", "燃爇膏脂磔桐實，非膠太燥則太溢。", "高價玄圭詭蒼璧，其實不直瓦與礫。", "羲獻不起歐褚畢，亦無李杜大詩伯。", "顛倒吏牘冒儒籍，乳臭小兒僅甲乙。", "苟且研磨暗竄易，奚李縱生懼稱屈。", "壽昌葉老獨奇崛，陟阪涉澗負囊笈。", "直笏圓丸動盈百，病風手試銅蟾滴。", "瀲灧龍光浮五色，便覺硯中轟霹靂。", "金錢亦不過求索，但欲流名寄篇什。", "噫嘻此一怪墨客，作書轉送三歎息。", "物有當黑不肯黑，事有當白不肯白。"]'),
('6d659562-93eb-490e-89a8-9bf4562a1ca1','題吳山長文英野舟五首  其一','方回','宋','宋诗','song-poetry','','[]','春潮滯雨橫舟晚，成就蘇州一段奇。',32,'全唐诗/poet.song.231000.json','["春潮滯雨橫舟晚，成就蘇州一段奇。", "向使有人爭此渡，韋郎眼底定無詩。"]'),
('a0743e0a-6982-490c-93d8-32c820d07b5f','題吳山長文英野舟五首  其二','方回','宋','宋诗','song-poetry','','[]','下邽老子扶黄屋，直上澶州城北樓。',32,'全唐诗/poet.song.231000.json','["下邽老子扶黄屋，直上澶州城北樓。", "遼陽鐵騎驚相問，舊日巴東野水舟。"]'),
('8e38d2bd-49bf-4a47-8abb-f3af3e92e1f5','題吳山長文英野舟五首  其三','方回','宋','宋诗','song-poetry','','[]','我有孤舟自天地，沙頭問渡苦無人。',32,'全唐诗/poet.song.231000.json','["我有孤舟自天地，沙頭問渡苦無人。", "誰家賈舶浮溟渤，脫命蛟龍亦損神。"]'),
('62cf3696-ef1a-4028-b66e-58d6bb30b50c','題吳山長文英野舟五首  其四','方回','宋','宋诗','song-poetry','','[]','大才定復不求售，至寶政須能自珍。',32,'全唐诗/poet.song.231000.json','["大才定復不求售，至寶政須能自珍。", "一篙用著方知貴，只恐悠悠懶問津。"]'),
('167b64cf-e450-4cbe-aa64-4238afb0a227','題吳山長文英野舟五首  其五','方回','宋','宋诗','song-poetry','','[]','世多漢水昭王事，誰辨烏江亭長心。',32,'全唐诗/poet.song.231000.json','["世多漢水昭王事，誰辨烏江亭長心。", "君知此處真堪託，天下無波可得深。"]'),
('585e212d-a77f-4309-81ff-83be2af9d496','喜程道大至約諸友二首  其一','方回','宋','宋诗','song-poetry','','[]','東籬殘菊未成塵，所見悠然意尚真。',64,'全唐诗/poet.song.231000.json','["東籬殘菊未成塵，所見悠然意尚真。", "玉瓚常聞歌旱麓，白顛何得賦車鄰。", "欲遵飯顆山頭路，合問深明閤裏人。", "頼是吾徒不全弱，能來爾汝話酸辛。"]'),
('7a9d7d9e-2b5d-464c-adbb-ce6f621b909b','喜程道大至約諸友二首  其二','方回','宋','宋诗','song-poetry','','[]','攢眉抱膝一衰翁，豈爲區區口腹窮。',64,'全唐诗/poet.song.231000.json','["攢眉抱膝一衰翁，豈爲區區口腹窮。", "早向前朝閲諸老，曾微晚輩紹遺風。", "草堂詩到夔州後，竹馬年思大歷中。", "略共清談商此事，未妨傾倒一樽同。"]'),
('97b7fd4a-54b4-4eb7-8382-1393898ba1e4','次韻金漢臣見雪聞雁二首  其一','方回','宋','宋诗','song-poetry','','[]','山城酒薄客愁濃，卧厭秋霖萬事慵。',32,'全唐诗/poet.song.231000.json','["山城酒薄客愁濃，卧厭秋霖萬事慵。", "九月十月忽飛雪，北人南人俱笑容。"]'),
('c042d3d1-b8f2-443f-8a96-a799c5d91131','次韻金漢臣見雪聞雁二首  其二','方回','宋','宋诗','song-poetry','','[]','月暗雲迷度杳冥，飛鳴未肯落寒汀。',32,'全唐诗/poet.song.231000.json','["月暗雲迷度杳冥，飛鳴未肯落寒汀。", "得無田里聲相似，獨此長官能細聽。"]'),
('23a6b2f4-a439-40c4-a762-52aadcbee11d','寄題汪君秀山高處','方回','宋','宋诗','song-poetry','','[]','秀山高處我未到，想見斯人獨嘯歌。',64,'全唐诗/poet.song.231000.json','["秀山高處我未到，想見斯人獨嘯歌。", "靜賞奇雲臨翠巘，醉吞朗月上銀河。", "異香染筆花間寫，清影摇衣竹裏過。", "愧無健句凌空闊，奈此天邊絕景何。"]'),
('f384e041-f16e-48d3-a641-425efd218b96','十月中澣酒熟客至分韻得菊字','方回','宋','宋诗','song-poetry','','[]','亂離脫此生，真復類殘菊。',108,'全唐诗/poet.song.231000.json','["亂離脫此生，真復類殘菊。", "嚴霜百草死，愧我一影獨。", "鄉鄰豪奪兒，豈不金滿屋。", "或乃盜賊起，全家被屠戮。", "賈禍由稔惡，寡悔勝干祿。", "聊保兩鬢白，時倒一樽綠。", "客有可人至，酒適今朝熟。", "隔牆馬蹄響，呵殿盛騶僕。", "天邊本無物，眼若送鴻鵠。"]'),
('7572b448-857e-4c84-86c8-07a16c41b7b1','以采菊東籬下悠然見南山爲韻賦十首  其一','方回','宋','宋诗','song-poetry','','[]','九日已過一，嘉菊無人采。',60,'全唐诗/poet.song.231000.json','["九日已過一，嘉菊無人采。", "晴軒醉餘芳，頼有我輩在。", "胸著酒斗許，意闊浩如海。", "誰能起九原，共與推千載。", "兒女較唇舌，我豈爾能凂。"]'),
('0217d3d5-1c03-46bb-853c-3a92e52a509d','以采菊東籬下悠然見南山爲韻賦十首  其二','方回','宋','宋诗','song-poetry','','[]','生者不聊生，死者已鬼錄。',60,'全唐诗/poet.song.231000.json','["生者不聊生，死者已鬼錄。", "死視生或優，冥默謝恥辱。", "側聞田野間，十人九饑腹。", "奈何值狼貪，尚欲肆荼毒。", "客去醉眼冷，獨坐數殘菊。"]'),
('47402a62-d7fa-40c5-8c82-c8e65bed44df','以采菊東籬下悠然見南山爲韻賦十首  其三','方回','宋','宋诗','song-poetry','','[]','我詩無所師，意略與古同。',60,'全唐诗/poet.song.231000.json','["我詩無所師，意略與古同。", "豪士見之笑，寒苦啼秋蟲。", "采菊忽見山，不辨南與東。", "奇句忽天來，目斷孤征鴻。", "豈有學聖賢，而不忍饑窮。"]'),
('041b3274-b5ee-4797-bb61-623dc2d89391','以采菊東籬下悠然見南山爲韻賦十首  其四','方回','宋','宋诗','song-poetry','','[]','移石甃缺路，折竹樊疏籬。',60,'全唐诗/poet.song.231000.json','["移石甃缺路，折竹樊疏籬。", "簷間見一蛛，懸身墮長絲。", "隨風有所罥，羅絡縱橫施。", "胸中密經緯，似不過一饑。", "用意爾許惡，何待網成時。"]'),
('ac9ad406-1116-4385-bc45-74f1dfba0cf1','以采菊東籬下悠然見南山爲韻賦十首  其五','方回','宋','宋诗','song-poetry','','[]','平生天外心，異乎諸子者。',60,'全唐诗/poet.song.231000.json','["平生天外心，異乎諸子者。", "著鞭無前途，焉用取竹馬。", "乍爭祖逖先，肯出桓溫下。", "黄鐘晚遭毀，轟雷釜鳴瓦。", "細玩郊沙爻，可不舉需疋。"]'),
('48528f2c-4bc8-4dd0-9bbf-e8a34483e8a2','以采菊東籬下悠然見南山爲韻賦十首  其六','方回','宋','宋诗','song-poetry','','[]','不謂予坦率，即謂予繆悠。',60,'全唐诗/poet.song.231000.json','["不謂予坦率，即謂予繆悠。", "冷官尚難爲，熱官何可求。", "寂寂雀羅門，無復車前騶。", "但恐嚴光足，終勝張禹頭。", "客來且一觴，十觴未遽休。"]'),
('999e87f9-7cce-4953-9abb-234dd1648955','以采菊東籬下悠然見南山爲韻賦十首  其七','方回','宋','宋诗','song-poetry','','[]','士衡怒鬼子，仲氏不謂然。',60,'全唐诗/poet.song.231000.json','["士衡怒鬼子，仲氏不謂然。", "雲間對日下，此語亦淺旃。", "丈夫貴有立，聲名動萬年。", "青蠅能肆污，白璧詎改妍。", "君但滿酌我，一笑吞青天。"]'),
('8491c89b-ac43-4cfc-a00a-a8bab245f848','以采菊東籬下悠然見南山爲韻賦十首  其八','方回','宋','宋诗','song-poetry','','[]','不見淵明面，淵明心可見。',60,'全唐诗/poet.song.231000.json','["不見淵明面，淵明心可見。", "問何以見之，老菊耐霜霰。", "尚欲招祖謝，豈不鄙湛羨。", "市朝紛屠剝，祿位甘苟賤。", "高舉能免此，學陶亦云善。"]'),
('af112155-cfcd-4b36-b090-04b18d1a083c','以采菊東籬下悠然見南山爲韻賦十首  其九','方回','宋','宋诗','song-poetry','','[]','正始有遺音，衣冠落東南。',60,'全唐诗/poet.song.231000.json','["正始有遺音，衣冠落東南。", "典午頼群賢，歷年百有三。", "吾聞運甓人，功與王謝參。", "晦儉佐宋齊，賣國爾乃甘。", "陶氏獨有孫，饑死終無慚。"]'),
('a53f3ae9-0571-497d-ad96-7742f1666dfa','以采菊東籬下悠然見南山爲韻賦十首  其一○','方回','宋','宋诗','song-poetry','','[]','今日見此山，明日見此山。',60,'全唐诗/poet.song.231000.json','["今日見此山，明日見此山。", "有時或不見，乃在雲霧間。", "世事亦如此，反覆多阻艱。", "陰晦待其晴，山色終當還。", "俗誚勿與競，誓死保此間。"]'),
('32260704-adda-4694-8bc6-4316fa0ffdc9','贈相士李山屋','方回','宋','宋诗','song-poetry','','[]','四十五萬坑長平，五十六萬敗彭城。',128,'全唐诗/poet.song.231000.json','["四十五萬坑長平，五十六萬敗彭城。", "頭小而銳重瞳子，可謂善戰能用兵。", "殺人何得慘如此，不知天亦還殺爾。", "世間産一虎頭相，幾陣生靈爲渠死。", "韓擒彭醢不足悲，無辜性命供娛嬉。", "漢家宗社計未定，商山老人歌紫芝。", "相人相窮不相達，天道好生不好殺。", "豈無袖手閒書生，一著滿盤死棋活。"]'),
('a6909a1b-632b-4b26-a5d9-135509e92e21','贈朱師裕','方回','宋','宋诗','song-poetry','','[]','相府違離二十年，弁兮突見外孫賢。',64,'全唐诗/poet.song.231000.json','["相府違離二十年，弁兮突見外孫賢。", "故因高韻如袁粲，豈但雄文似史遷。", "兵甲喧豗征馬地，音書斷阻去鴻天。", "因君略得平安信，諸老無多重愴然。"]'),
('7ca23843-56c0-4ba9-813e-e7b4fed7c9cd','十一月二十日南至二首  其一','方回','宋','宋诗','song-poetry','','[]','風吹六十二年春，又見陽和一夜新。',64,'全唐诗/poet.song.231000.json','["風吹六十二年春，又見陽和一夜新。", "興廢親更三國事，死生暗易萬城人。", "種花縱好誰同賞，置酒良難自慣貧。", "今獨身爲本宗長，思兄臨節倍悲辛。"]'),
('96f1b373-c29c-4747-8e47-30eea296b07d','十一月二十日南至二首  其二','方回','宋','宋诗','song-poetry','','[]','至節今年始得歸，祀先牲酒亦無幾。',64,'全唐诗/poet.song.231000.json','["至節今年始得歸，祀先牲酒亦無幾。", "兒孫長大衣裝少，婢僕頑慵廩餼微。", "交阯虞翻猶不死，荆州王粲竟何依。", "玉筩已想黄鐘動，只有心灰自懶飛。"]'),
('2d4722d0-ba53-4b03-a220-325ab784dd23','馬軍自杭至雨少止','方回','宋','宋诗','song-poetry','','[]','春盡雨還雨，山寒雲更雲。',48,'全唐诗/poet.song.231000.json','["春盡雨還雨，山寒雲更雲。", "晝常無日色，夜不見星文。", "蜂起此狂賊，馬來皆勁軍。", "尅期可平盡，玉石恐難分。"]'),
('adc54fbf-303b-45c4-9fc4-a1a669da01a1','予嘗治郡屢平賊嘆今所見不然','方回','宋','宋诗','song-poetry','','[]','昔在專城日，吾嘗破賊時。',48,'全唐诗/poet.song.231000.json','["昔在專城日，吾嘗破賊時。", "土豪勤問探，民戶感恩私。", "公論必旁采，下情須盡知。", "騎軍遠迎擊，孰識一先棋。"]'),
('250ed63a-d9cb-4154-8522-4752979dcace','十九日斬賊十二人始明正典刑','方回','宋','宋诗','song-poetry','','[]','兵興欲兩旬，三載氣初伸。',48,'全唐诗/poet.song.231000.json','["兵興欲兩旬，三載氣初伸。", "汝既甘從賊，官非樂殺人。", "早知膏白刃，何忍效黄巾。", "拙速無奇策，登城悉市民。"]'),
('f7dbb7e7-32fd-44db-a205-e42329ae2833','早大霧午大風寇銷兵解之象','方回','宋','宋诗','song-poetry','','[]','驟合公超霧，俄飛禦寇風。',48,'全唐诗/poet.song.231000.json','["驟合公超霧，俄飛禦寇風。", "大聲千里動，陰翳一時空。", "遠睇烽樓外，愁吟戰鼓中。", "所思何日見，還得一樽同。"]'),
('4ffa4cc2-2b9d-412d-b4a8-45db540c2434','二十一甲子晴','方回','宋','宋诗','song-poetry','','[]','昨日大風聲，今朝甲子晴。',48,'全唐诗/poet.song.231000.json','["昨日大風聲，今朝甲子晴。", "整襟衣頓爽，開匣鏡偏明。", "早就鯨鯢築，終全燕雀成。", "清和舊時節，新麵入山城。"]'),
('a7abfd60-cba7-40b3-9c51-00a434e63ebc','二十三日天氣絕佳西軍還二十四日東如績溪','方回','宋','宋诗','song-poetry','','[]','獨坐綠陰下，追思秋日春。',48,'全唐诗/poet.song.231000.json','["獨坐綠陰下，追思秋日春。", "眠蠶方放大，早麥欲嘗新。", "豈意賊生賊，忍聞人食人。", "何時兵遂解，縱遣上城民。"]'),
('5475732c-ab2f-45af-8454-a6c083bdc958','四月初二日出兵恰滿一月百姓未得下城','方回','宋','宋诗','song-poetry','','[]','久謂兵當解，何知戰未休。',48,'全唐诗/poet.song.231000.json','["久謂兵當解，何知戰未休。", "屬方甜笋蕨，遽已艷葵榴。", "骨痛金瘡作，心煩火色浮。", "滿城俱閉戶，不但一人愁。"]'),
('93d44efd-cfe8-4894-80cd-a88bcb3cb0e6','四月初四日聞績溪凡十五都賊焚欲盡傍出焚歙縣之南鄉遂焚至昌化','方回','宋','宋诗','song-poetry','','[]','昔日初聞寇，諸人早出師。',48,'全唐诗/poet.song.231000.json','["昔日初聞寇，諸人早出師。", "焚燒寧太廣，收勦已無遺。", "斧鉞何曾鈍，雷霆豈肯遲。", "遷延非决策，那得更狐疑。"]'),
('504864ff-c4f6-4cdc-83d8-abad269e9139','四月初九日清和絕佳聞賊焚歙南路蔓延五十餘里','方回','宋','宋诗','song-poetry','','[]','小園無客至，獨坐一繩床。',48,'全唐诗/poet.song.231000.json','["小園無客至，獨坐一繩床。", "霽日千林淨，薰風四月凉。", "禽魚完孕育，草木競芬香。", "姓命人難得，何爲有戰場。"]'),
('76dff839-84a7-4f6c-bbda-1c59a766fc7a','四月初十日得蜂蠆繭絲之句','方回','宋','宋诗','song-poetry','','[]','深言懼忤時，聊復一評之。',48,'全唐诗/poet.song.231000.json','["深言懼忤時，聊復一評之。", "靡暇防蜂蠆，惟工竭繭絲。", "因循終不恤，平定豈無期。", "麥赭秧田廢，人家半忍饑。"]'),
('fa6267de-1f53-4ce5-bdca-0111ee530b02','聞移東兵勦南賊','方回','宋','宋诗','song-poetry','','[]','破賊須先易，行軍要出奇。',48,'全唐诗/poet.song.231000.json','["破賊須先易，行軍要出奇。", "霆轟當不測，烏合本無知。", "夏稅催科日，秧田插蒔時。", "掃除如少緩，兩不便公私。"]'),
('f0e62db8-6234-4214-8379-8cfe6cd81762','客謂榴花早而多竹笋少歲旱','方回','宋','宋诗','song-poetry','','[]','客憂今歲旱，事已見幾微。',48,'全唐诗/poet.song.231000.json','["客憂今歲旱，事已見幾微。", "早早榴花密，遲遲竹笋稀。", "即今防黠賊，已若墮重圍。", "更使逢荒歉，嗚呼萬事非。"]'),
('4c6174f6-0ef5-409e-b7eb-dd4f90d01682','四月二十日客言兵所不至麥有黑蟲食之','方回','宋','宋诗','song-poetry','','[]','望望遥峰外，行行茂樹中。',48,'全唐诗/poet.song.231000.json','["望望遥峰外，行行茂樹中。", "愁添詩鬢白，旱覺戰塵紅。", "已嘆桑無繭，何期麥有蟲。", "南薰元不改，千古舜絃風。"]'),
('547b9cf8-7430-4acb-b0e0-7166e40f1cbf','觀蟻遷知雨','方回','宋','宋诗','song-poetry','','[]','行行密密復疏疏，銜子沿階粟粒如。',32,'全唐诗/poet.song.231000.json','["行行密密復疏疏，銜子沿階粟粒如。", "幾夜夏寒疑未雨，槐安國有五行書。"]'),
('17d3e05e-efd5-4b89-adeb-0268a9dfd732','四月二十六日雨後添嚴軍南擊賊寨','方回','宋','宋诗','song-poetry','','[]','端許憂差減，寧容病寖侵。',48,'全唐诗/poet.song.231000.json','["端許憂差減，寧容病寖侵。", "添兵薅草寇，垂早降梅霖。", "寨破山無險，田高水亦深。", "著書垂不朽，或可遂初心。"]'),
('95827b68-c196-4ae4-b2c8-71b3c33bf14a','四月二十七日梅雨甚驟','方回','宋','宋诗','song-poetry','','[]','黄梅三日雨，漏屋使人愁。',48,'全唐诗/poet.song.231000.json','["黄梅三日雨，漏屋使人愁。", "無飯不遑恤，有書猶欲修。", "綿延蜂蠆賊，震動犬牙州。", "兵甲從今洗，民窮尚可憂。"]'),
('adf25b0d-6bf7-48fa-96e9-655c27173e38','四月二十九日早起行園','方回','宋','宋诗','song-poetry','','[]','白髪蕭蕭一禿翁，披襟扶杖早凉中。',64,'全唐诗/poet.song.231000.json','["白髪蕭蕭一禿翁，披襟扶杖早凉中。", "偶因不飲全無寐，自笑能詩例得窮。", "梅雨園林江橘綠，竹風庭院海榴紅。", "若非守禦孤城閉，誰有幽居似此公。"]'),
('fdfa17af-b536-4d61-b66e-0b63e9412c4e','五月初二日聞祁門縣四月二十七日大水沒鼓樓蛟龍鬬爭溺死者多休寧縣江潭等處亦多漂溺','方回','宋','宋诗','song-poetry','','[]','今歲知何處，天刑亦慘哉。',48,'全唐诗/poet.song.231000.json','["今歲知何處，天刑亦慘哉。", "潢池猶未靜，洚水復爲災。", "民叛非無說，官貪有自來。", "祁門鄭龍鬬，此禍又誰胎。"]'),
('67568c91-f6bf-4126-84a2-35e2a6d6630f','五月初三日雨寒痰嗽','方回','宋','宋诗','song-poetry','','[]','門外葵花一丈高，詎期端午更綿袍。',64,'全唐诗/poet.song.231000.json','["門外葵花一丈高，詎期端午更綿袍。", "佩符豈有玉剛卯，挑藥久無金錯刀。", "人老形骸宜瘦劣，時危心肺倍焦勞。", "柴門晝掩身多病，聽雨寒窗首屢搔。"]'),
('8bb09466-42bf-4b4b-b02f-36fb53e691c0','五月十一日生朝三首  其一','方回','宋','宋诗','song-poetry','','[]','濁醪兒輩尚能謀，且勿驚憂且勿愁。',64,'全唐诗/poet.song.231000.json','["濁醪兒輩尚能謀，且勿驚憂且勿愁。", "不肯前朝峨豸角，可於當世較蠅頭。", "永無紫綬金章夢，甘與青鞋布襪休。", "旦夕賊平歲中熟，茅柴杯外更何求。"]'),
('15417b0d-1bbf-483f-af49-12315ee0b1c6','五月十一日生朝三首  其二','方回','宋','宋诗','song-poetry','','[]','本非高蹈掛朝冠，自是危途舉足難。',64,'全唐诗/poet.song.231000.json','["本非高蹈掛朝冠，自是危途舉足難。", "世上十年人不識，山中五月夜猶寒。", "感風垂死骨骸痛，止酒近旬杯杓乾。", "牽率親朋致嘉惠，時危敢作等閒看。"]'),
('02cd3d80-63a6-4c31-992c-1a5a4de69cb1','五月十一日生朝三首  其三','方回','宋','宋诗','song-poetry','','[]','强展愁眉進一杯，年年紅熟見楊梅。',64,'全唐诗/poet.song.231000.json','["强展愁眉進一杯，年年紅熟見楊梅。", "至親阻寇全無信，時貴嫌貧近不來。", "京兆舊遊張敞馬，督亢遥望劇辛臺。", "華榮寂寞手翻覆，好在徉狂老萬回。"]'),
('e2ead94d-37c1-4345-be64-2fa90212b5ac','五月二十一夜雨未止六晝夜水漲寇阻無人入城','方回','宋','宋诗','song-poetry','','[]','晝夜雨滂沱，平疇變海河。',48,'全唐诗/poet.song.231000.json','["晝夜雨滂沱，平疇變海河。", "地如隨水去，天豈厭人多。", "討叛猶輸粟，攻堅未掩戈。", "積陰凝殺氣，玄造意如何。"]'),
('7eacd958-6bb7-4a54-ab83-02fcf29edd0e','五月二十三日甲子交六月節稍晴三四五復大雨賊寨未下','方回','宋','宋诗','song-poetry','','[]','每日看天色，今年厭雨聲。',48,'全唐诗/poet.song.231000.json','["每日看天色，今年厭雨聲。", "重新六甲換，喜得一朝晴。", "疲卒淹窮谷，饑民守壞城。", "竹深荷淨處，猶憶舊承平。"]'),
('09a66ee6-c291-4fe6-b043-2c5bac657fc8','初二日許公度使君來自西坑賊寨見訪','方回','宋','宋诗','song-poetry','','[]','曰予視賊壘，雨且二十日。',156,'全唐诗/poet.song.231000.json','["曰予視賊壘，雨且二十日。", "山行屢顛仆，泥行馬沒膝。", "火攻未可施，諸軍睨空碧。", "小醜膽氣粗，亦有砲與石。", "持榜以招之，貸命續糧食。", "彼謂一下山，求活豈可得。", "使君廉且慈，眉攢咽爲塞。", "未必皆凶徒，脅從十有七。", "暴露數月矣，武將正憤悒。", "合圍焉肯退，但欲事鏖擊。", "天意不肯晴，詎不念冤抑。", "渠魁謀遁逃，所幸已就執。", "焉得遂兩解，曲赦與抆拭。"]'),
('f01eaaa2-58d7-431e-b201-0e8b7c9eb0dd','六月初七日雨始止初八日始晴','方回','宋','宋诗','song-poetry','','[]','昨夕星初見，茲晨霧亦披。',48,'全唐诗/poet.song.231000.json','["昨夕星初見，茲晨霧亦披。", "徯聞平賊報，先賦喜晴詩。", "□□猶如舊，新蟬未覺遲。", "皇天已悔禍，小醜復奚爲。"]'),
('60435e97-50f8-47f7-8be8-16e37cf87c45','六月十七日十八日大雨聞賊欲降','方回','宋','宋诗','song-poetry','','[]','誰遣青天變漏天，人閒無復有平田。',64,'全唐诗/poet.song.231000.json','["誰遣青天變漏天，人閒無復有平田。", "女媧鍊石端何物，子産禜龍未必然。", "死徙銜冤終不雪，生存忍餓更堪憐。", "腐儒自笑窮今極，旬月曾無一醉眠。"]'),
('080501a6-cf6a-4877-bc23-90c5670b15a3','六月二十二日守陴百姓始下城','方回','宋','宋诗','song-poetry','','[]','本不食官粟，亦令登敵樓。',48,'全唐诗/poet.song.231000.json','["本不食官粟，亦令登敵樓。", "鳴桴木杪急，傳箭夜深愁。", "暗躡蛇纏膝，塵搔虱滿頭。", "傳聞賊寨破，今日得歸休。"]'),
('e7c891f1-797a-48db-b297-238fe53e0b18','六月二十三日立秋喜聞賊平鎮將凱回歸府官俱還','方回','宋','宋诗','song-poetry','','[]','亂起杏花落，賊平梧葉飛。',48,'全唐诗/poet.song.231000.json','["亂起杏花落，賊平梧葉飛。", "頓忘三伏暑，竟解萬山圍。", "大將傷流矢，諸軍曳血衣。", "先登不如此，焉得凱歌歸。"]'),
('99d0029d-0c62-48c2-bf1c-6cd22edfcfba','寄題婺源程氏得寓亭','方回','宋','宋诗','song-poetry','','[]','今醉翁遨古醉鄉，斯亭有路到羲皇。',64,'全唐诗/poet.song.231000.json','["今醉翁遨古醉鄉，斯亭有路到羲皇。", "九流人品杯中物，萬卷家書膝上郎。", "山意相迎隨步好，花陰獨立滿身香。", "臨風詩思誰能畫，想見津津喜色黄。"]'),
('02b3bcbe-3f18-4727-a2be-9197cdfe5289','送歙尉牛寶臣','方回','宋','宋诗','song-poetry','','[]','身騎瘦馬著練衣，能儉誰云俸入微。',64,'全唐诗/poet.song.231000.json','["身騎瘦馬著練衣，能儉誰云俸入微。", "延禮老儒令子拜，束鈐蠻卒到村稀。", "向來髯漆今成雪，此去袍青合換緋。", "爲報鄉鄰索南物，錦囊惟有好詩歸。"]'),
('5fae758c-57f2-450d-b150-565d9f746015','孚舟亭獨坐','方回','宋','宋诗','song-poetry','','[]','犖確蒔秈米，淺清釣鯈魚。',288,'全唐诗/poet.song.231000.json','["犖確蒔秈米，淺清釣鯈魚。", "茲事不在多，克儉即有餘。", "俯仰六十載，山城八遷居。", "憶昔罷閫幕，始有此屋廬。", "鞠躬畚瓦礫，流汗薅茅苴。", "前後列花果，左右環圖書。", "誰令厠朝士，又駕太守車。", "大兵革宇宙，乘時沸猱狙。", "斸掘壞畦徑，抉偷夷庭除。", "厨荒敗炊爨，室空移貯儲。", "歸來問鄰舊，死徙徒欷歔。", "募工淘穢井，課僕通污渠。", "旋理短檠燈，復荷長柄鋤。", "倏忽九寒暑，出入無馿輿。", "忍貧不肯仕，人謂回也愚。", "今歲事大謬，羣賊屠郊墟。", "古樹伐作薪，野茹挑爲蔬。", "淡食已數月，窮乃至此歟。", "筋力既衰劣，鬢毛苦凋疏。", "以今較疇昔，百事皆弗如。", "弗如又何嗟，不繫天命且。", "柴荆永日閉，池亭秋霽初。", "朝看白雲起，暮對丹霞舒。", "獨坐心自賞，是身如空虛。"]'),
('b78d2f36-fb0c-496a-b767-d733a0d4fc96','送郭伯川','方回','宋','宋诗','song-poetry','','[]','皓首厖眉話昔遊，隙陰俯仰歎如流。',64,'全唐诗/poet.song.231000.json','["皓首厖眉話昔遊，隙陰俯仰歎如流。", "萬山中遇驅駰轡，十載前同上鶴樓。", "洚水餘氓猶粥飯，潢池小醜更戈矛。", "紛紛貪吏甚狼虎，盍與驅除絕後憂。"]'),
('71f81958-bcb6-4b47-927c-5a5182eda4c8','初凉','方回','宋','宋诗','song-poetry','','[]','餘民脫死初平寇，歉歲逢秋亦喜凉。',64,'全唐诗/poet.song.231000.json','["餘民脫死初平寇，歉歲逢秋亦喜凉。", "止水池邊臨樹影，逆風林下遡花香。", "尚欣鄰壁肯賒酒，不管空庖無宿糧。", "已往可驚來未測，延緣聊得撫流光。"]'),
('e7095bf9-3b61-4f6a-9dfb-3fa3fd6e2c47','懷慚','方回','宋','宋诗','song-poetry','','[]','逃生何處可茅庵，城市山林總不堪。',64,'全唐诗/poet.song.231000.json','["逃生何處可茅庵，城市山林總不堪。", "人莫我知姑用六，今非昔比更緘三。", "擘麟行酒海深淺，繫雁傳書天北南。", "數月兒曹盡饑瘦，無能衰叟但懷慚。"]'),
('899ba921-1c66-4bbb-83ff-bedcb790648d','望南山別峰見樹間煙出知有隠者','方回','宋','宋诗','song-poetry','','[]','南山有別峰，石樹相因依。',144,'全唐诗/poet.song.231000.json','["南山有別峰，石樹相因依。", "茲晨偶流目，遥見青煙微。", "未知此林下，誰家掩荆扉。", "我亦欲一往，結茅紉槲衣。", "秋飯所種粟，春羹自生薇。", "今年四閲月，孤城閉賊圍。", "當其薪粲絕，無翅何由飛。", "客謂郊關外，似覺事轉非。", "歲儉剽奪急，村荒遊徼稀。", "豺狼方磨牙，擇人以自肥。", "市隠世態惡，巖棲心事違。", "四海豈不廣，惆悵將焉歸。"]'),
('4ad59e5b-b5a6-4ec0-8ea8-519610675dbf','去萍草','方回','宋','宋诗','song-poetry','','[]','童子携竹器，摝去池中萍。',96,'全唐诗/poet.song.231000.json','["童子携竹器，摝去池中萍。", "見魚故已佳，水底林巒青。", "復呼荷鋤者，薙草汛我庭。", "蛇蚓無留藏，行徑免露零。", "剗穢致潔凈，撥翳生皛熒。", "朗月明其摶，古鏡還精靈。", "語寂理已會，慮澹神自冥。", "白髪一老翁，兀然坐孤亭。"]'),
('1c9a07ff-1622-475e-b4d9-e92ecbcd1081','送黟縣學官江歸上饒石湖精舍','方回','宋','宋诗','song-poetry','','[]','小桃源住飯不足，夜鶴傳聲趣駕還。',32,'全唐诗/poet.song.231000.json','["小桃源住飯不足，夜鶴傳聲趣駕還。", "細嚼紫陽山色飽，饞涎猶睨應天山。"]'),
('c4f8d874-f885-4f82-bf12-c3fb5833a437','有感三首  其一','方回','宋','宋诗','song-poetry','','[]','倉皇得郡免朝辭，十六年間老轉癡。',64,'全唐诗/poet.song.231000.json','["倉皇得郡免朝辭，十六年間老轉癡。", "一角未堪峨獬豸，二螯敢笑食蟛蜞。", "刊摩干寶搜神記，嘯詠陶潜責子詩。", "格是世人無識者，可能更索樹神知。"]'),
('95c54d6e-a4cb-42cc-b918-6e6cddd1a812','有感三首  其二','方回','宋','宋诗','song-poetry','','[]','十年歸把釣魚竿，萬變惟憑冷眼看。',64,'全唐诗/poet.song.231000.json','["十年歸把釣魚竿，萬變惟憑冷眼看。", "白髪相尋點鬼簿，紫金焉得返魂丹。", "漸驚老舊遺民盡，欲問承平往事難。", "秋日未須畏殘暑，浙江潮退即天寒。"]'),
('5c275bcf-d691-4357-92b7-79024a2082e4','有感三首  其三','方回','宋','宋诗','song-poetry','','[]','今沿古泝醉眉攢，堪轉輿旋老眼寒。',64,'全唐诗/poet.song.231000.json','["今沿古泝醉眉攢，堪轉輿旋老眼寒。", "晝靜倚楹常獨立，夜深撫几忽長嘆。", "關張運去金刀絕，王謝聲沉玉樹殘。", "欲淬筆鋒刳鬼膽，生冤死恨海漫漫。"]'),
('4e9ab7ba-b32c-4599-82d6-5442a3a09dda','聞汪翔甫八月十日卒去曹元會五月三日之報僅三月餘兩翁皆年八十四','方回','宋','宋诗','song-poetry','','[]','甫作詩爲兩翁壽，豈虞相繼駭予聞。',64,'全唐诗/poet.song.231000.json','["甫作詩爲兩翁壽，豈虞相繼駭予聞。", "八旬已過太公望，一旦俱爲冥漠君。", "場屋少時嘗張王，兵戈晚歲忽紛紜。", "全天所賦無遺憾，端復真修地下文。"]'),
('70c91fff-8f63-4ce5-8395-88ff2b9c9b93','悲歌五首  其一','方回','宋','宋诗','song-poetry','','[]','三十年前樂事饒，閒身無事暑初銷。',64,'全唐诗/poet.song.231000.json','["三十年前樂事饒，閒身無事暑初銷。", "携琴嶽寺延秋月，吹笛江樓過夜潮。", "自倚豪狂詩句疾，豈虞離亂鬢毛凋。", "故人死盡身猶在，交道生涯兩寂寥。"]'),
('d5822519-d986-4d49-bd52-9557872a3b4f','悲歌五首  其二','方回','宋','宋诗','song-poetry','','[]','更問公裳與幞頭，披襟散髪十年秋。',64,'全唐诗/poet.song.231000.json','["更問公裳與幞頭，披襟散髪十年秋。", "郭郎鮑老元相□，張丈殷兄且自由。", "善樂神仙惟有醉，算知天地本無愁。", "奈何尚欲誅姦鬼，亹亹寒窗筆不休。"]'),
('78556b5b-d654-4ebc-b37f-aa122cf08fb4','悲歌五首  其三','方回','宋','宋诗','song-poetry','','[]','獨立蕭蕭落葉風，閒居已忍十年窮。',64,'全唐诗/poet.song.231000.json','["獨立蕭蕭落葉風，閒居已忍十年窮。", "幸猶張籍不終瞎，未必杜微真是聾。", "瑣事可容知較盡，塵編敢謂讀皆通。", "骨骸欲朽心神在，未害藏山待至公。"]'),
('aa516180-be56-47b4-b689-35673cac4d16','悲歌五首  其四','方回','宋','宋诗','song-poetry','','[]','憂驚喜愕夢紛紛，了了誰能白黑分。',64,'全唐诗/poet.song.231000.json','["憂驚喜愕夢紛紛，了了誰能白黑分。", "晝夜星辰常轉換，春秋草木互芳芬。", "姬昌秦政今誰諱，呂洞鍾權近不聞。", "氣盡勢窮終變滅，世間萬事總浮雲。"]'),
('206401cb-b4f7-4405-8337-28124c5c92a7','悲歌五首  其五','方回','宋','宋诗','song-poetry','','[]','窮凶極詐肆淫貪，賓主湖山晝夜酣。',64,'全唐诗/poet.song.231000.json','["窮凶極詐肆淫貪，賓主湖山晝夜酣。", "世事可欺沙武口，天誅難免木綿庵。", "貲財已籍宮宜赭，腰領猶全首欠函。", "地下麗華應有語，不因玉樹失江南。"]'),
('19416115-4437-4498-8715-db370ef83660','贈黟縣星學舒碧雲','方回','宋','宋诗','song-poetry','','[]','原夫官賦省題詩，何乃甘心改業爲。',64,'全唐诗/poet.song.231000.json','["原夫官賦省題詩，何乃甘心改業爲。", "場屋久忘塗注乙，星辰閒測斗牛箕。", "細看肖貌殊清徹，徐玩揮毫亦怪奇。", "聞道天文脩晉志，淳風會有立朝時。"]'),
('c9b9581c-bec4-41d5-9f6b-79ebe1da8244','九月初五日','方回','宋','宋诗','song-poetry','','[]','暮雨蕭蕭鼓角風，草枯木落雁橫空。',64,'全唐诗/poet.song.231000.json','["暮雨蕭蕭鼓角風，草枯木落雁橫空。", "每逢九日不勝感，垂近七旬無奈窮。", "螃蟹今年猶未有，茅柴我輩亦堪中。", "籬邊瘦菊青如粟，已勝芙蓉萬朵紅。"]'),
('7765dcee-505d-4dd8-9d13-a0074c02d13e','庚寅','方回','宋','宋诗','song-poetry','','[]','江湖秋水事茫茫，近縣猶聞有戰場。',64,'全唐诗/poet.song.231000.json','["江湖秋水事茫茫，近縣猶聞有戰場。", "多病多憂欺此老，半醒半醉了重陽。", "見山籬下無人至，戲馬臺頭幾客忙。", "萬事不同時節似，感今懷古倍悲凉。"]'),
('dcc2c6b0-c041-4087-9631-a3be05bf866e','美許孝子','方回','宋','宋诗','song-poetry','','[]','聖善已云遠，義方猶此親。',48,'全唐诗/poet.song.231000.json','["聖善已云遠，義方猶此親。", "須嘗許止藥，未老竇郎椿。", "竹院深床穩，烟庖垢面塵。", "曾參養曾皙，剩閲舞雩春。"]'),
('c104c1c3-5dc3-4205-854b-de43f1790f3c','孔府判野耘嘗宦雲南今以餘瘴多病意欲休官因讀唐書南詔傳爲此二詩問其風俗  其一','方回','宋','宋诗','song-poetry','','[]','萬里蠶叢國，西南出漏天。',192,'全唐诗/poet.song.231000.json','["萬里蠶叢國，西南出漏天。", "吐蕃唐徼接，越巂漢疆連。", "參井星躔外，岷峨雪界邊。", "䍧船元下粵，劍棧忽朝燕。", "驃信狂圖歇，苴咩險要鎸。", "稱元更號謂，督爽革官聯。", "慰諭開行府，咨諏肅使權。", "貝仍通一覓，土尚錫雙田。", "飾齒金兼漆，充衣卉與氈。", "瓜匏冬更實，桃杏臘尤妍。", "混壹良堪喜，誅求或未悛。", "霜威才蒞止，輿誦總驩然。", "歸橐無蠻貨，征袍有瘴煙。", "□曾甘鞅掌，由此困沉綿。", "柔遠華風浹，同文譯史傳。", "願聞談土俗，王會纂周篇。"]'),
('2daa1b0f-4006-4f3d-875e-76c0bb7a8ce2','孔府判野耘嘗宦雲南今以餘瘴多病意欲休官因讀唐書南詔傳爲此二詩問其風俗  其二','方回','宋','宋诗','song-poetry','','[]','漢代哀牢種，瀘南大渡河。',192,'全唐诗/poet.song.231000.json','["漢代哀牢種，瀘南大渡河。", "其都居善闡，有水號牂牁。", "丞相祠諸葛，將軍畏伏波。", "石扶碑故在，銅作柱難磨。", "古但羈縻耳，今如震懾何。", "一戎平六詔，萬旅削三峨。", "跣足遑機弩，氈頭敢荷戈。", "鬼王牽駿駔，冺國效文螺。", "梵供花優鉢，經傳葉貝多。", "異香燃篤耨，碩果噉波羅。", "碧鈿懸珠珥，銀鈎摘象馱。", "深秋如夏熱，窮臘亦春和。", "霧毒飛鳶墮，風腥巨蟒過。", "已還生定遠，猶類病維摩。", "宦思輕髦梗，閒心願澗阿。", "此鄉非瘴土，何幸小婆娑。"]'),
('f2f86303-5ced-4f2c-acb5-448d198d2c96','丞相大觀文馬公先生挽詞三首  其一','方回','宋','宋诗','song-poetry','','[]','四載咸淳相，艱哉去國情。',48,'全唐诗/poet.song.231000.json','["四載咸淳相，艱哉去國情。", "極知幾事密，或遂好謀成。", "董卓徵荀爽，陳桓免晏嬰。", "爲公翻左漢，尚覺寸丹明。"]'),
('5d1ea6a2-0104-4755-94bf-d047c174e71e','丞相大觀文馬公先生挽詞三首  其二','方回','宋','宋诗','song-poetry','','[]','病篤辭台席，明年遂失襄。',48,'全唐诗/poet.song.231000.json','["病篤辭台席，明年遂失襄。", "少容公展布，豈遽國危亡。", "此老爲微子，吾君類偃王。", "欺孤木綿鬼，寸斬亦何傷。"]'),
('47006dcc-4b0e-4c63-bf12-9e8d941a2ce6','丞相大觀文馬公先生挽詞三首  其三','方回','宋','宋诗','song-poetry','','[]','天地干戈阻，門生合會喪。',48,'全唐诗/poet.song.231000.json','["天地干戈阻，門生合會喪。", "謂傳和相鉢，有靦陸公莊。", "衰鈍辜陶冶，危疑去廟廊。", "空懷精衛意，無奈海茫茫。"]'),
('b430bf0e-e900-45e3-8c08-62cffdb31f8c','上南行十二首  其一','方回','宋','宋诗','song-poetry','','[]','初過城南門，即過城下渡。',48,'全唐诗/poet.song.231000.json','["初過城南門，即過城下渡。", "豈無小筍輿，未若且徒步。", "霜重船板滑，水涸岸石露。", "我老人不識，小讓樵者路。"]'),
('20b6e6ec-94b5-4e9f-a0b6-18277fc93b6c','上南行十二首  其二','方回','宋','宋诗','song-poetry','','[]','歷險極可畏，升高宜少休。',48,'全唐诗/poet.song.231000.json','["歷險極可畏，升高宜少休。", "嶺水東西分，終亦歸同流。", "臧獲相爾汝，借竈燃枯槱。", "五里一酌酒，聊以娛茲遊。"]'),
('f0573775-d3ae-49cf-a226-28136f19df1b','上南行十二首  其三','方回','宋','宋诗','song-poetry','','[]','我不上南山，垂近四十載。',48,'全唐诗/poet.song.231000.json','["我不上南山，垂近四十載。", "山中花瓢翁，尚與山俱在。", "據高瞰人世，昔田今爲海。", "道傍魏公亭，柱化礎亦敗。"]'),
('f1b8815b-68c9-472c-a297-f77fc002a00c','上南行十二首  其四','方回','宋','宋诗','song-poetry','','[]','七里南山邊，更作三里程。',48,'全唐诗/poet.song.231000.json','["七里南山邊，更作三里程。", "十里舊榷界，雙橋酒有聲。", "身老友朋盡，事殊時代更。", "茅店迷處所，飲徒眠九京。"]'),
('c69cbe6a-6911-494d-900c-5225b7147abe','上南行十二首  其五','方回','宋','宋诗','song-poetry','','[]','金焦大小孤，號爲天下奇。',48,'全唐诗/poet.song.231000.json','["金焦大小孤，號爲天下奇。", "繄此水中岑，突兀頗似之。", "千古幾洚水，蛟龍不能移。", "寄言甕牖士，守道當如茲。"]'),
('e016182b-72d9-49bf-93f0-78acd57cba15','上南行十二首  其六','方回','宋','宋诗','song-poetry','','[]','溪北曰富登，溪南曰富代。',48,'全唐诗/poet.song.231000.json','["溪北曰富登，溪南曰富代。", "其西曰澤富，富固人所愛。", "民貧今已極，名實殊不對。", "此村名杏村，杏花果安在。"]'),
('0568f7fe-c3d9-4519-8cc0-d76fe516539a','上南行十二首  其七','方回','宋','宋诗','song-poetry','','[]','昔聞馬糞巷，今涉牛矢嶺。',48,'全唐诗/poet.song.231000.json','["昔聞馬糞巷，今涉牛矢嶺。", "無牛亦無矢，步步入佳境。", "望我端人居，時焉一引領。", "亦如馬糞邊，王謝芳更永。"]'),
('8af03f72-f21e-4e4f-816a-fd4f3b879861','上南行十二首  其八','方回','宋','宋诗','song-poetry','','[]','葉有義謂何，根有即葉有。',48,'全唐诗/poet.song.231000.json','["葉有義謂何，根有即葉有。", "登嶺問地名，强辨果是否。", "我觀松柏竹，青青黄落後。", "葉有有此葉，可以觀此守。"]'),
('31da0fa4-f51c-48f7-8c29-b017776df393','上南行十二首  其九','方回','宋','宋诗','song-poetry','','[]','斯人近云亡，華算八十四。',48,'全唐诗/poet.song.231000.json','["斯人近云亡，華算八十四。", "登堂拜畫像，衣冠昂古製。", "有子身不死，科名今九世。", "焉知三家村，乃見萬乘器。"]'),
('c6c29468-b8de-4ff7-9c08-0ed93af973e4','上南行十二首  其一○','方回','宋','宋诗','song-poetry','','[]','棄官逃世名，居此深谷中。',48,'全唐诗/poet.song.232000.json','["棄官逃世名，居此深谷中。", "谷深夜更深，劇談滋無窮。", "照壁書燈青，煨爐茶火紅。", "門外曉鷄鳴，天地號霜風。"]'),
('37cb1368-3301-4e96-b286-e026411dc6ac','上南行十二首  其一一','方回','宋','宋诗','song-poetry','','[]','君子貴淡交，不在杯炙間。',48,'全唐诗/poet.song.232000.json','["君子貴淡交，不在杯炙間。", "主人苦留客，因辭乃得還。", "中道逢故舊，酒肉又如山。", "半醉可以去，豈不知時艱。"]'),
('06745d70-7587-46ad-b8f5-a0dcc4064bc4','上南行十二首  其一二','方回','宋','宋诗','song-poetry','','[]','談笑復談笑，竟忘早與晚。',48,'全唐诗/poet.song.232000.json','["談笑復談笑，竟忘早與晚。", "翩翻凌深波，恍惚度層巘。", "醉身但覺輕，歸路不知遠。", "人生常如茲，百年亦易遣。"]'),
('208ae69f-7706-4c81-a86a-ce5b93305593','歲盡即事三首  其一','方回','宋','宋诗','song-poetry','','[]','閒門空宇日蕭蕭，天地無情鬢轉凋。',64,'全唐诗/poet.song.232000.json','["閒門空宇日蕭蕭，天地無情鬢轉凋。", "政使面顔成菜色，未應官職愛冰條。", "藏山竹簡光陰短，寄隴梅枝信息遥。", "不寐夜窗聽風雪，枯腸殊欠一樽澆。"]'),
('f325c194-a177-4a8c-a9a9-3b7c920f5375','歲盡即事三首  其二','方回','宋','宋诗','song-poetry','','[]','七里灘西更上灘，十年生事一漁竿。',64,'全唐诗/poet.song.232000.json','["七里灘西更上灘，十年生事一漁竿。", "故人共駭霜毛短，俗子猶嫌鐵面寒。", "雪屋五更天地獨，梅詩一句古今難。", "虛名浪得真何用，空使先生刻肺肝。"]'),
('f0212040-b184-4a5e-a814-7efa733337ef','歲盡即事三首  其三','方回','宋','宋诗','song-poetry','','[]','干戈洶湧一年間，酒債何時可盡還。',64,'全唐诗/poet.song.232000.json','["干戈洶湧一年間，酒債何時可盡還。", "盜起屢煽鄰縣火，軍興全赭近城山。", "天陰體倦金瘡痛，歲儉家寒藿食艱。", "最苦梅開厭求索，柴扉草舍不容關。"]'),
('1de77b6d-ae19-472e-b700-68367fbe2965','倚梅觀雪','方回','宋','宋诗','song-poetry','','[]','空山浩浩朔風吹，蕭颯如蓬兩鬢垂。',64,'全唐诗/poet.song.232000.json','["空山浩浩朔風吹，蕭颯如蓬兩鬢垂。", "獨倚寒梅看遠雪，合呼美酒賦新詩。", "剡舟地逈何由往，隴驛天遥亦謾思。", "忽憶立年湖上事，金樽銀筆永無期。"]'),
('4eb4666b-27f0-4a86-bf46-5564e7791dbc','再賦倚梅觀雪以前詩太哀故','方回','宋','宋诗','song-poetry','','[]','清莫清哉亦壯哉，茅廬何自致瓊瑰。',64,'全唐诗/poet.song.232000.json','["清莫清哉亦壯哉，茅廬何自致瓊瑰。", "江南勝賞無如雪，天下難題最是梅。", "剪水玉蛾能送瑞，司花青帝想憐才。", "老臣詩就天顔喜，叩齒當空酹一杯。"]'),
('c5243b15-d959-4257-a187-457991644ee6','梅','方回','宋','宋诗','song-poetry','','[]','玉樓仙去老逋坡，天下詩人奈爾何。',64,'全唐诗/poet.song.232000.json','["玉樓仙去老逋坡，天下詩人奈爾何。", "茅舍一枝元不少，水村千樹未爲多。", "力排殺氣回元造，善保陽神養內和。", "暗處尋香疏認影，可容冶思羨凌波。"]'),
('94d396b6-4bd6-4f02-a939-0bdb8a4c0238','雪','方回','宋','宋诗','song-poetry','','[]','老面臨高不畏風，塵寰一變蕊珠宮。',64,'全唐诗/poet.song.232000.json','["老面臨高不畏風，塵寰一變蕊珠宮。", "驟難金碧茅茨別，預喜蝗螟瘴癘空。", "至潔獨凝羣物表，太和元在極寒中。", "絕憐詩骨能禁許，惟有梅梢肖此翁。"]'),
('23402321-5cb3-4265-8bcb-5eef73f17b00','十二月二十八日立春次韻王山長俊甫','方回','宋','宋诗','song-poetry','','[]','餘生橄欖蠖求伸，久作屠酥最後人。',64,'全唐诗/poet.song.232000.json','["餘生橄欖蠖求伸，久作屠酥最後人。", "萬事不關閒處眼，三朝聊喜歲前春。", "草芽地已回生意，雪霽天應念小民。", "船活東遊君决計，何當同載自由身。"]'),
('4f789873-f49d-4f79-8f9d-b244ef2cb751','辛卯元日三首  其一','方回','宋','宋诗','song-poetry','','[]','六十年前五歲兒，夢魂歷歷萬艱危。',64,'全唐诗/poet.song.232000.json','["六十年前五歲兒，夢魂歷歷萬艱危。", "數聲春雨微中酒，絕好梅花大欠詩。", "老病自應無世味，退脩焉用要人知。", "十兄弟行唯身在，未可全狂且半癡。"]'),
('6fcf7d37-cee2-43c4-9a87-a1538360b786','辛卯元日三首  其二','方回','宋','宋诗','song-poetry','','[]','回首同庚五歲孫，老夫老矣尚何言。',64,'全唐诗/poet.song.232000.json','["回首同庚五歲孫，老夫老矣尚何言。", "一生酒債兼詩債，數畝花園半菜園。", "雨濘謂難來賀客，馬嘶誰忽顧閒門。", "倏無驟有真天相，徑爲茅柴覆瓦樽。"]'),
('80c8608a-2843-4bfb-bc3c-02dfee372d6e','辛卯元日三首  其三','方回','宋','宋诗','song-poetry','','[]','十年爭席聽漁樵，辦著心情耐寂寥。',64,'全唐诗/poet.song.232000.json','["十年爭席聽漁樵，辦著心情耐寂寥。", "老覺歲華殊易邁，愁嫌日晷似難消。", "縱無詩句題桃板，也有春光到柳條。", "何限貴人近俱殀，鎮長窮健不逍遥。"]'),
('841d0009-2bcb-49e2-b594-bc123124f99e','寄題九華蘇君明甫夢牛亭','方回','宋','宋诗','song-poetry','','[]','融融洩洩非煙霧，金門玉堂嚴陛枑。',256,'全唐诗/poet.song.232000.json','["融融洩洩非煙霧，金門玉堂嚴陛枑。", "上帝高居朝百靈，神人真官儼無數。", "九華種德萱堂仙，許傍紅雲聽韶頀。", "瓊林宴罷偃霓旌，詔賜麒麟引歸路。", "似牛非牛斯何祥，夢覺生此玉樹郎。", "渥洼汗馬實非馬，洛洞髯珠誰謂羊。", "天上真龍世莫測，例晦頭角韜晶光。", "夢中之牛頗類此，豈果噉芻甘服箱。", "忠臣事君比螻蟻，慈父愛子號豚犬。", "鳩雎夫婦雁兄弟，託物取象意微婉。", "冉耕伯牛司馬牛，大賢名字何赫烜。", "得非此母奇此兒，他年負重能致遠。", "繡輿羽衛歸蓬萊，奇徵異兆猶昭回。", "作亭大刻夢牛記，銀黄上冢兼榮哀。", "函關道士駕西邁，萬歲樹精焉在哉。", "邂逅便當知止足，拽轉鼻頭歸去來。"]'),
('56d8837e-f6a3-445f-bea9-8e7a1a0d583d','寄仇仁近白廷玉張仲實京口當塗江陰三學正兼述新歲陰雨春寒有懷','方回','宋','宋诗','song-poetry','','[]','同時糾正諸侯學，鐺脚相鄰總鉅邦。',64,'全唐诗/poet.song.232000.json','["同時糾正諸侯學，鐺脚相鄰總鉅邦。", "足可養廉三斛米，未妨溫故一燈窗。", "有人北面求宗旨，無事東流送大江。", "向道紫陽山色好，何爲不肯泝溪瀧。"]'),
('7a69a989-2523-4174-a50f-adc0104fb93f','六十五春寒吟七首  其一','方回','宋','宋诗','song-poetry','','[]','日日春寒晝掩扉，驚嗟六十五年非。',64,'全唐诗/poet.song.232000.json','["日日春寒晝掩扉，驚嗟六十五年非。", "未爲白傅同州起，猶勝坡翁海外歸。", "斗分軍興羣盜作，浙鄉水患細民饑。", "忍窮苟活猶閒管，痛惜殘梅萬點飛。"]'),
('418214fc-3de8-4e58-b3f1-5e3139d41c66','六十五春寒吟七首  其二','方回','宋','宋诗','song-poetry','','[]','當是平生取數多，窮途無力戰羣魔。',64,'全唐诗/poet.song.232000.json','["當是平生取數多，窮途無力戰羣魔。", "二千石濫知州事，三十年羞進士科。", "人老决難重少壯，春寒畢竟漸晴和。", "籌來算往終無益，且傍殘梅作醉歌。"]'),
('baedfb32-037d-4942-be72-592daccf34a7','六十五春寒吟七首  其三','方回','宋','宋诗','song-poetry','','[]','老眼閒中子細看，天公作劇故多端。',64,'全唐诗/poet.song.232000.json','["老眼閒中子細看，天公作劇故多端。", "雪占歲稔何曾稔，雨作春寒斷是寒。", "酒盡悶多歡笑少，花開折易長成難。", "暮年不喜金仙說，到此心才悟六觀。"]'),
('a4ec1df6-92ff-4d4f-a539-bd81028825d9','六十五春寒吟七首  其四','方回','宋','宋诗','song-poetry','','[]','病骨春寒欠酒澆，關山滿眼雁程遥。',64,'全唐诗/poet.song.232000.json','["病骨春寒欠酒澆，關山滿眼雁程遥。", "有人恨過江淹賦，何處魂堪宋玉招。", "六十五翁來日短，百千萬事迅風飄。", "平生知己驚俱盡，一影窮山伴寂寥。"]'),
('f63a9f94-3d7a-40c6-9bc0-85c73ba19ac6','六十五春寒吟七首  其五','方回','宋','宋诗','song-poetry','','[]','清曉林禽百種鳴，春寒漸暖變新聲。',64,'全唐诗/poet.song.232000.json','["清曉林禽百種鳴，春寒漸暖變新聲。", "向陽死草青先茁，解凍枯池綠再生。", "太子四門何足怪，麻姑三海自堪驚。", "回頭最念兒童輩，不識燈宵舊太平。"]'),
('46c51b3b-8015-4ea1-abb8-9f5a2c33d849','六十五春寒吟七首  其六','方回','宋','宋诗','song-poetry','','[]','性癖耽吟本不工，平生竟復坐詩窮。',64,'全唐诗/poet.song.232000.json','["性癖耽吟本不工，平生竟復坐詩窮。", "狀頭浪說三千字，舉手行爲七十翁。", "夜永自憐燈是伴，春寒最苦酒難中。", "王侯螻蟻終同盡，便出陽神也落空。"]'),
('4c029790-b286-4ed8-8a56-142f8f086caa','六十五春寒吟七首  其七','方回','宋','宋诗','song-poetry','','[]','知舊驚嗟踵喪亡，劣容此老據藜床。',64,'全唐诗/poet.song.232000.json','["知舊驚嗟踵喪亡，劣容此老據藜床。", "六旬有五猶窮健，百拙無雙但醉狂。", "蒔菜連畦終歲飽，種梅匝屋滿家香。", "不須苦怨春寒惡，榾柮爐邊味最長。"]'),
('0e881921-fc6f-4d81-b61a-15e5ce392888','上元再題','方回','宋','宋诗','song-poetry','','[]','梅殘萬點路傍雪，桃露一班梢上紅。',32,'全唐诗/poet.song.232000.json','["梅殘萬點路傍雪，桃露一班梢上紅。", "惆悵六鼇山已去，了無情緒答春風。"]'),
('2aca7aa6-1d27-49fa-81ea-9dbc1d83449c','送紫陽王山長俊甫如武林五首  其一','方回','宋','宋诗','song-poetry','','["\u8861\u5c71"]','乾淳以後學無師，嘉紹厭厭士氣衰。',64,'全唐诗/poet.song.232000.json','["乾淳以後學無師，嘉紹厭厭士氣衰。", "何等淫辭南嶽稿，不祥妖讖晚唐詩。", "三風盍遣鄭聲放，一日忽驚周鼎移。", "歐九登庸柳七棄，昭陵曾築太平基。"]'),
('0e0ce7d6-ec9f-4305-96d4-631cefdfd44c','送紫陽王山長俊甫如武林五首  其二','方回','宋','宋诗','song-poetry','','[]','紛紛肉食笑儒冠，頼有吾徒耐歲寒。',64,'全唐诗/poet.song.232000.json','["紛紛肉食笑儒冠，頼有吾徒耐歲寒。", "心遠要期來哲共，眼高不受俗書瞞。", "樽前笑語窺胸次，燈下工夫見筆端。", "好向故都求益友，歸時敢作去時看。"]'),
('a2b0e93a-e885-443b-9480-e7862d3815e3','送紫陽王山長俊甫如武林五首  其三','方回','宋','宋诗','song-poetry','','[]','戰鼙征騎洶人寰，此道煙昏霧晦間。',64,'全唐诗/poet.song.232000.json','["戰鼙征騎洶人寰，此道煙昏霧晦間。", "萬世難磨朱氏學，一官來管紫陽山。", "窮冬碩果何曾食，滄海明珠不再還。", "能作春霆啟幽蟄，終身我亦巷瓢顔。"]'),
('7a6a2a87-786f-42c1-b22c-bfd45e5914f1','送紫陽王山長俊甫如武林五首  其四','方回','宋','宋诗','song-poetry','','[]','儒風掃地久堪哀，誰與前朝養禍胎。',64,'全唐诗/poet.song.232000.json','["儒風掃地久堪哀，誰與前朝養禍胎。", "真魏無年喬鄭壽，杜游不作董丁來。", "游魂葛嶺人方醉，轉盼陳橋業遽灰。", "頼是紫陽書尚在，不隨遷鼎委蒿萊。"]'),
('03d0e078-f114-4ab9-a739-eb9e2aa3eaba','送紫陽王山長俊甫如武林五首  其五','方回','宋','宋诗','song-poetry','','["\u897f\u6e56"]','錢塘湖上試經過，便似秦淮玉樹歌。',64,'全唐诗/poet.song.232000.json','["錢塘湖上試經過，便似秦淮玉樹歌。", "突兀樓臺新佛剎，依稀燈火舊沙河。", "士皆戎服駢鞍馬，女尚宮粧拂黛蛾。", "我欲同君理輕棹，蘇堤呼酒酹東坡。"]'),
('5c20132e-60d6-4bb6-b767-471e84477308','寄趙賓暘二首  其一','方回','宋','宋诗','song-poetry','','[]','秀亭山下舊吾廬，十二年鄰長者居。',64,'全唐诗/poet.song.232000.json','["秀亭山下舊吾廬，十二年鄰長者居。", "近別復經三換曆，相疏不寄一行書。", "諸郎已了婚姻未，所至堪憐盜賊餘。", "老我種瓜生事拙，想君更苦食無魚。"]'),
('5bf5e03f-55d8-4784-ab9b-e98581349fbd','寄趙賓暘二首  其二','方回','宋','宋诗','song-poetry','','[]','才疏意廣道難行，深入窮山隠姓名。',64,'全唐诗/poet.song.232000.json','["才疏意廣道難行，深入窮山隠姓名。", "自分一瓢終陋巷，誰知五馬昔專城。", "去年是處興兵甲，此老無人問死生。", "忽憶杜微今七十，寄聲聊見不忘情。"]'),
('57020e54-92b0-49ce-9dfe-6b85c437d9ea','不寐十首  其一','方回','宋','宋诗','song-poetry','','[]','清寒雪夜天，欹枕暗燈前。',48,'全唐诗/poet.song.232000.json','["清寒雪夜天，欹枕暗燈前。", "總爲多思慮，常令少睡眠。", "著書傳後世，講學紹先賢。", "老死將無日，空閒十二年。"]'),
('982aeeb6-8f57-4325-ac39-7a15131797ab','不寐十首  其二','方回','宋','宋诗','song-poetry','','[]','孤燈深夜半，何乃撫床爲。',48,'全唐诗/poet.song.232000.json','["孤燈深夜半，何乃撫床爲。", "道左時難料，心方世豈知。", "孰刊前代史，肯作近人詩。", "黠鬼應相笑，乾坤一老癡。"]'),
('c258fcd9-8ddf-4473-97e1-8f6cf69c7d76','不寐十首  其三','方回','宋','宋诗','song-poetry','','[]','暮年無寐意，燈與影應知。',48,'全唐诗/poet.song.232000.json','["暮年無寐意，燈與影應知。", "誰復名三叛，空勞賦五噫。", "今人難與語，來世尚堪期。", "準易揚雄業，真成覆瓿爲。"]'),
('0fcf82fd-24db-4cfa-b43b-0cdfece8d239','不寐十首  其四','方回','宋','宋诗','song-poetry','','[]','無寐復無寐，自知仍自知。',48,'全唐诗/poet.song.232000.json','["無寐復無寐，自知仍自知。", "少狂今始悔，宿疾尚堪醫。", "雪水消殘酒，燈花送好詩。", "元龍湖海氣，老矣復何施。"]'),
('e0f9a885-e6b9-41d1-9643-be4405b13447','不寐十首  其五','方回','宋','宋诗','song-poetry','','[]','世間無限事，總不屬閒人。',48,'全唐诗/poet.song.232000.json','["世間無限事，總不屬閒人。", "必欲伸公論，寧如愛老身。", "武成難盡信，泰誓尚非真。", "衛府公閭語，何哉彼鬼神。"]'),
('68f3f393-7495-4931-b9b5-82b0eab0414a','不寐十首  其六','方回','宋','宋诗','song-poetry','','[]','夜眠纔合眼，即見此諸公。',48,'全唐诗/poet.song.232000.json','["夜眠纔合眼，即見此諸公。", "骸骨已應朽，精神猶自通。", "老懷常忽忽，暮景極怱怱。", "知己恩難報，皇天識寸衷。"]'),
('5eb4c421-4a05-4e65-a249-a66f07c40eef','不寐十首  其七','方回','宋','宋诗','song-poetry','','[]','雪聲兼雨聲，靜聽到殘更。',48,'全唐诗/poet.song.232000.json','["雪聲兼雨聲，靜聽到殘更。", "爲底常無寐，寧當有不平。", "食多嫌氣濁，衾薄覺神清。", "萬古書燈眼，心常與共明。"]'),
('86a3e4d9-c724-4629-8fdc-d6af2a5aae21','不寐十首  其八','方回','宋','宋诗','song-poetry','','[]','涉世形容悴，違時嗜好偏。',48,'全唐诗/poet.song.232000.json','["涉世形容悴，違時嗜好偏。", "偶猶身未死，豈爲己無眠。", "道喪文趨刻，談高學類禪。", "申生真斃犬，望帝竟啼鵑。"]'),
('564ced89-7cec-4c2d-8465-ab561f16ee52','不寐十首  其九','方回','宋','宋诗','song-poetry','','[]','竺國輪迴說，誣民斷勿疑。',48,'全唐诗/poet.song.232000.json','["竺國輪迴說，誣民斷勿疑。", "還知已死後，即是未生時。", "六道何憑考，三身故强推。", "反終更原始，不寐試深思。"]'),
('8a75b3ec-8f98-42ea-a49e-62115a110b1c','不寐十首  其一○','方回','宋','宋诗','song-poetry','','[]','細字昏難讀，孤燈冷獨挑。',48,'全唐诗/poet.song.232000.json','["細字昏難讀，孤燈冷獨挑。", "黄虀餘口味，白豆驗心苗。", "玉枕方春夢，金門正早朝。", "先生唯默坐，窗外雨蕭蕭。"]'),
('9ea05f83-0ed7-4d4e-a511-819511280ce3','寄題桐君祠','方回','宋','宋诗','song-poetry','','[]','問姓云何但指桐，桐孫終古與無窮。',64,'全唐诗/poet.song.232000.json','["問姓云何但指桐，桐孫終古與無窮。", "遥知學出神農氏，獨欠書傳太史公。", "可用有名留世上，定應不死在山中。", "休官老守慚高致，政恐猶難立下風。"]'),
('21c1953c-7d1a-4a64-a46b-ad761d1297d4','徐制準挽辭','方回','宋','宋诗','song-poetry','','[]','紛紜鐘鼎誤公卿，孰與山林保令名。',64,'全唐诗/poet.song.232000.json','["紛紜鐘鼎誤公卿，孰與山林保令名。", "不共鵠袍爭舉業，早令熊轡紹詩聲。", "人間倏忽驚興廢，物外從容了死生。", "何限貂蟬無葬地，一丘風月自佳城。"]'),
('cee9189e-c65e-42a5-8ae8-229a263c949f','十二月二十日立春係癸巳歲予年已六十七白劉唱和有云共把十千沽一斗相看七十欠三年因此遣興','方回','宋','宋诗','song-poetry','','[]','客途窮極亦陶然，自覺平生愧樂天。',64,'全唐诗/poet.song.232000.json','["客途窮極亦陶然，自覺平生愧樂天。", "能辦十千沽一斗，何知七十欠三年。", "日晴雪路初行處，春到椒盤未頌前。", "好念故園小兒女，團欒聞早醉花邊。"]'),
('ef3f6a3e-90a0-4a58-91c2-6d3473f4904a','癸巳元日年六十七','方回','宋','宋诗','song-poetry','','[]','生平矻矻短檠窗，晚節灰心殢酒缸。',64,'全唐诗/poet.song.232000.json','["生平矻矻短檠窗，晚節灰心殢酒缸。", "百歲三分新過二，十行一目舊無雙。", "又驚客枕聽春雨，即合歸舟上浙江。", "未必樊遲劣顔子，故應學稼勝爲邦。"]'),
('60e9964b-d6db-4938-a49f-069cb92385e6','元日小雨','方回','宋','宋诗','song-poetry','','[]','紅垂燈穗倍常明，緩緩晴須作好晴。',64,'全唐诗/poet.song.232000.json','["紅垂燈穗倍常明，緩緩晴須作好晴。", "著柳春風微有色，催花夜雨細無聲。", "爐香早起蹣跚拜，杯酒朋來瀲灧傾。", "一日一詩舊年例，新年一日兩詩成。"]'),
('9d45b392-758e-4e2d-9a25-9d7ae8929ac1','初六日過湖','方回','宋','宋诗','song-poetry','','[]','長於花擔看梅花，不訪山巔問水涯。',64,'全唐诗/poet.song.232000.json','["長於花擔看梅花，不訪山巔問水涯。", "世換湖光無減少，時來春色與增加。", "荒榛德祐權臣宅，老樹咸平處士家。", "一醉第三橋畔酒，佳蔬菜更美魚蝦。"]'),
('1bb237c7-8439-4166-8131-48dccd91d819','放夜','方回','宋','宋诗','song-poetry','','[]','深夜樓前笑語譁，禁街鐘鼓暫停撾。',64,'全唐诗/poet.song.232000.json','["深夜樓前笑語譁，禁街鐘鼓暫停撾。", "冶游謔浪非吾事，富足歡娛有幾家。", "春酒可能融鬢雪，書燈獨自照梅花。", "黄柑猶見昇平物，四十年前客永嘉。"]'),
('0ce6ad68-6aee-4884-92a3-56d80e800312','觀燈小酌十四夜半大風而雨','方回','宋','宋诗','song-poetry','','[]','皓月微紅映落霞，試呼樽酒答年華。',64,'全唐诗/poet.song.232000.json','["皓月微紅映落霞，試呼樽酒答年華。", "柑爲天下無雙果，梅是春前第一花。", "自古良辰難得友，暫時老子不思家。", "夜深忽作大風雨，樂事元來亦未奢。"]'),
('34798884-ef63-4635-8a8b-662b35be8fc1','追懷甲戌清明宇文信仲知郡大卿同尤張二倅過予小園賞花','方回','宋','宋诗','song-poetry','','[]','甲戌清明鬢未翁，邦君過我小園中。',64,'全唐诗/poet.song.232000.json','["甲戌清明鬢未翁，邦君過我小園中。", "牡丹初喜開千朵，劫火何知付一空。", "展轉干戈春夢斷，凄凉風雨客途窮。", "九原可作應垂涕，今日前時事不同。"]'),
('dede8684-15f1-4eff-b765-69584af53f0f','數日項頰顴咽腫痛髪中有瘡','方回','宋','宋诗','song-poetry','','[]','有生必死理之常，酒到何爲不舉觴。',64,'全唐诗/poet.song.232000.json','["有生必死理之常，酒到何爲不舉觴。", "未問劉伶墳上土，何妨張詠鬢邊瘡。", "叔和解訣行尸脈，仲景工言越婢湯。", "知命吾當謝醫藥，服膺參也戰兢章。"]'),
('55d40082-a7a0-448e-b5dd-19411fc06859','春寒久病','方回','宋','宋诗','song-poetry','','[]','似覺今年太坎軻，春寒無策與降魔。',64,'全唐诗/poet.song.232000.json','["似覺今年太坎軻，春寒無策與降魔。", "斷支酒費貧如故，細讀醫書病更多。", "客夢鄉關心破碎，好花時節雨消磨。", "時人豈識衣冠會，清朗蘭亭晉永和。"]'),
('fd9952d6-5fd2-4644-9ca6-d9b10d31f976','送徐如心如婺源三十韻','方回','宋','宋诗','song-poetry','','[]','之子成春服，歡言駕出遊。',288,'全唐诗/poet.song.232000.json','["之子成春服，歡言駕出遊。", "殘紅三月路，疊翠萬山州。", "夏后乘輴澤，軒皇煉藥丘。", "曠平初渺莽，屈曲漸深幽。", "比縣干戈偃，諸村盜賊收。", "室廬還舊貫，邸店競新修。", "蠶月門多鐍，秧田草盡耰。", "畫龍沽肆古，檻虎驛程脩。", "天目蟠根遠，王干設險遒。", "徑紆橫巨石，澗潔見游鯈。", "嶽勢攀衡霍，星文摘斗牛。", "桑麻敦本業，笋蕨勝珍羞。", "谷冷長杉密，岡溫早茗抽。", "宣平何處在，太白此中求。", "仙墅丹池火，僧廬野竹秋。", "農談通稗史，騷詠入樵謳。", "楚雨三江外，吳雲五嶺頭。", "夕陽彭蠡浦，潮水浙河流。", "西望番君國，東思越相州。", "孰云民俗儉，政爾士風優。", "輿隸知周孔，章縫盛魯鄒。", "聖賢一道續，天地四書留。", "闕里瞻庠序，師臣拜冕旒。", "永懷枌梓故，能奠藻芹不。"]'),
('a2bda131-88b0-4a00-bc42-39053cc57d0a','三月三日西湖第三橋四首  其一','方回','宋','宋诗','song-poetry','','["\u897f\u6e56"]','北曲南歌日日新，紅粧不逐落紅春。',32,'全唐诗/poet.song.232000.json','["北曲南歌日日新，紅粧不逐落紅春。", "網魚野老何曾覷，豈是心腸木石人。"]'),
('7018871b-3c4e-4cad-bb86-1e14534f6962','三月三日西湖第三橋四首  其二','方回','宋','宋诗','song-poetry','','["\u897f\u6e56"]','正月橋西賣酒家，柳初青眼草初芽。',32,'全唐诗/poet.song.232000.json','["正月橋西賣酒家，柳初青眼草初芽。", "重來紅紫隨風雨，猶有野田黄菜花。"]'),
('bd8f11dd-8c23-4e57-ae52-b24e8f830eed','三月三日西湖第三橋四首  其三','方回','宋','宋诗','song-poetry','','["\u897f\u6e56"]','盡道西湖久寂寥，紅欄干落但空橋。',32,'全唐诗/poet.song.232000.json','["盡道西湖久寂寥，紅欄干落但空橋。", "細思未有蘇隄日，且把閒愁著酒澆。"]'),
('138ad5fa-8e2a-4aa5-aa47-8b0cfb608e68','三月三日西湖第三橋四首  其四','方回','宋','宋诗','song-poetry','','["\u897f\u6e56"]','野蔌隨宜酒半醺，富兒盤饌擁紅裙。',32,'全唐诗/poet.song.232000.json','["野蔌隨宜酒半醺，富兒盤饌擁紅裙。", "蘭亭會上無絲竹，芥蔕區區笑右軍。"]'),
('a96cfb4c-bfe6-49e6-a5cf-86f753231be1','寒熱不調病一月餘','方回','宋','宋诗','song-poetry','','[]','不肯中和按故常，膈痰鼻涕更頭瘍。',64,'全唐诗/poet.song.232000.json','["不肯中和按故常，膈痰鼻涕更頭瘍。", "塵飛泥涴三春盡，熱熯寒僵一月强。", "乍把酒盃嫌藥氣，屢翻詩卷寫醫方。", "年年憶得古人語，端午綿衣未可藏。"]'),
('6e82cbbb-8338-4487-a57d-65635992c5fb','病後夏初雜書近况十首  其一','方回','宋','宋诗','song-poetry','','[]','含桃豌豆喜嘗新，罌粟花邊已送春。',64,'全唐诗/poet.song.232000.json','["含桃豌豆喜嘗新，罌粟花邊已送春。", "豈謂單衣揮扇手，仍爲敗絮擁爐身。", "唾壺甫換痰仍滿，藥貼多誇料不真。", "火熱冰寒但絕欲，世間疫癘本無神。"]'),
('7650905d-0c9e-4046-8825-e284401800be','病後夏初雜書近况十首  其二','方回','宋','宋诗','song-poetry','','[]','怯寒重著舊綿裘，已見盆栽坼絳榴。',64,'全唐诗/poet.song.232000.json','["怯寒重著舊綿裘，已見盆栽坼絳榴。", "自厭一春常服藥，忽驚半月不梳頭。", "畫評懶與癡兒辨，詩序難禁晚進求。", "带礪有盟猶未保，當時誰識種瓜侯。"]'),
('37704459-cede-4030-887f-1c5cc8ecb375','病後夏初雜書近况十首  其三','方回','宋','宋诗','song-poetry','','[]','駸駸七十保餘齡，魚眼無眠夜夜醒。',64,'全唐诗/poet.song.232000.json','["駸駸七十保餘齡，魚眼無眠夜夜醒。", "魂夢不迷神女雨，形容欲似老人星。", "參同契注房中術，歸去來辭座右銘。", "却笑空王太膚淺，張皇浪說八師經。"]'),
('d871dff3-0bd9-46fe-b8b5-deccbf2c5f7c','病後夏初雜書近况十首  其四','方回','宋','宋诗','song-poetry','','[]','客樓卧病過花時，老態如狂復似癡。',64,'全唐诗/poet.song.232000.json','["客樓卧病過花時，老態如狂復似癡。", "甚欲不餐煙火食，頗能時賦草茅詩。", "餘生自曉寸關尺，他日誰傳髓骨皮。", "少許青梅傾斗酒，心醒貌醉爾焉知。"]'),
('9241f221-3ddf-45bf-b97a-b340b96677cd','病後夏初雜書近况十首  其五','方回','宋','宋诗','song-poetry','','[]','初掃蠶今欲繭時，無朝無暮雨垂垂。',64,'全唐诗/poet.song.232000.json','["初掃蠶今欲繭時，無朝無暮雨垂垂。", "漁家長價蓑衣貴，種戶流涎麥飯遲。", "跬步過從難跋涉，等閒脫著繫安危。", "肉芝石髓身中有，可向山靈遽朵頤。"]'),
('737eac81-2eba-41e0-8abb-f5e74dcb13e9','病後夏初雜書近况十首  其六','方回','宋','宋诗','song-poetry','','[]','六年三潦困餘黎，誰識他年舊浙西。',64,'全唐诗/poet.song.232000.json','["六年三潦困餘黎，誰識他年舊浙西。", "靡有孑遺何可忽，不知歸去果安之。", "屬方理屋又聞漏，垂欲出門仍畏泥。", "家在窮山亂雲外，自慚無策救兒饑。"]'),
('600ef269-7f2f-4a47-952c-27ffcb53d36b','病後夏初雜書近况十首  其七','方回','宋','宋诗','song-poetry','','[]','今年春夏極窮忙，日檢醫書校藥方。',64,'全唐诗/poet.song.232000.json','["今年春夏極窮忙，日檢醫書校藥方。", "甫得木瓜治膝腫，又須荆芥沐頭瘍。", "一生辛苦身多病，四至平和脈尚强。", "壽及龜堂老睦守，不難萬首富詩囊。"]'),
('f8eefd9c-b314-4e2b-be2e-32c84882cd7b','病後夏初雜書近况十首  其八','方回','宋','宋诗','song-poetry','','[]','富兒肥馬躍雕鞍，同伴何由識木蘭。',64,'全唐诗/poet.song.232000.json','["富兒肥馬躍雕鞍，同伴何由識木蘭。", "拄杖扶携元未老，交床隨逐本無官。", "三叉路口人心異，百尺樓頭客眼寒。", "黠鬼老狐足妖怪，架中閒摘舊書看。"]'),
('08252a3e-cb7d-4512-91e5-c8acff1f4894','病後夏初雜書近况十首  其九','方回','宋','宋诗','song-poetry','','["\u5cb3\u9633\u697c"]','妙年剛謂世無愁，汗漫猖狂萬里游。',64,'全唐诗/poet.song.232000.json','["妙年剛謂世無愁，汗漫猖狂萬里游。", "夢裏講經天竺國，醉中橫笛岳陽樓。", "散花女已無蹤矣，老樹精今尚在不。", "咋舌噬臍更摇手，顔瓢曾瑟外何求。"]'),
('49977e4b-d5f7-481d-965d-bb14e2fdca06','病後夏初雜書近况十首  其一○','方回','宋','宋诗','song-poetry','','[]','一切牽纏斷孟勞，何金爲带紫爲袍。',64,'全唐诗/poet.song.232000.json','["一切牽纏斷孟勞，何金爲带紫爲袍。", "老從楊柳櫻桃去，醉肯螟蛉蜾蠃豪。", "共慶龍從乾五會，誰工雉食鼎三膏。", "折腰彭澤不歸去，未必東坡肯和陶。"]'),
('436dc508-5629-40ef-bc39-2b93d1fd7ef2','有感','方回','宋','宋诗','song-poetry','','[]','玩透羲爻未畫前，今時天即古時天。',64,'全唐诗/poet.song.232000.json','["玩透羲爻未畫前，今時天即古時天。", "回空其庶亦其庶，軻死不傳焉不傳。", "積憤淫傷詩未削，暗籌微婉史誰編。", "繼周百世民彝在，豈爲興亡有變遷。"]'),
('b565122a-0260-4728-a653-114ac02cb036','呈閻子靜廉訪翰學二首  其一','方回','宋','宋诗','song-poetry','','[]','先生誰解與傳神，寫向吾詩似亦親。',64,'全唐诗/poet.song.232000.json','["先生誰解與傳神，寫向吾詩似亦親。", "文字老坡真學士，丰姿太白謫仙人。", "明庭瑞彩陳圭璧，治世奇祥出鳳麟。", "一道澄清非所凂，湖山暫此岸綸巾。"]'),
('f52a9554-761b-4d27-b525-e84ce5737233','呈閻子靜廉訪翰學二首  其二','方回','宋','宋诗','song-poetry','','["\u897f\u6e56"]','文星炯炯照勾吳，草詔金鑾舊老儒。',64,'全唐诗/poet.song.232000.json','["文星炯炯照勾吳，草詔金鑾舊老儒。", "今□□公高北斗，後身白傅到西湖。", "要途未若閒官樂，心服□□貌敬殊。", "臭味果能有投合，及門豈在急摳趨。"]'),
('4e4ce2dc-7c00-4183-8d18-90ce79538ed5','送醫工郭耕道','方回','宋','宋诗','song-poetry','','[]','上古三皇軒農羲，天始有柱地有基。',352,'全唐诗/poet.song.232000.json','["上古三皇軒農羲，天始有柱地有基。", "腹虛與實療民饑，心塞與開植民彝。", "保民性命專厥司，握生殺權名曰醫。", "萬事萬物有偶奇，一陰一陽之所爲。", "五運六氣相參差，流行百骸敷四肢。", "河隄蟻竅如針錐，榮衛微爽顛不治。", "沉裏浮表數及遲，指下難明審毫釐。", "能肉其骨扶其危，神聖工巧古所推。", "汴梁凱旋并門師，代州之郭天下知。", "半留中原半南移，大方脈科三百朞。", "黄金臺邊驛騎馳，大樹古巷傳言絲。", "趣裝北上揚喜眉，藥囊香細溫風吹。", "肘後之祕神護持，本草我亦一二窺。", "素問難經手曾披，但於一事似有疑。", "左右心肝腎肺脾，女人反此背看之。", "叔和脈經無此辭，託名爲訣翻支離。", "尺盛尺弱分兩岐，句拙語俗意有疵。", "舉世附和莫鉗鎚，惟晁公武能辨茲。", "欲攀易牙別澠淄，郭侯去矣不可羈。", "丹砂赤箭參朮芝，豕苓雞壅敗鼓皮。", "百發百中謹所施，樓護侯鯖勿涎垂。", "弘景當有還山期，贈行聊效黄庭詩。"]'),
('b65b532b-f73f-4e09-8e63-a592517f50c2','四月十二日飲陸君用見山堂','方回','宋','宋诗','song-poetry','','[]','硯几書床茂樹間，花深竹密地寬閒。',32,'全唐诗/poet.song.232000.json','["硯几書床茂樹間，花深竹密地寬閒。", "綠陰正是濃時節，遮盡人家只見山。"]'),
('37779402-b7a5-4fcb-81a7-c303d5d6c12c','何仁甫作室日生男','方回','宋','宋诗','song-poetry','','[]','築室肇聞開吉卜，弄璋恰喜共良辰。',64,'全唐诗/poet.song.232000.json','["築室肇聞開吉卜，弄璋恰喜共良辰。", "千間廣厦連雲起，一顆明珠入掌新。", "撰上梁文焉用我，作湯餠客可無人。", "門閭如此須高大，他日能容駟馬輪。"]'),
('f6617509-1bfe-4650-8b81-ce4c2ffee302','送徐似之歸新城','方回','宋','宋诗','song-poetry','','[]','趁潮小緩轉船頭，不枉湖山十日留。',32,'全唐诗/poet.song.232000.json','["趁潮小緩轉船頭，不枉湖山十日留。", "喜得閻徐二學士，爲傳佳句過中州。"]'),
('795f5a27-ce40-454a-9efc-0b2e9294d30a','午節','方回','宋','宋诗','song-poetry','','[]','年年節與物相符，筍已成竿燕欲雛。',32,'全唐诗/poet.song.232000.json','["年年節與物相符，筍已成竿燕欲雛。", "客裏不知端午近，賣花擔上見菖蒲。"]'),
('37eadfb4-5202-43a3-920b-d86d89a1f465','送和仲寬壽陽尉','方回','宋','宋诗','song-poetry','','[]','青衫淝水去，亦足慰高年。',48,'全唐诗/poet.song.232000.json','["青衫淝水去，亦足慰高年。", "縣以州名壽，官於尉號仙。", "戰場潜鬼火，耕野起人煙。", "綵棒無勞設，蒲輪下九天。"]'),
('0093a324-1bc8-4362-9380-ed72eb1f2517','五月初十日病體少甦','方回','宋','宋诗','song-poetry','','[]','仙棋一局爛樵柯，塵世紛紛夢幻多。',64,'全唐诗/poet.song.232000.json','["仙棋一局爛樵柯，塵世紛紛夢幻多。", "病起鏡中非復我，愁來酒外更無它。", "逍遥悟解參莊叟，矍鑠形容謝伏波。", "忽省明朝又生日，暮年歸計欲如何。"]'),
('8b2dbba0-83db-420c-9f80-a7b7d29c04fc','是日大雨水漲','方回','宋','宋诗','song-poetry','','[]','三橋北畔清湖水，雙塔西邊曉日樓。',64,'全唐诗/poet.song.232000.json','["三橋北畔清湖水，雙塔西邊曉日樓。", "展轉愈知吾事拙，因循復作半年留。", "海風石首隨潮上，梅雨航船入市浮。", "時節不殊榮悴異，腐儒盃酒暫忘憂。"]'),
('5aa737cb-a4ec-46ce-abf7-282c700ee730','癸巳生日二首  其一','方回','宋','宋诗','song-poetry','','[]','夜來終日雨如傾，曉起樓頭喜漸晴。',64,'全唐诗/poet.song.232000.json','["夜來終日雨如傾，曉起樓頭喜漸晴。", "血氣衰微吾道勝，慾心死絕此身生。", "一區宅愧先人業，萬首詩垂後世名。", "蚊喙收聲蛙不吠，忽聞鄰柳送啼鶑。"]'),
('195d2fb3-d34c-46a9-853c-5462c233197b','癸巳生日二首  其二','方回','宋','宋诗','song-poetry','','[]','倚樓歷歷算行藏，囏阻顛危暗自傷。',64,'全唐诗/poet.song.232000.json','["倚樓歷歷算行藏，囏阻顛危暗自傷。", "垂近七旬天所借，孰憐三歲父云亡。", "嶺南蠱毒千山霧，燕北氈寒六月霜。", "殿榜郡符皆畫餠，空餘骨痛似金瘡。"]'),
('68c2355b-1287-4760-880a-38743fbaf801','生日再書','方回','宋','宋诗','song-poetry','','[]','湯餠隨緣和醤醯，六年三潦念民饑。',64,'全唐诗/poet.song.232000.json','["湯餠隨緣和醤醯，六年三潦念民饑。", "重逢白髪人生日，願見黄梅雨止時。", "詩好遠過千歲壽，家貧深負五男兒。", "許身稷契杜陵老，豈謂殘生乃至斯。"]'),
('564cdccc-8a1b-4ff5-95cc-4744d3a0ab84','用五男兒再賦','方回','宋','宋诗','song-poetry','','[]','每於生日賦新詩，似覺今年老更癡。',64,'全唐诗/poet.song.232000.json','["每於生日賦新詩，似覺今年老更癡。", "竊謂齊公千駟馬，豈如陶氏五男兒。", "能拚久客常沉醉，不念全家慣忍饑。", "七十尚爭三屈指，挂冠一紀此差奇。"]'),
('04a2a23a-f409-4365-ba5b-3b335cb7cd7b','贈醫士清溪居士丘通甫','方回','宋','宋诗','song-poetry','','[]','乃翁挾藝專淮鄉，使死者生危不亡。',320,'全唐诗/poet.song.232000.json','["乃翁挾藝專淮鄉，使死者生危不亡。", "遠如扁鵲師長桑，又如近世龐安常。", "所交者誰龍虎驤，真李臨淮郭汾陽。", "軍門出入一藥囊，精兵十萬無金瘡。", "參苓硝石雄附薑，補瀉虛實調炎凉。", "晚擇所從遨真揚，郄家太尉王東床。", "有子有子跨竈郎，半夜衣傳肘後方。", "清溪居士清名香，心欲識面形參商。", "邇來解后古餘杭，其言亹亹慨以慷。", "七表八裏誰能詳，三部九候吾獨臧。", "八十一難聲琅琅，素問靈樞腹爲箱。", "望形察色起仆僵，馘俘二豎完膏肓。", "傷寒足脈根膀胱，過經七日妖災禳。", "度彼沒溺君爲航，淺學不識空望洋。", "若有人兮雲錦裳，飲君一劑壽而康。", "贈君詩篇金玉相，貫月夜虹光燄長。", "乾坤六合何茫茫，生民性命孰翕張。", "惟將惟相惟醫良，良將無人戰卒戕。", "良相無人賢士藏，良醫無人彭作殤。", "焉得萬筆千縑緗，屈君著書肩岐黄。"]'),
('5290207f-14de-463f-8966-9aff4ae2500e','次韻徐容齋贈丘通甫','方回','宋','宋诗','song-poetry','','[]','絕如山谷贈初君，奇絕新詩妙絕文。',64,'全唐诗/poet.song.232000.json','["絕如山谷贈初君，奇絕新詩妙絕文。", "斥逐三彭精異術，破除二豎奏元勳。", "千莖白雪難重少，一匕玄霜幸見分。", "可惜向來缺參請，按摩搬運漫辛勤。"]'),
('439a8865-6e1d-4f48-b843-b117a7557635','梅雨大水','方回','宋','宋诗','song-poetry','','[]','積年梅雨動兼旬，咎證源源殆有因。',64,'全唐诗/poet.song.232000.json','["積年梅雨動兼旬，咎證源源殆有因。", "狐假虎威饒此輩，鼠穿牛角念吾民。", "涎流白飯難僥倖，汗滴青秧浪苦辛。", "曲許乖龍啖梁燕，何如饑溺拯窮人。"]'),
('43ad68e7-26bb-42e3-bef2-d2cb22ff3f49','五月九日甲子至月望庚午大雨水不已十首  其一','方回','宋','宋诗','song-poetry','','[]','夜半觀天象，無星定肯晴。',48,'全唐诗/poet.song.232000.json','["夜半觀天象，無星定肯晴。", "河流兼市沒，船勢與樓平。", "未殺漂摇意，仍添颯灑聲。", "人膏飫魚鼈，真宰忍忘情。"]'),
('8d33f39a-91a1-4ff6-bb28-44a6672e3411','五月九日甲子至月望庚午大雨水不已十首  其二','方回','宋','宋诗','song-poetry','','[]','波浪冒原田，羣魚不自全。',48,'全唐诗/poet.song.232000.json','["波浪冒原田，羣魚不自全。", "返常真足怪，行險絕堪憐。", "驟作乘時快，遄成失勢顛。", "兒童拾鰻鱔，爭著柳枝穿。"]'),
('310be043-b8b1-4de6-a070-c17533d453ae','五月九日甲子至月望庚午大雨水不已十首  其三','方回','宋','宋诗','song-poetry','','[]','陸走無非水，樓居併是泥。',48,'全唐诗/poet.song.232000.json','["陸走無非水，樓居併是泥。", "褰裳難跋涉，執蓋困扶携。", "國慮白圭壑，城危智伯堤。", "暘烏果安在，轉覺漏天低。"]'),
('b27b1985-5ba3-47f1-befd-7422ead1029c','五月九日甲子至月望庚午大雨水不已十首  其四','方回','宋','宋诗','song-poetry','','[]','江南梅子雨，騷客古今愁。',48,'全唐诗/poet.song.232000.json','["江南梅子雨，騷客古今愁。", "豈意連年夏，頻妨庶事秋。", "爲魚民自痛，食肉爾何憂。", "衰老那禁得，看天獨倚樓。"]'),
('cbeb86c1-a024-486b-829a-1237abbf7fb0','五月九日甲子至月望庚午大雨水不已十首  其五','方回','宋','宋诗','song-poetry','','[]','能免堯捐瘠，端由稷播艱。',48,'全唐诗/poet.song.232000.json','["能免堯捐瘠，端由稷播艱。", "民生頻不競，世故政相關。", "穴蟻移樓杪，田蛙産竈間。", "豐凶卜簷溜，半月響潺湲。"]'),
('703a6501-25cf-4c57-b95c-e2ea01c73dd0','五月九日甲子至月望庚午大雨水不已十首  其六','方回','宋','宋诗','song-poetry','','[]','眼待稻花看，青苗浸急湍。',48,'全唐诗/poet.song.232000.json','["眼待稻花看，青苗浸急湍。", "萬家應慟哭，五月更恒寒。", "政爾千倉足，猶云一飯難。", "凶災忽如此，容易便平安。"]'),
('2f9702e1-f11f-4019-8764-4e249696f8e0','五月九日甲子至月望庚午大雨水不已十首  其七','方回','宋','宋诗','song-poetry','','[]','蒸漬衣巾醭，拘攣臂膝頑。',48,'全唐诗/poet.song.232000.json','["蒸漬衣巾醭，拘攣臂膝頑。", "老身何足恤，時事自多艱。", "井滿瓢堪汲，船高樹可攀。", "蒼生百萬億，性命雨暘間。"]'),
('c4529e96-2563-4621-bb19-6b385db7f9c4','五月九日甲子至月望庚午大雨水不已十首  其八','方回','宋','宋诗','song-poetry','','[]','平地驚胥怒，滔天類鯀湮。',48,'全唐诗/poet.song.232000.json','["平地驚胥怒，滔天類鯀湮。", "稍低三板水，不活百城人。", "已拚過從絕，徒工徙倚頻。", "鵠形無白粲，蜂起有黄巾。"]'),
('fa69844d-9b40-47ca-b15e-a9f5081f87a4','五月九日甲子至月望庚午大雨水不已十首  其九','方回','宋','宋诗','song-poetry','','[]','今日雲霄客，何人禹稷思。',48,'全唐诗/poet.song.232000.json','["今日雲霄客，何人禹稷思。", "樹高堪避溺，稻盡底充饑。", "苦口非吾事，衰軀異昔時。", "東溟容有限，細讀后山詩。"]'),
('77d0df79-9e7d-4bfe-afca-626c8cf8e1ff','五月九日甲子至月望庚午大雨水不已十首  其一○','方回','宋','宋诗','song-poetry','','["\u897f\u6e56"]','西湖湖外水，洶湧入城流。',48,'全唐诗/poet.song.232000.json','["西湖湖外水，洶湧入城流。", "比戶升高閣，通衢塞大舟。", "學泅兒輩喜，絕爨老夫憂。", "會見蹄涔涸，魚蝦悔浪游。"]'),
('9aaa104b-ef14-4bd0-9ed3-191d90764162','十六日水退雨不已次受益韻二首  其一','方回','宋','宋诗','song-poetry','','[]','暑雨民咨怨，由來直匪今。',48,'全唐诗/poet.song.232000.json','["暑雨民咨怨，由來直匪今。", "濕能蒸病骨，滴欲碎歸心。", "積水連村郭，前途昧淺深。", "雄風楚臺上，誰且獨披襟。"]'),
('be43ec77-bdbb-46bd-8423-7160b3c00705','十六日水退雨不已次受益韻二首  其二','方回','宋','宋诗','song-poetry','','[]','七年逢四潦，苟活到于今。',48,'全唐诗/poet.song.232000.json','["七年逢四潦，苟活到于今。", "每值月離畢，難逢木守心。", "江兼湖共滿，憂與恨俱深。", "萬頃青秧沒，田家淚濕襟。"]'),
('2d6b49aa-cdac-4b49-94ac-bff3869a0750','再用前韻','方回','宋','宋诗','song-poetry','','[]','此事誰知我，他年豈料今。',48,'全唐诗/poet.song.232000.json','["此事誰知我，他年豈料今。", "棋殘才有眼，燈暗欲無心。", "衰老常爲客，山林故自深。", "忘形侶猿鶴，可待整冠襟。"]'),
('1ac055ae-6c3e-4de8-9e95-3d7932fbf305','十七十八日猶雨','方回','宋','宋诗','song-poetry','','[]','浮雲幾萬里，白日悶晴暉。',48,'全唐诗/poet.song.232000.json','["浮雲幾萬里，白日悶晴暉。", "稍覺波濤縮，猶聞點滴微。", "兩旬捐破扇，五月著寒衣。", "老病憂時事，高門馬自肥。"]'),
('c137d19b-0d81-4a89-88d2-37144f5b1304','十九日始晴','方回','宋','宋诗','song-poetry','','[]','今日簷仍滴，何人膽不寒。',48,'全唐诗/poet.song.232000.json','["今日簷仍滴，何人膽不寒。", "曬帆船尚濕，掃市路才乾。", "造化玄機轉，生靈死命完。", "傳聞睦東館，樓閣付驚湍。"]'),
('e5410aaa-b6a9-4b64-99a8-d1525ed264a1','次韻受益苦雨二首  其一','方回','宋','宋诗','song-poetry','','[]','乃者黄梅近，朝朝以雨書。',48,'全唐诗/poet.song.232000.json','["乃者黄梅近，朝朝以雨書。", "將無作人鮓，孰不困河魚。", "近郡淹城郭，連村浸室廬。", "何當與奇術，辟穀駕飛車。"]'),
('d58cf8cd-8351-400e-bfbf-357976700cfe','次韻受益苦雨二首  其二','方回','宋','宋诗','song-poetry','','[]','甘澤關民命，隨時不在多。',48,'全唐诗/poet.song.232000.json','["甘澤關民命，隨時不在多。", "滴穿簷下石，爛倒水中荷。", "天有凶荒歲，人無政事科。", "誠心能撫字，乖氣轉爲和。"]'),
('cb5b00aa-a0e5-4299-90f6-96ee7b1af488','湖上喜晴','方回','宋','宋诗','song-poetry','','[]','人閒塵不到，別是一清凉。',48,'全唐诗/poet.song.232000.json','["人閒塵不到，別是一清凉。", "雨足千峰淨，風薰百草香。", "陰森穿茂密，汩㶁泝深長。", "想見吳中路，連天盡綠秧。"]'),
('7b0037b7-d47a-4a31-bd93-7b1d54d172bf','次韻受益喜晴二首  其一','方回','宋','宋诗','song-poetry','','[]','誰扶一輪日，與掃萬重雲。',48,'全唐诗/poet.song.232000.json','["誰扶一輪日，與掃萬重雲。", "水已落數尺，田猶收幾分。", "大鈞回叶氣，疏網削深文。", "爾飯堪餬口，忍爲梁上君。"]'),
('92c23e3f-5e8b-49ec-a5c2-7d7fa52ccce1','次韻受益喜晴二首  其二','方回','宋','宋诗','song-poetry','','[]','高樓曉氣清，鐘鼓報新晴。',48,'全唐诗/poet.song.232000.json','["高樓曉氣清，鐘鼓報新晴。", "乍覩陽烏色，頻聞喜鵲聲。", "縱難期上熟，差足慰深耕。", "忍見民窮極，唯宜歲事成。"]'),
('10b00305-a956-499b-97f2-2bdbd1a43690','次韻閻學士靖軒贈受益山居二首  其一','方回','宋','宋诗','song-poetry','','[]','十里方諸影綠鬟，空濛瀲灧一窗間。',32,'全唐诗/poet.song.232000.json','["十里方諸影綠鬟，空濛瀲灧一窗間。", "天河不洗讀書眼，未可同君上此山。"]'),
('99c605a3-0c57-475d-baaf-f35c63a2fec3','次韻閻學士靖軒贈受益山居二首  其二','方回','宋','宋诗','song-poetry','','[]','八月濤江五月湖，畫圖一見粟生膚。',32,'全唐诗/poet.song.232000.json','["八月濤江五月湖，畫圖一見粟生膚。", "君家奄有兩奇觀，更覺天真勝畫圖。"]'),
('dea943ea-f2e9-4813-8048-c928bafb747d','十九日甲戌晴己卯晚又雨二首  其一','方回','宋','宋诗','song-poetry','','[]','稍復橋痕舊，俄驚礎汗非。',48,'全唐诗/poet.song.232000.json','["稍復橋痕舊，俄驚礎汗非。", "豈宜真洶湧，止可略霏霺。", "河伯毋流毒，雲師幸霽威。", "劣能驅暑氣，即願吐晴暉。"]'),
('2f0a5acd-058f-41c2-bb15-93f5ef0f6385','十九日甲戌晴己卯晚又雨二首  其二','方回','宋','宋诗','song-poetry','','[]','吳郡傳猶庶，嚴灘報可驚。',48,'全唐诗/poet.song.232000.json','["吳郡傳猶庶，嚴灘報可驚。", "田中車水出，城上駕船行。", "旅屋仍簁漏，窮簷用盎盛。", "幸而有雷電，此雨不難晴。"]'),
('62ad23a9-8353-4889-ba1a-2a5d81f6e6ca','二十五日庚辰連作暴雨即霽','方回','宋','宋诗','song-poetry','','[]','昨日占天色，心知有異同。',48,'全唐诗/poet.song.232000.json','["昨日占天色，心知有異同。", "甫能湖水綠，不合曉霞紅。", "龍挾滂沱過，蠅驚霹靂空。", "斯須即開霽，共快楚臺風。"]'),
('ea5c6525-0c93-4973-8824-95043d8be4a3','贈淳邑風水山人何君','方回','宋','宋诗','song-poetry','','[]','誰保南陽百世阡，控頤別頰每堪憐。',64,'全唐诗/poet.song.232000.json','["誰保南陽百世阡，控頤別頰每堪憐。", "發丘郎將焉容禦，裸葬王孫幸獲全。", "何所不如圍即墨，厥今安在像祁連。", "小詩更舉樊崇事，好與慈孫孝子傳。"]'),
('59e2928e-6724-4ca7-bab6-37aa47f5e64d','題陳正之蘭亭','方回','宋','宋诗','song-poetry','','[]','十六迴更癸丑春，蘭亭臨本尚如新。',32,'全唐诗/poet.song.232000.json','["十六迴更癸丑春，蘭亭臨本尚如新。", "學書良易人難學，聊喜他鄉見似人。"]'),
('3d1b29d7-de9a-4ddc-91e5-0862dce95a36','病中夜思','方回','宋','宋诗','song-poetry','','[]','垂及七旬叟，行將三伏時。',48,'全唐诗/poet.song.232000.json','["垂及七旬叟，行將三伏時。", "歸期秋未定，病勢夜尤危。", "眼困終難寐，心明尚可醫。", "陰寒伺陽燠，間隙不容絲。"]'),
('22ceaa99-52a3-4461-9216-895bccea55b1','次韻金直卿夏夜','方回','宋','宋诗','song-poetry','','[]','樓高夜獨吟，鑑古復籌今。',48,'全唐诗/poet.song.232000.json','["樓高夜獨吟，鑑古復籌今。", "不競當知命，無瑕在養心。", "人聲鐘後絕，天影水中深。", "風檻微凉處，時時一正襟。"]'),
('35949a4b-b8dc-405a-9ea6-c4365513fea6','題李提舉心遠軒','方回','宋','宋诗','song-poetry','','[]','心遠淵明擬問之，悠然身世見山時。',64,'全唐诗/poet.song.232000.json','["心遠淵明擬問之，悠然身世見山時。", "强名真意元無物，緣底忘言更有詩。", "宇宙襟懷千斛酒，王侯勳業一枰棋。", "古來大隠在朝市，可待休官辦菊籬。"]'),
('12fe53c2-e534-40fe-b30e-8f47ef9cb844','題張長卿竹梅用蘇黄各二句','方回','宋','宋诗','song-poetry','','["\u897f\u6e56"]','西湖處士骨應槁，不復龍蛇看揮掃。',32,'全唐诗/poet.song.232000.json','["西湖處士骨應槁，不復龍蛇看揮掃。", "是誰招此斷腸魂，竹外一枝斜更好。"]'),
('377d9617-1f80-49d0-82c7-583fc441bd80','六月二十九夜','方回','宋','宋诗','song-poetry','','[]','小閣微凉上，閒人半醉中。',48,'全唐诗/poet.song.232000.json','["小閣微凉上，閒人半醉中。", "雙明螢度水，一向柳拖風。", "委曲聊隨俗，艱難敢諱窮。", "香山吾不逮，猶勝杜陵翁。"]'),
('e07d066b-786f-47d4-83a1-e30ddbc1c812','七月初一日早起','方回','宋','宋诗','song-poetry','','[]','太白星初上，參旗井鉞連。',48,'全唐诗/poet.song.232000.json','["太白星初上，參旗井鉞連。", "新秋知幾日，酷暑極今年。", "足不能離地，心常欲契天。", "水鄉差得稔，亢旱念山田。"]'),
('7c9196a2-2548-495d-b604-a55bd273a897','樓夜','方回','宋','宋诗','song-poetry','','[]','危欄空闊上，牛斗轉天心。',48,'全唐诗/poet.song.232000.json','["危欄空闊上，牛斗轉天心。", "爲底常無寐，頻來故獨臨。", "船聲終夜靜，樓影半河陰。", "詩就忘工拙，隨宜莫苦吟。"]'),
('81707899-7e75-4a41-ab20-f72000f68820','呈趙左丞','方回','宋','宋诗','song-poetry','','[]','邇年士夫乏廉稱，或以廉稱不稱能。',208,'全唐诗/poet.song.232000.json','["邇年士夫乏廉稱，或以廉稱不稱能。", "兼廉且能毅且弘，嗟我有眼見未曾。", "君侯妙年翔鯤鵬，橫擊海宇無與朋。", "孝事其親行有恒，移忠於君德日昇。", "胸中朗徹水月澄，筆端變化雲霧蒸。", "惠者懷之威者懲，內作心膂外股肱。", "浙右艱食何頻仍，六年三潦歲不登。", "勸分之意極哀矜，坐使粒價不敢騰。", "餒腹再果僵復興，今秋大稔稻沒塍。", "長吏於民無弋矰，如寒與裘暑與冰。", "老夫昔也霜後鷹，即今僅似癡凍蠅。", "一紀不仕閒如僧，少陵日困糴五升。", "猶此客窗吟孤燈，往哉一見賢左丞。"]'),
('3c0937a4-e71b-41c2-a6c8-23ed1cb7b87d','觀喪事','方回','宋','宋诗','song-poetry','','[]','悠悠誰到百年身，百萬杭民一聚薪。',32,'全唐诗/poet.song.232000.json','["悠悠誰到百年身，百萬杭民一聚薪。", "棺內棺前爭幾許，挽郎自是白鬚人。"]'),
('be971f1d-221a-4d3b-9b69-3e1446ea4a69','中秋雨','方回','宋','宋诗','song-poetry','','[]','瘴癘干戈脫此生，一隅略見舊承平。',32,'全唐诗/poet.song.232000.json','["瘴癘干戈脫此生，一隅略見舊承平。", "上元燈火中秋月，但苦人心不肯晴。"]'),
('ee84fe8b-2e91-4d8e-9a5d-408bec9c4adc','代次韻聞砧','方回','宋','宋诗','song-poetry','','[]','誰家秋夜搗衣聲，遥憶良人在戍營。',64,'全唐诗/poet.song.232000.json','["誰家秋夜搗衣聲，遥憶良人在戍營。", "野宿貔貅天一角，樹移烏鵲月三更。", "怨懷想像閨中切，逸韻悠揚枕上清。", "砧杵催成歲遲暮，撫時亦覺壯心驚。"]'),
('32f65244-2da2-428f-9c9f-d8376d4c17db','送臨安洪行之次鮮于伯幾韻','方回','宋','宋诗','song-poetry','','[]','丈夫志四方，出戶無萬里。',132,'全唐诗/poet.song.232000.json','["丈夫志四方，出戶無萬里。", "焉能縮如蝸，鬰鬰久居此。", "于思今子駿，落筆甫友美。", "衮褒一字難，何獨賞之子。", "勿謂貌甚尫，力可拔象齒。", "隘哉招海柳，詎識子路喜。", "橄欖政復苦，異彼道傍李。", "豈其諫塗開，可口不見紀。", "峨峨黄金臺，梯飈凌太紫。", "大川楫方舟，明堂棟文梓。", "新豐馬周足，斗酒可以洗。"]'),
('4dc9780c-2983-4e13-9131-2383fbc78b21','八月二十九日雨霽玩古蘭','方回','宋','宋诗','song-poetry','','[]','積雨不可出，五日無鹽醯。',108,'全唐诗/poet.song.232000.json','["積雨不可出，五日無鹽醯。", "縱復有雨具，出門將告誰。", "茲辰復何辰，明窗漏晴曦。", "我有古猗蘭，瓦斛以蒔之。", "舉世無識者，惟有秋蝶知。", "紫穗密匼匝，雪茸紛葳蕤。", "國香襲衣袖，堅坐神自怡。", "微詠韓子操，長歌湘纍詞。", "空庖不遑省，聊足忘調饑。"]'),
('63349d35-4403-4875-a4c8-c264e5118a5a','九月初四日大風雨近重陽無酒夜成二首  其一','方回','宋','宋诗','song-poetry','','[]','怕見秋深秋又深，青燈白髪厭愁霖。',64,'全唐诗/poet.song.232000.json','["怕見秋深秋又深，青燈白髪厭愁霖。", "百年剩幾重陽日，萬事都無一稱心。", "自揣老懷饒感慨，可須佳節强登臨。", "在陳自鄶哦韓句，敢望空罍有濁斟。"]'),
('cabf59bf-465a-41ba-b3f6-1413cc0b180d','九月初四日大風雨近重陽無酒夜成二首  其二','方回','宋','宋诗','song-poetry','','[]','秋霖欲洗庾公塵，不管樓頭客恨新。',64,'全唐诗/poet.song.232000.json','["秋霖欲洗庾公塵，不管樓頭客恨新。", "塞雁又爲江左客，菊花曾識晉時人。", "百年虛谷先生老，一紀嚴州太守貧。", "幾向客中度重九，苦無佳句答良辰。"]'),
('511599e3-2a5a-4938-b44b-a32dd393960b','猗蘭秋思三首  其一','方回','宋','宋诗','song-poetry','','[]','猗蘭奕葉曉疏晴，栩栩秋光小蝶輕。',32,'全唐诗/poet.song.232000.json','["猗蘭奕葉曉疏晴，栩栩秋光小蝶輕。", "皂翅綉花三五點，庾郎無句畫難成。"]'),
('d8e533d9-f227-437a-8e5a-408ed20ee47c','猗蘭秋思三首  其二','方回','宋','宋诗','song-poetry','','[]','綠葉枝頭紫粟叢，素花抽雪細茸茸。',32,'全唐诗/poet.song.232000.json','["綠葉枝頭紫粟叢，素花抽雪細茸茸。", "國香政要枯如臘，旋買離騷置冊中。"]'),
('b12dcd2b-e333-4383-a49c-dac87b39ace6','猗蘭秋思三首  其三','方回','宋','宋诗','song-poetry','','[]','老子今年忽不貧，價方玉佩有蘭紉。',32,'全唐诗/poet.song.232000.json','["老子今年忽不貧，價方玉佩有蘭紉。", "一枝半朵懸衣带，肯羨腰間大羽人。"]'),
('92111ebb-8de0-4072-9b38-3daabd20fbd7','晚晴','方回','宋','宋诗','song-poetry','','[]','油泥方滑道，返照隔樓明。',48,'全唐诗/poet.song.232000.json','["油泥方滑道，返照隔樓明。", "年已如秋老，心猶愛晚晴。", "鼓刀寧異遇，带索定徒行。", "倚遍闌干夜，寒砧處處聲。"]'),
('2a425cdb-19d5-4140-b36a-74feae31aa32','九日汪元卿送酒亦有相拉者以病嗽不出','方回','宋','宋诗','song-poetry','','[]','紫蘭黄菊園丁送，亦有鄰翁送酒來。',64,'全唐诗/poet.song.232000.json','["紫蘭黄菊園丁送，亦有鄰翁送酒來。", "何忽於斯須煮藥，不然夫豈怯銜盃。", "登高朋友空相覓，抱病情懷未易開。", "過了重陽更堪醉，霜天螃蟹小春梅。"]'),
('7604d789-308f-4485-b444-ad24af92d72e','九月十二日得蟹小酌','方回','宋','宋诗','song-poetry','','[]','莫欺虛谷太凄凉，短髪頻搔意自長。',64,'全唐诗/poet.song.232000.json','["莫欺虛谷太凄凉，短髪頻搔意自長。", "萬古江山宜晚景，一番宇宙更秋光。", "東籬把菊非塵世，左手持螯可醉鄉。", "二物於吾猶莫逆，達人何日不重陽。"]'),
('7b5f0bb4-1a54-47b4-94ec-9dab0ded49ba','贈相士王秀溪','方回','宋','宋诗','song-poetry','','[]','不惜佳人國爲傾，髑髏頭蓋野狐精。',32,'全唐诗/poet.song.232000.json','["不惜佳人國爲傾，髑髏頭蓋野狐精。", "丈夫更有何郎粉，老眼須君業鏡明。"]'),
('735ac239-ff2b-4b58-a369-8de998054baf','松江使君張周卿致泖口蟹四十輩','方回','宋','宋诗','song-poetry','','[]','松江太守今賢侯，喜有螃蟹無監州。',236,'全唐诗/poet.song.232000.json','["松江太守今賢侯，喜有螃蟹無監州。", "左手持螯右杯酒，文章政事第一流。", "吳田今年十分秋，各執稻穗朝厥酋。", "初生瑣細類蟛𧑅，既長魁巨肩蝤蛑。", "漁父橫江竹爲斷，照夜紛紜燈火亂。", "取之一蟹勝一蟹，尖美於團十月半。", "怒目橫行敢抗虎，宜爾就擒墮烹爨。", "黄堂不忍專俊味，遣餉不減錦繡段。", "老夫菜腸久雷鳴，忽四十輩來崢嶸。", "得公宰相三斗鼻吸之醋，剉我坡仙一年好景之橙。", "金臍雪脆手自擘，何必牛炙兼羊羹。", "饞拏涎攫快一醉，焉待將糖而彌躁，带糟而微生。", "一詩往謝張夫子，莫怪無厭猶未已。", "內黄侯承津致矣，但欠青州從事耳。"]'),
('ecdb1a1f-89ce-4945-a45f-43e7b8439e8d','次張鵬飛解官舊韻','方回','宋','宋诗','song-poetry','','[]','聚斂臣應愧直臣，暫閒身似勝官身。',64,'全唐诗/poet.song.232000.json','["聚斂臣應愧直臣，暫閒身似勝官身。", "險夷異路良難測，進退忘懷直任真。", "萬國山河封域廣，九天日月照臨新。", "烏臺鳳沼登耆舊，屈指如公幾正人。"]'),
('01ef5a2e-1fd6-4763-9f53-49ed87d20d11','平心胡祕監誕日','方回','宋','宋诗','song-poetry','','[]','五朝遺老四專城，年號凡經十四更。',64,'全唐诗/poet.song.232000.json','["五朝遺老四專城，年號凡經十四更。", "八袠即今踰少壯，七人從昔冠耆英。", "凍窗映雪能堅坐，泥屐看山只步行。", "清健如公天下少，平心心事十分平。"]'),
('d326164e-6702-4127-ae68-352142c08af5','次韻張中白元日','方回','宋','宋诗','song-poetry','','[]','瓣香清曉肅冠紳，戶外遥山展翠顰。',64,'全唐诗/poet.song.232000.json','["瓣香清曉肅冠紳，戶外遥山展翠顰。", "瘦影自憐耽醉叟，歡聲何限喜晴人。", "怱怱節序梅花老，衮衮塵埃世事新。", "自有天來至今日，不知芳草幾番春。"]'),
('352090e4-28f8-46fa-9700-d57d3db69641','正月初三日水西寺','方回','宋','宋诗','song-poetry','','[]','不到水西久，十年懷夢思。',48,'全唐诗/poet.song.232000.json','["不到水西久，十年懷夢思。", "重行兵後路，暗覓壁間詩。", "僧出房俱鐍，人遊榼自隨。", "隔溪望城郭，未覺似春時。"]'),
('06a1adbb-7443-47e3-8086-1cb24bd68191','次韻方去言用予喜歸韻見寄三首  其一','方回','宋','宋诗','song-poetry','','[]','秋高親見老崖來，險阻嶔崎付一杯。',64,'全唐诗/poet.song.232000.json','["秋高親見老崖來，險阻嶔崎付一杯。", "萬古懸知名不夜，九泉誰免骨爲灰。", "輕鷗熟與風波狎，勁柏寧資糞壤栽。", "却笑諸兒浪生死，大都暮落枉朝開。"]'),
('5947470e-fbab-447d-aa96-3d919f187f9a','次韻方去言用予喜歸韻見寄三首  其二','方回','宋','宋诗','song-poetry','','[]','筆法君追寶晉齋，禪機我愧老蒲鞋。',64,'全唐诗/poet.song.232000.json','["筆法君追寶晉齋，禪機我愧老蒲鞋。", "嘗僚臺閫相知舊，得友江山到處佳。", "鐵馬塵高頻極目，錦鱗音斷豈忘懷。", "亦思竹底陪溪逸，人品終疑未易儕。"]'),
('c0a6e282-5eb8-4ba9-900a-5df38f974e3e','次韻方去言用予喜歸韻見寄三首  其三','方回','宋','宋诗','song-poetry','','[]','野鳥呼風金粟堆，曲江宮殿委荒苔。',64,'全唐诗/poet.song.232000.json','["野鳥呼風金粟堆，曲江宮殿委荒苔。", "是非誰辦筆褒貶，鴻燕屢驚春去來。", "偃月人今姦骨朽，浣花翁未醉眉開。", "吟君詩罷登山崦，立盡斜陽尚懶迴。"]'),
('593c9f76-5d04-4e73-a9e4-f99d181ba150','慶陸仁重舉男四首  其一','方回','宋','宋诗','song-poetry','','[]','治郡年才半買臣，青春天上送麒麟。',32,'全唐诗/poet.song.232000.json','["治郡年才半買臣，青春天上送麒麟。", "鼎來好事由陰德，曾活澄江十萬人。"]'),
('e8e198d0-774b-49c6-99db-6b759952ea49','慶陸仁重舉男四首  其二','方回','宋','宋诗','song-poetry','','[]','相門佳氣夜葱葱，早已憑熊更夢熊。',32,'全唐诗/poet.song.232000.json','["相門佳氣夜葱葱，早已憑熊更夢熊。", "二十此郎作文賦，乃翁仍是黑頭公。"]'),
('4a9bd572-9e76-45be-8b06-db700c39124d','慶陸仁重舉男四首  其三','方回','宋','宋诗','song-poetry','','[]','昇平重見上元天，簫鼓聲中璧月圓。',32,'全唐诗/poet.song.232000.json','["昇平重見上元天，簫鼓聲中璧月圓。", "惟有高門更多喜，金盤分送洗兒錢。"]'),
('b9a4c28e-74a6-4846-a682-7ad403435c7b','慶陸仁重舉男四首  其四','方回','宋','宋诗','song-poetry','','[]','積善懸知慶有餘，芝蘭衮衮秀階除。',32,'全唐诗/poet.song.232000.json','["積善懸知慶有餘，芝蘭衮衮秀階除。", "紫陽一滴泉源遠，早聘名儒授四書。"]'),
('88ad9662-5681-44f2-8dce-9c240f6b0fa1','贈相士戚淳祖','方回','宋','宋诗','song-poetry','','[]','朝匹吳君暮越臣，一顰何用訾東鄰。',32,'全唐诗/poet.song.232000.json','["朝匹吳君暮越臣，一顰何用訾東鄰。", "阿承醜女五噫婦，似勝苧蘿山下人。"]'),
('1a85c9c2-5eeb-4791-b56e-9525007dcb2d','題前歙令楚君雪梅圖','方回','宋','宋诗','song-poetry','','[]','洛雪一丈凍獨鼾，誰其排闥驚袁安。',64,'全唐诗/poet.song.232000.json','["洛雪一丈凍獨鼾，誰其排闥驚袁安。", "千載神交兩賢令，寄意愛此英姿寒。", "馬縮龍埋萬木折，胸次陽和骨立鐵。", "紈袴兒曹東風花，不耐春寒能耐雪。"]'),
('46b6624a-1df7-48fa-95cf-42f54066c9c6','春寒','方回','宋','宋诗','song-poetry','','[]','燈節蕭條雷後雪，花天料峭雨餘霜。',32,'全唐诗/poet.song.232000.json','["燈節蕭條雷後雪，花天料峭雨餘霜。", "經旬不出無情緒，恰見鵝兒似酒黄。"]'),
('9b88a665-f0b7-41a5-a17b-f57b31e815da','新晴','方回','宋','宋诗','song-poetry','','[]','女伴新晴喜曬衣，老人閒步覽春暉。',32,'全唐诗/poet.song.232000.json','["女伴新晴喜曬衣，老人閒步覽春暉。", "隔籬一樹桃花發，初見今年粉蝶飛。"]'),
('7625238b-8e24-477f-b4e8-e435ae7cf4eb','贈相士雷月篷','方回','宋','宋诗','song-poetry','','[]','肯着雙瞳子，來看一禿翁。',48,'全唐诗/poet.song.232000.json','["肯着雙瞳子，來看一禿翁。", "短篷君載月，孤屋我吟風。", "籛耳終遺骨，松喬竟落空。", "癡人喜甜舌，誰悟大槐宮。"]'),
('42f33552-8c01-4aca-ab52-fd3818037587','春寒紀異','方回','宋','宋诗','song-poetry','','[]','今年一何異，人日苦連雨。',288,'全唐诗/poet.song.232000.json','["今年一何異，人日苦連雨。", "甲子復不晴，吾密識諸簿。", "燒燈前一夕，轟然震雷鼓。", "醉卧初未聞，遄駭雪霰舞。", "乍暄汗膚爛，倏凍尪脊僂。", "造物謔百昌，摩手遽斫斧。", "侵尋二月初，野桃半吞吐。", "嚴霜甚臘天，挫使顔色沮。", "日昏盪黑子，天暗墮黄土。", "占讖或未習，災眚亦可覩。", "有客言近縣，癘鬼肆虐侮。", "槌撞體肢軟，骾棘喉咽楚。", "一家朝團欒，暮輒踣四五。", "上丁祭孔廟，儒冠列如堵。", "鼻壅背肩縮，咯唾滿廊廡。", "閒居乏薪炭，畏風緊扃戶。", "病輕勿輅醫，芎芷自煎煮。", "橫縱亂方書，疊重着褐裋。", "向來佳氣和，藜杖涉園渚。", "掃涸詗新泉，搜枯攬幽莽。", "融澌跳鮒鯈，潤壤泄蛙鼁。", "謂即挈蠻榼，所至品村酤。", "此意未獲騁，叉戟已見拒。", "遥遥鶑花饒，惴惴蠶麥腐。"]'),
('2dce7c59-1528-4eec-9dbb-c025df095540','夜聞訓狐','方回','宋','宋诗','song-poetry','','[]','十載離鄉邑，言歸理舊鋤。',48,'全唐诗/poet.song.232000.json','["十載離鄉邑，言歸理舊鋤。", "僅憐空宅在，半駭近鄰無。", "古廟叢枯木，寒宵吠訓狐。", "兵餘有乖氣，春色亦荒蕪。"]'),
('5f75ff78-d6b0-451a-b7ad-ee0d510ada3b','行園僧約同飲','方回','宋','宋诗','song-poetry','','[]','晴向小園窺，今朝忽有詩。',48,'全唐诗/poet.song.232000.json','["晴向小園窺，今朝忽有詩。", "乳鵝殽菜葉，躍鵲顫花枝。", "春氣寒終暖，愁人老更衰。", "醉僧約同飲，徇俗未容辭。"]'),
('cac4d25a-573e-4152-825e-8f9b6ee707f7','櫻桃花','方回','宋','宋诗','song-poetry','','[]','淺淺花開料峭風，苦無妖色畫難工。',32,'全唐诗/poet.song.232000.json','["淺淺花開料峭風，苦無妖色畫難工。", "十分不肯精神露，留與他時著子紅。"]'),
('9a2a6e76-ae70-494a-bf60-35eb4de79e10','海棠花','方回','宋','宋诗','song-poetry','','[]','錦城春色萬人迷，飯顆無心著品題。',32,'全唐诗/poet.song.232000.json','["錦城春色萬人迷，飯顆無心著品題。", "實不如華謾穠艷，秋霜誰覷海棠梨。"]'),
('c162907a-a160-49ae-b072-b0570adfd7c2','薺菜花','方回','宋','宋诗','song-poetry','','[]','鬬草吳王眩越娃，終然輸與老陶家。',32,'全唐诗/poet.song.232000.json','["鬬草吳王眩越娃，終然輸與老陶家。", "雪挑霜煮春無盡，不似吾園薺菜花。"]'),
('881f530d-76ce-4cc9-832a-570c85ddd414','青菜花','方回','宋','宋诗','song-poetry','','[]','只供寒士飽詩腸，不伴佳人上繡床。',32,'全唐诗/poet.song.232000.json','["只供寒士飽詩腸，不伴佳人上繡床。", "黄蝶似花花似蝶，柴門春盡滿田香。"]'),
('f94523e7-5882-44bf-b64b-0f78ac10b822','早桃花','方回','宋','宋诗','song-poetry','','[]','劉郎異種出天台，雪裏夭夭解早開。',32,'全唐诗/poet.song.232000.json','["劉郎異種出天台，雪裏夭夭解早開。", "鄰舍覓花聊折送，祇應遥認是紅梅。"]'),
('4184adbc-fed7-4c94-96af-e6ab74205058','千葉桃花','方回','宋','宋诗','song-poetry','','[]','此亦桃花彼亦桃，成蹊各各綻春苞。',32,'全唐诗/poet.song.232000.json','["此亦桃花彼亦桃，成蹊各各綻春苞。", "一朝開出紅千葉，何啻高才十倍曹。"]'),
('b1a5de6e-99ba-4e79-b5ba-57cc597c4272','二色桃花','方回','宋','宋诗','song-poetry','','[]','阮郎溪上醉腮融，驀忽深紅又淺紅。',32,'全唐诗/poet.song.232000.json','["阮郎溪上醉腮融，驀忽深紅又淺紅。", "料得金閨描繡樣，一花成換幾針茸。"]'),
('0413d80e-d9e8-4bc8-8d94-1df5422bb6bc','碧桃花','方回','宋','宋诗','song-poetry','','[]','一種玄都舊種花，誰將縞雪換蒸霞。',32,'全唐诗/poet.song.232000.json','["一種玄都舊種花，誰將縞雪換蒸霞。", "羣仙醉啖瑶池果，况核曾封白玉砂。"]'),
('5ea6442d-e288-4817-8946-4d242311b3b8','李花','方回','宋','宋诗','song-poetry','','[]','仙根判耦得無差，春對夭桃夏對瓜。',32,'全唐诗/poet.song.232000.json','["仙根判耦得無差，春對夭桃夏對瓜。", "此豈輕浮閒果子，白花亦復勝紅花。"]'),
('1982620d-c846-4b18-9adc-963347b26989','梨花','方回','宋','宋诗','song-poetry','','[]','仙姿白雪帔青霞，月淡春濃意不邪。',32,'全唐诗/poet.song.232000.json','["仙姿白雪帔青霞，月淡春濃意不邪。", "天上嫦娥人未識，料應清雅似梨花。"]'),
('b6daa5bf-99e4-4d81-866d-a453bf997f00','雪條花','方回','宋','宋诗','song-poetry','','[]','槁若叢蓍未見妍，一條條雪半春天。',32,'全唐诗/poet.song.232000.json','["槁若叢蓍未見妍，一條條雪半春天。", "醉鞍把玩歸來晚，蒲市人驚玉馬鞭。"]'),
('f47cd8cd-641e-42c8-8ca1-f19cdae81051','紫荆花','方回','宋','宋诗','song-poetry','','[]','疏枝堅瘦骨爲皮，忽迸紅英簇紫蕤。',32,'全唐诗/poet.song.232000.json','["疏枝堅瘦骨爲皮，忽迸紅英簇紫蕤。", "嬌女乍看齒生液，分明茜糝綴餳枝。"]'),
('48a59ebb-7c66-402f-a971-76fe98e65632','山茶花','方回','宋','宋诗','song-poetry','','[]','石楠巖桂萬年枝，方駕分花占四時。',32,'全唐诗/poet.song.232000.json','["石楠巖桂萬年枝，方駕分花占四時。", "犀甲鶴頭傲霜雪，入春猶見歲寒姿。"]'),
('5438a1ef-ed6f-4106-ad27-3341ce89939d','月月紅花','方回','宋','宋诗','song-poetry','','[]','十二循環換律筒，芳葩長是笑春風。',32,'全唐诗/poet.song.232000.json','["十二循環換律筒，芳葩長是笑春風。", "山家不識堯蓂莢，日歷聊憑月月紅。"]'),
('5389e517-865f-4210-84d4-e396d994745f','楊花','方回','宋','宋诗','song-poetry','','["\u897f\u6e56"]','燕忙鶑懶聽芳詞，憶醉西湖畫舫時。',32,'全唐诗/poet.song.232000.json','["燕忙鶑懶聽芳詞，憶醉西湖畫舫時。", "山墅不知春早晚，隔牆數點墮書帷。"]'),
('bcdfbc94-48c5-4d2c-b396-29c6a16d0316','桐花','方回','宋','宋诗','song-poetry','','[]','悵惜年光怨子規，王孫見事一何遲。',32,'全唐诗/poet.song.232000.json','["悵惜年光怨子規，王孫見事一何遲。", "等閒春過三分二，憑仗桐花報與知。"]'),
('0ee36963-88dd-47f8-9b23-6dfd5693daa8','蘭花','方回','宋','宋诗','song-poetry','','[]','雪盡深林出異芬，枯松槁槲亂紛紛。',32,'全唐诗/poet.song.232000.json','["雪盡深林出異芬，枯松槁槲亂紛紛。", "此中恐是蘭花處，未許行人著意聞。"]'),
('7100939c-42ae-4a81-a1b1-71ecf7e5ae29','蕙花','方回','宋','宋诗','song-poetry','','[]','藥辨君臣醫或誤，花旌王后俗徒奢。',32,'全唐诗/poet.song.232000.json','["藥辨君臣醫或誤，花旌王后俗徒奢。", "早蘭晚蕙真兄弟，我與二難分等差。"]'),
('1712782e-1dea-41dc-a2f8-65e7388831f2','黄薔薇花','方回','宋','宋诗','song-poetry','','[]','春工借露染鶑裳，欲學東籬一樣黄。',32,'全唐诗/poet.song.232000.json','["春工借露染鶑裳，欲學東籬一樣黄。", "輸與菊花在何處，止禁晴暖不禁霜。"]'),
('ff09b5aa-80ae-4d1f-8980-a72e678fe0b5','紅薔薇花','方回','宋','宋诗','song-poetry','','[]','月桂金沙各鬬春，薔薇紅透更精神。',32,'全唐诗/poet.song.232000.json','["月桂金沙各鬬春，薔薇紅透更精神。", "雖然面似佳人笑，滿體鋒鋩解刺人。"]'),
('e94a40ce-1038-43f5-8299-6c02707642cf','酴醿花','方回','宋','宋诗','song-poetry','','[]','未用爐薰燃篤耨，何須粉面佐娉婷。',32,'全唐诗/poet.song.232000.json','["未用爐薰燃篤耨，何須粉面佐娉婷。", "通宵痛飲此花下，露滴杯中酒更醒。"]'),
('d3913347-e52d-4015-9fe2-d6a6f75fe632','木香花','方回','宋','宋诗','song-poetry','','[]','海南藥物木香重，何似𩰀鬆高架花。',32,'全唐诗/poet.song.232000.json','["海南藥物木香重，何似𩰀鬆高架花。", "春晚日長香滿院，天教富貴屬詩家。"]'),
('e8f630fa-d519-4001-b2bf-18c5e79cd801','衮繡毬花','方回','宋','宋诗','song-poetry','','[]','舞姬初試薄羅衣，趁蝶隨蜂玩午暉。',32,'全唐诗/poet.song.232000.json','["舞姬初試薄羅衣，趁蝶隨蜂玩午暉。", "各折一枝入深院，歡聲贏得繡毬歸。"]'),
('2e1d52a1-28f4-48c9-8ec5-5dc4216fa430','芍藥花','方回','宋','宋诗','song-poetry','','[]','眼中不復見姚黄，從古揚州亞洛陽。',32,'全唐诗/poet.song.232000.json','["眼中不復見姚黄，從古揚州亞洛陽。", "何止中郎虎賁似，政堪花相相花王。"]'),
('a482131f-be47-42c1-9363-4db4c2fd690a','修石山','方回','宋','宋诗','song-poetry','','[]','土山未甚正，有石亦頗欹。',264,'全唐诗/poet.song.232000.json','["土山未甚正，有石亦頗欹。", "方矩一再度，夙具鍤與箕。", "晨興命工徒，將一大治之。", "掃礫斫枯枿，擁泥護芳荑。", "春雷已驚蟄，猶以寒自疑。", "蚯蚓縮未動，蝦𢋙僵如癡。", "此役彼不安，慈憫其忍爲。", "復有蜈蚣蝎，壤發難迅馳。", "僕夫聽使去，梃杵肯遽施。", "至所謂蛇者，衆怒爭剪夷。", "赤練稍宛轉，碎首忽若糜。", "人跡不至處，擲出園外籬。", "天地主生育，乳孕無窮期。", "何土草不茂，何水魚不滋。", "毒堇及淫蜮，賦物曷至茲。", "崢嶸不能畝，蝸蟻千萬斯。", "凶惡如此輩，均受亭毒私。", "理有不可曉，顔跖同世時。", "閒居理花藥，娛心聊自怡。", "小小事興作，蟲豸關安危。", "何况大騷動，瘡痏良可知。", "誅惡亦一快，感慨因成詩。"]'),
('f9b3da32-713d-46ed-af09-3019a9b4a8bd','所聞','方回','宋','宋诗','song-poetry','','[]','荷鍤除園棘，鄰翁誦所聞。',48,'全唐诗/poet.song.232000.json','["荷鍤除園棘，鄰翁誦所聞。", "花開爭共折，草長竟誰耘。", "薪赭近郊樹，畬燒無主墳。", "問言何至此，軍馬日紛紛。"]'),
('497e565c-b90b-47d2-a757-efd1d9ce9b16','治圃雜書二十首  其一','方回','宋','宋诗','song-poetry','','[]','天地一閒人，園林數畝春。',48,'全唐诗/poet.song.232000.json','["天地一閒人，園林數畝春。", "認苗諳藥性，養果護花身。", "社友同疏飯，鄰兒笑野巾。", "空庭維老馬，不出動經旬。"]'),
('e4d79795-c068-49f6-ac43-8bc2012ac34f','治圃雜書二十首  其二','方回','宋','宋诗','song-poetry','','[]','汲水洗青石，寘之盛酒樽。',48,'全唐诗/poet.song.232000.json','["汲水洗青石，寘之盛酒樽。", "身閒宜獨坐，手冷喜時捫。", "曉露黏花片，春苔蝕浪痕。", "從吾已安穩，不復動雲根。"]'),
('9a1b862a-23a7-4e2e-83b8-f9a19049539f','治圃雜書二十首  其三','方回','宋','宋诗','song-poetry','','[]','閉戶全無事，窺園頗自由。',48,'全唐诗/poet.song.232000.json','["閉戶全無事，窺園頗自由。", "不堪箝紙尾，乍可把鋤頭。", "避樹斜開徑，邀泉曲放溝。", "吾心元自直，兒輩勿相尤。"]'),
('c801c2b1-e6f9-4ab8-8d39-b5d65c3deeeb','治圃雜書二十首  其四','方回','宋','宋诗','song-poetry','','[]','林間一磐石，壺酒玩春暉。',48,'全唐诗/poet.song.232000.json','["林間一磐石，壺酒玩春暉。", "混沌本無竅，桔橰焉用機。", "亂花紅雪舞，遠岫翠屏圍。", "車馬紛紛者，能知此似稀。"]'),
('d889e911-e063-470f-b676-20d28cab0a95','治圃雜書二十首  其五','方回','宋','宋诗','song-poetry','','[]','燈花昨夜饒，喜事集今朝。',48,'全唐诗/poet.song.232000.json','["燈花昨夜饒，喜事集今朝。", "新立蒲萄架，初嘗枸杞苗。", "天清詩眼豁，春暖酒痰消。", "更復得奇石，數峰昂碧霄。"]'),
('0d87f656-3530-4887-8eae-039ad1f867fa','治圃雜書二十首  其六','方回','宋','宋诗','song-poetry','','[]','胸中書萬卷，老去與誰論。',48,'全唐诗/poet.song.232000.json','["胸中書萬卷，老去與誰論。", "不善謀人國，猶堪灌我園。", "草長門晝掩，鵲下土新翻。", "物理閒推測，天機未易言。"]'),
('4bc27d00-16a5-41e5-aecb-ad7b3ee9fefc','治圃雜書二十首  其七','方回','宋','宋诗','song-poetry','','[]','花有如罌粟，能同橘不遷。',48,'全唐诗/poet.song.232000.json','["花有如罌粟，能同橘不遷。", "茄藤宜硬地，豆莢惡肥田。", "元勰齊民術，夷吾土物篇。", "園丁初未讀，口訣自相傳。"]'),
('dbb2a8d7-ae54-4cc9-ad3e-e22acf8ae51f','治圃雜書二十首  其八','方回','宋','宋诗','song-poetry','','[]','十載前初種，酴醿間木香。',48,'全唐诗/poet.song.232000.json','["十載前初種，酴醿間木香。", "對花猶綠髪，携酒有黄堂。", "忽起風雲陣，幾成鹿豕場。", "少陵憶嚴尹，非復舊春光。"]'),
('669cbb0c-ec81-4099-8b38-780c0fa7f72b','治圃雜書二十首  其九','方回','宋','宋诗','song-poetry','','[]','萬山山頂郡，城郭欠陂池。',48,'全唐诗/poet.song.232000.json','["萬山山頂郡，城郭欠陂池。", "灘落動千丈，井深非一施。", "養魚埋巨甕，澆菜緝脩縻。", "蹇淺仍辛苦，逍遥意自知。"]'),
('1fdcb963-7032-44ef-9574-8f45019d39b9','治圃雜書二十首  其一○','方回','宋','宋诗','song-poetry','','[]','新年雨雪頻，五戊又踰旬。',48,'全唐诗/poet.song.232000.json','["新年雨雪頻，五戊又踰旬。", "寒更過於臘，晴猶不似春。", "燕瘖甘再蟄，花瘦黯無神。", "賣樹翁來說，村多疫死人。"]'),
('7a217efd-8443-41c0-95c4-9d14248f27e8','治圃雜書二十首  其一一','方回','宋','宋诗','song-poetry','','[]','今日春纔暖，侵晨董蒔耘。',48,'全唐诗/poet.song.232000.json','["今日春纔暖，侵晨董蒔耘。", "禽聲眠欲覺，花氣夢先聞。", "樹絡蜘蛛縷，泥鎪𦚧䏰紋。", "乾坤無晝夜，生意自芸芸。"]'),
('4feb9532-5c0c-4790-bab5-ca9f85959ea4','治圃雜書二十首  其一二','方回','宋','宋诗','song-poetry','','[]','岑寂觀羣動，舂容領衆香。',48,'全唐诗/poet.song.232000.json','["岑寂觀羣動，舂容領衆香。", "三椽容卧起，一鍤共行藏。", "俗眼榮朝槿，頑軀敵閏楊。", "皮枯面黧黑，心鏡皎如霜。"]'),
('593a0540-6398-4948-8aab-b4b2168b5341','治圃雜書二十首  其一三','方回','宋','宋诗','song-poetry','','[]','真山焉用假，山假意還真。',48,'全唐诗/poet.song.232000.json','["真山焉用假，山假意還真。", "巨石起奇士，幽蘭延故人。", "雲生如望嶽，地僻不爭春。", "圖畫傳京洛，應多欲問津。"]'),
('664a61f6-9edf-4ac6-87a3-2855b3694f60','治圃雜書二十首  其一四','方回','宋','宋诗','song-poetry','','[]','山甑饙秈米，春瓶炙草茶。',48,'全唐诗/poet.song.232000.json','["山甑饙秈米，春瓶炙草茶。", "無能賡喜起，自愛押車斜。", "老不貪仙藥，貧猶種好花。", "人間十萬戶，難得一詩家。"]'),
('2b251a7c-7217-488f-96fe-79d5061979cf','治圃雜書二十首  其一五','方回','宋','宋诗','song-poetry','','[]','猿鶴閒朋友，知予近况無。',48,'全唐诗/poet.song.232000.json','["猿鶴閒朋友，知予近况無。", "春遊靴露指，夜讀燭燃鬚。", "醉苦鄰僧强，饑從小僕逋。", "山農來賣笋，與米當青蚨。"]'),
('5a9aab33-6f9d-4835-8d19-21d98c46d01e','治圃雜書二十首  其一六','方回','宋','宋诗','song-poetry','','[]','破袖通閑手，危欄寄遠心。',48,'全唐诗/poet.song.232000.json','["破袖通閑手，危欄寄遠心。", "品花嚴位置，枚笋遴監臨。", "鼎鼐生無望，戈鋋老不任。", "唯應宰斯谷，歲歲長清陰。"]'),
('57dfead0-3ba5-4518-a72b-ca760aeeb4d1','治圃雜書二十首  其一七','方回','宋','宋诗','song-poetry','','[]','徑捷人蹤雜，牆頹地界斜。',48,'全唐诗/poet.song.232000.json','["徑捷人蹤雜，牆頹地界斜。", "織籬呼野老，烹茗諭鄰家。", "舊穴通羊豕，新畦隔芋瓜。", "尚當分汝果，幸勿竊予花。"]'),
('dcb462d7-36d3-455e-8508-17a32bb877be','治圃雜書二十首  其一八','方回','宋','宋诗','song-poetry','','[]','遠石疑堪取，層崖試共登。',48,'全唐诗/poet.song.232000.json','["遠石疑堪取，層崖試共登。", "偶遊梵王舍，略話祖師燈。", "怪象撐獰盼，殘碑搨壞稜。", "世間何不有，巢賊亦齋僧。"]'),
('16f63745-5be0-4420-bcb5-9a2f8d6c354c','治圃雜書二十首  其一九','方回','宋','宋诗','song-poetry','','[]','芍藥抽紅銳，荼䕷縋綠長。',48,'全唐诗/poet.song.232000.json','["芍藥抽紅銳，荼䕷縋綠長。", "幾家蠶落紙，比屋燕分梁。", "穀雨深春近，茶煙永日香。", "詩成懶磨墨，拄杖畫苔牆。"]'),
('895e9e13-f812-4d4b-a954-1bc524d1556c','治圃雜書二十首  其二○','方回','宋','宋诗','song-poetry','','[]','圃事亦兒嬉，因成二十詩。',48,'全唐诗/poet.song.232000.json','["圃事亦兒嬉，因成二十詩。", "似蒙神物助，堪作畫圖披。", "南面開書閣，東偏浚墨池。", "土功恐難極，莫可且隨宜。"]'),
('8cefb33b-82ab-4c86-a065-1459e49f4f0e','用韻送唐師善歸九仙二首  其一','方回','宋','宋诗','song-poetry','','[]','杞菊先生誤作州，歸來誰復與同遊。',64,'全唐诗/poet.song.232000.json','["杞菊先生誤作州，歸來誰復與同遊。", "蓑衣正可眠牛背，肉食終非相虎頭。", "欲起黄陳分宇宙，能穿草樹憩深幽。", "相看不用多言說，須向拈花笑處求。"]'),
('4c72cd59-506d-499e-ba36-a1b2626a5b39','用韻送唐師善歸九仙二首  其二','方回','宋','宋诗','song-poetry','','[]','李長庚願識荆州，馬伏波今愧少遊。',64,'全唐诗/poet.song.232000.json','["李長庚願識荆州，馬伏波今愧少遊。", "古道直能膠鳳觜，官身焉取爛羊頭。", "苦心文字雕奇劂，遁世林巒擅僻幽。", "鶴竹蜂花有家法，唐瓢更向外人求。"]'),
('5c067175-51ba-4944-8deb-37f7d31e5bd4','寄題九仙俞君竹屋','方回','宋','宋诗','song-poetry','','[]','竹繞屋之外，屋中人定賢。',48,'全唐诗/poet.song.232000.json','["竹繞屋之外，屋中人定賢。", "戛風疑有客，攪雨不妨禪。", "勿起青奴想，毋垂玉版涎。", "新梢添秀色，長日照吟編。"]'),
('59bae301-de54-45a3-91a0-cd1042f2f89a','初夏六首  其一','方回','宋','宋诗','song-poetry','','[]','衰懶新詩少，芳菲急景過。',48,'全唐诗/poet.song.232000.json','["衰懶新詩少，芳菲急景過。", "來牟初餠餌，科斗已笙歌。", "獨幸閒扃戶，誰方遠荷戈。", "隔牆落金彈，但避勿誰何。"]'),
('a6eaacdd-9af7-4c30-a069-02a0a291afd2','初夏六首  其二','方回','宋','宋诗','song-poetry','','[]','梅熟枇杷肥，山寒更衲衣。',48,'全唐诗/poet.song.232000.json','["梅熟枇杷肥，山寒更衲衣。", "爨童鋤菜去，饑雀入厨飛。", "湖海歸來晚，親朋亂後稀。", "可容無定力，事事與心違。"]'),
('b6b1de26-70d0-4a32-83af-39ecf603baa2','初夏六首  其三','方回','宋','宋诗','song-poetry','','[]','近午初微暑，侵晨尚薄寒。',48,'全唐诗/poet.song.232000.json','["近午初微暑，侵晨尚薄寒。", "暗窗蠶績響，危棟燕泥乾。", "問價纖絺貴，尋盟舊扇完。", "野人言麥熟，出郭好同看。"]'),
('c07ec92d-5c81-4d37-9862-9b0c1248ccc5','初夏六首  其四','方回','宋','宋诗','song-poetry','','[]','茂密踰千樹，深幽僅一家。',48,'全唐诗/poet.song.232000.json','["茂密踰千樹，深幽僅一家。", "新蟬初蛻殻，穉菊始分椏。", "潤氣青陰石，晴光白濕沙。", "晚凉督園叟，添竹引籬瓜。"]'),
('113c42ed-4f7b-4e55-8395-27c97bd9f5a9','初夏六首  其五','方回','宋','宋诗','song-poetry','','[]','窗皎日穿紙，巾凉風透紗。',48,'全唐诗/poet.song.232000.json','["窗皎日穿紙，巾凉風透紗。", "捕蟲憐鬬雀，蝕果去饞蝸。", "腸滑嫌灰酒，脾虛已未茶。", "暑天仍老境，强飯庶無他。"]'),
('0b8f9d46-dd33-422e-a593-d266479a9b41','初夏六首  其六','方回','宋','宋诗','song-poetry','','[]','霹靂疑天裂，霶𩃱劇海翻。',48,'全唐诗/poet.song.232000.json','["霹靂疑天裂，霶𩃱劇海翻。", "勢來能許怒，事過了無痕。", "朱已泥櫻核，青還茁韭根。", "晚晴聽人說，溪漲近城門。"]'),
('9fd78215-e00a-45b8-a71b-266dc96a6d7f','贈程君以忠楊君泰之  其一','方回','宋','宋诗','song-poetry','','[]','後生可畏古云然，斗大荒城得兩賢。',64,'全唐诗/poet.song.232000.json','["後生可畏古云然，斗大荒城得兩賢。", "句眼端能敲一字，吟腸何啻著千年。", "淡中滋味參須透，聖處工夫語不傳。", "我有長明古燈在，未妨三絕少陵編。"]'),
('724f5ca7-6b72-44c6-a69c-cdd3bbb32f92','贈程君以忠楊君泰之  其二','方回','宋','宋诗','song-poetry','','[]','程君骨骼鼎鐘古，楊子精神霜月明。',64,'全唐诗/poet.song.232000.json','["程君骨骼鼎鐘古，楊子精神霜月明。", "學海一針元自正，詞場百喙不能鳴。", "文潜雄渾開前路，無己深幽助晚成。", "老我苦心知己解，相逢差足慰平生。"]'),
('6abaf203-a723-4469-bc57-ef12a92a9c5e','書歙縣楚明府送行詩軸','方回','宋','宋诗','song-poetry','','[]','俸儘青錢少，衣惟白苧粗。',48,'全唐诗/poet.song.232000.json','["俸儘青錢少，衣惟白苧粗。", "賃樓鄰羽客，買錦護梅圖。", "棋每藏高著，詩曾斷幾鬚。", "生祠誰畫得，清苦一臞儒。"]'),
('3934c22d-fb25-4362-a9cc-04023d6ac939','飲天慶觀即席賦吳體','方回','宋','宋诗','song-poetry','','[]','寂靜日月白雲鄉，漂摇湖海厖眉郎。',64,'全唐诗/poet.song.232000.json','["寂靜日月白雲鄉，漂摇湖海厖眉郎。", "壁間猶見畫龍在，柱表不聞歸鶴翔。", "杯酒新竹與同色，爐熏異花無此香。", "索茗澆渴上馬去，綠樹含雨山蒼凉。"]'),
('d079e3fc-84f8-43fe-be67-d32b68e76cc6','聽客話二首  其一','方回','宋','宋诗','song-poetry','','[]','一叟西郊至，農談半日閒。',48,'全唐诗/poet.song.232000.json','["一叟西郊至，農談半日閒。", "但容身少健，未覺世多艱。", "役倚淘金免，逋期穫麥還。", "苦辛仍節儉，聊得老田閒。"]'),
('10dd39bf-d993-47df-a0c3-35b7701e7c9a','聽客話二首  其二','方回','宋','宋诗','song-poetry','','[]','客言亂時事，可駭不堪聞。',48,'全唐诗/poet.song.232000.json','["客言亂時事，可駭不堪聞。", "田主戕凶佃，民妻掠亂軍。", "草高城裏屋，樹赭壠頭墳。", "降盜多珍賄，人傳大將分。"]'),
('1b0352bb-8278-4b14-9a6b-9252aae80e2b','聞盜發亡男雷孫墓','方回','宋','宋诗','song-poetry','','[]','得非阿瞞黨，忍作發丘郎。',48,'全唐诗/poet.song.232000.json','["得非阿瞞黨，忍作發丘郎。", "誰實驅爲賊，官今視若常。", "故無金椀出，豈有竹書藏。", "風俗衰如此，非徒痛此殤。"]'),
('d134f3df-f04b-41fe-abb5-bc92fd14a604','贈相士蔡槐','方回','宋','宋诗','song-poetry','','[]','腸腹自蟬龜，從渠作廟犧。',48,'全唐诗/poet.song.232000.json','["腸腹自蟬龜，從渠作廟犧。", "詎應身食肉，乃使世攢眉。", "子勿工皮相，吾終欠口醫。", "華亭唳秋鶴，今復幾人思。"]'),
('36902775-896b-4065-a065-91865abf5756','次韻李允道四言','方回','宋','宋诗','song-poetry','','[]','之子酒所，龍蛇揮掃。',40,'全唐诗/poet.song.232000.json','["之子酒所，龍蛇揮掃。", "清風拂硯，明月視稿。", "佳思湧出，傍觀驚倒。", "豈不有學，升之曰造。"]'),
('0c201acc-e419-4068-824c-e09385001381','惜硯中花','方回','宋','宋诗','song-poetry','','[]','花擔移來錦繡叢，小窗瓶水浸春風。',32,'全唐诗/poet.song.232000.json','["花擔移來錦繡叢，小窗瓶水浸春風。", "朝來不忍輕磨墨，落硯香粘數點紅。"]'),
('3ab7e698-10c9-4319-bc4f-c9753f50c5c0','次韻恢大山擬古三首  其一','方回','宋','宋诗','song-poetry','','[]','高不至元愷，下不爲庶頑。',72,'全唐诗/poet.song.232000.json','["高不至元愷，下不爲庶頑。", "木雁有不幸，霧豹藏其斑。", "天衢龍鳳翔，萬一冀附攀。", "未若頌我酒，善閉劉伶關。", "歲寒昆蟲蟄，日暮飛鳥還。", "小侯大者王，焉識商顔山。"]'),
('62500b3d-256c-4b26-b66c-ba61921de2b5','次韻恢大山擬古三首  其二','方回','宋','宋诗','song-poetry','','[]','六用甚鍛鞴，我非金石頑。',72,'全唐诗/poet.song.232000.json','["六用甚鍛鞴，我非金石頑。", "謂古有不死，請看湘筠斑。", "神仙虛空中，黄鵠高難攀。", "月娥本無藥，鬼門焉有關。", "自能節嗜慾，即是丹九還。", "內觀無愧心，所至三神山。"]'),
('a35cc631-2e10-46b9-af3d-5b6d074cec3f','次韻恢大山擬古三首  其三','方回','宋','宋诗','song-poetry','','[]','六度莫先慧，三風尤惡頑。',72,'全唐诗/poet.song.232000.json','["六度莫先慧，三風尤惡頑。", "此心朗如鏡，磨盡青銅斑。", "微利毫髪計，虛名分寸攀。", "朝市多此人，平地劍門關。", "老夫一丘壑，轍迹無往還。", "彼哉峴山泣，况乃泣牛山。"]'),
('73d4d259-10bc-40fd-96af-884ed0e4fecd','再用恢大山韻三首  其一','方回','宋','宋诗','song-poetry','','[]','官罷賓客散，家貧僮僕頑。',72,'全唐诗/poet.song.232000.json','["官罷賓客散，家貧僮僕頑。", "尚有此阿堵，苔錢何斑斑。", "酒從田父飲，果聽鄰人攀。", "四壁夜無盜，焉在門常關。", "浪作送窮文，五鬼驅復還。", "士各行乃志，慎毋賦招山。"]'),
('2f348a1f-5e79-40dd-8a8b-a46f3f4a589e','再用恢大山韻三首  其二','方回','宋','宋诗','song-poetry','','[]','書貴有容德，曰無嫉于頑。',72,'全唐诗/poet.song.232000.json','["書貴有容德，曰無嫉于頑。", "鳳鳴鷙其翰，貍首於菟斑。", "楚楚夸毗子，自謂高難攀。", "焉能凂我哉，冰炭何相關。", "君欲遂勝彼，隻輪俾無還。", "不見古戰場，暴骨堆如山。"]'),
('e9da4e64-b039-4f7b-922a-f08e4cc4ada0','再用恢大山韻三首  其三','方回','宋','宋诗','song-poetry','','[]','往古豈可泥，羣飲懲商頑。',72,'全唐诗/poet.song.232000.json','["往古豈可泥，羣飲懲商頑。", "我有漉酒巾，糟粕常斕斑。", "其在易之需，雲天未渠攀。", "宴樂以俟時，雞鳴當開關。", "醉鄉幸有路，可往不用還。", "何能顧金錢，悠然頹玉山。"]'),
('97a01d07-9576-4b3f-838e-3e4c7ad7ee84','俳體戲書二首  其一','方回','宋','宋诗','song-poetry','','[]','擬訓諸郎業典墳，浪嗔衆富醉紅裙。',64,'全唐诗/poet.song.232000.json','["擬訓諸郎業典墳，浪嗔衆富醉紅裙。", "千金子擁三千客，萬戶侯提百萬軍。", "带索榮公知不羨，飲瓢顔子定無聞。", "淵明肯仰宣明面，早辦棺前自祭文。"]'),
('ae3f0eec-a7a6-41a4-8f6f-ebbc8ae4be54','俳體戲書二首  其二','方回','宋','宋诗','song-poetry','','[]','世變茫茫不可期，珊瑚作婢搗黄糜。',64,'全唐诗/poet.song.232000.json','["世變茫茫不可期，珊瑚作婢搗黄糜。", "八千里有假附子，二十年無生荔枝。", "司馬夢迷蘇小小，屏山詩痛李師師。", "祇應骨朽心猶在，倒海難湔萬古悲。"]'),
('eb6ae38b-4830-4db4-8af8-17f8b7ac4758','感事','方回','宋','宋诗','song-poetry','','[]','直道難容世，深言易絕交。',48,'全唐诗/poet.song.232000.json','["直道難容世，深言易絕交。", "但稱司馬好，勿解子雲嘲。", "彼自盟黄棘，吾寧藉白茅。", "一竿至清水，歸去老江郊。"]'),
('3990944f-6ea8-4476-99cc-1ea779c5f4c8','秋日古蘭花十首  其一','方回','宋','宋诗','song-poetry','','[]','綠葉梢頭紫粟攢，離騷經裏古秋蘭。',32,'全唐诗/poet.song.232000.json','["綠葉梢頭紫粟攢，離騷經裏古秋蘭。", "時人誤喚孩兒菊，惟有詩翁解細看。"]'),
('aef58231-a265-48c7-99b7-1f29f08eccc8','秋日古蘭花十首  其二','方回','宋','宋诗','song-poetry','','[]','可待清秋菊共芳，春苗夏葉已先香。',32,'全唐诗/poet.song.232000.json','["可待清秋菊共芳，春苗夏葉已先香。", "握蘭故事人誰識，夙世龐眉漢署郎。"]'),
('8de7b871-95bc-40a2-b0f5-0edf90f651c9','秋日古蘭花十首  其三','方回','宋','宋诗','song-poetry','','[]','遠聞香淡近聞濃，紫穗絲絲吐雪茸。',32,'全唐诗/poet.song.232000.json','["遠聞香淡近聞濃，紫穗絲絲吐雪茸。", "不識幽人殢姝子，兒曹方醉木芙蓉。"]'),
('adfb7bd8-7456-43a1-932b-f7730d39e9f2','秋日古蘭花十首  其四','方回','宋','宋诗','song-poetry','','[]','玉露金風喜乍凉，紫莖綠葉薦秋芳。',32,'全唐诗/poet.song.232000.json','["玉露金風喜乍凉，紫莖綠葉薦秋芳。", "今年最好中秋月，更著秋蘭月下香。"]'),
('96ac15b6-25e3-497a-8201-0514903be897','秋日古蘭花十首  其五','方回','宋','宋诗','song-poetry','','[]','大似斯文不遇時，無人採佩世無知。',32,'全唐诗/poet.song.232000.json','["大似斯文不遇時，無人採佩世無知。", "援琴與鼓猗蘭操，五百年間一退之。"]'),
('4222a4ad-3cb4-4396-bd90-83e96f2e9c25','秋日古蘭花十首  其六','方回','宋','宋诗','song-poetry','','[]','椒漿桂酒蕙蒸殽，學子人能誦楚騷。',32,'全唐诗/poet.song.232000.json','["椒漿桂酒蕙蒸殽，學子人能誦楚騷。", "惟有籍蘭無識者，老夫對爾首頻搔。"]'),
('0d9d9476-f571-4b74-a329-bbbdcefb8a59','秋日古蘭花十首  其七','方回','宋','宋诗','song-poetry','','[]','紉蘭爲佩楚忠臣，直道從來不屈身。',32,'全唐诗/poet.song.232000.json','["紉蘭爲佩楚忠臣，直道從來不屈身。", "爲報拖金鳴玉者，如君多是折腰人。"]'),
('deb75ec6-81e3-4db9-9c67-0e95badb2a08','秋日古蘭花十首  其八','方回','宋','宋诗','song-poetry','','[]','雪絲鬆細紫團欒，今代無人識古蘭。',32,'全唐诗/poet.song.232000.json','["雪絲鬆細紫團欒，今代無人識古蘭。", "本草圖經川續斷，今人誤作古蘭看。"]'),
('84f26395-21dd-4c30-b5b7-08dbc74e2f76','秋日古蘭花十首  其九','方回','宋','宋诗','song-poetry','','[]','一幹一花山谷語，今蘭不是古時蘭。',32,'全唐诗/poet.song.232000.json','["一幹一花山谷語，今蘭不是古時蘭。", "重陽菊畔千絲紫，隆準曾孫却解看。"]'),
('cb3daaaa-b75d-411e-a8bf-8b330081e0f6','秋日古蘭花十首  其一○','方回','宋','宋诗','song-poetry','','[]','楚詞蘭有晦翁註，模寫真容本陸璣。',32,'全唐诗/poet.song.232000.json','["楚詞蘭有晦翁註，模寫真容本陸璣。", "不待花開著囊貯，紫莖綠葉可熏衣。"]'),
('6bffb923-b8bb-473c-8624-c9372d60c033','偶讀易兌卦衍朋友之義送歷陽廣文倪耕道應淵','方回','宋','宋诗','song-poetry','','[]','易象麗澤兌，朋友以講習。',240,'全唐诗/poet.song.232000.json','["易象麗澤兌，朋友以講習。", "設官爲之師，義取互相益。", "六位六爻畫，分明如六人。", "君子不可疏，小人不可親。", "初以剛居下，不與四爲應。", "和兌未有疑，吉士故可信。", "二以剛居中，承三其人柔。", "孚兌內不感，有吉無悔尤。", "六三柔失位，其凶曰來兌。", "來兌欲媚我，妄說政可外。", "九以剛居四，六處三五間。", "商度久乃决，在惡三之姦。", "五象師之位，剛德既中正。", "上比六見剝，願勿信彼佞。", "極說不知已，引三之柔類。", "此道未光大，正人所遐棄。", "一令而民說，燮調奠乾坤。", "一言朋友說，師道亦云尊。", "大哉說之道，惟以剛爲主。", "師友相與間，柔佞謹勿取。"]'),
('b51fe0c4-3d1a-4a6a-84b3-44a63bbd4265','次韻張鵬飛三絕  其一','方回','宋','宋诗','song-poetry','','[]','舐犢區區笑老牛，阿瞞焉恤一楊彪。',32,'全唐诗/poet.song.232000.json','["舐犢區區笑老牛，阿瞞焉恤一楊彪。", "英雄誤理大床話，賣藥惟應學伯休。"]'),
('4523b948-9cd4-4d65-a426-560a9f6d31ee','次韻張鵬飛三絕  其二','方回','宋','宋诗','song-poetry','','[]','酒箴酒頌日夜讀，後喜伯倫前子雲。',32,'全唐诗/poet.song.232000.json','["酒箴酒頌日夜讀，後喜伯倫前子雲。", "浪說平生三萬卷，一言無用總虛文。"]'),
('f0b34cc4-1ec8-4ffe-9c0d-d689e6368500','次韻張鵬飛三絕  其三','方回','宋','宋诗','song-poetry','','[]','雪天人品最高者，蓑笠江干一釣竿。',32,'全唐诗/poet.song.232000.json','["雪天人品最高者，蓑笠江干一釣竿。", "才有侍兒焉識此，党暉陶穀總酸寒。"]'),
('3b0a273e-436b-4a24-9773-329311c41723','寄題濟南蔣氏務本堂','方回','宋','宋诗','song-poetry','','[]','人生真樂在田廬，幾頃膏腴幾卷書。',64,'全唐诗/poet.song.232000.json','["人生真樂在田廬，幾頃膏腴幾卷書。", "遴選友朋研簡冊，撫存僮僕課犁耡。", "紫荆一樹永無恙，丹桂五枝應有餘。", "孝弟儉勤植根柢，時聞佳氣又充閭。"]'),
('08ac244e-f95f-4235-bba3-89050330206a','久苦春寒三月三日戲作俳體','方回','宋','宋诗','song-poetry','','[]','似惜殘紅未放稀，佳人怯試薄羅衣。',64,'全唐诗/poet.song.232000.json','["似惜殘紅未放稀，佳人怯試薄羅衣。", "桃花水漲冰猶凝，燕子泥融雪更飛。", "老去尋芳元自懶，病來吹霎不如歸。", "常嫌禊帖書清朗，爾許奇寒可浴沂。"]'),
('69d98b5a-37ff-48d5-af08-4f1e0e391cf9','再賦春寒','方回','宋','宋诗','song-poetry','','[]','已近江南煮酒天，單衣時節更重綿。',64,'全唐诗/poet.song.232000.json','["已近江南煮酒天，單衣時節更重綿。", "女郎鬬草頻呵手，老子看花剩聳肩。", "歸燕迎風簾外語，新鵝怯水岸間眠。", "雪如柳絮絮如雪，醉眼難禁故放顛。"]'),
('400b5271-d729-4180-9247-2c8f4f0bad4e','徐遜綿題三賢祠堂詩有云士死惟留姓與名天下第一議論也再賦二首  其一','方回','宋','宋诗','song-poetry','','[]','殷仁周壽缺圓形，釋寶仙清笑乞靈。',64,'全唐诗/poet.song.232000.json','["殷仁周壽缺圓形，釋寶仙清笑乞靈。", "何限台階隆爵位，誰堪鼎足並儀形。", "歲寒臭味松梅竹，乾象光芒日月星。", "野服不殊人品似，年年蘋藻薦芳馨。"]'),
('9891b2c2-7a33-4aaa-b4e6-9acf0b1f4d59','徐遜綿題三賢祠堂詩有云士死惟留姓與名天下第一議論也再賦二首  其二','方回','宋','宋诗','song-poetry','','[]','黌宇祠堂塑像新，兩朝邦伯間邦民。',64,'全唐诗/poet.song.232000.json','["黌宇祠堂塑像新，兩朝邦伯間邦民。", "沒身不朽緣何事，異世相知自有人。", "梅魄鶴魂招處士，松心鳳咮吊纍臣。", "宮牆數仞嚴香火，似勝蕭蕭野水濱。"]'),
('4ebd13d1-3ce6-4d68-83d1-8388bb7b86d0','爲徐企題趙子昂所畫二馬','方回','宋','宋诗','song-poetry','','[]','相馬有伯樂，畫馬有伯時。',140,'全唐诗/poet.song.232000.json','["相馬有伯樂，畫馬有伯時。", "伯樂永已矣，伯時猶見之。", "長林之下無茂草，此馬得無半飽饑。", "一疋背樹似揩癢，一疋齕枯首羸垂。", "趙子作此必有意，志士失職心傷悲。", "我思肥馬不可羈，不如瘦馬劣易騎。", "焉得生致此二疋，馬亦如我老且衰。", "破鞍弊韉骨硉矹，狂豪敢學幽并兒。", "無世塵處天地闊，我後子先緩轡看山時賦詩。"]'),
('c6142d74-fcfc-4a91-aa7c-4c8beedfea63','清明日有感','方回','宋','宋诗','song-poetry','','[]','想見吾兒挈我孫，澆松燒笋杏花村。',64,'全唐诗/poet.song.232000.json','["想見吾兒挈我孫，澆松燒笋杏花村。", "自憐久罄青蚨橐，猶喜能賒綠蟻樽。", "萬事是非雙鬢識，十人兄弟一身存。", "春殘决合爲歸計，未聽啼鵑已斷魂。"]'),
('0c9cb8ad-8670-4f94-945e-764b98cd9f6d','寄題德清周氏牡丹花臺','方回','宋','宋诗','song-poetry','','[]','百品千株養牡丹，遠同京洛近新安。',64,'全唐诗/poet.song.232000.json','["百品千株養牡丹，遠同京洛近新安。", "種非富貴不能種，看到子孫方是看。", "麟脯瓊漿金鑿落，蛾眉翠袖玉闌干。", "天香易賦難陪席，政恐詩翁骨相寒。"]'),
('3d008ffd-2220-4ff7-aeba-beec1176c37f','夜讀','方回','宋','宋诗','song-poetry','','[]','酒醒不能寐，夜起讀我書。',96,'全唐诗/poet.song.232000.json','["酒醒不能寐，夜起讀我書。", "讀久良有得，就枕省其愚。", "古人骨已朽，言語留緒餘。", "不頼燈與目，何以决豕魚。", "我心本至明，燈目焉得如。", "所取外有資，終由受處虛。", "內外相爲賜，猶彼食飲歟。", "不有脾胃實，八珍將吐諸。"]'),
('df915c8d-8b2e-49e2-bd00-3c4d0ec6c290','三月十七夜大雷雨用韻酬俞好問四首  其一','方回','宋','宋诗','song-poetry','','[]','徹夜無眠直到明，擬春晴又不春晴。',64,'全唐诗/poet.song.232000.json','["徹夜無眠直到明，擬春晴又不春晴。", "酒材劣致平原督，花事愁聞望帝聲。", "病體慣經寒熱證，倦途渾忘短長程。", "五年浩蕩江湖夢，猶喜相逢得友生。"]'),
('2c53380c-4b8b-43e1-aa08-3522be0ade97','三月十七夜大雷雨用韻酬俞好問四首  其二','方回','宋','宋诗','song-poetry','','[]','惡風夜洶疾雷頻，稍卧還興起倒身。',64,'全唐诗/poet.song.232000.json','["惡風夜洶疾雷頻，稍卧還興起倒身。", "政復花時如此雨，誰知我輩本無春。", "破衣垢膩瘡饒癢，短被斜欹脚倦伸。", "捱耐天明招敢叟，能來破悶頼斯人。"]'),
('98137b3b-47ea-42d7-8f6f-e17f1a28e705','三月十七夜大雷雨用韻酬俞好問四首  其三','方回','宋','宋诗','song-poetry','','[]','薄有鹽醯胹竹孫，夜寒城郭似荒村。',64,'全唐诗/poet.song.232000.json','["薄有鹽醯胹竹孫，夜寒城郭似荒村。", "遠更已覺踰三鼓，獨酌無聊罄一樽。", "此道粗聞元自少，衆人欲殺幸猶存。", "盲風怪雨青燈暗，莊蝶難憑入夢魂。"]'),
('5571c3f1-ba5c-4f4a-97e9-fbe8750da2bb','三月十七夜大雷雨用韻酬俞好問四首  其四','方回','宋','宋诗','song-poetry','','[]','倦眠書硯付埃氛，煙盡當窗一篆雲。',64,'全唐诗/poet.song.232000.json','["倦眠書硯付埃氛，煙盡當窗一篆雲。", "黠鼠誰令如鬼物，癡貓吾欲與彈文。", "雨餘自揣薪槱絕，客裏尤憐僕廝勤。", "花盡春殘不須惜，好謀歸棹趁南薰。"]'),
('07367124-f411-44e3-9f11-2791897afda1','同劉仲鼎全君玉飲徐子英家分韻得雞字','方回','宋','宋诗','song-poetry','','[]','詰曲盤桓手共携，暮歸了不記東西。',64,'全唐诗/poet.song.232000.json','["詰曲盤桓手共携，暮歸了不記東西。", "初筵秩秩談無底，厦屋渠渠醉似泥。", "老貌白頭愧青鬢，豪吟野鶩雜家雞。", "相看一笑消長日，未信人間物易齊。"]'),
('ea0dcf00-90b7-4ae7-bb69-ca019b8f60ae','寄張鵬飛浙東','方回','宋','宋诗','song-poetry','','[]','政是清和四月天，馬頭無數好山川。',64,'全唐诗/poet.song.232000.json','["政是清和四月天，馬頭無數好山川。", "千花果熟黄鶑樹，百穀秧深白鷺田。", "漢傳風霜驅使節，越溪冰玉劈吟牋。", "四州士友相吟送，應羨風標似謫仙。"]'),
('3a6876a2-8f75-479e-a730-06a8e0702ccd','壽昌鄭生入天目山禮僧','方回','宋','宋诗','song-poetry','','[]','欲作空門補處人，如何頭上裹頭巾。',32,'全唐诗/poet.song.232000.json','["欲作空門補處人，如何頭上裹頭巾。", "曹溪一夜傳衣鉢，元是當年行者身。"]'),
('a760839e-442d-45f6-bd6a-a74bb72e7315','題李伯時赤脚仙','方回','宋','宋诗','song-poetry','','[]','可是馿蹄復馬蹄，忍將玉雪污汙泥。',32,'全唐诗/poet.song.232000.json','["可是馿蹄復馬蹄，忍將玉雪污汙泥。", "世情巇險君知否，滿地人間鐵蒺藜。"]'),
('8c281a33-4d6d-4dd3-802b-a502fee8726f','題來將軍括蒼送行詩卷','方回','宋','宋诗','song-poetry','','[]','將軍從元戎，六年守襄陽。',240,'全唐诗/poet.song.232000.json','["將軍從元戎，六年守襄陽。", "大小百餘戰，裂衣裹金瘡。", "相逢說往事，鬚髯猶奮張。", "歲晚不得志，巡邏分窮鄉。", "窮鄉民不多，詩書間耕桑。", "古不識兵火，承平異邊方。", "一朝六鼇抃，罅隙疏隄防。", "有盜黠如鼠，有吏貪如狼。", "將軍手拊摩，不忍斧斫傷。", "一語對曲直，冷泉解沸湯。", "去著來時袍，蕭然無裝囊。", "但有送行詩，至今猶珍藏。", "壯士困資格，逆旅慳齎糧。", "况又頗抱病，新添滿頤霜。", "萬人爲翰墨，無一曹思王。", "萬人握干殳，無一關雲長。", "幸而一有之，時論紛臧倉。", "恨不釃斗酒，與公歌慨慷。", "將軍未五十，意氣摩穹蒼。", "春鴻定决起，天驥終高驤。"]'),
('def8a2ac-9260-4c25-8845-d2f90be508aa','送李震鶴田姪就題其詩集','方回','宋','宋诗','song-poetry','','[]','駟馬未多疏受去，竹林且擬阮咸遊。',32,'全唐诗/poet.song.232000.json','["駟馬未多疏受去，竹林且擬阮咸遊。", "想見天風鶴鳴和，月臨蕙帳夜山秋。"]'),
('c2a162b5-33e9-4892-9d70-463e147eef12','又題畫赤脚仙','方回','宋','宋诗','song-poetry','','[]','萬古天冠地屨身，畫師遊戲恐非真。',32,'全唐诗/poet.song.232000.json','["萬古天冠地屨身，畫師遊戲恐非真。", "父生師教成何事，甘作蓬頭跣足人。"]'),
('793e5d4d-83b0-46be-bcc3-080b826fd0d9','寄同年宗兄桐江府判去言五首  其一','方回','宋','宋诗','song-poetry','','[]','聯翩同掛別闈名，尚得秋崖病體輕。',32,'全唐诗/poet.song.232000.json','["聯翩同掛別闈名，尚得秋崖病體輕。", "三十四年如一瞬，夢中時見老先生。"]'),
('741c12ae-eeee-4fda-bf00-186671418a7f','寄同年宗兄桐江府判去言五首  其二','方回','宋','宋诗','song-poetry','','[]','秋崖猶子蛟峰弟，同榜三人老弟兄。',32,'全唐诗/poet.song.232000.json','["秋崖猶子蛟峰弟，同榜三人老弟兄。", "君玉中嘗辭直指，去言晚乃佐專城。"]'),
('37b576ab-2366-4bda-9601-63d768fff840','寄同年宗兄桐江府判去言五首  其三','方回','宋','宋诗','song-poetry','','[]','不識康廬真刺史，可憐德祐假平章。',32,'全唐诗/poet.song.232000.json','["不識康廬真刺史，可憐德祐假平章。", "木綿老鬼死遺臭，萬古秋崖姓字香。"]'),
('3a32c1f5-a45e-4665-b4df-fa4090e61cb6','寄同年宗兄桐江府判去言五首  其四','方回','宋','宋诗','song-poetry','','[]','子陵灘上一詩翁，七十四年雙耳聾。',32,'全唐诗/poet.song.232000.json','["子陵灘上一詩翁，七十四年雙耳聾。", "第一老窮吟第一，一樽時與酹江風。"]'),
('3fd69ef7-15c0-4046-9f0b-525567761ea8','寄同年宗兄桐江府判去言五首  其五','方回','宋','宋诗','song-poetry','','[]','好山多處說嚴陵，官事閒時定一登。',32,'全唐诗/poet.song.232000.json','["好山多處說嚴陵，官事閒時定一登。", "野寺豈無僧十百，愛僧須是愛詩僧。"]'),
('5b09b055-ce21-464b-b735-ab6860c0f19c','贈牟仲啟','方回','宋','宋诗','song-poetry','','[]','存齋尚書曾大父，勇退不肯登二府。',256,'全唐诗/poet.song.232000.json','["存齋尚書曾大父，勇退不肯登二府。", "脫靴亭記斥巨閹，風節文章照千古。", "雌甲偶同君乃祖，早衣綉衣持漢斧。", "飲苕溪水二十年，杜門不出守環堵。", "老眼青此名家孫，妙齡謹恪寡語言。", "試文合應進士格，貤澤宜霑任子恩。", "時異數奇以藝隠，粉墨丹青窮討論。", "建章宮可一尺紙，刻畫萬戶雕千門。", "東坡先生萬卷腹，顔筋柳骨寓枯木。", "我嘗竊評文與可，所寫是詩不是竹。", "後生可畏但勉旃，矧爾文獻亦西蜀。", "讀書少著十年工，落筆定無一點俗。", "紫陽山下虛谷翁，懸知萬古皆虛空。", "虛翁之心卧我谷，夜嘯山月朝吟風。", "請君爲我畫此意，三間茅屋深雲中。", "我詩或足傳不朽，與君姓字俱無窮。"]'),
('d0a4a67b-bd21-4e62-9806-45ebee85c625','爲徐企題李伯時馬','方回','宋','宋诗','song-poetry','','[]','此畫良真李伯時，形容飛動卒難詩。',32,'全唐诗/poet.song.232000.json','["此畫良真李伯時，形容飛動卒難詩。", "但將元祐蘇黄作，開卷焚香朗誦之。"]'),
('02c7f66a-ba3e-40ed-b272-5e96d362501e','題錦織回文圖','方回','宋','宋诗','song-poetry','','[]','纚笄宵衣，古士婦服。',40,'全唐诗/poet.song.232000.json','["纚笄宵衣，古士婦服。", "高髻雲鬟，叔季之俗。", "繄是丹青，間以冠髽。", "孰爲主婦，果蘇蕙耶。"]'),
('11e09539-3041-49d5-99f9-8e867907ff7d','次韻徐子英讀予所抄趙章泉詩','方回','宋','宋诗','song-poetry','','[]','陳隋餘習尚塵飛，可乏詩壇白羽揮。',64,'全唐诗/poet.song.232000.json','["陳隋餘習尚塵飛，可乏詩壇白羽揮。", "凡物晚成華者實，如吾素論是耶非。", "三生不墮揚州夢，一笑應知佛祖機。", "苦學若人亦餘事，真源向上更深微。"]'),
('df5d0b21-f10a-4606-88a7-e0dc0dddf4d8','上饒周君夢至梅花洞吟曰我家本住梅花洞一陣風來一陣香爲賦長句','方回','宋','宋诗','song-poetry','','[]','帝敕王家專管竹，子猷高風誰可續。',256,'全唐诗/poet.song.232000.json','["帝敕王家專管竹，子猷高風誰可續。", "西州間生文與可，後來特判篔簹谷。", "帝敕陶家專管菊，千載淵明一影獨。", "分司旁出可無人，醉插齊山容杜牧。", "梅花天下第一花，天下好詩翰林家。", "孤山山下清淺水，疏影年年橫復斜。", "水中漉影出此句，美玉鑿石金淘沙。", "至今和靖一丘壑，敢有代者需齊瓜。", "乾坤故異醯雞甕，元來別有梅花洞。", "玉堂不隔蓬與弱，自是世人肉身重。", "周郎妙年有仙骨，月夜往來跨鸞鳳。", "自言家住梅洞中，怕泄天機稱是夢。", "芙蓉城主傳石丁，洞天是處花冥冥。", "蓮花博士薇花郎，玉階除拜時告廷。", "世間善賦梅花者，定皆梅洞諸仙靈。", "梅洞梅洞果何在，七十萬里天常青。"]'),
('e9d23dc9-884b-4337-b817-b5b875837568','贈善畫龍虎吳伯原雜言','方回','宋','宋诗','song-poetry','','[]','荀氏八龍，慈明無雙。',162,'全唐诗/poet.song.232000.json','["荀氏八龍，慈明無雙。", "豈有頭與角，可以模形容。", "賈氏三虎，偉節最怒。", "豈有毛與皮，可以析毫縷。", "古人畫馬非畫馬，借此繪寫英雄姿。", "東方角龍西奎虎，天有之人亦有之。", "善書畫意不畫像，妙在託興如聲詩。", "點睛飛去果有許，烈裔顧凱亦未奇。", "卧龍未飛，睡虎不吼。", "一飛鱗蟲附之皆上升，一吼百獸聞之悉竄走。", "人見此圖指點爪牙然不然，我得此圖屈伸語默觀聖賢。"]'),
('3dd3db72-64c9-4d76-a822-12e79646bbc2','乙未生日二首  其一','方回','宋','宋诗','song-poetry','','[]','南北間關萬死身，今年六十九年人。',64,'全唐诗/poet.song.232000.json','["南北間關萬死身，今年六十九年人。", "偶容有酒仍容健，不嘆無官肯嘆貧。", "遣禮送詩煩故舊，借樓市饌請比鄰。", "還聞共說虛翁壽，似陸嚴州過八旬。"]'),
('9a113b18-245e-4370-a3c2-fc4ec67e2093','乙未生日二首  其二','方回','宋','宋诗','song-poetry','','[]','虛叟慚非飲八仙，舉杯屬客每陶然。',64,'全唐诗/poet.song.232000.json','["虛叟慚非飲八仙，舉杯屬客每陶然。", "重逢今日初生日，預算明年致仕年。", "元亮有兒聊慰意，斛斯爲話且隨緣。", "老衰不競黄陳律，前日詩如白樂天。"]'),
('5122d0e1-9279-4c80-a174-6a9b2284071b','偶讀戲書','方回','宋','宋诗','song-poetry','','[]','萬物乾坤判女男，始終玄理要精探。',64,'全唐诗/poet.song.232000.json','["萬物乾坤判女男，始終玄理要精探。", "九還七返無成說，一守三存亦浪談。", "未必陽神正解出，可憐癡計謾多貪。", "誰能喚起梅花夢，生死何爲十有三。"]'),
('8957e233-c16b-45ec-ba6f-6b08f0ee1c50','真定路教授鹿泉李君丁亥五月十二日巳時生紫陽虛叟方回丁亥五月十一日巳時生相遇旅邸同登酒樓各出新詩遂成老友','方回','宋','宋诗','song-poetry','','[]','邂逅相逢兩禿翁，亥年巳月巳時同。',64,'全唐诗/poet.song.232000.json','["邂逅相逢兩禿翁，亥年巳月巳時同。", "偶先一日敢爭長，各及七旬俱固窮。", "塵世誰能吟鬢白，少年莫笑醉顔紅。", "累朝南北興亡事，合徵公爲太史公。"]'),
('b5732728-a111-4ac9-8544-1dd86d7f0797','乙未六月大暑','方回','宋','宋诗','song-poetry','','[]','平分天四序，最苦是炎蒸。',48,'全唐诗/poet.song.232000.json','["平分天四序，最苦是炎蒸。", "在我須無欲，於斯患不能。", "又應當閔雨，誰識始藏冰。", "人力回元造，生生實所憑。"]'),
('130b6875-566b-4a45-a75d-e563b688ffef','秋後漸凉','方回','宋','宋诗','song-poetry','','[]','樓東清曉起參旗，火伏三金喜應期。',32,'全唐诗/poet.song.232000.json','["樓東清曉起參旗，火伏三金喜應期。", "車馬塵中猶苦熱，故山已是早凉時。"]'),
('80536cf5-ed6f-4638-9a2e-a0f4cff23ba9','贈呂肖卿三首  其一','方回','宋','宋诗','song-poetry','','[]','雖未登三十，知君已幾年。',48,'全唐诗/poet.song.232000.json','["雖未登三十，知君已幾年。", "先師斧脩月，名父柱擎天。", "失怙初周晬，耽吟早極玄。", "孤身能自立，萬卷絕芸編。"]'),
('e915b4d5-9a05-475d-9b40-bacf67604aa4','贈呂肖卿三首  其二','方回','宋','宋诗','song-poetry','','[]','千萬人叢裏，應難一一尋。',48,'全唐诗/poet.song.232000.json','["千萬人叢裏，應難一一尋。", "政須真具眼，始可與關心。", "匠手斤忘堊，禪機芥遇針。", "絕弦吾欲理，忽復有知音。"]'),
('a9c01823-01dc-4f56-afd8-f17f565b4b4c','贈呂肖卿三首  其三','方回','宋','宋诗','song-poetry','','[]','知己身俱老，逢君淚欲傾。',48,'全唐诗/poet.song.232000.json','["知己身俱老，逢君淚欲傾。", "不時思令舅，無可報難兄。", "湓浦稀魚素，陽山杳雁程。", "平安只消息，聊此慰羈情。"]'),
('7c1fda86-292c-4606-b9b3-9b64262a187c','次韻呂肖卿講學三首  其一','方回','宋','宋诗','song-poetry','','[]','平生但力田，豈計不逢年。',48,'全唐诗/poet.song.232000.json','["平生但力田，豈計不逢年。", "吾道桴浮海，斯文筆補天。", "早能丹點鐵，曾用白嘲玄。", "萬慮今亡矣，焚香易一編。"]'),
('c0f0a64e-7d3e-4eb8-99bf-d05f8a504494','次韻呂肖卿講學三首  其二','方回','宋','宋诗','song-poetry','','[]','玄珠在掌握，一失永難尋。',48,'全唐诗/poet.song.232000.json','["玄珠在掌握，一失永難尋。", "豈不求成道，誰其辦苦心。", "待時花結果，著力杵磨針。", "何幸忘年去，能鳴治世音。"]'),
('aaf750e0-e16b-43c8-a0d0-a0561f4e7987','次韻呂肖卿講學三首  其三','方回','宋','宋诗','song-poetry','','[]','忽復機鋒對，真堪底裏傾。',48,'全唐诗/poet.song.232000.json','["忽復機鋒對，真堪底裏傾。", "果能成伏老，時許喚殷兄。", "可惜茲逢晚，相期不計程。", "受恩凡兩世，焉敢恝無情。"]'),
('a5a0cef8-31b6-4911-8182-e8a643bd2b47','寄題休寧趙氏雲屋省心翠侍問道亭有有堂五首  其一','方回','宋','宋诗','song-poetry','','[]','不品官班但品人，深雲藏屋屋藏身。',32,'全唐诗/poet.song.232000.json','["不品官班但品人，深雲藏屋屋藏身。", "就中別有難藏者，名震京師鄭子真。"]'),
('a4ec002d-7910-4651-b71b-1952b84645f2','寄題休寧趙氏雲屋省心翠侍問道亭有有堂五首  其二','方回','宋','宋诗','song-poetry','','[]','心屬何人省者誰，自家主宰自家知。',32,'全唐诗/poet.song.232000.json','["心屬何人省者誰，自家主宰自家知。", "從來此地惺惺處，不要醫工用藥醫。"]'),
('152e8b0e-1aa0-4b90-bb65-f56cb4f166b6','寄題休寧趙氏雲屋省心翠侍問道亭有有堂五首  其三','方回','宋','宋诗','song-poetry','','[]','青疏老瘦碧孱顔，杳杳深深萬翠間。',32,'全唐诗/poet.song.232000.json','["青疏老瘦碧孱顔，杳杳深深萬翠間。", "侍坐侍行仍侍立，雪松霜竹雨餘山。"]'),
('27ea6524-80e4-4a52-9cd2-c8380422fcc8','寄題休寧趙氏雲屋省心翠侍問道亭有有堂五首  其四','方回','宋','宋诗','song-poetry','','[]','三叉路口駐車輪，莫訝知津更問津。',32,'全唐诗/poet.song.232000.json','["三叉路口駐車輪，莫訝知津更問津。", "何限出門向西笑，忙行不似慢行人。"]'),
('4575a935-e655-4de1-9d5c-0366926d75aa','寄題休寧趙氏雲屋省心翠侍問道亭有有堂五首  其五','方回','宋','宋诗','song-poetry','','[]','貫朽青錢粟腐紅，何如心不愧天公。',32,'全唐诗/poet.song.232000.json','["貫朽青錢粟腐紅，何如心不愧天公。", "一方寸裏無餘物，却笑敖倉武庫窮。"]'),
('fac007ec-a809-4353-9ff3-2a8755749d53','贈方太初三首  其一','方回','宋','宋诗','song-poetry','','[]','秋崖宗老在，餘子眇鄉原。',48,'全唐诗/poet.song.232000.json','["秋崖宗老在，餘子眇鄉原。", "奎壁懸文宿，嵩衡鎮厚坤。", "求田饒許汜，叱馭笑王尊。", "賢與愚俱盡，天難問九門。"]'),
('7a113890-b394-4795-9148-391493ef6548','贈方太初三首  其二','方回','宋','宋诗','song-poetry','','[]','秋崖仙去久，猶有竹溪君。',48,'全唐诗/poet.song.232000.json','["秋崖仙去久，猶有竹溪君。", "合草金鑾詔，頻驚鐵馬羣。", "川遥魚素斷，風急雁行分。", "賀忽翻爲弔，傷心寄些文。"]'),
('f1526aeb-a696-49e4-b116-e5ba6a4f80c7','贈方太初三首  其三','方回','宋','宋诗','song-poetry','','[]','秋崖元不死，夢寐想儀刑。',48,'全唐诗/poet.song.232000.json','["秋崖元不死，夢寐想儀刑。", "縱使長松倒，終殊衆草零。", "羣兒奪朱紫，之子出藍青。", "可惜科場廢，難徼筆硯靈。"]'),
('cd1a960b-917b-4bce-898d-4b2c5aa312cc','追懷秋崖吏部知郡宗伯','方回','宋','宋诗','song-poetry','','[]','崖仙終牖下，壑鬼死漳南。',48,'全唐诗/poet.song.232000.json','["崖仙終牖下，壑鬼死漳南。", "人品誰今識，朝端汝豈堪。", "杞崩溶子口，鯀殛木綿庵。", "猶憶弄權日，湖山極宴酣。"]'),
('3bfe7a81-2c87-4ebf-abc6-a0bcf88e5ce5','閩中鄭君炎南仲兩魁鄉賦比自霅教爲昌化簿','方回','宋','宋诗','song-poetry','','[]','三山鵠袍十萬衆，兩紀知名鄭南仲。',320,'全唐诗/poet.song.232000.json','["三山鵠袍十萬衆，兩紀知名鄭南仲。", "妙年官賦甲秋闈，一發輒中仍再中。", "豈知天地大變革，原夫八韻竟無用。", "雖然改爾亦得力，斗南斗北聲價鬨。", "黄金臺降中書敕，水晶宮請博士俸。", "得人豈必泥古法，省場舍選出鄉貢。", "儒風未盡棄端章，學徒尚多習弦誦。", "但苦官冷飯不足，三載誑腹虀百甕。", "終更受代頗已久，始聞巨軸以詩送。", "定是弟子多賢才，吳興先生實梁棟。", "即今佐邑號爲簿，尹丞不殊權任重。", "况乃唐昌風俗淳，山深歲稔少爭訟。", "丈夫詎皆作卿相，一命關係民疾痛。", "偏見私意勿力競，潜轉密移但微諷。", "方冊頻窺身儘貧，苞苴不納心奚恐。", "崇卑有無置度外，時一極目天宇空。", "江東接壤異西浙，桑蠶春忙田晚種。", "樽俎盤饌極儉嗇，無大牲臠及乳湩。", "吾聞易彖識時義，未妨枳棘棲鸞鳳。", "聊復亦耳磨歲月，慎勿輕爲棺糞夢。"]'),
('08899245-da62-44cc-b48b-fc8b91faf1bf','贈筆工馮應科','方回','宋','宋诗','song-poetry','','[]','世言善書不擇筆，此物豈可不精擇。',304,'全唐诗/poet.song.232000.json','["世言善書不擇筆，此物豈可不精擇。", "空弓難責養由射，快劍始堪孟賁擊。", "多錢而賈長袖舞，工良器利貴相得。", "文房四寶擬四賢，最不易致管城伯。", "乍可微鈍勿太尖，又恐過肥寧少瘠。", "一兔僅足成一枚，奈何攟束動𧥄𧥄。", "氄毛亂毳紛交加，醉人蓬首髪不櫛。", "落腕當如畫鐵椎，顧乃蔞弱欠筋力。", "山谷道人昔有取，諸葛鷄距異棗核。", "長句哦贈林爲之，餘子徐偃似無骨。", "上黨華陵君家孫，苦心隠藝造玄極。", "買非其人拂袖行，但取賞音不論直。", "二毫三副及散卓，隨意真行作波磔。", "燕丹匕首付荆卿，血不濡縷笑空擿。", "紫鸜鵒眼刷絲文，誰無端石與歙石。", "奚李法傳外諸孫，我亦尚有潘衡墨。", "擣冰槌玉烏絲欄，百軸千筒動充斥。", "惟有毛錐真强項，不受折簡屢太息。", "善書今誰第一人，馮應科筆今第一。"]'),
('54e278fe-0cfd-4c2d-a484-f435a98b2b1c','雜書五首  其一','方回','宋','宋诗','song-poetry','','[]','鼻涕垂頤銀竹凍，腦脂遮眼黑花飛。',32,'全唐诗/poet.song.232000.json','["鼻涕垂頤銀竹凍，腦脂遮眼黑花飛。", "此身尚覺非吾有，焉問人間萬事非。"]'),
('0fd9ba2c-c12f-49fb-8a53-abb8b0322269','雜書五首  其二','方回','宋','宋诗','song-poetry','','[]','卜世周家謂過之，從來歷數亦難知。',32,'全唐诗/poet.song.232000.json','["卜世周家謂過之，從來歷數亦難知。", "豈期河洛亡三翮，不比房心續續微。"]'),
('44a467b8-1658-4f54-90c4-3b6725b520f4','雜書五首  其三','方回','宋','宋诗','song-poetry','','[]','細修佳傳酬知己，曲就微生頼若人。',32,'全唐诗/poet.song.232000.json','["細修佳傳酬知己，曲就微生頼若人。", "一點報恩心獨在，時時常見夢中身。"]'),
('f85e5417-cf73-40b4-8fd5-27d8f7017290','雜書五首  其四','方回','宋','宋诗','song-poetry','','[]','一毫不敢昧蒼天，生世明年七十年。',32,'全唐诗/poet.song.232000.json','["一毫不敢昧蒼天，生世明年七十年。", "自恨肉身無報答，日常飽飯夜安眠。"]'),
('15eea280-00f4-4d7b-a64a-1f64a44eb73f','雜書五首  其五','方回','宋','宋诗','song-poetry','','["\u8861\u5c71"]','饒君遒緊日千篇，未辦驪珠出九淵。',32,'全唐诗/poet.song.232000.json','["饒君遒緊日千篇，未辦驪珠出九淵。", "欲詣彭城陳正字，須參南嶽趙章泉。"]'),
('68517395-4d9e-46b2-abc3-d40f7334b7a5','哭川無竭禪師二首  其一','方回','宋','宋诗','song-poetry','','[]','師令題畫像，圓寂十朝前。',48,'全唐诗/poet.song.232000.json','["師令題畫像，圓寂十朝前。", "拙句應曾見，微痾竟不痊。", "笑談猶可想，偈頌總堪傳。", "千柱攢金碧，辛勤二十年。"]'),
('5d173712-bf03-435c-aba9-5d62b1127799','哭川無竭禪師二首  其二','方回','宋','宋诗','song-poetry','','[]','幾登瀟灑閣，共坐聽松風。',48,'全唐诗/poet.song.232000.json','["幾登瀟灑閣，共坐聽松風。", "異骨癯僧健，多魔老守窮。", "是身終有死，何物不成空。", "豈料龍鍾老，題詩先哭公。"]'),
('627223ab-bdac-4315-8edb-8f1670a32354','再哭無竭禪師','方回','宋','宋诗','song-poetry','','[]','倒撐無底船和尚，撐上西天是世尊。',64,'全唐诗/poet.song.232000.json','["倒撐無底船和尚，撐上西天是世尊。", "萬壑啼猿如下淚，一江明月與招魂。", "涅槃滿證無生果，解脫深參阿字門。", "却笑孤山人未遠，浪歌身異性長存。"]'),
('e531a346-6e76-46c6-8f52-52bd2acbb2ba','次韻九月十七日飲陸君用見山堂','方回','宋','宋诗','song-poetry','','[]','鳳凰山下隠君廬，水竹寬閒十畝餘。',64,'全唐诗/poet.song.232000.json','["鳳凰山下隠君廬，水竹寬閒十畝餘。", "稚子已能題砌葉，飲徒時許共畦蔬。", "杜同谷怨長鑱柄，馬伏波思下澤車。", "何似此公一丘壑，潸心逸興酉陽書。"]'),
('5f03c3c3-1004-4249-83a7-5aa7a9a39241','九月二十五書事二首','方回','宋','宋诗','song-poetry','','[]','蒼顔未怯冷風吹，過了殘秋更自奇。',64,'全唐诗/poet.song.232000.json','["蒼顔未怯冷風吹，過了殘秋更自奇。", "細嚼菊花吞美酒，閒拈柿葉寫新詩。", "繄誰屢賀參元火，與客仍消李遠棋。", "七十餘齡能有幾，開懷切勿皺愁眉。"]'),
('bd575d2d-37e1-4e1d-b3e6-0743716783a9','九月初六日客報吾州初一日大火城中俱盡吾家亦盡七八九報皆然初十日始報吾家幸免拆毀屋十餘間二十五日得王山長親家書始知僅存州治州倉州學書院吾家免焚餘所免不過數十家','方回','宋','宋诗','song-poetry','','[]','生死由來一念間，回頭不落鬼門關。',64,'全唐诗/poet.song.232000.json','["生死由來一念間，回頭不落鬼門關。", "細思上策莫如醉，稍據要津焉得閒。", "婢僕凍饑猶戀主，兒童婚嫁合還山。", "一窮惹起無窮事，獨樂吾惟學巷顔。"]'),
('ec7b5d88-94f8-4f65-b95a-b80bbbcfb8cc','于氏琵琶行','方回','宋','宋诗','song-poetry','','[]','君不見木蘭女郎代戍邊，鐵甲卧起二十年。',330,'全唐诗/poet.song.232000.json','["君不見木蘭女郎代戍邊，鐵甲卧起二十年。", "不知誰作古樂府，至今流傳木蘭篇。", "又不見公孫大娘舞劍器，揮霍低昂動天地。", "我杜少陵有長歌，每一讀之生壯氣。", "漢時昭君顔如花，强令出塞禁風沙。", "馬上無以寫愁思，推手爲琵却手琶。", "昭君死作青冢土，琵琶却傳來漢家。", "一弦一字萬怨恨，始聽歡樂終咨嗟。", "燕代佳人有于氏，春日黄鶑韻桃李。", "齒犀微露朱砂唇，手荑緩轉青葱指。", "聲外調聲非桿撥，意中寫意自宮徵。", "曲闌歌罷或潸然，何能動人一至此。", "有時不用琵琶歌，辯如儀秦勇賁軻。", "武昌東西說赤壁，洙泗南北誇黄河。", "一炬一失百萬却，古今勝敗何其多。", "拔山蓋世亦淚下，騅兮虞兮奈若何。", "老夫嗜好無它癖，爲爾看朱幾成碧。", "白髪多情似樂天，衫袖江州司馬濕。", "前身不是木蘭舊女郎，今生恐是公孫真大娘。", "哦此琵琶敲詩腸，爾或因之姓名香。"]'),
('2fcf52e3-7104-424b-b27f-3f279401131f','讀孟信州和方亨道六月雨時當雪天改爲欲作雪先作雨次韻','方回','宋','宋诗','song-poetry','','[]','欲作雪，先作雨，十月墐戶入室處。',206,'全唐诗/poet.song.232000.json','["欲作雪，先作雨，十月墐戶入室處。", "東作豐登未可期，南方瘴癘已堪禦。", "去年雪不及臘間，霜天桃杏敷紅顔。", "今年夏竟無冰賣，富屋錢謾堆如山。", "秋來數郡融風烈，萬舍煙灰千屋拆。", "驕陽失性化爲霖，鞭蛟笞龍精髓竭。", "救火救水不少閒，民生下土何其難。", "此時早降六花瑞，時寒休徵猶可還。", "雁低樓外彤雲起，萬里北風開爽氣。", "雨聲一變爲霰聲，霰效前驅雪踵至。", "古稱民以食爲天，天欲飽民殊易然，但恐燮理無真賢。", "果能燮理得真賢，豈不一白二白三白年年當有年。"]'),
('18c3f143-28ff-428a-b011-07f63a8e8a85','次韻徐子英江樓二首  其一','方回','宋','宋诗','song-poetry','','[]','虛器浮名蜃結樓，潮痕才落水添舟。',64,'全唐诗/poet.song.232000.json','["虛器浮名蜃結樓，潮痕才落水添舟。", "醫工藥不關生死，詹尹蓍寧究咎休。", "華蓋天臨批鳳誥，長楊日侍射熊侯。", "是人有命皆能致，終許難憑智力求。"]'),
('0a27a7b4-ca7a-4828-809c-9b1520110b44','次韻徐子英江樓二首  其二','方回','宋','宋诗','song-poetry','','[]','娛老曾微燕子樓，謀生又欠木奴洲。',64,'全唐诗/poet.song.232000.json','["娛老曾微燕子樓，謀生又欠木奴洲。", "不無造物司行止，豈與齊民繫戚休。", "幸際乾龍亨庶物，故希晉馬錫康侯。", "妙齡今日如公等，聲氣方當叶應求。"]'),
('3192b7c2-44a9-4c5f-ab37-4c10758acdf8','次韻夾谷子括吳山晚眺  其一','方回','宋','宋诗','song-poetry','','[]','詩眼書胸碧宙寬，暮天摇落縱遐觀。',64,'全唐诗/poet.song.232000.json','["詩眼書胸碧宙寬，暮天摇落縱遐觀。", "霜明楓葉紅於染，春點梅梢玉不寒。", "北望遥迎書雁至，南烹屢饜鱠魚殘。", "一規明月懸江海，幾許人家夜枕安。"]'),
('6baa3624-b72b-45d9-81e0-f17db9b1324f','次韻夾谷子括吳山晚眺  其二','方回','宋','宋诗','song-poetry','','[]','鶻飛欲沒海天寬，萬動盈虛靜處觀。',64,'全唐诗/poet.song.232000.json','["鶻飛欲沒海天寬，萬動盈虛靜處觀。", "一畫微陽迎日至，九疇休徵驗時寒。", "世間劫火灰何限，物外仙棋局未殘。", "好與蒼生司性命，五風十雨報平安。"]'),
('e0c5e9f7-e578-447b-a851-10e82fd61f1f','次韻夾谷子括吳山晚眺  其三','方回','宋','宋诗','song-poetry','','[]','落木蕭蕭澤國寬，偶舒巖嘯縱川觀。',64,'全唐诗/poet.song.232000.json','["落木蕭蕭澤國寬，偶舒巖嘯縱川觀。", "六鼇海闊征帆遠，萬象天低步屧寒。", "旅泊餘生簞食菲，宦遊舊味甕虀殘。", "達人不墮牛山淚，何待將心與汝安。"]'),
('46dd9e1e-35ff-4ae0-bd13-cb894d81fb64','次韻俞如問旅思送之遊松江','方回','宋','宋诗','song-poetry','','[]','芰製荷紉未絮衣，溪船信宿自堪歸。',64,'全唐诗/poet.song.232000.json','["芰製荷紉未絮衣，溪船信宿自堪歸。", "倚門尚爾嗟行役，抱甕元來久息機。", "江闊天遥鴻雁斷，日斜歲暮稻粱稀。", "芋爐有地煨風雪，骨肉團欒夜共圍。"]'),
('2135f1ee-acc5-4c09-ba36-1f52f61265e6','再六次韻徐子英江樓','方回','宋','宋诗','song-poetry','','[]','最愁人處最高樓，空望三神想十洲。',64,'全唐诗/poet.song.232000.json','["最愁人處最高樓，空望三神想十洲。", "大藥不靈從老病，把茅猶在盍歸休。", "許追竹士陪梅友，肯羨蜂王慕蝶侯。", "曾點當時未舍瑟，誰知心地異由求。"]'),
('9fac8940-bc8f-4b4d-85ba-35697135e7e6','老而健貧而詩自志其喜八首  其一','方回','宋','宋诗','song-poetry','','[]','弱冠至休致，日須成一詩。',48,'全唐诗/poet.song.232000.json','["弱冠至休致，日須成一詩。", "貧猶常飲客，老幸不招醫。", "節欲無真病，輕財似太癡。", "此吟得佳句，新買早梅枝。"]'),
('288f1894-d4b3-4c34-a2d3-b24bbe09a131','老而健貧而詩自志其喜八首  其二','方回','宋','宋诗','song-poetry','','[]','一時詩有思，何待苦吟成。',48,'全唐诗/poet.song.232000.json','["一時詩有思，何待苦吟成。", "老易惟難健，貧多但少清。", "藏書終不賣，耽酒別無營。", "十六年林下，休官萬事輕。"]'),
('bbdeaca9-8e7e-4e92-a28a-04e1402429a5','老而健貧而詩自志其喜八首  其三','方回','宋','宋诗','song-poetry','','[]','拙宦知今是，頹顔及古稀。',48,'全唐诗/poet.song.232000.json','["拙宦知今是，頹顔及古稀。", "寡言爲暖藥，微醉當寒衣。", "空腹蟬當飽，長身鶴肯肥。", "天容清更健，不省桔槹機。"]'),
('94eabff4-0bb3-4981-a837-24e4acc2d605','老而健貧而詩自志其喜八首  其四','方回','宋','宋诗','song-poetry','','[]','萬山讀書地，近偶脫煙氛。',48,'全唐诗/poet.song.232000.json','["萬山讀書地，近偶脫煙氛。", "幸保分膰廟，常營葬骨墳。", "婿佳殊逸少，兒懶過宗文。", "忽憶門前月，僧敲醉亦聞。"]'),
('234ca0d4-9565-413b-8c22-d181e89487dc','老而健貧而詩自志其喜八首  其五','方回','宋','宋诗','song-poetry','','[]','老翁處處有，不健復何爲。',48,'全唐诗/poet.song.232000.json','["老翁處處有，不健復何爲。", "貧戶家家是，能詩始足奇。", "東坡捐玉带，白傅放楊枝。", "新有僧相識，時來說易詩。"]'),
('5dff2e3f-c341-4684-8641-597ff1955311','老而健貧而詩自志其喜八首  其六','方回','宋','宋诗','song-poetry','','[]','清而貧最樂，健以老何傷。',48,'全唐诗/poet.song.232000.json','["清而貧最樂，健以老何傷。", "短髪蓬加雪，貞心菊耐霜。", "凍吟乏薪炭，醉卧混衾裳。", "冰檗憐兒女，年皆四十强。"]'),
('bfafc7ce-7933-4056-8861-c8d1f40876e2','老而健貧而詩自志其喜八首  其七','方回','宋','宋诗','song-poetry','','[]','才具雖無用，襟期亦未非。',48,'全唐诗/poet.song.232000.json','["才具雖無用，襟期亦未非。", "良難營脫粟，誰肯質深衣。", "爲士當知耻，觀人不相肥。", "還家缺車馬，猶解步如飛。"]'),
('013719e5-9826-4768-ad2f-170e28ae52db','老而健貧而詩自志其喜八首  其八','方回','宋','宋诗','song-poetry','','[]','蹉跎早七旬，老健保清貧。',48,'全唐诗/poet.song.232000.json','["蹉跎早七旬，老健保清貧。", "識破元來易，言傳恐未真。", "但能積陰德，焉用出陽神。", "釋怨恩須報，天終相吉人。"]'),
('f918b21d-d382-4f3d-a4b9-ad4ea4ed2e8b','初七日丁丑長至前喜晴','方回','宋','宋诗','song-poetry','','[]','樓南紅氣滿霜天，新霽湖山曉色妍。',64,'全唐诗/poet.song.232000.json','["樓南紅氣滿霜天，新霽湖山曉色妍。", "七日喜逢長至日，百年慚到古稀年。", "故園捲餠思新菜，凍井澆梅出暖泉。", "誰信少陵夔府後，肯吟六琯五紋篇。"]'),
('142b4661-037e-4734-86b4-6e99969486b6','長至日書','方回','宋','宋诗','song-poetry','','[]','年年春至此胚腪，地上嚴凝地底溫。',64,'全唐诗/poet.song.232000.json','["年年春至此胚腪，地上嚴凝地底溫。", "能幾蟾蜍圓月魄，即須霹靂起雷門。", "知時久偃蛟龍勢，養氣深培草木根。", "表裏陽和見天道，梅花別是一乾坤。"]'),
('c2e4b01e-aac1-494f-815d-49e61cd14208','用夾谷子括吳山晚眺韻十首  其一','方回','宋','宋诗','song-poetry','','[]','湖共江寬更海寬，遥天縱玩復橫觀。',64,'全唐诗/poet.song.232000.json','["湖共江寬更海寬，遥天縱玩復橫觀。", "雅知山對吟肩瘦，未怯霜欺醉面寒。", "感召豐登饒粒食，撫摩瘦敝起彫殘。", "生靈百萬俱高枕，公亦官清夢寐安。"]'),
('c4934390-ecc1-4290-960c-ec78da6bb8ef','用夾谷子括吳山晚眺韻十首  其二','方回','宋','宋诗','song-poetry','','[]','三吳百越楚天寬，不厭登臨不厭觀。',64,'全唐诗/poet.song.232000.json','["三吳百越楚天寬，不厭登臨不厭觀。", "畫舫紅橋隨處有，丹樓碧宇倚空寒。", "梅邊吟思春光早，雁外歸心夕照殘。", "燈火沙河塘上路，豈無凍屋卧袁安。"]'),
('a84e0c89-3f51-4977-ad1d-354649a40860','用夾谷子括吳山晚眺韻十首  其三','方回','宋','宋诗','song-poetry','','[]','梯天直上俯平寬，故國繁華尚可觀。',64,'全唐诗/poet.song.232000.json','["梯天直上俯平寬，故國繁華尚可觀。", "西子有船春色去，伍員無廟暮濤寒。", "九原事往人難問，四序功成歲又殘。", "米賤酒平慰遲暮，巢林聊得一枝安。"]'),
('43944703-351b-4a62-bc25-0fcc8a86e4d1','用夾谷子括吳山晚眺韻十首  其四','方回','宋','宋诗','song-poetry','','[]','抖擻羈懷强自寬，時登吳阜一閒觀。',64,'全唐诗/poet.song.232000.json','["抖擻羈懷强自寬，時登吳阜一閒觀。", "陸機不作蓴羹在，雷煥無蹤劍氣寒。", "倏忽池臺荒草合，等閒歌舞落花殘。", "興亡生死真常在，命要深知分要安。"]'),
('d51833e2-066e-46c2-aed4-84f0070a61ad','用夾谷子括吳山晚眺韻十首  其五','方回','宋','宋诗','song-poetry','','[]','泰伯封疆四望寬，勝將吳越舊書觀。',64,'全唐诗/poet.song.232000.json','["泰伯封疆四望寬，勝將吳越舊書觀。", "苧羅山下春纔到，麋鹿臺邊沼已寒。", "不有採香專怙寵，可能嘗膽便除殘。", "今年木德臨心宿，重見家家衽席安。"]'),
('f18b780d-ca37-4a62-8bfa-45233e2e58e1','用夾谷子括吳山晚眺韻十首  其六','方回','宋','宋诗','song-poetry','','[]','一錐無地百弓寬，萬事須分兩眼觀。',64,'全唐诗/poet.song.232000.json','["一錐無地百弓寬，萬事須分兩眼觀。", "仙子樓居凌倒景，野人卉服耐奇寒。", "金釵玉斝春帷滿，黄卷青燈曉漏殘。", "興廢榮枯手翻覆，幾家能遣子孫安。"]'),
('819ba2a1-4e26-4a32-aca7-1575faf45098','用夾谷子括吳山晚眺韻十首  其七','方回','宋','宋诗','song-poetry','','[]','蕩蕩天寬眼亦寬，區區笑爾井中觀。',64,'全唐诗/poet.song.232000.json','["蕩蕩天寬眼亦寬，區區笑爾井中觀。", "帆來狗國毛人遠，樓倚牛郎織女寒。", "迅速年華榆燧改，槁枯世味蔗滓殘。", "絕憐棺糞紛紛夢，未必槐安果是安。"]'),
('92020238-4963-49ae-bfa0-99e6f61f44a6','用夾谷子括吳山晚眺韻十首  其八','方回','宋','宋诗','song-poetry','','[]','情知新國用刑寬，坐致湖山復舊觀。',64,'全唐诗/poet.song.232000.json','["情知新國用刑寬，坐致湖山復舊觀。", "浙右誰非三世宦，江南終不十分寒。", "錢王陌上花猶好，蘇小門前柳未殘。", "革故鼎新誰料得，舉安天下勝偏安。"]'),
('02de15de-5986-4d2c-a054-7a553e963601','用夾谷子括吳山晚眺韻十首  其九','方回','宋','宋诗','song-poetry','','[]','極目無窮六合寬，仰天如以渾儀觀。',64,'全唐诗/poet.song.232000.json','["極目無窮六合寬，仰天如以渾儀觀。", "日躔箕斗逢長至，月宿奎婁屆大寒。", "肘後方多難却老，杯中物到莫留殘。", "來年七十身猶健，容膝歸歟亦易安。"]'),
('bd55cc38-04d7-4362-957a-8dc148801442','用夾谷子括吳山晚眺韻十首  其一○','方回','宋','宋诗','song-poetry','','[]','眼底胸中稍放寬，超然何肯惑榮觀。',64,'全唐诗/poet.song.232000.json','["眼底胸中稍放寬，超然何肯惑榮觀。", "餘年早已知天命，古道誰堪共歲寒。", "驛使寄梅心獨遠，禪師分芋口無殘。", "十詩說盡登臨意，我但徐行步步安。"]'),
('78b92305-8d6b-4037-abde-727754062bfc','寄壽牟提刑獻之巘  其一','方回','宋','宋诗','song-poetry','','[]','七十閒人兩地仙，恰如同見會昌年。',64,'全唐诗/poet.song.232000.json','["七十閒人兩地仙，恰如同見會昌年。", "詩名我愧劉賓客，心事君真白樂天。", "致仕元無官爵累，藏書各有子孫傳。", "磻溪淇澳可齊壽，入相封侯恐未然。"]'),
('4243ed86-2d83-4f4a-9547-9317a80b9d09','寄壽牟提刑獻之巘  其二','方回','宋','宋诗','song-poetry','','[]','乃翁曾記脫靴亭，直節高風有寧馨。',64,'全唐诗/poet.song.232000.json','["乃翁曾記脫靴亭，直節高風有寧馨。", "知命時年棄軒冕，傳心學問本家庭。", "飽餐霅水仍苕水，高揭文星更壽星。", "我亦七旬乃雌甲，林慚磵愧負山靈。"]'),
('f2b4d498-7b97-4fb9-8b72-dbb68357fb95','曉思','方回','宋','宋诗','song-poetry','','[]','霜天鐘鼓趣晨興，老我無氈脚似冰。',64,'全唐诗/poet.song.232000.json','["霜天鐘鼓趣晨興，老我無氈脚似冰。", "千騎馬塵跑玉勒，一枝梅影伴香燈。", "年當致仕元無位，心亦懷歸苦未能。", "政用括囊保衰暮，可勞妬婦憤填膺。"]'),
('b3eedbce-e96e-4223-9c6e-d3b43231bcb8','開鏡見瓶梅','方回','宋','宋诗','song-poetry','','[]','開奩見明鏡，聊以肅吾櫛。',48,'全唐诗/poet.song.232000.json','["開奩見明鏡，聊以肅吾櫛。", "旁有一瓶梅，橫斜數枝入。", "真花在瓶中，鏡中果何物。", "玩此不能已，悠然若有得。"]'),
('2505992e-6890-429d-b4f5-bf7ebb12d1a8','贈吳琴士會龍','方回','宋','宋诗','song-poetry','','[]','古琴口歌兮手弦，今琴何爲兮不然。',98,'全唐诗/poet.song.232000.json','["古琴口歌兮手弦，今琴何爲兮不然。", "今人作詩動千篇，不弦不歌兮無傳。", "關雎麟趾留遺編，離騷以來諸吟仙。", "我每見之月在淵。", "請君携琴詣我古梅前，君弦其後兮我歌以先。", "君如夜寒不來旃昌黎之十操兮，將獨歌之淚潺湲。"]'),
('b034a3b3-56b0-4c7b-8145-c05dbacab8fa','乙未十二月二十四日立丙申春予忝七十','方回','宋','宋诗','song-poetry','','[]','十歲端平舊丙申，元貞重見丙申春。',64,'全唐诗/poet.song.232000.json','["十歲端平舊丙申，元貞重見丙申春。", "幾災幾難到今日，諸父諸兄皆古人。", "未及懸車官已解，不能負販子俱貧。", "細思多少同庚者，地下先埋富貴身。"]'),
('ec78f6d5-66f3-48e1-bd99-52dc0cba349f','次韻鄧善之書懷七首  其一','方回','宋','宋诗','song-poetry','','[]','二十八迴見，天門闔左扉。',48,'全唐诗/poet.song.232000.json','["二十八迴見，天門闔左扉。", "不嫌筆端退，但駭鏡中非。", "自愛希聲瑟，誰知尚絅衣。", "人生年七十，肯復壯心飛。"]'),
('223b0e80-749a-40df-b8af-b5d85ba775b3','次韻鄧善之書懷七首  其二','方回','宋','宋诗','song-poetry','','[]','老懷饒感慨，無一可歡娛。',48,'全唐诗/poet.song.232000.json','["老懷饒感慨，無一可歡娛。", "久矣還初服，胡然落半途。", "流年蘇武雁，往事左慈鱸。", "莫笑腰圍減，還堪作酒壺。"]'),
('aa60517c-8397-42f1-9bc4-0a4a66287101','次韻鄧善之書懷七首  其三','方回','宋','宋诗','song-poetry','','[]','今代鄧元侯，書窗不外求。',48,'全唐诗/poet.song.232000.json','["今代鄧元侯，書窗不外求。", "寡言良有味，節用絕無愁。", "真是溫如玉，兼能爽似秋。", "鑾坡宜趣召，夜直結鄰樓。"]'),
('32124094-4279-45a9-aa87-1a4c2863c9f9','次韻鄧善之書懷七首  其四','方回','宋','宋诗','song-poetry','','[]','我聽髯張作，清於月夜笳。',48,'全唐诗/poet.song.232000.json','["我聽髯張作，清於月夜笳。", "曹思先七子，杜老到三巴。", "有力能推拉，無疵可汰沙。", "文潜遺論在，霜露老蒹葭。"]'),
('dfb81c6a-ebad-4c75-aaf9-e5b3274c8fd3','次韻鄧善之書懷七首  其五','方回','宋','宋诗','song-poetry','','[]','子將今月旦，可否判生枯。',48,'全唐诗/poet.song.232000.json','["子將今月旦，可否判生枯。", "高論真能借，羈懷未覺孤。", "竹吟風拂席，花飲月當壚。", "甚願陪遊屐，唯慚老杜殊。"]'),
('5c3b6a6e-412e-4281-a1a8-1e8828bcb446','次韻鄧善之書懷七首  其六','方回','宋','宋诗','song-poetry','','[]','以遜而綿者，居然古性情。',48,'全唐诗/poet.song.232000.json','["以遜而綿者，居然古性情。", "溫恭瞻道貌，響浪聽心聲。", "施藥痊諸病，留田與後耕。", "日予拜嘉惠，欲報乏連城。"]'),
('271221d9-9be9-482c-9efe-4edc0b1aeabd','次韻鄧善之書懷七首  其七','方回','宋','宋诗','song-poetry','','[]','昭諫先生宅，咸平處士廬。',48,'全唐诗/poet.song.232000.json','["昭諫先生宅，咸平處士廬。", "大名無死朽，外物幾乘除。", "歲月勤稽古，山林永遂初。", "能詩直餘事，焉不藺相如。"]'),
('4fd60dd9-5451-4c8f-b0a6-127e17fe9c9c','乙未歲除二首  其一','方回','宋','宋诗','song-poetry','','[]','豈料身爲七十翁，開懷且放醉顔紅。',64,'全唐诗/poet.song.232000.json','["豈料身爲七十翁，開懷且放醉顔紅。", "身存惟恨恩難報，世換還驚事總空。", "百歲尚餘三袠數，萬詩枉費一生工。", "盍簪列炬渾如夢，不似今年築底窮。"]'),
('0068de04-9fdb-442f-8a72-d2f1511ab080','乙未歲除二首  其二','方回','宋','宋诗','song-poetry','','[]','五十五時官早休，即今七十復何求。',64,'全唐诗/poet.song.232000.json','["五十五時官早休，即今七十復何求。", "亦思稍爲兒孫計，政恐深貽祖父羞。", "豈不憶家良有說，偶然得酒更無憂。", "諸公富貴新桃版，我是春前舊土牛。"]'),
('3e30ba2c-cfc4-4197-bfcf-17a4dbd15076','丙申元日五絕  其一','方回','宋','宋诗','song-poetry','','[]','新年仍著舊年衣，老健深慚七十希。',32,'全唐诗/poet.song.232000.json','["新年仍著舊年衣，老健深慚七十希。", "一炷爐香拜天地，今春早早買船歸。"]'),
('30e68345-d894-4032-9eb5-c4bbc2447b24','丙申元日五絕  其二','方回','宋','宋诗','song-poetry','','[]','五更春雨細無聲，石路濺泥齒屐鳴。',32,'全唐诗/poet.song.232000.json','["五更春雨細無聲，石路濺泥齒屐鳴。", "後飲屠蘇懶奔走，可能也喜鵓鳩晴。"]'),
('a3b10b08-e007-47b6-9529-c5ed006a04a7','丙申元日五絕  其三','方回','宋','宋诗','song-poetry','','[]','雪餘連雨滿城泥，喝道宵行萬馬蹄。',32,'全唐诗/poet.song.232000.json','["雪餘連雨滿城泥，喝道宵行萬馬蹄。", "昨夜隔年書未點，瓶梅燈畔一枝低。"]'),
('09523861-16db-4a02-a10c-cdb9bb76c0f8','丙申元日五絕  其四','方回','宋','宋诗','song-poetry','','[]','送寒迎暖柳梢知，風自東來著意吹。',32,'全唐诗/poet.song.232000.json','["送寒迎暖柳梢知，風自東來著意吹。", "百萬人家賀新歲，幾家荼壘有新詩。"]'),
('6b37037d-2dc8-4128-98d7-754216b68d22','丙申元日五絕  其五','方回','宋','宋诗','song-poetry','','[]','案上瓶梅閲兩年，添花未有買花錢。',32,'全唐诗/poet.song.232000.json','["案上瓶梅閲兩年，添花未有買花錢。", "東風恰似憐窮客，吹到新詩四五篇。"]'),
('35c57c1a-488f-4f0d-bc33-250eb46161e0','謝張老山御史慶予七十','方回','宋','宋诗','song-poetry','','[]','身是空中一點塵，心包天地却無垠。',64,'全唐诗/poet.song.232000.json','["身是空中一點塵，心包天地却無垠。", "隨緣任運勤收斂，補過知幾暗省循。", "孰料百年登七袠，深慚白髪對青春。", "江梅欲結枝頭子，合放餘花次第新。"]'),
('a3fcb56b-c946-4d69-b0db-51aecc61781d','又次韻張御史鵬飛','方回','宋','宋诗','song-poetry','','[]','休致衰年暗自驚，閒呼張丈喚殷兄。',64,'全唐诗/poet.song.232000.json','["休致衰年暗自驚，閒呼張丈喚殷兄。", "馬塵往往逢新貴，鷗夢依依憶舊盟。", "洛社繪圖慚九老，漢庭綿蕝付諸生。", "繡衣御史煩推轂，我有蓑衣永不更。"]'),
('12ae97dd-96d6-4776-b347-b3ecb408796f','次韻俞好問慶予七十','方回','宋','宋诗','song-poetry','','[]','固窮早類從心孔，懶讀今如便腹邊。',64,'全唐诗/poet.song.232000.json','["固窮早類從心孔，懶讀今如便腹邊。", "時制堪驚小戴記，初筵敢擬衛公篇。", "云何此老偏令壽，其或斯文遂有傳。", "見一庵前碧溪在，花瓢歸飲許仙泉。"]'),
('bd4a94bc-4291-4023-8a45-520c001e1ed8','正月連雨','方回','宋','宋诗','song-poetry','','[]','新年未有一詩新，轉覺羈懷感慨頻。',64,'全唐诗/poet.song.232000.json','["新年未有一詩新，轉覺羈懷感慨頻。", "人日直連元日雨，梅花合讓杏花春。", "避愁愁不拾孤影，怕冷冷偏纏老身。", "幾夜五更了無寐，床頭黠鼠亦欺人。"]'),
('75ebf0f2-2219-4c40-9e45-34f8d78ce37d','題羅雲叔周昉宮女','方回','宋','宋诗','song-poetry','','[]','顛倒三郎養祿兒，當年想是此蛾眉。',32,'全唐诗/poet.song.232000.json','["顛倒三郎養祿兒，當年想是此蛾眉。", "不須真有聊須畫，或可東城出一奇。"]'),
('8652eae1-c723-4da8-89cc-c787eba0e2c3','追用徐廉使參政子方申屠侍御致遠張御史鵬飛元日倡酬韻六首  其一','方回','宋','宋诗','song-poetry','','[]','萬馬鳴鞭欲曉時，閒人盥潄未妨遲。',64,'全唐诗/poet.song.232000.json','["萬馬鳴鞭欲曉時，閒人盥潄未妨遲。", "兒童賀喜休多拜，卿相遷除不預知。", "隨分乍醒仍乍醉，放懷無喜亦無悲。", "新年自愛新詩好，歙硯梅邊洗刷絲。"]'),
('38791174-467d-4b99-af9a-7a05bfcf4564','追用徐廉使參政子方申屠侍御致遠張御史鵬飛元日倡酬韻六首  其二','方回','宋','宋诗','song-poetry','','[]','名臣汲黯鄭當時，筆陣秦王將尉遲。',64,'全唐诗/poet.song.232000.json','["名臣汲黯鄭當時，筆陣秦王將尉遲。", "疾電震雷千里起，乖龍老蜃九淵知。", "諸公猶羨歸田樂，老我終無叩角悲。", "補衮得人卧桑野，可愁二月賣新絲。"]'),
('2d64222b-30ab-454d-b659-7ea299ab7d9b','追用徐廉使參政子方申屠侍御致遠張御史鵬飛元日倡酬韻六首  其三','方回','宋','宋诗','song-poetry','','[]','物有先時有後時，天工無早亦無遲。',64,'全唐诗/poet.song.232000.json','["物有先時有後時，天工無早亦無遲。", "飽禁夜雨元非惡，暗受春風或未知。", "一死頻煩衰白報，三生不爲落紅悲。", "解紛憶得吾家學，徑與揮刀截亂絲。"]'),
('a75125b0-5ad1-4b58-84be-79bd99907af8','追用徐廉使參政子方申屠侍御致遠張御史鵬飛元日倡酬韻六首  其四','方回','宋','宋诗','song-poetry','','[]','即是黄鶑紫燕時，稍晴肯放百花遲。',64,'全唐诗/poet.song.232000.json','["即是黄鶑紫燕時，稍晴肯放百花遲。", "酒來尚許顔紅借，春好何容鬢雪知。", "扶杖可從靈壽賜，聞琴肯作孟嘗悲。", "山深粗有延年藥，歸老松根掘兔絲。"]'),
('cfaa02d2-7389-4dcb-b8d6-fe2a08164365','追用徐廉使參政子方申屠侍御致遠張御史鵬飛元日倡酬韻六首  其五','方回','宋','宋诗','song-poetry','','[]','歲歲花時是病時，不爭春早與春遲。',64,'全唐诗/poet.song.232000.json','["歲歲花時是病時，不爭春早與春遲。", "陰晴謾復題窗記，節氣還因檢歷知。", "杜若薦芳聊可采，秭歸啼苦未須悲。", "老翁堪與少年競，勤把青銅照頷絲。"]'),
('5cd31716-5b38-4415-a20f-c60fdb25c8ba','追用徐廉使參政子方申屠侍御致遠張御史鵬飛元日倡酬韻六首  其六','方回','宋','宋诗','song-poetry','','[]','七十翁非浪走時，夜窗自恨賦歸遲。',64,'全唐诗/poet.song.232000.json','["七十翁非浪走時，夜窗自恨賦歸遲。", "睡稀枕上無春夢，吟苦樓前有月知。", "茅索願追田畯喜，瓜薪遥念室人悲。", "却須天上綸言手，小爲農甿緩繭絲。"]'),
('3c9f8d44-c69e-4de1-b9f7-de07b1620f79','題祝公輔靜得齋','方回','宋','宋诗','song-poetry','','[]','鄭衛撼俗耳，姬姜接凡目。',288,'全唐诗/poet.song.232000.json','["鄭衛撼俗耳，姬姜接凡目。", "醇酎誑渴吻，大房誘饑腹。", "一閾內外間，鮮不妄舉足。", "堂堂七尺軀，頃刻萬感觸。", "人生性本靜，情動乃有欲。", "靜善動亦善，堯舜可同躅。", "動惡喪厥靜，爲桀爲禽犢。", "恭惟方寸心，性情頼管束。", "勿狎寧孔畏，匪狂尚箕肅。", "思精造詣深，察久酬應熟。", "北辰居其所，初九不遠復。", "可待豶豕牙，故已童牛牿。", "性靜人所同，心靜我所獨。", "心靜非不動，存性情乃伏。", "天地與我者，所寶不盈掬。", "完我所固有，得之異逐鹿。", "苦辛子祝子，爲親營半菽。", "頗欲謝湖海，歸歟卧茅屋。", "清夜一孤燈，不疚內自燭。", "養氣非養體，未藉臺餽肉。", "胸中線五色，筆底泉萬斛。", "誰其相料理，回首送鴻鵠。", "離婁下十四，三自義何縟。", "紫陽居資對，我亦當熟讀。"]'),
('3ba52c87-f3fc-49c1-a2b1-729afc300d03','贈癡庵柴頭陀','方回','宋','宋诗','song-poetry','','[]','蕭梁宗補闕，棄官爲頭陀。',274,'全唐诗/poet.song.232000.json','["蕭梁宗補闕，棄官爲頭陀。", "一篇息心銘，至今猶永歌。", "不愛紫綬黄金带，不愛雕鞍白玉珂。", "草椽布衲，一筇一蓑。", "臺城一旦甑墮地，公卿麋爛僨干戈。", "當時獨有宗無名，翛然野鶴山之阿。", "今代柴癡庵，獨把竹帚柄。", "待掃衆生塵，同作大圓鏡。", "不肉不饑，不綿不冷。", "太室爲衾，大塊爲枕。", "一飯不再餐，一茶不再飲。", "脫袍擲笏作百姓，十年悟道保真性。", "昭文大學湛然翁，半夜室中傳祖印。", "無求於世長精神，自淨其心延壽命。", "野狐禪子落邪蹊，唯我癡庵獨也正。", "向來解后逢癡庵，贈我竹爲帚者三。", "一掃嗔，二掃貪。", "惟有一病掃不得，兩癡相值同酸鹹。", "雖然我更有一帚，建立天地同不朽。", "掃愁掃閙掃是非，其帚何名名曰酒。"]'),
('12b04aa2-11dc-46f7-9fcf-870009d81ec7','送曹士弘四明丈亭巡檢并呈前尚書翰林學士王公伯厚','方回','宋','宋诗','song-poetry','','[]','之子博古今，妙年著儒冠。',216,'全唐诗/poet.song.232000.json','["之子博古今，妙年著儒冠。", "顧肯易戎服，屑爲游徼官。", "未喜弓力武，尚愛虀鹽酸。", "紫面頰骨聳，赤心膽氣完。", "得非真將種，終當拜漢壇。", "曰予俎豆學，素不夢糞棺。", "甬東富海物，槁鮮供烹餐。", "曰予豈嗜味，啖茹實所安。", "共惟伯厚父，三入專金鑾。", "萬古貯胸次，四溟涸毫端。", "今年七十五，兩紀歌考槃。", "舉世一影獨，晚進再拜難。", "庶幾因此行，摳衣趨門闌。", "幸不辭孺悲，晝夜勤仰鑽。", "列宿共辰極，衆羽朝祥鸞。", "萬物各從類，同心臭如蘭。", "去去不可追，著鞭駛征鞍。", "我亦意欲往，惜哉步蹣跚。"]'),
('2941b9f5-cfbc-4b36-9795-8a1dc0929794','贈數學蕭吉卿','方回','宋','宋诗','song-poetry','','[]','蓍草占周易，君從簡處尋。',48,'全唐诗/poet.song.232000.json','["蓍草占周易，君從簡處尋。", "運籌見奇偶，落筆判升沉。", "總悟生時數，誰萌分外心。", "吾衰今七十，惟有死山林。"]'),
('ca4c7bc8-de29-4a70-b8c1-03d7c09bea97','與孟能靜飲聯句復和三首  其一','方回','宋','宋诗','song-poetry','','[]','三月一日春如酒，紅是桃花綠楊柳。',32,'全唐诗/poet.song.232000.json','["三月一日春如酒，紅是桃花綠楊柳。", "人生不醉欲如何，不如意常十八九。"]'),
('cb474a09-d60c-432d-8978-de9e4bd379c7','與孟能靜飲聯句復和三首  其二','方回','宋','宋诗','song-poetry','','[]','暫茲袖公補天手，誰能箝我談天口。',32,'全唐诗/poet.song.232000.json','["暫茲袖公補天手，誰能箝我談天口。", "挹斗酌海兩相逢，天風吹入無何有。"]'),
('bf634a15-bafc-42cc-9a7b-2d2c3c56a7d4','與孟能靜飲聯句復和三首  其三','方回','宋','宋诗','song-poetry','','[]','三月三日一觴酒，同上危樓望晴柳。',32,'全唐诗/poet.song.232000.json','["三月三日一觴酒，同上危樓望晴柳。", "豈可不飲負此春，向來風雨十朝九。"]'),
('eed47653-8435-4d2b-8520-aa1a47af80e0','與孟能靜飲聯句復和三首  其四','方回','宋','宋诗','song-poetry','','[]','何必水邊看麗人，何必水晶行素鱗。',32,'全唐诗/poet.song.232000.json','["何必水邊看麗人，何必水晶行素鱗。", "曲阜橋邊同一醉，杭州城裏兩閒身。"]'),
('8a9e0176-a7c7-41b7-ac9f-1f651e75932b','與孟能靜飲聯句復和三首  其五','方回','宋','宋诗','song-poetry','','[]','仕宦可止不止酒，乃所願學陶五柳。',64,'全唐诗/poet.song.232000.json','["仕宦可止不止酒，乃所願學陶五柳。", "春夏秋冬皆有花，四時無日不重九。", "莫欺左持蟹螯手，莫笑涎流麵車口。", "醉能題壁又能歌，德行文章總無有。"]'),
('ecf87bad-51ce-49ad-afca-3f67b0160959','三月六日再用韻二首  其一','方回','宋','宋诗','song-poetry','','[]','忘形爾汝日詩酒，閉戶拒客笑泄柳。',64,'全唐诗/poet.song.232000.json','["忘形爾汝日詩酒，閉戶拒客笑泄柳。", "慷慨酩酊屬我輩，若楚雲夢吞八九。", "隔橋暫許作鄰人，莫待寄書憑雁鱗。", "聚首良難分手易，人生誰得自由身。"]'),
('5026208d-1685-48a0-8da3-b09f8e805901','三月六日再用韻二首  其二','方回','宋','宋诗','song-poetry','','[]','百杯不亂善食酒，如手捧玉肘生柳。',64,'全唐诗/poet.song.232000.json','["百杯不亂善食酒，如手捧玉肘生柳。", "貌醉心醒戒亢悔，一斟一酌乾用九。", "猶龍世豈無斯人，漁網可致皆常鱗。", "蜾蠃螟蛉勿浪語，得似劉伶雞肋身。"]'),
('1d131580-911f-4808-85ab-cb982a3b4d15','三月初五日孟君復王元俞治中十人同會分韻得詩字','方回','宋','宋诗','song-poetry','','[]','春光九十日，半爲風雨欺。',144,'全唐诗/poet.song.232000.json','["春光九十日，半爲風雨欺。", "人生一百年，懷抱無好時。", "茲辰復何辰，晴烟霏柳絲。", "佳友可我意，閒愁忽如遺。", "座客有十人，十人皆能詩。", "景色既已妍，談笑無相疑。", "酌酒不計數，惟醉以爲期。", "鬮韻有險易，鶴頭側復垂。", "上巳後二日，此會竟大奇。", "芥蒂死生間，吾嘗笑羲之。", "王侯宰槐國，蟻身不自知。", "顧此一夢耳，不飲庸非癡。"]'),
('d80c105d-1922-4d82-b7ef-94b87c5ac53c','呈吳門王治中元俞都中參政伯大孫先人同榜','方回','宋','宋诗','song-poetry','','[]','君家兩參預，漢代韋平氏。',240,'全唐诗/poet.song.232000.json','["君家兩參預，漢代韋平氏。", "留耕而耕存，惟有是以似。", "乃祖忠文公，補天扶國是。", "乃父敬愍侯，浮海將使指。", "直諫炳遺藁，大節燁信史。", "神遊天地間，不亡何謂死。", "先人前甲戌，忠文榜下士。", "一升上雲端，一沉墮井底。", "老夫近乙亥，敬愍守吾里。", "朱轓過桐江，共飲釣臺水。", "英英玉樹郎，世濟元凱美。", "忠文既有孫，敬愍又有子。", "邂逅忽相逢，不意聞正始。", "貯胸踰萬卷，運肘動百紙。", "華年弱冠近，緊官半刺比。", "長風破巨浪，未易測涯涘。", "契好詎敢論，臭味差足恃。", "異時吳閶遊，小舟或一艤。", "相門復生相，貽厥有如此。", "乃知吾家兒，不過豚犬耳。"]'),
('35fbe549-35a9-4e13-a1be-0b4ffd6976fb','孟君復贈王侯元俞詩兩皆英妙神奇次韻','方回','宋','宋诗','song-poetry','','[]','孟侯與王侯，妙年俱作州。',144,'全唐诗/poet.song.232000.json','["孟侯與王侯，妙年俱作州。", "窮窮鬼揄我，汝堪並英游。", "汝無曲逆計，汝無裨諶謀。", "汝乃蹄涔水，可配江河流。", "倉卒不能答，吐舌瞠雙眸。", "二侯不自貴，屑與耄叟儔。", "歌豈有檀板，舞亦無珠韝。", "磨玉藉沙石，以故交情綢。", "蓋公曹參舍，甪里張良求。", "綠鬢間白髪，一獻還一酬。", "俗態動枘鑿，對面風馬牛。", "二侯不我棄，庶哉企前脩。"]'),
('013d4493-9886-4907-8ffc-5df12acb8c01','呈呂使君留卿','方回','宋','宋诗','song-poetry','','[]','大門昔有謠，呂氏一千中。',240,'全唐诗/poet.song.232000.json','["大門昔有謠，呂氏一千中。", "華胄所自出，恭惟齊太公。", "君伯先郡王，張韓劉岳同。", "百戰護諸將，易名稱武忠。", "武忠棣華衆，皆有遠祖風。", "分閫仗斧鉞，威望真非熊。", "子姓幾百人，人人俱英雄。", "人人俱智慧，人人俱疏通。", "三衢今使君，尤其明且聰。", "劍光夜衝斗，玉氣日貫虹。", "好士出天性，坐滿樽不空。", "民懷吏膽落，於物大有功。", "驛馬走中原，蹇蹇臣匪躬。", "北上夏雲赤，南還春花紅。", "割牲飣鮓脯，邂逅孤山東。", "念此門下士，陋巷甘固窮。", "昨者諸彥集，長裾織青葱。", "豈謂龍虎閣，著此垂翅鴻。", "高懷極戀戀，莫景殊匆匆。", "願言一轉手，西江掛飛蓬。"]'),
('7e580546-a8e1-4b94-a50c-f393ced41293','記三月十日西湖之遊呂留卿主人孟君復方萬里爲客','方回','宋','宋诗','song-poetry','','["\u897f\u6e56"]','丙申上巳七日後，一主二賓夫豈偶。',384,'全唐诗/poet.song.232000.json','["丙申上巳七日後，一主二賓夫豈偶。", "遣車却騎錢塘門，主人滿船富殽酒。", "別喚輕船載僕從，大船品字著三友。", "旁觀指點知爲誰，對峙玉人間白叟。", "豈無識者訝此老，不愧妙年兩賢守。", "孟侯呂侯將相家，早綰金章紆紫綬。", "方干雲孫聳吟肩，左右鼎鼐中瓦缶。", "雖然蘭臭尚同心，劇談鋒起各虛受。", "是日杭人詫佛事，焚寄冥財聽僧誘。", "公子王孫傾城出，姆携艷女夫挈婦。", "放生亭遠騖長堤，保叔塔高陟危阜。", "居然紅裙濕芳草，亦有瑜珥落宿莽。", "暖熱已極天色變，大風滔天怒濤吼。", "篙師繚繞孤山背，倘佯裏湖保無咎。", "百舠千舫第二橋，四聖觀前依古柳。", "春色濃時良佳哉，遊人聚處可拾否。", "一杯一杯入醉鄉，詼嘲謔笑無不有。", "泉幣重費忘多少，歌妓頻呼雜妍醜。", "似狂非狂癡非癡，何啻萬衆悉迴首。", "我時頹然乎其間，看朱成碧辰至酉。", "健啖晚菘兼早韭，快賞調冰仍雪藕。", "歸途恍然了不記，曉窗半醒卧噎嘔。", "一日之樂三日病，寧負衰軀護饞口。", "願從孟侯觴呂侯，更著百千沽十斗。"]'),
('ca8cf229-02d1-4894-8cb9-a6ca5d6ecbf4','今春苦雨初有春半曾無十日晴之句去立夏無幾日愈雨足成五詩  其一','方回','宋','宋诗','song-poetry','','[]','小樓欲下怕泥行，春半曾無十日晴。',32,'全唐诗/poet.song.232000.json','["小樓欲下怕泥行，春半曾無十日晴。", "老眼看花如隔霧，只消卧聽賣花聲。"]'),
('839ab20c-1402-48b0-a8c1-59dadc9a23be','今春苦雨初有春半曾無十日晴之句去立夏無幾日愈雨足成五詩  其二','方回','宋','宋诗','song-poetry','','[]','今年草草過清明，春莫曾無十日晴。',32,'全唐诗/poet.song.232000.json','["今年草草過清明，春莫曾無十日晴。", "擔上牡丹猶許見，城中渾不識鶑聲。"]'),
('453ce5e1-80e0-4063-90c4-6de6c6c64c53','今春苦雨初有春半曾無十日晴之句去立夏無幾日愈雨足成五詩  其三','方回','宋','宋诗','song-poetry','','[]','青梅未了已朱櫻，春盡曾無十日晴。',32,'全唐诗/poet.song.232000.json','["青梅未了已朱櫻，春盡曾無十日晴。", "稍欲出城問蠶麥，生愁城外杜鵑聲。"]'),
('05aea040-2ea8-419e-b048-9d93154ae707','今春苦雨初有春半曾無十日晴之句去立夏無幾日愈雨足成五詩  其四','方回','宋','宋诗','song-poetry','','[]','湖頭准擬賞新晴，雨過風號萬馬聲。',32,'全唐诗/poet.song.232000.json','["湖頭准擬賞新晴，雨過風號萬馬聲。", "宋玉未誇巫峽夢，杜陵翻作渼陂行。"]'),
('ed1322e5-2923-4e5e-87f2-0d40eeb88b17','今春苦雨初有春半曾無十日晴之句去立夏無幾日愈雨足成五詩  其五','方回','宋','宋诗','song-poetry','','[]','讀書聽雨過三更，定是明朝又不晴。',32,'全唐诗/poet.song.232000.json','["讀書聽雨過三更，定是明朝又不晴。", "就枕未鼾饑鼠出，掀書舐硯上燈檠。"]'),
('4cf566ad-95c1-4f49-ada1-e44c2fc74bd5','春雨不已甚憂蠶麥二首  其一','方回','宋','宋诗','song-poetry','','[]','提籃采葉雨淋淋，蠶婦無言恨自深。',32,'全唐诗/poet.song.232000.json','["提籃采葉雨淋淋，蠶婦無言恨自深。", "綺陌惜花小兒女，愁眉相似不同心。"]'),
('a15c3815-056c-4a1e-8294-9a683cb741b1','春雨不已甚憂蠶麥二首  其二','方回','宋','宋诗','song-poetry','','[]','籠炊湯沸餠如銀，辛苦焉知種麥人。',32,'全唐诗/poet.song.232000.json','["籠炊湯沸餠如銀，辛苦焉知種麥人。", "今歲夏初似高鳳，黄雲欲割半沉淪。"]'),
('757addd4-5909-4da7-99c5-f50a08280c90','題柯德陽埽塵齋','方回','宋','宋诗','song-poetry','','[]','堯舜上聖姿，猶以學爲事。',288,'全唐诗/poet.song.232000.json','["堯舜上聖姿，猶以學爲事。", "矧伊匪生知，不學知不致。", "可學而不學，是謂自暴棄。", "俯首就佔畢，又患學不至。", "恭惟天地心，無極一生二。", "陰陽既已判，太少二生四。", "生生滋無窮，科斗積乳孳。", "籀篆隸真行，同文或以異。", "因繼幾前王，冊府建中秘。", "號爲蓬萊山，校書及正字。", "計資不量材，抱槧剔蠹蘱。", "尸優副劣間，顛倒足笑喟。", "之子讀五車，便腹爲篋笥。", "合登天祿閣，太一照藜吹。", "顧使跧蓬蒿，飯茹宮有侐。", "陳蕃掃天下，借曰未得位。", "掃我方冊塵，我有筆爲篲。", "讎勘極精審，披閲盡劬瘁。", "殘火秦坑遺，斷簡汲冢出。", "端倪究盤頡，古初探炎𨼾。", "五十衍蓍爻，九百采稗記。", "微吟泣山精，幽嘯却野鬽。", "淨几如我心，暗室了無愧。", "老夫敢苦口，曰此藝成易。"]'),
('3558074c-670b-4dd4-bb4b-f00e32af211e','索雲叔新茶','方回','宋','宋诗','song-poetry','','[]','穀雨已過又梅雨，故山猶未致新茶。',32,'全唐诗/poet.song.232000.json','["穀雨已過又梅雨，故山猶未致新茶。", "清風兩腋玉川句，三百團應似太誇。"]'),
('65c7c4f5-38dc-406a-bd57-f8136fcaa60f','閒書二首  其一','方回','宋','宋诗','song-poetry','','[]','年來心事樂陶陶，氣不低垂亦不豪。',64,'全唐诗/poet.song.232000.json','["年來心事樂陶陶，氣不低垂亦不豪。", "酒飲八分何必滿，棋贏一子便爲高。", "脩行到此元非易，把捉從今更要牢。", "搢笏可須煩左手，年年留取剩持螯。"]'),
('945eed22-04a7-43e1-99f2-ce7edff574f2','閒書二首  其二','方回','宋','宋诗','song-poetry','','[]','草木歸根白露零，寒蛬欲蟄動酸吟。',64,'全唐诗/poet.song.232000.json','["草木歸根白露零，寒蛬欲蟄動酸吟。", "每驚世事如翻手，難保人生不負心。", "曠野嗟嗟三獻玉，權門詡詡四知金。", "舊來梁上稱君子，猶自潜形伺夜深。"]'),
('4c6beb91-7932-401f-9ab7-dc3b223cea3e','呈孟君復能靜使君二首  其一','方回','宋','宋诗','song-poetry','','[]','細玩包瓜以杞爻，俊人肯與禿翁交。',64,'全唐诗/poet.song.232000.json','["細玩包瓜以杞爻，俊人肯與禿翁交。", "公侯復始須廊廟，爾汝忘形未草茅。", "各誦新詩針遇芥，相期古道漆投膠。", "一樽百尺樓頭酒，玄白無心賦解嘲。"]'),
('e5d9ca42-a7c1-46eb-935e-7fa1422d2157','呈孟君復能靜使君二首  其二','方回','宋','宋诗','song-poetry','','[]','乃祖麒麟第一人，乃孫今代筆如神。',64,'全唐诗/poet.song.232000.json','["乃祖麒麟第一人，乃孫今代筆如神。", "三遷孟子慈闈教，十二甘羅相閥身。", "海內豪吟公與我，花邊痛飲夏連春。", "浮生倏忽關山隔，數步過橋莫厭頻。"]'),
('fe543536-c2bb-4e4b-a0dc-752fa6183e68','用前韻酬孟君復二首  其一','方回','宋','宋诗','song-poetry','','[]','吞若虞翻夢裏爻，古人不死與神交。',64,'全唐诗/poet.song.232000.json','["吞若虞翻夢裏爻，古人不死與神交。", "成名永保傳青簡，臨事終當藉白茅。", "足可一瓢居陋巷，豈堪二膳養東膠。", "龜藏六用泥中樂，未信時人蝘蜓嘲。"]'),
('24b4c7ec-a9b9-457d-bb9f-899799dd1c14','用前韻酬孟君復二首  其二','方回','宋','宋诗','song-poetry','','[]','眼空敢謂世無人，松菟相依似有神。',64,'全唐诗/poet.song.232000.json','["眼空敢謂世無人，松菟相依似有神。", "邂逅十洲三島客，崎嶇萬死一生身。", "深斟滿酌堪同醉，雪鬢霜髯愧不春。", "別後詩筒恐難數，何如聊爾倡酬頻。"]'),
('510c754e-6a44-411a-951a-c2fb6973dfe4','送天台楊仲儒秀才如北','方回','宋','宋诗','song-poetry','','[]','送君詩者悉豪雄，男子身窮道不窮。',64,'全唐诗/poet.song.232000.json','["送君詩者悉豪雄，男子身窮道不窮。", "爲問何憑遊海內，唯應所恃在胸中。", "渡過淮水即河水，路背南風多北風。", "誰料褐衣抱珠璧，九霄夜月貫長虹。"]'),
('e530ecf8-29e7-43da-9aa1-6f0031526338','贈綦大將軍  其一','方回','宋','宋诗','song-poetry','','[]','將軍早學萬人敵，從父行軍十六七。',112,'全唐诗/poet.song.232000.json','["將軍早學萬人敵，從父行軍十六七。", "上馬如飛海東青，大羽勁弓轟霹靂。", "直欲生擒彼不庭，天山之北北復北。", "總兵王子設危穽，陷陣先鋒淪異域。", "時或偶違心轉壯，身可暫縻膝不屈。", "夜驅汗血還漢朝，萬里沙場如咫尺。", "臣父以死報國家，澡雪父冤見天日。"]'),
('3615b561-3d80-43b5-837e-7d8dc49472c3','贈綦大將軍  其二','方回','宋','宋诗','song-poetry','','[]','先皇玉带親解賜，加侑金錢千百億。',276,'全唐诗/poet.song.232000.json','["先皇玉带親解賜，加侑金錢千百億。", "登時築壇拜大將，隨意委禽聘賢室。", "前茅出鎮萬貔貅，東南五湖天半壁。", "鳳凰山下忽相逢，我舊聞名今面識。", "精忠純孝故無雙，武藝文材俱第一。", "既能高著國手棋，又能穩賦作家詩。", "既能善戰善騎射，七書背誦無餘遺。", "又能雙鈎寫楷字，顔筋柳骨妙畫錐。", "既如諸葛渡瀘水，又如龔遂清潢池。", "章亥六合半已到，象胥九譯靡不知。", "凉州蒲萄無復染，交趾薏苡夫何疑。", "踘場壯士閲劍舞，鈴閣騷人陪酒巵。", "笑談灑落意嫺雅，喜看賓主無厭時。", "邇來宣城察事尤瑰奇，明目張膽鋤羣私。", "去年稻田百圩沒，秋潦至今猶渺瀰。", "孰謂不潦罔省府，公斥其人真姦欺。", "百戰將軍古有之，未聞將軍亦肯念民饑。"]'),
('b4597c3e-2f62-49d5-b2f8-ee3501064394','送楊剛中嘉定州教','方回','宋','宋诗','song-poetry','','[]','忽似登黄甲，元來本白丁。',48,'全唐诗/poet.song.232000.json','["忽似登黄甲，元來本白丁。", "官清專學校，恩重感朝廷。", "側聽吳儂語，讙傳蜀産靈。", "儒風嗣言偃，子細爲談經。"]'),
('86c1781a-3ec0-48bb-89af-d5579e8d455a','次韻趙雲中飲呈孟君復二首  其一','方回','宋','宋诗','song-poetry','','[]','舊業田荒百頃萊，眉頭長與醉懷開。',64,'全唐诗/poet.song.232000.json','["舊業田荒百頃萊，眉頭長與醉懷開。", "春愁忍共金釵訣，夜禁偏嫌玉漏催。", "聚散有情都是夢，古今無物不成灰。", "何時再覓狹邪路，白骨誰非塌井苔。"]'),
('6d0153d4-a1ca-4287-b97b-b44c36e547a9','次韻趙雲中飲呈孟君復二首  其二','方回','宋','宋诗','song-poetry','','[]','可遨崑閬步瀛萊，祇愛鑽腮笑靨開。',64,'全唐诗/poet.song.232000.json','["可遨崑閬步瀛萊，祇愛鑽腮笑靨開。", "暮雨朝雲元易散，昏鍾曉鼓故相催。", "身如病鶴猶遺骨，心似焦桐亦未灰。", "縱使吾曹不排闥，不應門閾上蒼苔。"]'),
('091ec60c-38a4-4cd0-bf8d-6e62b7932907','讀孟君復贈岳仲遠詩勉賦呈二公子','方回','宋','宋诗','song-poetry','','[]','維岳武穆王，復讎議不合。',288,'全唐诗/poet.song.232000.json','["維岳武穆王，復讎議不合。", "老檜賣中原，神龍困蟻𠾱。", "維孟忠襄公，緩兵策弗納。", "清之三京師，萬衆死者卅。", "憸黨梗國論，孰與噬而嗑。", "世事可流涕，循至虞不臘。", "秦鄭兩姦駔，百年棺已闔。", "骨朽遺臭在，厥後極茸闒。", "岳氏家幾傳，陽羨溪山市。", "故書三萬卷，金石爛模搨。", "孟氏神童孫，卜宅占苕霅。", "詩聲鸞鳳鳴，衆作掃蛙蛤。", "猗歟先王公，百戰動摧拉。", "身在國庶幾，心與天響答。", "造物報勳裔，縱未黄其閤。", "各各神仙姿，不受塵土雜。", "臭味崇芝蘭，情誼篤鶼鰈。", "著我珠玉間，鬢蓬愧衰颯。", "冷話暗燈火，清宴倒壺榼。", "時凭城邊樓，同望湖外塔。", "二豪馬蹄花，春堤厭蹴踏。", "而我枯如僧，山肩一破衲。", "未甘脫儒冠，蕭寺求掛搭。", "終不望漢廷，安車聘申蓋。"]'),
('8f005a04-12c8-425c-9d88-7af1d1495e32','送溫州學正陳希靜','方回','宋','宋诗','song-poetry','','[]','多士推溫學，耆儒佐冷官。',48,'全唐诗/poet.song.232000.json','["多士推溫學，耆儒佐冷官。", "雖爲絳帳亞，似可錦衣看。", "父老時枌社，師生日杏壇。", "在家書宦考，三歲定朝端。"]'),
('b5201c0b-3db1-4e98-806f-4cacb4492320','送太平州張府判鈔庫官還任','方回','宋','宋诗','song-poetry','','[]','判州垂闊步，筦庫忽斜飛。',48,'全唐诗/poet.song.232000.json','["判州垂闊步，筦庫忽斜飛。", "談笑胸無物，精神眼有威。", "將門生貴種，詩域悟玄機。", "捉月江頭路，吟鞍幾醉歸。"]'),
('c1c5a489-3c45-426d-8db2-1ae863f23fb3','送汪庭芝高士如嚴州  其一','方回','宋','宋诗','song-poetry','','[]','四海無家只一身，桐江西上訪仙真。',32,'全唐诗/poet.song.232000.json','["四海無家只一身，桐江西上訪仙真。", "七年太守吾聊爾，况汝窮山管道人。"]'),
('49941a9e-76a2-4a37-a565-bfd879d01403','送汪庭芝高士如嚴州  其二','方回','宋','宋诗','song-poetry','','[]','書符呪水空多事，辟穀熬鉛苦用心。',32,'全唐诗/poet.song.232000.json','["書符呪水空多事，辟穀熬鉛苦用心。", "閒讀異書痛飲酒，佳時亦復一彈琴。"]'),
('358f32a9-0237-46f2-b2e6-251c8e5dfc64','送汪庭芝高士如嚴州  其三','方回','宋','宋诗','song-poetry','','[]','我致仕年死期近，汝出家時生理難。',32,'全唐诗/poet.song.232000.json','["我致仕年死期近，汝出家時生理難。", "滄海桑田何可料，一杯別酒莫留殘。"]'),
('65038b48-ce76-4955-aae8-1abde3a3e8d6','送宜興張教授彥高','方回','宋','宋诗','song-poetry','','[]','憶我南湖老，循王又有孫。',48,'全唐诗/poet.song.232000.json','["憶我南湖老，循王又有孫。", "新升陽羨郡，改觀大成門。", "官異吏曹冗，士知師道尊。", "諸生果成服，此事要深論。"]'),
('98ceb05c-5d6c-477c-99f9-90479f11c327','前參政浙西廉訪徐子方得代送別三十韻','方回','宋','宋诗','song-poetry','','["\u897f\u6e56"]','往時參大政，諸老扈先朝。',288,'全唐诗/poet.song.232000.json','["往時參大政，諸老扈先朝。", "合執調元柄，猶乘問俗軺。", "登良爰改紀，肅政各遷喬。", "明甚奎文揭，堅能泰岳摇。", "吳山懸夜月，浙水噴秋潮。", "薦拔皆奇士，寅恭盡選僚。", "重名三翮鼎，古韻九成韶。", "混合氛祲定，因循習尚驕。", "不扶儒學起，焉革庶風澆。", "周繼言堪考，殷因世未遥。", "西湖舊精舍，南渡昔圜橋。", "祠植三賢仆，書重萬卷雕。", "武林增炳煥，文廟鬰岧嶢。", "不朽垂聲價，無窮沸詠謠。", "學肩游子夏，謨過益臯陶。", "鵬運三千日，龍飛九五朝。", "遐方馳幣聘，曲藝齒旌招。", "共擬膺三錫，何煩奉六條。", "有心思綠野，無意上青霄。", "壯節甘恬退，高風久寂寥。", "一閒如我願，百病應時消。", "僉謂衣當衮，公宜館有翹。", "終須坐廊廟，未許老漁樵。", "世道存元氣，天時正斗杓。"]'),
('59b87457-5d42-4186-b092-06feee63f4e5','丙申生日七十自賦二首  其一','方回','宋','宋诗','song-poetry','','[]','先君無罪謫封川，天畀遺孤出瘴煙。',64,'全唐诗/poet.song.232000.json','["先君無罪謫封川，天畀遺孤出瘴煙。", "忽到古希年七十，猶思上大化三千。", "苦吟足可編詩史，狂醉真宜號謫仙。", "五子傳家無一物，聊將書冊當青氈。"]'),
('54960caf-17b2-436b-a5cf-15270c482472','丙申生日七十自賦二首  其二','方回','宋','宋诗','song-poetry','','[]','一尺光陰七寸餘，暗驚前路恐無餘。',64,'全唐诗/poet.song.232000.json','["一尺光陰七寸餘，暗驚前路恐無餘。", "匹如月欠三分滿，又似蓂飄六片初。", "學問文章俱廢忘，科名官職總空虛。", "諸孫中有小丁亥，十歲應能讀我書。"]'),
('5afa0c7a-947d-477b-a353-bd4ed3a88df8','牟獻之提刑來杭納婿慶予七十次韻二首  其一','方回','宋','宋诗','song-poetry','','[]','論交未覺白頭新，閉戶車成合轍輪。',64,'全唐诗/poet.song.232000.json','["論交未覺白頭新，閉戶車成合轍輪。", "自古云希七十老，即今僅見兩三人。", "欲心久絕身宜健，醉鼻常鼾夢不春。", "嫁女婚男多少事，忘懷任運莫傷神。"]'),
('f18fbd27-f141-4a43-9538-f99b731a4821','牟獻之提刑來杭納婿慶予七十次韻二首  其二','方回','宋','宋诗','song-poetry','','[]','扁舟一水接湖杭，久別先生道德光。',64,'全唐诗/poet.song.232000.json','["扁舟一水接湖杭，久別先生道德光。", "名子我方思右咳，隔鄰公此選東床。", "彭聃上壽終澌盡，劉白同年各健强。", "梅子黄時雨如許，小留信宿共清觴。"]'),
('650aa612-5d7f-40a3-a3dc-2d02a4eccc86','孟君復仲春來杭相聚三月餘一日必三胥會忽焉告去直敘離懷爲四言一首','方回','宋','宋诗','song-poetry','','[]','九年三見，昔疏未親。',240,'全唐诗/poet.song.232000.json','["九年三見，昔疏未親。", "一日三見，今也何頻。", "有來者馬，于霅之濱。", "有柳未絮，時維仲春。", "豈無可交，華屋朱輪。", "接膝握手，豈無他人。", "睠焉陋巷，總是纍臣。", "孟獻忘勢，王翰願鄰。", "嗟子之意，孔厚且真。", "揣我所有，閴無一珍。", "英英令節，穆穆良辰。", "泛彼清漣，出其闍闉。", "和風吹衣，芳露滴巾。", "載聽其嚶，載采其辛。", "乃饌我鮮，乃酌我醇。", "我酣子謔，子吟我呻。", "我無子鬩，子無我顰。", "厥月三團，百笑弗嗔。", "積潦滿道，朝炊無薪。", "繫鞍于門，致此嘉賓。", "我窺子胸，萬卷橫陳。", "目電舌雷，筆聖詩神。", "鍛以一字，衡之千鈞。", "吉甫史克，蒙莊靈均。"]'),
('eb0762bd-36cd-4cc0-a58e-048d0aa75116','次韻張師道慶予七十','方回','宋','宋诗','song-poetry','','[]','齋沐披來卷，焚香道主臣。',96,'全唐诗/poet.song.232000.json','["齋沐披來卷，焚香道主臣。", "誤蒙玉堂老，垂顧草廬人。", "帝所聞韶奏，朝廷掌制綸。", "屬請長孺告，肯逐子雲貧。", "公佇登翹館，吾惟釣富春。", "骨將埋冢墓，心敢望陶鈞。", "百歲倒七指，萬形歸一塵。", "莊生真浪語，豈有八千椿。"]'),
('527bcf14-5431-4e32-83d5-8b82f5827b02','送常德教趙君','方回','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','岳陽州城危樓前，無地但有水與天。',384,'全唐诗/poet.song.232000.json','["岳陽州城危樓前，無地但有水與天。", "一點之青惟君山，四顧洶湧心茫然。", "吾嘗北風吹湖船，飛過洞庭一日間。", "高桅一昂摩日邊，及其一低如沉淵。", "竈不可炊薪不燃，躍出釜水如盆翻。", "神驚魄裭乾坤顛，江豚出沒蛟鼉掀。", "小兒號啼大人眠，貓嘔狗吐流腥涎。", "饑僵渴仆三不餐，自曉至昏縮若拳。", "始從武口入武川，然後相賀性命完。", "龍陽縣西百丈牽，古鼎大鎮控羣蠻。", "丹砂水銀充市廛，千機織錦綠紅鮮。", "北上江陵通襄樊，南接長沙衡岳連。", "陶淵明記桃花源，訪尋遺跡揚吾鞭。", "長松巨柏萬且千，近人不畏猨猱懸。", "琴床藥爐濺瀑泉，白髪道士如神仙。", "尺許大字鐵屈盤，吾詩頗奇留刊鎸。", "此事一往四十年，至今夜猶夢湘沅。", "隆準雲孫腹便便，昔者金門班鷺鴛。", "胡爲近亦寒無氈，屑往芹宮專冷官。", "略有廩粟有俸錢，飯雖不足聊粥饘。", "風雅之後聞屈原，千古哀怨離騷傳。", "惟楚有材實多賢，幸爲人師何憾旃。", "坎流叵測行止難，或逆而泝順而沿。", "可不隨機信天緣，竹枝歌聲宮商宣。"]'),
('fc58a4f9-9734-41de-8ef7-60d413ff87d6','送楊復之歸吾里','方回','宋','宋诗','song-poetry','','[]','四十青春七十翁，客樓時得一樽同。',64,'全唐诗/poet.song.232000.json','["四十青春七十翁，客樓時得一樽同。", "子將仕矣雲霄上，我合歸歟澗谷中。", "凉夜歲星守南斗，豐年江國喜西風。", "許追父老雞豚社，爲說猶能醉頰紅。"]'),
('a7e5f85a-2b6b-4cc7-a51c-cc93f222e058','題獨鹿圖','方回','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','誰嘗失之，羣起競逐。',40,'全唐诗/poet.song.232000.json','["誰嘗失之，羣起競逐。", "不見泰山，一得百覆。", "文王之囿，草羨泉足。", "生逢茲辰，呦呦攸伏。"]'),
('477bc851-d1ea-4593-bc6f-fe8ceb321ba5','題九歌圖','方回','宋','宋诗','song-poetry','','[]','惟此楚騷，能歌蓋寡。',38,'全唐诗/poet.song.232000.json','["惟此楚騷，能歌蓋寡。", "我醉友能老嚴灘者，駕風驂雲。", "此誰其寫，是常夢中與之遊也。"]'),
('99b9460c-fb5f-466d-aa8b-cf5f97a80ebc','七十翁五言十首  其一','方回','宋','宋诗','song-poetry','','[]','豈謂真成老，元來總墮虛。',48,'全唐诗/poet.song.232000.json','["豈謂真成老，元來總墮虛。", "它鄉身似雁，永夜眼如魚。", "未覺知幾早，惟嫌料事疏。", "縱無三閣饌，猶有五車書。"]'),
('48760eb6-037a-4658-b158-caadc04a5d4e','七十翁五言十首  其二','方回','宋','宋诗','song-poetry','','[]','愁與憂全異，歡於樂尚遥。',48,'全唐诗/poet.song.232000.json','["愁與憂全異，歡於樂尚遥。", "百年元易度，一日却難消。", "玉叵圭中必，桐猶爨下焦。", "襟懷殊鬰鬰，縱目却飄飄。"]'),
('743eb00f-64e4-4265-9c07-9c28a1c1338d','七十翁五言十首  其三','方回','宋','宋诗','song-poetry','','[]','五月炎歊早，冰盤未薦瓜。',48,'全唐诗/poet.song.232000.json','["五月炎歊早，冰盤未薦瓜。", "客中如許熱，林下豈無家。", "體炙巾繒火，膚斑點鐵砂。", "一杯慶七十，汗滴暮樓霞。"]'),
('cf1259a3-10cf-45b5-9d9f-9d9eaf697bc0','七十翁五言十首  其四','方回','宋','宋诗','song-poetry','','[]','瘴癘金蠶毒，干戈鐵馬羣。',48,'全唐诗/poet.song.232000.json','["瘴癘金蠶毒，干戈鐵馬羣。", "一生逃萬死，百歲僅三分。", "遑恤恒饑子，姑留自祭文。", "醺醺人笑我，方寸不醺醺。"]'),
('53ab6c5a-52ca-477d-b638-c34ab385eff3','七十翁五言十首  其五','方回','宋','宋诗','song-poetry','','[]','七堠長亭路，前程已不多。',48,'全唐诗/poet.song.232000.json','["七堠長亭路，前程已不多。", "最欺吾老者，絕奈後生何。", "去晚陶弘景，迷凶馬伏波。", "幸逢黄菌耦，且賦紫芝歌。"]'),
('15beb988-4500-494c-ae76-d7a9dd4022a6','七十翁五言十首  其六','方回','宋','宋诗','song-poetry','','[]','隻影兼孤喙，攢眉更結喉。',48,'全唐诗/poet.song.232000.json','["隻影兼孤喙，攢眉更結喉。", "一生無大喜，萬種有閒愁。", "冠豸羞言路，憑熊齒郡侯。", "休官十六載，不報破家讎。"]'),
('dca6469e-de9d-4d8b-9055-eb1d0e940d68','七十翁五言十首  其七','方回','宋','宋诗','song-poetry','','[]','故人書見問，近况復如何。',48,'全唐诗/poet.song.232000.json','["故人書見問，近况復如何。", "酒病沉綿劇，詩愁感慨多。", "脛枯全似鶴，髻小僅如螺。", "更許十年活，漁磯破幾蓑。"]'),
('008e5732-05d0-492a-ab93-1c708024d2e4','七十翁五言十首  其八','方回','宋','宋诗','song-poetry','','[]','父母嗟難報，乾坤荷曲成。',48,'全唐诗/poet.song.232000.json','["父母嗟難報，乾坤荷曲成。", "居然生壽相，頗亦竊詩名。", "箕子九疇範，太公三略兵。", "老身寧坎止，時彥或流行。"]'),
('33caee47-be3c-411d-8dc3-8bceee9d207b','七十翁五言十首  其九','方回','宋','宋诗','song-poetry','','[]','詩家自有律，高處在平中。',48,'全唐诗/poet.song.232000.json','["詩家自有律，高處在平中。", "能使生爲熟，何愁拙不工。", "嚴祠七里瀨，漢鼎一絲風。", "敢謂方虛叟，還如陸放翁。"]'),
('bd1cbcbd-32d8-465a-8d4c-81e61b240a70','七十翁五言十首  其一○','方回','宋','宋诗','song-poetry','','[]','紫陽山下住，問字足儒生。',48,'全唐诗/poet.song.232000.json','["紫陽山下住，問字足儒生。", "鮮果枝頭熟，新醅甕面清。", "學師朱仲晦，詩友許宣平。", "焉得孟能靜，滄浪共濯纓。"]'),
('297d2e92-2a17-42ce-b88c-30c7a9cfa8a9','寄題呂常山平章錦繡香中','方回','宋','宋诗','song-poetry','','[]','修善過如修亭館，種德高於種花木。',192,'全唐诗/poet.song.232000.json','["修善過如修亭館，種德高於種花木。", "四時芳菲人不知，蜂猶有鼻蝶有目。", "公心一寸春萬宇，好事如麻不計斛。", "將相富貴世不少，鐘鳴夜行鼎折足。", "我公之遊追張良，我公之隠勝梅福。", "猶憶妙年伐鬼國，二師擊宛騎斬郁。", "獨樂先生五畝園，大庇寒士萬間屋。", "圖形已上功臣閣，投老未數王官谷。", "千葩萬卉春晝長，范蠡西施著膏沐。", "錦天繡地香中醉，漢相政窘千金牘。", "一品閒身釋衮衣，萬古芳名垂汗竹。", "紅霞蒸處幾東風，會見瑶池三度熟。"]'),
('b639fb08-cffb-42a2-a940-d5f4f87bcc91','七十翁吟七言十首  其一','方回','宋','宋诗','song-poetry','','[]','莫笑衰頹七十翁，老來柔外尚剛中。',64,'全唐诗/poet.song.232000.json','["莫笑衰頹七十翁，老來柔外尚剛中。", "評詩青眼時雖白，借酒蒼顔也自紅。", "輕薄交遊翻手雨，艱難仕宦打頭風。", "休官至此六逢閏，能忍窮人不送窮。"]'),
('26829d8e-506c-413a-a172-0bc1f53a6246','七十翁吟七言十首  其二','方回','宋','宋诗','song-poetry','','[]','自笑衰頹七十翁，全將拙鈍易豪雄。',64,'全唐诗/poet.song.232000.json','["自笑衰頹七十翁，全將拙鈍易豪雄。", "猶賢乎已思詩苦，不失其馳飲酒恭。", "女嫁男婚俱失望，廷臚殿對總書空。", "倚樓夜夜看星斗，未了昏鐘又曉鐘。"]'),
('7e3517c5-e0b0-42e3-8ba3-b8a9682816f7','七十翁吟七言十首  其三','方回','宋','宋诗','song-poetry','','[]','一鳴場屋老書生，晚節蹉跎百不成。',64,'全唐诗/poet.song.232000.json','["一鳴場屋老書生，晚節蹉跎百不成。", "舊試卷忘塗注乙，新吟藁漫草真行。", "柄臣全似逢崔胤，座主徒勞識李程。", "第五阿房關許事，樊川終自有詩名。"]'),
('90c573ee-c405-4759-b0fc-7228d5153bd0','七十翁吟七言十首  其四','方回','宋','宋诗','song-poetry','','[]','飽觀代謝四時成，勿訝陰晴小變更。',64,'全唐诗/poet.song.232000.json','["飽觀代謝四時成，勿訝陰晴小變更。", "何許三牲聊淡食，向來五馬亦徒行。", "長哦王粲登樓作，浪得朱雲請劍名。", "我死故應非短命，彼饕誰果是長生。"]'),
('54ab6b22-0c69-45fc-ac7a-4aa277188f4f','七十翁吟七言十首  其五','方回','宋','宋诗','song-poetry','','[]','千古斯文未陸沉，夏因周繼太駸駸。',64,'全唐诗/poet.song.232000.json','["千古斯文未陸沉，夏因周繼太駸駸。", "瓜分繆主貛郎學，灰燼陰傳檜賊心。", "江總不慚同北狩，鍾儀何限尚南音。", "一龕花院傷前事，猶勝棺穿蔓草深。"]'),
('b60db01a-b926-4e91-8d0d-78ad8f5630fb','七十翁吟七言十首  其六','方回','宋','宋诗','song-poetry','','[]','幼孤何敢事兒嬉，聞道惟慚性鈍遲。',64,'全唐诗/poet.song.232000.json','["幼孤何敢事兒嬉，聞道惟慚性鈍遲。", "早尚虛文迷釋老，晚參實學泝濂伊。", "五更燈火芸千卷，兩世冠裳桂一枝。", "夢幻無成吾不怨，庾愁江恨鬢絲絲。"]'),
('7aaa3d03-ba3b-4352-b636-c1ba406a8b55','七十翁吟七言十首  其七','方回','宋','宋诗','song-poetry','','[]','神奇臭腐變窮通，宇宙紛紜醉眼中。',64,'全唐诗/poet.song.232000.json','["神奇臭腐變窮通，宇宙紛紜醉眼中。", "鄧禹第堪文學掾，劉歆早作國師公。", "干戈世故千岐異，禮樂民彝萬古同。", "造化豈應全聵聵，秋來依舊有西風。"]'),
('43fbbb3a-9c6a-41f0-93c7-8d5f636698ea','七十翁吟七言十首  其八','方回','宋','宋诗','song-poetry','','[]','幾夜樓東曉望時，長庚缺月傍參旗。',64,'全唐诗/poet.song.232000.json','["幾夜樓東曉望時，長庚缺月傍參旗。", "江湖已滿焉能久，天地將秋更不疑。", "暑漸變凉差可喜，老難重少自堪悲。", "年來輩行凋零盡，詩卷中多賦挽詩。"]'),
('815962df-68d3-424b-a222-22dfa62b74a2','七十翁吟七言十首  其九','方回','宋','宋诗','song-poetry','','[]','三十科名續父燈，豈知七十老無能。',64,'全唐诗/poet.song.232000.json','["三十科名續父燈，豈知七十老無能。", "兒童半長餘猶幼，門戶中衰久未興。", "南畝盡捐猶有宅，白頭垂禿已如僧。", "平生詩力秋尤健，萬里霜天擊怒鷹。"]'),
('dbb14a95-2a0d-4d58-883b-a838aad2522a','七十翁吟七言十首  其一○','方回','宋','宋诗','song-poetry','','[]','頹齡僥倖古來稀，休致多年但欠歸。',64,'全唐诗/poet.song.232000.json','["頹齡僥倖古來稀，休致多年但欠歸。", "决不再思龜左顧，幸猶免賦雉朝飛。", "江山如舊幾寒暑，天地無情多是非。", "能辦東籬一杯酒，可須疏傅有金揮。"]'),
('f889d522-6b99-4bda-a646-13ccfac5f3e9','送李際可婺源州學正','方回','宋','宋诗','song-poetry','','[]','星源初建郡，芹泮視諸侯。',48,'全唐诗/poet.song.232000.json','["星源初建郡，芹泮視諸侯。", "前序聯官長，公堂糾士流。", "彥章陸贄作，元晦孟軻儔。", "遺帙三年飽，畬租少莫憂。"]'),
('b9bee5f6-e0fd-4a0e-b2da-3c7beb038392','送張古心明道山長','方回','宋','宋诗','song-poetry','','[]','恭惟程伯子，遠紹孔門真。',48,'全唐诗/poet.song.232000.json','["恭惟程伯子，遠紹孔門真。", "間氣千年聚，遺書萬禩新。", "金陵明道長，草澤古人心。", "坐席諸生侍，春風迹未陳。"]'),
('a5073dbc-3ed0-4577-a3bd-d58734046f97','送陳子振池州學正','方回','宋','宋诗','song-poetry','','[]','聞說池陽郡，初能曲突虞。',48,'全唐诗/poet.song.232000.json','["聞說池陽郡，初能曲突虞。", "學官如舊否，文選尚存無。", "魚蟹江淮聚，桑麻雨露腴。", "物平仍酒賤，時佩翠微壺。"]'),
('068faf74-9354-45b4-b96a-84a0c24ab84b','六月二十八日立秋','方回','宋','宋诗','song-poetry','','[]','平生爲客太匆匆，已上西江又復東。',64,'全唐诗/poet.song.232000.json','["平生爲客太匆匆，已上西江又復東。", "只信一朝飛舴艋，何知五度落梧桐。", "絕憐牛女常遭謗，粗足蓴鱸不嘆窮。", "世外世間異天壤，政須深谷卧秋風。"]'),
('be17b753-7959-49a2-9295-01a6f190591b','七十翁吟五言古體十首  其一','方回','宋','宋诗','song-poetry','','[]','無妻牧犢子，带索榮啟期。',96,'全唐诗/poet.song.232000.json','["無妻牧犢子，带索榮啟期。", "予亦年七十，幸猶未至茲。", "頗亦似陶翁，粗有五男兒。", "乃父休官早，致汝恒苦饑。", "掛冠六七閏，方當掛冠時。", "治生了無策，惟耽酒與詩。", "室人愧交讁，雖壽夫奚爲。", "後死信無益，固窮諒何悲。"]'),
('3ad140c8-81cb-4242-aa9e-43a4350a08ab','七十翁吟五言古體十首  其二','方回','宋','宋诗','song-poetry','','[]','昔聞老萊子，希年奉慈親。',96,'全唐诗/poet.song.232000.json','["昔聞老萊子，希年奉慈親。", "佯作小兒啼，斕斑綵衣身。", "事有異天壤，予生何不辰。", "三歲喪吾父，萬里南海濱。", "先君四難弟，今皆爲古人。", "五房伯仲十，獨予登七旬。", "道路謾奔走，燈火徒苦辛。", "此詩比蓼莪，一吟一傷神。"]'),
('af6f7f5a-418a-4830-a584-acf72b465d10','七十翁吟五言古體十首  其三','方回','宋','宋诗','song-poetry','','[]','先祖八十四，卒予生之年。',96,'全唐诗/poet.song.232000.json','["先祖八十四，卒予生之年。", "先父五十六，予甫三歲焉。", "厥今七十叟，萬死偶獲全。", "過父豈不愧，逮祖恐未然。", "初學晚頗進，粗亦窺聖賢。", "常感知己恩，不報負我冤。", "夢寐此心明，暗室如青天。", "無田與兒孫，未爲無所傳。"]'),
('ddaf4b5d-9c73-4099-83fe-b8c7e9f68cd1','七十翁吟五言古體十首  其四','方回','宋','宋诗','song-poetry','','[]','五男三女兒，僥倖肖吾祖。',96,'全唐诗/poet.song.232000.json','["五男三女兒，僥倖肖吾祖。", "賢愚掛懷抱，笑陶敢效杜。", "長男近寄書，長女化爲土。", "嗟予七十翁，哭此四十女。", "此女抱恨久，嫁不得其所。", "厥夫實鴟鴞，厥舅乃狼虎。", "讕訟欲殺予，破家謝官府。", "不禁毀璧痛，何啻茹荼苦。"]'),
('76e0117c-8816-4fbc-b6e5-deb9ec07ff5e','七十翁吟五言古體十首  其五','方回','宋','宋诗','song-poetry','','["\u8861\u5c71"]','詩人而壽者，近有數老仙。',96,'全唐诗/poet.song.232000.json','["詩人而壽者，近有數老仙。", "後有陸放翁，前有曾茶山。", "亦復有二趙，南塘與章泉。", "年皆八九十，至今詩集傳。", "南嶽五藁出，豈無劉後村。", "老妓風水僧，兩詩太不然。", "三生感容堂，晚節尤可憐。", "虛叟年七十，努力當勉旃。"]'),
('8538f528-cd98-41f1-8ca6-1715348cda79','七十翁吟五言古體十首  其六','方回','宋','宋诗','song-poetry','','[]','後山與簡齋，僅年四十九。',96,'全唐诗/poet.song.232000.json','["後山與簡齋，僅年四十九。", "詩少句句佳，天地同不朽。", "予幼初學詩，一日賦一首。", "頹齡忽七十，詩果傳後否。", "僥倖擢儒科，邂逅至郡守。", "幾死坐此耳，詩於我何負。", "壽長詩故多，才短詩故醜。", "苟活許作詩，餘生付詩酒。"]'),
('94a03cec-356e-4db4-984a-dbee4c981745','七十翁吟五言古體十首  其七','方回','宋','宋诗','song-poetry','','[]','晦庵感興詩，本非得意作。',96,'全唐诗/poet.song.232000.json','["晦庵感興詩，本非得意作。", "近人輒效尤，以詩言理學。", "志南寫柳吹，曼卿詠禽樂。", "我翁盛稱之，豈不物象托。", "小巷旗誇酒，大賈褐懷璧。", "喝咄野狐禪，未必實有得。", "歐公不論文，孟子不言易。", "平生守所見，弱冠至七十。"]'),
('04e4f4d6-7ce6-4030-bdc0-e78dd4687b07','七十翁吟五言古體十首  其八','方回','宋','宋诗','song-poetry','','[]','幼嘗習古詩，生平不滿百。',96,'全唐诗/poet.song.232000.json','["幼嘗習古詩，生平不滿百。", "人生如蝸牛，欲升一丈壁。", "我幸七尺身，燥土餘三尺。", "目此寸進難，涎盡喙不濕。", "平生修省心，不啻震虩虩。", "晚若蹈虎尾，更甚履愬愬。", "庶幾其可免，寧受凍饑厄。", "徒步勝安車，亦勿乘下澤。"]'),
('3e12f2f5-4444-4b26-a484-80be5546f119','七十翁吟五言古體十首  其九','方回','宋','宋诗','song-poetry','','[]','今所以知古，頼世有書史。',96,'全唐诗/poet.song.232000.json','["今所以知古，頼世有書史。", "後所以信今，豈不亦藉此。", "昔在韓魏公，治平四載耳，仁皇實錄就。", "賊賈獨不爾，竊位十六年，不奏理廟紀。", "咸淳至德祐，抑又可知矣。", "國亡邪正混，衮撻筆孰泚。", "衰翁抱丹心，但恐將溘死。"]'),
('50a7ea8a-9742-4801-960b-2fd654bbd4ab','七十翁吟五言古體十首  其一○','方回','宋','宋诗','song-poetry','','[]','世短心徒長，日暮道更遠。',96,'全唐诗/poet.song.232000.json','["世短心徒長，日暮道更遠。", "偶榮匪運泰，驟落非命蹇。", "王侯死無葬，將相謫不返。", "賤窮齒禿缺，尚許噉糲飯。", "配享宣尼廟，文學可商偃。", "云何從祀廡，傳註王鄭混。", "平生三萬卷，晚節葉糞本。", "外華已焉哉，襏襫謝公衮。"]'),
('f766392c-b1c8-47e3-9784-0a90cece45da','七十翁吟七言十絕  其一','方回','宋','宋诗','song-poetry','','[]','自知酒量防踰矩，敢詫詩才妙斵輪。',32,'全唐诗/poet.song.232000.json','["自知酒量防踰矩，敢詫詩才妙斵輪。", "古聖賢心得絲許，雖非尼扁異愚民。"]'),
('34248cf9-398e-458b-8c0a-02b5209a1488','七十翁吟七言十絕  其二','方回','宋','宋诗','song-poetry','','[]','頓爾繆爲象山學，雕吾痛絕水心文。',32,'全唐诗/poet.song.232000.json','["頓爾繆爲象山學，雕吾痛絕水心文。", "潜夫詩格溫夫字，掩耳平生不願聞。"]'),
('446b61e4-6a78-4747-93c8-b230ddc6a24d','七十翁吟七言十絕  其三','方回','宋','宋诗','song-poetry','','[]','詩備衆體更須熟，文成一家仍不陳。',32,'全唐诗/poet.song.232000.json','["詩備衆體更須熟，文成一家仍不陳。", "晚悔昨非思改紀，規隨養氣省心人。"]'),
('ebedc7c1-0197-4386-ada7-b347cfaf7e9f','七十翁吟七言十絕  其四','方回','宋','宋诗','song-poetry','','[]','鄭玄三禮王弼易，亦繪冕旒配孔庭。',32,'全唐诗/poet.song.232000.json','["鄭玄三禮王弼易，亦繪冕旒配孔庭。", "虛耗中原實衛霍，麒麟閣上也圖形。"]'),
('bee6e757-b7a9-4443-874f-d842d3dc6d6f','七十翁吟七言十絕  其五','方回','宋','宋诗','song-poetry','','[]','一河綠水小樓前，八十老翁猶駕船。',32,'全唐诗/poet.song.232000.json','["一河綠水小樓前，八十老翁猶駕船。", "七十老翁幸靜坐，有書不讀真可憐。"]'),
('02a78b30-ab4c-4607-a8bc-c85f6d57baa4','七十翁吟七言十絕  其六','方回','宋','宋诗','song-poetry','','[]','恨予生不及晦翁，撰杖鵝湖觀異同。',32,'全唐诗/poet.song.232000.json','["恨予生不及晦翁，撰杖鵝湖觀異同。", "豈減游楊侍程子，未甘籍湜事韓公。"]'),
('2034ed56-53ff-42d0-9222-3b964b12b9a6','七十翁吟七言十絕  其七','方回','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','膾炙鯨鵬吾不佞，撮捫蚤虱爾徒勞。',32,'全唐诗/poet.song.232000.json','["膾炙鯨鵬吾不佞，撮捫蚤虱爾徒勞。", "泰山夜半見紅日，政要人生著脚高。"]'),
('c3638838-fefa-449d-a943-18cf79093955','七十翁吟七言十絕  其八','方回','宋','宋诗','song-poetry','','[]','後山卒僅四十九，諱日崇寧一日前。',32,'全唐诗/poet.song.232000.json','["後山卒僅四十九，諱日崇寧一日前。", "當時假使餘七袠，忍見中原丙午年。"]'),
('7c652a88-4ee6-4453-98a4-ec72fc79877a','七十翁吟七言十絕  其九','方回','宋','宋诗','song-poetry','','[]','周家八百年天下，文武焉知有赧王。',32,'全唐诗/poet.song.232000.json','["周家八百年天下，文武焉知有赧王。", "老壽彭公亦餘骨，始知生死是興亡。"]'),
('0723c767-2a46-4799-805c-7ae37b88353c','七十翁吟七言十絕  其一○','方回','宋','宋诗','song-poetry','','[]','少陵詩詫古來希，老病餘生曷不歸。',32,'全唐诗/poet.song.232000.json','["少陵詩詫古來希，老病餘生曷不歸。", "不信神仙不信佛，死時惟裹破深衣。"]'),
('8682c4f9-6e35-4c14-b7c9-298bdbb6ddc5','送劉都事五十韻','方回','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','近人於仕宦，如以韓盧獵。',288,'全唐诗/poet.song.232000.json','["近人於仕宦，如以韓盧獵。", "泰山有不見，得獸誇足捷。", "學問夫何如，有書鑰諸篋。", "府史以爲師，僅能署吏牒。", "雕鞍驟肥馬，畫閣貯美妾。", "萬一至公相，豈堪任調燮。", "老友劉密翁，早隸周孔業。", "大輅鸞和鳴，大樂律呂協。", "南省據都曹，不以貴自挾。", "朋來多下交，賓至必謙接。", "解官寓城東，座寒乏氈㲲。", "高卧懶問選，兩落秋蓂莢。", "積薪後居上，彼勇哂吾怯。", "爲言恥孟晉，如病夏畦脅。", "有時酤我飲，荒墅縱步屧。", "果核飣俎豆，羹糝供匕筴。", "居然道懷孚，宜爾情話接。", "公才豈不知，大川宜作楫。", "顧於名利波，未肯卜利涉。", "人生惑外物，種種意欲愜。", "高睨官爵梯，等級恨不躐。", "愚竊窺此翁，嗜欲穽已斂。", "寧爲三省魯，不慕一諾俠。", "經史入胸中，邱陵堆重疊。"]'),
('c7083aa3-2dfc-48ee-88c2-f9daf2003d5d','張老山御史寄七夕詩今近中秋奉問','方回','宋','宋诗','song-poetry','','[]','籠鶴囊琴駕短篷，夏初言別又秋中。',64,'全唐诗/poet.song.232000.json','["籠鶴囊琴駕短篷，夏初言別又秋中。", "一天遥共團圓月，兩地相忘矍鑠翁。", "朝廷還公黄閣相，江湖乞我白蘋風。", "金臺乍到朋簪盍，肯繫吟牋寄早鴻。"]'),
('0e835cc5-0201-489f-a950-e8cabfd7885a','方去言府判挽詩二首  其一','方回','宋','宋诗','song-poetry','','[]','諸老非前日，吾宗有若人。',48,'全唐诗/poet.song.232000.json','["諸老非前日，吾宗有若人。", "大圭全粹質，勁柏挺長身。", "倉卒完鄉縣，艱難寢戰塵。", "深慚銘筆短，未足永堅珉。"]'),
('7b3840b2-548b-4241-955e-d03130acac91','方去言府判挽詩二首  其二','方回','宋','宋诗','song-poetry','','[]','壬戌同登日，秋崖尚見之。',48,'全唐诗/poet.song.232000.json','["壬戌同登日，秋崖尚見之。", "王家子敬字，謝氏惠連詩。", "鄉校六龍渡，宗盟七桂枝。", "殘碑麟筆絕，後死嘆吾衰。"]'),
('dc51d10d-2e01-4d52-8ceb-245b81f35186','呈呂使君二首  其一','方回','宋','宋诗','song-poetry','','[]','中川孤嶼稱詩才，雁蕩龍湫遍賞來。',64,'全唐诗/poet.song.232000.json','["中川孤嶼稱詩才，雁蕩龍湫遍賞來。", "千騎君侯鳴競病，五年朋友共敲推。", "舊題謝守池邊草，新寓逋仙屋角梅。", "欲叩吟窗看奇句，不應相遇只銜盃。"]'),
('09404ff8-52ef-4063-b3f2-b4d7c4e875ea','呈呂使君二首  其二','方回','宋','宋诗','song-poetry','','[]','紛紛衮衮笑儒酸，獨愛虀鹽遠綺紈。',64,'全唐诗/poet.song.232000.json','["紛紛衮衮笑儒酸，獨愛虀鹽遠綺紈。", "國手文章無敵手，將壇家世上詩壇。", "海艘蕩寇鯨波靜，江寺除凶鬼膽寒。", "才調極高心轉小，近時人物此尤難。"]'),
('a22e22ec-5b3c-4095-88f3-5c7dd995d05f','題畫馬','方回','宋','宋诗','song-poetry','','[]','芻秣豐肥十二閑，筆追韓幹此圖間。',32,'全唐诗/poet.song.232000.json','["芻秣豐肥十二閑，筆追韓幹此圖間。", "誰描馿瘦更詩瘦，首與雙肩共一山。"]'),
('46320e7c-1189-4c6a-96f7-64136094100e','題宣和黄頭畫','方回','宋','宋诗','song-poetry','','[]','石綠藤黄間麝煤，半枯瘦篠羽毰毸。',32,'全唐诗/poet.song.232000.json','["石綠藤黄間麝煤，半枯瘦篠羽毰毸。", "一時艮嶽天顔笑，乞與宣和印押來。"]'),
('7954cbb5-0da5-4a35-827f-fc4a50adcfdf','題陶介夫見山軒  其一','方回','宋','宋诗','song-poetry','','[]','湖上山如畫，何人解見山。',24,'全唐诗/poet.song.232000.json','["湖上山如畫，何人解見山。", "此心無一事，盡日捲簾間。"]'),
('2db5f883-bbab-4251-a6d8-e6b14c0ad467','題陶介夫見山軒  其二','方回','宋','宋诗','song-poetry','','[]','湖上山如故，湖邊客總非。',24,'全唐诗/poet.song.232000.json','["湖上山如故，湖邊客總非。", "容堂今不見，凉夜草螢飛。"]'),
('44b27398-edac-43c2-8418-78292cfb6051','寄平江王元俞治中并呈孟君復總管','方回','宋','宋诗','song-poetry','','[]','兩玉人俱出相家，一時頓有富才華。',64,'全唐诗/poet.song.232000.json','["兩玉人俱出相家，一時頓有富才華。", "登樓賦詠追王粲，落帽風流致孟嘉。", "未肯一莖生白髪，相逢九日醉黄花。", "蘇臺欲往何由得，獨立吳山眺晚霞。"]'),
('b90f1287-3599-4a67-bb56-828c14700e48','送繆鳴陽六言','方回','宋','宋诗','song-poetry','','[]','象山之學超詣，水心之學刻畫。',56,'全唐诗/poet.song.232000.json','["象山之學超詣，水心之學刻畫。", "後村之詩卑陋，樗寮之字怪癖。", "舉世隨聲雷同，衆啞啞我愬愬。", "此四者皆不可，尤不可第一癖。"]'),
('1fb0447d-9509-4113-91d0-c8ee842b4975','讀陶集愛其致意於菊者八因作八首 一曰秋菊盈園而持醪靡由','方回','宋','宋诗','song-poetry','','[]','陶公愛菊滿園秋，甚欲持醪竟靡由。',32,'全唐诗/poet.song.232000.json','["陶公愛菊滿園秋，甚欲持醪竟靡由。", "世事重華那復爾，無錢更覺少陵愁。"]'),
('5ebe24b2-8e76-4c1d-8fc9-a5d519572520','讀陶集愛其致意於菊者八因作八首 二曰空服九華','方回','宋','宋诗','song-poetry','','[]','金英足可換君骨，綠醑寧當腐我腸。',32,'全唐诗/poet.song.232000.json','["金英足可換君骨，綠醑寧當腐我腸。", "空服九華無九醖，帝鄉何似醉爲鄉。"]'),
('bb6aa3a4-0148-40de-95c2-e8ad3269ad25','讀陶集愛其致意於菊者八因作八首 三曰菊爲制頹齡','方回','宋','宋诗','song-poetry','','[]','自性不隨黄落去，始能爲爾制頹齡。',32,'全唐诗/poet.song.232000.json','["自性不隨黄落去，始能爲爾制頹齡。", "涪翁具眼曾拈出，我爲重吟換鬼聽。"]'),
('30f0d090-b417-49eb-9abf-8c5ec75944fb','讀陶集愛其致意於菊者八因作八首 四曰塵爵耻虛罍寒華徒自榮','方回','宋','宋诗','song-poetry','','[]','杯空無酒非瓶恥，恥在虛罍敢怨嗟。',32,'全唐诗/poet.song.232000.json','["杯空無酒非瓶恥，恥在虛罍敢怨嗟。", "想見此翁不憔悴，天寒猶自有榮花。"]'),
('81838f8d-61a2-41b3-976c-b00cb46f8d03','讀陶集愛其致意於菊者八因作八首 五曰芳菊開林耀青松冠岩列懷此貞秀姿卓爲霜下傑','方回','宋','宋诗','song-poetry','','[]','人間紅葉去無蹤，膏沐誰爲百草容。',32,'全唐诗/poet.song.232000.json','["人間紅葉去無蹤，膏沐誰爲百草容。", "霜傑同時謚貞秀，抗衡惟許老蟠龍。"]'),
('ab2c06a9-a22e-4776-9d45-49452361c5fe','讀陶集愛其致意於菊者八因作八首 六曰採菊東籬下悠然見南山','方回','宋','宋诗','song-poetry','','[]','採採東籬迹易尋，悠然見處孰知心。',32,'全唐诗/poet.song.232000.json','["採採東籬迹易尋，悠然見處孰知心。", "也曾目送飛鴻否，誰不能揮叔夜琴。"]'),
('f1d07740-2c21-4c69-aefd-44608b7eaad9','讀陶集愛其致意於菊者八因作八首 七曰秋菊有佳色裛露掇其英','方回','宋','宋诗','song-poetry','','[]','飲酒成詩二十篇，詩成多在菊花邊。',32,'全唐诗/poet.song.232000.json','["飲酒成詩二十篇，詩成多在菊花邊。", "秋英掇取枝頭露，想見朝朝起卯前。"]'),
('d88b58b2-747d-4387-a8fc-9689b6b029ea','讀陶集愛其致意於菊者八因作八首 八曰松菊猶存','方回','宋','宋诗','song-poetry','','[]','種松今世見松老，種菊常年見菊開。',32,'全唐诗/poet.song.232000.json','["種松今世見松老，種菊常年見菊開。", "十一月霜花欲槁，巾車豈可更遲迴。"]'),
('f1cdc202-15aa-4f69-8c02-20caf6e754b1','丙申重九前後得今日都無病一句成十首  其一','方回','宋','宋诗','song-poetry','','[]','今日都無病，清晨獨倚樓。',48,'全唐诗/poet.song.232000.json','["今日都無病，清晨獨倚樓。", "端能常自遣，孰謂不堪憂。", "老謝人間事，寒添雨後秋。", "江天詩滿眼，可似賈胡留。"]'),
('34beca24-971a-481a-9ee6-682a8186bb37','丙申重九前後得今日都無病一句成十首  其二','方回','宋','宋诗','song-poetry','','[]','今日都無病，康强百不憂。',48,'全唐诗/poet.song.232000.json','["今日都無病，康强百不憂。", "近霜黄菊月，過雨紫蘭秋。", "可醉豈容避，欲歸遄復休。", "寒衣漿補辦，此外更何求。"]'),
('7945aa31-4b26-478a-a807-26f481746635','丙申重九前後得今日都無病一句成十首  其三','方回','宋','宋诗','song-poetry','','[]','今日都無病，沉吟算此生。',48,'全唐诗/poet.song.232000.json','["今日都無病，沉吟算此生。", "誓將全晚節，懶復問脩程。", "畏事防憂患，收心入老成。", "近時學康節，更敢競時名。"]'),
('d1361314-e63d-47c8-a85a-d6188b81ce8a','丙申重九前後得今日都無病一句成十首  其四','方回','宋','宋诗','song-poetry','','[]','今日都無病，今年粗慰心。',48,'全唐诗/poet.song.232000.json','["今日都無病，今年粗慰心。", "西風田畯喜，南斗歲星臨。", "人老顔如雪，家貧菊似金。", "典衣作重九，猶可一杯斟。"]'),
('621da4e8-7f97-4f3a-b545-0765037cbb33','丙申重九前後得今日都無病一句成十首  其五','方回','宋','宋诗','song-poetry','','[]','今日都無病，移盆看菊花。',48,'全唐诗/poet.song.232000.json','["今日都無病，移盆看菊花。", "極知詩易臠，唯苦酒難賒。", "政用匆匆過，何妨小小差。", "重陽七十度，大半在天涯。"]'),
('cb41a5da-28eb-450c-a03a-55c991e2629f','丙申重九前後得今日都無病一句成十首  其六','方回','宋','宋诗','song-poetry','','[]','今日都無病，重陽酒滿樽。',48,'全唐诗/poet.song.232000.json','["今日都無病，重陽酒滿樽。", "淺斟聊慰意，高枕恐消魂。", "杜老萸難得，陶家菊尚存。", "鄰人送糕果，遥憶小兒孫。"]'),
('c5f74103-2868-43ba-a283-6e4124a1f7a3','丙申重九前後得今日都無病一句成十首  其七','方回','宋','宋诗','song-poetry','','[]','今日都無病，黄花酒一觴。',48,'全唐诗/poet.song.232000.json','["今日都無病，黄花酒一觴。", "登臨憐老者，風雨過重陽。", "稔歲真希有，南天始欲凉。", "餘生容苟活，不敢昧蒼蒼。"]'),
('8e72778c-cdc8-41dd-99b5-49924b5ffca6','丙申重九前後得今日都無病一句成十首  其八','方回','宋','宋诗','song-poetry','','[]','今日都無病，重陽倏又過。',48,'全唐诗/poet.song.232000.json','["今日都無病，重陽倏又過。", "濁醪常醉好，佳菊未開多。", "豈必皆時節，焉容不嘯歌。", "一樽二三友，風雨奈予何。"]'),
('316085a4-ca9a-4f1d-b504-08662b483e13','丙申重九前後得今日都無病一句成十首  其九','方回','宋','宋诗','song-poetry','','[]','今日都無病，持杯得自如。',48,'全唐诗/poet.song.232000.json','["今日都無病，持杯得自如。", "空行萬里路，枉讀一生書。", "可奈多魔障，真當棄腐餘。", "休官十六載，此計未全疏。"]'),
('637ce106-79df-489f-908b-ab15b7fd4def','丙申重九前後得今日都無病一句成十首  其一○','方回','宋','宋诗','song-poetry','','[]','今日都無病，閒將往事思。',48,'全唐诗/poet.song.232000.json','["今日都無病，閒將往事思。", "不爲一己計，寧受百人欺。", "老鈍文章拙，溫恭禮數卑。", "臨風一杯酒，此意未全衰。"]'),
('3a9308f2-5e8a-429f-953c-b57f1d6d8daa','趙氏鄮山書院詩并序','方回','宋','宋诗','song-poetry','','[]','國學在國，鄉校在鄉。',200,'全唐诗/poet.song.232000.json','["國學在國，鄉校在鄉。", "在遂曰序，在黨曰庠。", "虞夏殷周，厥制彌詳。", "家亦有塾，以脩以藏。", "蒙而已養，長罔不臧。", "下而爲士，上而侯王。", "莫不有師，扶綱植常。", "生人之類，頼此以生。", "四海九州，以治以平。", "家德戶行，靡刑靡兵。", "豈若後世，喪實存名。", "業豈無齋，論亦有堂。", "所習伊何，止於詞章。", "剽竊掇拾，青紫爲榮。", "高虛卑淺，燭理弗明。", "亦儒其冠，亦公亦卿。", "鄮山之塾，誰實成之。", "匪有所覬，而斯營之。", "一聖百賢，厥廡煌煌。", "睎之則是，景行是行。"]'),
('bbe58bfc-6076-423f-bd9c-79848f1135cf','呈李讓臣就寄翰林閻學士','方回','宋','宋诗','song-poetry','','[]','鞭霆來自紫皇宮，天上綸言播德風。',64,'全唐诗/poet.song.232000.json','["鞭霆來自紫皇宮，天上綸言播德風。", "爲報玉堂真學士，猶憐雪鬢老詩翁。", "星明斗極璇霄北，水注蓬萊碧海東。", "身不能飛心獨往，承顔常在夢魂中。"]'),
('effaf157-9719-4c4c-8ac8-e78619b1aebe','久過重陽菊英粲然即事十首  其一','方回','宋','宋诗','song-poetry','','[]','早伴茱萸插帽紗，尚堪薦酒更堪茶。',32,'全唐诗/poet.song.232000.json','["早伴茱萸插帽紗，尚堪薦酒更堪茶。", "花邊行立花邊坐，不是閒花是菊花。"]'),
('e1bda538-c2a1-485d-8c58-2dad63a27b1b','久過重陽菊英粲然即事十首  其二','方回','宋','宋诗','song-poetry','','[]','種就株株攢萬蕊，摘多幹幹茁三椏。',32,'全唐诗/poet.song.232000.json','["種就株株攢萬蕊，摘多幹幹茁三椏。", "此詩兩句煩君聽，不是閒花是菊花。"]'),
('3dcdfdfb-3969-464f-a88f-4638aa2a1afc','久過重陽菊英粲然即事十首  其三','方回','宋','宋诗','song-poetry','','[]','倏過重陽幾一月，菊花更覺有精神。',32,'全唐诗/poet.song.232000.json','["倏過重陽幾一月，菊花更覺有精神。", "必重陽日始賞菊，此是人間最俗人。"]'),
('f868f72b-8174-4f5f-bfa1-290e2b3f708b','久過重陽菊英粲然即事十首  其四','方回','宋','宋诗','song-poetry','','[]','紫陽山下園五畝，一半教兒種菊花。',32,'全唐诗/poet.song.232000.json','["紫陽山下園五畝，一半教兒種菊花。", "霜漸濃時花更好，六年何事未還家。"]'),
('7949ff71-e92c-4b96-ade9-088387a24812','久過重陽菊英粲然即事十首  其五','方回','宋','宋诗','song-poetry','','[]','平生我解量人品，元亮真成晉伯夷。',32,'全唐诗/poet.song.232000.json','["平生我解量人品，元亮真成晉伯夷。", "我欲招魂無別物，剩將酒灑菊花枝。"]'),
('ffa44dc8-3b6b-4714-a9bb-e98969ad94f1','久過重陽菊英粲然即事十首  其六','方回','宋','宋诗','song-poetry','','[]','菊芳蘭秀幸同時，汾水劉郎語最悲。',32,'全唐诗/poet.song.232000.json','["菊芳蘭秀幸同時，汾水劉郎語最悲。", "誰果肖蘭誰肖菊，未知黄落又爲誰。"]'),
('88aa405c-a118-4556-b942-1443068037fc','久過重陽菊英粲然即事十首  其七','方回','宋','宋诗','song-poetry','','[]','風霜無畏最耐久，糞壤不資真自然。',32,'全唐诗/poet.song.232000.json','["風霜無畏最耐久，糞壤不資真自然。", "正則夕餐骨已換，凌江端作跨鰲仙。"]'),
('1633dee1-bf3b-43ed-9b2b-e7f09e65435c','久過重陽菊英粲然即事十首  其八','方回','宋','宋诗','song-poetry','','[]','把之手香嚼齒香，飫之燕之香肺腸。',32,'全唐诗/poet.song.232000.json','["把之手香嚼齒香，飫之燕之香肺腸。", "金英滿泛日百盞，何必帝鄉姑醉鄉。"]'),
('2f2e5e6b-c6d4-48b8-aa11-fbda3a4bde6d','久過重陽菊英粲然即事十首  其九','方回','宋','宋诗','song-poetry','','[]','有酒泛菊釂美酒，無酒嗅菊倚闌干。',32,'全唐诗/poet.song.232000.json','["有酒泛菊釂美酒，無酒嗅菊倚闌干。", "時人誰會先生意，常把霜枝子細看。"]'),
('29cb581d-5004-42c1-9679-55ee11a989b4','久過重陽菊英粲然即事十首  其一○','方回','宋','宋诗','song-poetry','','[]','江南菊花差晚開，把酒前蘭復後梅。',32,'全唐诗/poet.song.232000.json','["江南菊花差晚開，把酒前蘭復後梅。", "天公何嘗負此老，天下腐儒臣方回。"]'),
('43358ad1-ca67-4a0a-ab75-38f54c601708','喜宗兄端叟再會武林還暨陽二首  其一','方回','宋','宋诗','song-poetry','','[]','我亦七旬老，公爲兩歲兄。',48,'全唐诗/poet.song.232000.json','["我亦七旬老，公爲兩歲兄。", "共知吾輩拙，各頼此心平。", "江海逃簪紱，乾坤寢甲兵。", "喜逢又惜別，久幸蔭宗盟。"]'),
('bd610cdf-39b1-4968-afda-3babeb99f978','喜宗兄端叟再會武林還暨陽二首  其二','方回','宋','宋诗','song-poetry','','[]','兵間曾脫死，不意各年高。',48,'全唐诗/poet.song.232000.json','["兵間曾脫死，不意各年高。", "未覺才全盡，猶能氣頗豪。", "有詩嘗互看，無酒可同遨。", "吳越相思夢，誰云隔夜濤。"]'),
('953ad72d-744b-4a14-8fdd-3f3a94899c0f','漫興九首  其一','方回','宋','宋诗','song-poetry','','[]','吐納誰能較故新，更須大藥鍛金銀。',32,'全唐诗/poet.song.232000.json','["吐納誰能較故新，更須大藥鍛金銀。", "有詩傳世書傳子，自是人間不死人。"]'),
('b9ad65d0-691d-4b3e-ab96-518c523bfabc','漫興九首  其二','方回','宋','宋诗','song-poetry','','[]','洶洶戰場元不懼，恓恓貧巷亦無憂。',32,'全唐诗/poet.song.232000.json','["洶洶戰場元不懼，恓恓貧巷亦無憂。", "千金浪費如泥土，今日何人識故侯。"]'),
('978d1611-c2a3-4758-a6c1-a88281e95795','漫興九首  其三','方回','宋','宋诗','song-poetry','','[]','才到黄花有酒傾，今人動欲作淵明。',32,'全唐诗/poet.song.232000.json','["才到黄花有酒傾，今人動欲作淵明。", "瓶無儲粟夜無被，此事知君學未成。"]'),
('f96a1829-9f4d-42b9-a91d-f68cbdeb9651','漫興九首  其四','方回','宋','宋诗','song-poetry','','[]','餓信黥英遇漢皇，攀龍附鳳化侯王。',32,'全唐诗/poet.song.232000.json','["餓信黥英遇漢皇，攀龍附鳳化侯王。", "河豚魚毒亡身耳，何至身亡族亦亡。"]'),
('e9ec2b6c-f03e-4e4f-b690-0ce6cce242b5','漫興九首  其五','方回','宋','宋诗','song-poetry','','[]','陰陰白晝似昏黄，平地愁城萬里長。',32,'全唐诗/poet.song.232000.json','["陰陰白晝似昏黄，平地愁城萬里長。", "稻卧三秋常是雨，菊殘十月尚無霜。"]'),
('c9c37fc2-d0b3-48c5-b7d4-9ff379bb18e4','漫興九首  其六','方回','宋','宋诗','song-poetry','','[]','枕上半醒中酒病，樓前時過賣花聲。',32,'全唐诗/poet.song.232000.json','["枕上半醒中酒病，樓前時過賣花聲。", "千門萬戶俱更換，惟此依稀舊太平。"]'),
('21267f44-40fe-48e5-b4d5-d70e61035441','漫興九首  其七','方回','宋','宋诗','song-poetry','','[]','向人開口便言閒，每一題詩便說山。',32,'全唐诗/poet.song.232000.json','["向人開口便言閒，每一題詩便說山。", "請俸坐曹食粱肉，又聞滿考轉官班。"]'),
('8dae7718-3243-458b-a35b-1c3cf022a37b','漫興九首  其八','方回','宋','宋诗','song-poetry','','[]','興賦雍容誦麥陂，徐徐別頤用金椎。',32,'全唐诗/poet.song.232000.json','["興賦雍容誦麥陂，徐徐別頤用金椎。", "通身都是藏污罪，揖讓如儀解說詩。"]'),
('c57660f8-01a7-4065-b443-e144aca6e7d0','漫興九首  其九','方回','宋','宋诗','song-poetry','','[]','新莽窮姦卓極凶，姦人更有阿瞞雄。',32,'全唐诗/poet.song.232000.json','["新莽窮姦卓極凶，姦人更有阿瞞雄。", "紛紛豎子成何事，野火山林一燒空。"]'),
('85774783-4454-47a4-bfcc-2a9c3e1c6cd2','記火','方回','宋','宋诗','song-poetry','','[]','吾州斗大城，辛丑爇於火。',240,'全唐诗/poet.song.232000.json','["吾州斗大城，辛丑爇於火。", "予時年十五，天地一蜾蠃。", "竄身城北門，尚憶雙髻鬌。", "秋暑七月半，洶湧沸炎堁。", "日午饑無食，枝頭得梨果。", "不謂心尚孩，析薪未克荷。", "先君儒起家，負冤踣奔播。", "赭垣獲苟免，小宅亦云頗。", "先祖之舊居，竟弗脫此禍。", "二三叔父家，貲産素不夥。", "焚如既已酷，生理各坎軻。", "老者漸喪亡，頼嘗教敕我。", "田屋悉破散，江湖走一舸。", "掇科敭歷久，身幸青紫裹。", "中年營一區，稍於己意可。", "紫陽正面南，烏聊在其左。", "前榮藝花木，後圃蒔菜蓏。", "軍興盜賊起，萬卷破甑墮。", "乙未九月災，天特赦么麽。", "巋然七十翁，吾其理歸柁。"]'),
('b6b0f86d-17ba-4056-8ccd-515c3e234e17','雜興十二首  其一','方回','宋','宋诗','song-poetry','','[]','生世六六載，始獲玷末科。',84,'全唐诗/poet.song.232000.json','["生世六六載，始獲玷末科。", "選官六六載，仕少閒日多。", "逆旅脫兵火，專城免干戈。", "中原久隔絕，忽焉得經過。", "水涸梁山泊，淮流受黄河。", "往者故已矣，方來將若何。", "開歲七十一，聊擬自挽歌。"]'),
('2baad336-8783-41b5-adfc-07776a2ed4e3','雜興十二首  其二','方回','宋','宋诗','song-poetry','','[]','十月菊半槁，垂迫長至節。',96,'全唐诗/poet.song.232000.json','["十月菊半槁，垂迫長至節。", "炎州天氣殊，蟄戶猶未閉。", "北方當此時，無雨有爲雪。", "吳霖百晝夜，不見霜露結。", "瘦馬濺腐泥，裸袒舟子熱。", "老子所居隘，糞穢足嘔泄。", "西望萬重山，中有茅宇潔。", "何當歸去來，獨卧一榻設。"]'),
('89ba214e-bc48-4ebb-ac03-b7dc635ef81a','雜興十二首  其三','方回','宋','宋诗','song-poetry','','[]','詩禮以發塚，非獨王莽然。',72,'全唐诗/poet.song.232000.json','["詩禮以發塚，非獨王莽然。", "手不離珠玉，世豈一桓玄。", "昔在魯聞人，匪值孔聖旃。", "焉得兩觀誅，破彼辨與堅。", "子陵湍石上，元亮菊籬邊。", "夷齊不可跂，頼有此二賢。"]'),
('f33095ff-f633-414f-8b80-5a723de9c92a','雜興十二首  其四','方回','宋','宋诗','song-poetry','','[]','風高紫蘭摧，雪近黄菊槁。',96,'全唐诗/poet.song.232000.json','["風高紫蘭摧，雪近黄菊槁。", "物理有代謝，焉得長美好。", "古聖毓庶物，必欲使壽老。", "不幸凶短折，豈若保終考。", "莊生强齊物，妄謂彭聃夭。", "龜鶴動千齡，難與蜉蝣道。", "什襲夜光璧，誰忍碎茲寶。", "我評菊與蘭，終勝百凡草。"]'),
('6d0ba586-779e-4e3e-9197-7f79ab886ac1','雜興十二首  其五','方回','宋','宋诗','song-poetry','','[]','古人謹廟萃，後世重墓藏。',96,'全唐诗/poet.song.232000.json','["古人謹廟萃，後世重墓藏。", "埋骨冀裕後，其術傳青囊。", "富貴出葬穴，此說何渺茫。", "含襚富珠玉，所見尤不長。", "自從開闢來，天地幾戰場。", "禍亂遭發掘，不免帝與王。", "甚者有逆孫，暴其先世喪。", "何由繫彼頸，巨刃揮天揚。"]'),
('39bd49a7-d94d-4781-81ec-ff1dc9d90f48','雜興十二首  其六','方回','宋','宋诗','song-poetry','','[]','七十合致仕，已閒十六年。',72,'全唐诗/poet.song.232000.json','["七十合致仕，已閒十六年。", "不謂得此壽，念之豈非天。", "固窮甘蔬飯，窒慾省藥錢。", "脫遇人負我，微慍遄釋然。", "豈無不朽句，作詩垂萬篇。", "人品雖中中，此心無愧焉。"]'),
('f4294382-71be-4a14-ab48-2c6304d8cbcf','雜興十二首  其七','方回','宋','宋诗','song-poetry','','[]','茲辰何太喜，久雨見紅日。',96,'全唐诗/poet.song.232000.json','["茲辰何太喜，久雨見紅日。", "當其陰晦時，日未嘗不出。", "有物苦障之，雲霧暗如漆。", "讒夫蔽天明，忽去巷伯嫉。", "泥汙后土乾，歸路賃馿匹。", "山中可釀酒，自舂元亮秫。", "預量小兒孫，時索梨與栗。", "茅簷得霜晴，炙背閲書帙。"]'),
('35dfa2d0-3e94-4f14-b920-628d156670fb','雜興十二首  其八','方回','宋','宋诗','song-poetry','','[]','稻熟苦淫雨，九月盡十月。',96,'全唐诗/poet.song.232000.json','["稻熟苦淫雨，九月盡十月。", "已刈及未刈，半芽半漂沒。", "饑飽係民命，此變豈可忽。", "雲師如葛伯，仇餉佚天罰。", "死木生菌蕈，化螢草未歇。", "恒燠繆爲恩，乖氣一何悖。", "何如時寒風，霜晴大明揭。", "田父得舂枕，一飯肉白骨。"]'),
('5721a03a-8bd5-45ac-a976-7881513c711e','雜興十二首  其九','方回','宋','宋诗','song-poetry','','[]','人固有倒行，天亦有逆施。',72,'全唐诗/poet.song.232000.json','["人固有倒行，天亦有逆施。", "膾肝富且壽，沴氣乃至茲。", "歲旱茂稊稗，夜暗號鴞鴟。", "正卯宜一律，遇塗姑巽辭。", "麟經沒其名，直以盜書之。", "萬古流惡聲，榮華能幾時。"]'),
('cf19fa47-6abe-4730-bbf2-08fd8f7a8b9e','雜興十二首  其一○','方回','宋','宋诗','song-poetry','','[]','勢位高於己，諂子奴事之。',96,'全唐诗/poet.song.232000.json','["勢位高於己，諂子奴事之。", "虎後狐前行，假威將誰欺。", "才藝卑於己，苟且相追隨。", "庶幾不見軏，延譽借諛辭。", "老夫久擇交，此心故異茲。", "勿攀勢位高，毋友才藝卑。", "章惇招不往，豐谷以爲師。", "彭城陳正字，貽我有良規。"]'),
('7d91f832-21aa-4619-9f0d-910502c38e2d','雜興十二首  其一一','方回','宋','宋诗','song-poetry','','[]','請託或有求，攀附謂可羨。',72,'全唐诗/poet.song.232000.json','["請託或有求，攀附謂可羨。", "不羨復不求，貴公何必見。", "恥折元亮腰，免向宣明面。", "江淹所賦恨，未必識馮衍。", "甘從伯倫醉，久忘子夏戰。", "白首爾同歸，自作豈天譴。"]'),
('7380c5f8-a08c-410a-887f-d18c10dc1421','雜興十二首  其一二','方回','宋','宋诗','song-poetry','','[]','魯論安昌侯，田至二百頃。',96,'全唐诗/poet.song.232000.json','["魯論安昌侯，田至二百頃。", "後堂羅曲旃，女樂極妍靚。", "晚愛肥牛亭，僣上輒有請。", "行內憂外家，略不效忠鯁。", "口張理義門，胸裹利欲穽。", "持國送與人，獨欲保首領。", "焉知赤眉禍，暴尸肉未冷。", "寄言發塚儒，厥報捷響影。"]'),
('bd5d2fae-1fe0-4449-a190-9e0d7dd20794','送述明居士燕道覺歸東林','方回','宋','宋诗','song-poetry','','["\u5e90\u5c71", "\u897f\u6e56"]','君不見錢塘西湖三賢堂，林蘇宋人白傅唐。',236,'全唐诗/poet.song.232000.json','["君不見錢塘西湖三賢堂，林蘇宋人白傅唐。", "三賢生本不相識，死乃異代同蒸嘗。", "又不見吳江垂虹三高祠，鴟夷一舸浮西施。", "天隨陸子玄真子，求志逃名非一時。", "何似廬山東林三大老，生偶同時不同道。", "道若不同同中心，香爐峰下足幽討。", "雁門法師禪非禪，虎溪道士仙非仙。", "栗里先生醉非醉，三方寸地通一天。", "妥靈猶想當時笑，鼎立宇宙膽相照。", "借問此笑笑者何，別有丹青不傳妙。", "述明棄官歸東林，玉帝降敕榮冠簪。", "羽衣似與儒釋異，所不異者胸中心。", "我謂不須較同異，亦勿强求笑中意。", "天下至今知幾晉法當忘言，祖述淵明醉還醉。"]'),
('a3f320a2-2c1a-4897-b26f-148b2a8c2559','循分','方回','宋','宋诗','song-poetry','','[]','閒與蒼穹酹一杯，誓將坦蕩答疏恢。',64,'全唐诗/poet.song.232000.json','["閒與蒼穹酹一杯，誓將坦蕩答疏恢。", "誰非身住蓬萊島，汝自心生灧澦堆。", "事久終難逃定論，運亨豈必藉高才。", "墮膚裂指河冰合，自有春風到早梅。"]'),
('6bcde824-e3a6-410b-aba2-82bf7f761d4b','挽分水柳溪何處士二首  其一','方回','宋','宋诗','song-poetry','','[]','太學師名士，初踰志學年。',48,'全唐诗/poet.song.232000.json','["太學師名士，初踰志學年。", "樹蘐竭甘旨，肯室擅林泉。", "盜踵兵戈起，家并里社全。", "陳蕃舊懸榻，惜未致斯賢。"]'),
('5d84ade3-0cdd-4d77-b287-81e2a1362b20','挽分水柳溪何處士二首  其二','方回','宋','宋诗','song-poetry','','[]','歷數更端後，英雄崛起間。',48,'全唐诗/poet.song.232000.json','["歷數更端後，英雄崛起間。", "子真逃谷口，甪里老商顔。", "德共三槐遠，名堪五柳攀。", "知賢慚拙守，論譔幸藏山。"]'),
('432d2665-2ab0-4b45-be00-e96e8b44fef1','日長至寓杭  其一','方回','宋','宋诗','song-poetry','','[]','閒身不想入鵷行，家近何分客與鄉。',64,'全唐诗/poet.song.232000.json','["閒身不想入鵷行，家近何分客與鄉。", "所喜今年年最稔，又逢此日日初長。", "雲容頓改不爲雨，雪意尚慳仍作霜。", "豈意老翁開八袠，朋來聊與共清觴。"]'),
('c6ffde02-6c9c-4dd1-9d88-d1b111ad26d6','日長至寓杭  其二','方回','宋','宋诗','song-poetry','','[]','自從丱角至童顛，是事無心總聽天。',64,'全唐诗/poet.song.232000.json','["自從丱角至童顛，是事無心總聽天。", "今日喜逢長至日，來年恰遇古希年。", "一官三紀閒居半，萬馬千軍命偶全。", "適有蜜蜂肯伴我，晴香爛醉玉梅前。"]'),
('64f56857-1714-4b79-8551-5fb83065066d','送張子敬湖南宣慰司都事','方回','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','湘水綠，湘山青。',168,'全唐诗/poet.song.232000.json','["湘水綠，湘山青。", "南衡嶽，北洞庭。", "太微翼軫相緯經。", "上直長沙老人星，其下潭府甲南溟。", "有芷彌岸蘭彌汀，騷人墨客紉芳馨。", "丹砂黄金翡翠翎，日中百賈喧雷霆。", "艷舞皓歌酣旗亭，王宮細腰誇娉婷。", "如斗如蜜餐楚萍，誰其能賦弔獨醒。", "厥今宣幕小朝廷，如君人物猶典刑。", "可振儒鐸鳴道鈴，無使斯文淪晦冥。", "南軒大名揭南斗，南軒舊軒無恙否。", "君能一出扶顛手，亦足與之同不朽。"]'),
('fb455174-1541-483f-8220-d6ba1792fc0a','追次郡君至節韻','方回','宋','宋诗','song-poetry','','[]','天地育萬物，風霜非作威。',96,'全唐诗/poet.song.232000.json','["天地育萬物，風霜非作威。", "陰陽互闔闢，造化潜玄機。", "凍樹根本固，宿莽芽甲微。", "外貌若槁死，其中春已歸。", "志士甘隠處，栖栖將疇依。", "龍蛇蟄深窟，肯嘆寒無衣。", "三變復爲泰，鬼神不能違。", "雷霆行且起，梅邊玩晴暉。"]'),
('45578da5-1667-4b8f-b5ed-debc93d1efa8','寄老山張鵬飛御史','方回','宋','宋诗','song-poetry','','[]','通袖風霜手，揮毫雅頌音。',48,'全唐诗/poet.song.232000.json','["通袖風霜手，揮毫雅頌音。", "柄臣曾見憚，素士許同吟。", "包括滄溟淺，蜚騰歲月深。", "一朝夢惟肖，槁草仰商霖。"]'),
('99b35ceb-c618-467d-8474-e1861d087f31','寄集賢閻子靜學士','方回','宋','宋诗','song-poetry','','[]','新年七十一衰翁，此道心知萬折東。',64,'全唐诗/poet.song.232000.json','["新年七十一衰翁，此道心知萬折東。", "名位集賢唐學士，文章內相陸宣公。", "兩朝綸浡傾前古，四海紳緌立下風。", "手把一枝梅欲寄，江南歲暮待春鴻。"]'),
('ffec59c5-e291-4752-a450-e6f30aec5e1c','紙窗','方回','宋','宋诗','song-poetry','','[]','梅水仙花插古銅，紙窗通日不通風。',32,'全唐诗/poet.song.232000.json','["梅水仙花插古銅，紙窗通日不通風。", "天香何假龍涎爇，地暖無勞獸炭烘。"]'),
('38831034-320e-4028-95ca-60ec48e3e57a','閉戶','方回','宋','宋诗','song-poetry','','[]','閉戶瓶梅滿屋香，小樓微醉月昏黄。',32,'全唐诗/poet.song.232000.json','["閉戶瓶梅滿屋香，小樓微醉月昏黄。", "三更獨坐猶無寐，更欲移花近枕傍。"]'),
('8e84d1b5-827d-4673-aa11-9cb12174fa8b','題譯學張提舉乃尊開封府尹張彥亨所藏郭熙盤車圖','方回','宋','宋诗','song-poetry','','[]','車轣轆，牛觳觫。',344,'全唐诗/poet.song.232000.json','["車轣轆，牛觳觫。", "積雪皚皚，飛雪䔩䔩。", "前車上嶺後車續，老牛服箱顧寒犢。", "高雪彌山，低雪滿谷。", "戴笠執鞭，凍腰跼曲。", "畫師畫此何年事，關塞遠征輓芻粟。", "莫道牛疲項領禿，人疲於牛痛欲哭。", "峻嶺之下舊村落，蕭灑人煙知幾簇。", "莫道餉車過門外，門內田家眠正熟。", "百車千車過不已，敲門乞索何時足。", "牛豈不需藁一束，人豈不取一匙粥。", "雞犬不可保，妻子或竄伏。", "畫中水閣爾整齊，焉知不是逃亡屋。", "我聞造化心至公，人間乃有兩般風。", "庶民雌風扇臭穢，何獨楚王之風雄。", "天地山川同一雪，眼見雪同心各別。", "梁園才子簡欲授，栘監老臣氈自齧。", "貧人閉戶洛陽卧，壯士銜枚蔡州滅。", "紅爐錦帳羔酒斟，豈識盤車圖中意愁絕。", "春日陌上花，同遨擲果車，不爾鰥翁嫠婦對花成咨嗟。", "秋夜樓上月，同醉生塵襪，不爾羈臣逐客對月翻淒咽。", "嗚呼身在雪嶺盤車圖，還知世有子猷訪戴無。"]'),
('289cdbba-518e-45d8-9bbc-c068aa12a669','二十三日大雪彌甚','方回','宋','宋诗','song-poetry','','[]','壓船塞戶路迷途，絮帽氈衣馬緩驅。',64,'全唐诗/poet.song.232000.json','["壓船塞戶路迷途，絮帽氈衣馬緩驅。", "一夜遽然三尺許，萬家歡謂幾年無。", "美觀頓覺湖山改，生意潜迴草木枯。", "麵賤米平來歲事，饑民誰與續朝晡。"]'),
('a3cddd6d-129b-4590-a739-1204d69e46e9','回生丁亥方端叟乙酉長二歲其弟名萬里庚寅少三歲用予舊韻來訂兄弟之盟依韻奉答二首  其一','方回','宋','宋诗','song-poetry','','[]','聞說庚寅弟，兼思乙酉兄。',48,'全唐诗/poet.song.232000.json','["聞說庚寅弟，兼思乙酉兄。", "樓高江樹遠，帆去暮潮平。", "藥豈能延壽，符焉可避兵。", "各憑心事好，共保歲寒盟。"]'),
('88614793-372e-489a-9476-8a99f97fca30','回生丁亥方端叟乙酉長二歲其弟名萬里庚寅少三歲用予舊韻來訂兄弟之盟依韻奉答二首  其二','方回','宋','宋诗','song-poetry','','[]','越州兄弟好，年與德俱高。',48,'全唐诗/poet.song.232000.json','["越州兄弟好，年與德俱高。", "未覺同宗吝，寧須蓋代豪。", "雪爐稱夜坐，花墅接春遨。", "何日成三老，茶甌瀹碧濤。"]'),
('3f701f92-0b25-4c06-a38a-c95b9bfe38d6','二十七日又大雪凡半月','方回','宋','宋诗','song-poetry','','[]','茂林枯樹總模糊，半月簷聲乍有無。',64,'全唐诗/poet.song.232000.json','["茂林枯樹總模糊，半月簷聲乍有無。", "天鼓北風神轉王，地窮南海瘴全蘇。", "戰鼙戍角夜烽火，旅棹征鞍朝道途。", "辛苦一生亦奇絕，暮年猶許畫寒爐。"]'),
('d156e3c5-c92e-47c1-88d1-8b54080e13ab','二十八日殘雪不消懷舊','方回','宋','宋诗','song-poetry','','[]','老眼今猶見雪明，幾番絕景慰生平。',64,'全唐诗/poet.song.232000.json','["老眼今猶見雪明，幾番絕景慰生平。", "三高祠畔吳江棹，百戰軍前鄂漢城。", "顛沛艱難垂欲死，登臨慷慨謾多情。", "駱駝乳紫青貂暖，老矣無由再玉京。"]'),
('009c9e6e-0271-477d-ba29-66d5915ce1b0','二十九日歲除','方回','宋','宋诗','song-poetry','','[]','六十年前幼學兒，端平明日改嘉熙。',64,'全唐诗/poet.song.232000.json','["六十年前幼學兒，端平明日改嘉熙。", "黟川亡妹來歸日，歙隴先君改葬時。", "學問文章成畫餠，科名官爵著饒棋。", "細思未覺家聲墜，能忍窮人不是癡。"]'),
('0f54d5d5-d1f5-4fb6-a483-cf97503d698c','丁酉元日年七十一  其一','方回','宋','宋诗','song-poetry','','[]','晚節詩如白樂天，每逢元日有新篇。',64,'全唐诗/poet.song.232000.json','["晚節詩如白樂天，每逢元日有新篇。", "九臚唱第今三紀，七袠開端又一年。", "風雪五更憐過馬，兒孫百指望歸船。", "老身窮健無煩惱，猶倚文章賣酒錢。"]'),
('fa34c95a-e526-4c77-9957-5c250cc64411','丁酉元日年七十一  其二','方回','宋','宋诗','song-poetry','','[]','扶胥灣口鐵山頭，汗漫空爲萬里遊。',64,'全唐诗/poet.song.232000.json','["扶胥灣口鐵山頭，汗漫空爲萬里遊。", "一第僅如晁濟北，萬詩堪繼陸嚴州。", "可用老扶靈壽杖，也曾親到結鄰樓。", "餘生無所求於世，今世何人識故侯。"]'),
('013c06a1-b40b-49dd-8b96-6938ea638a13','元日感事','方回','宋','宋诗','song-poetry','','[]','羞將白髪見青春，世事何關蟣虱臣。',64,'全唐诗/poet.song.232000.json','["羞將白髪見青春，世事何關蟣虱臣。", "去就時難千里夢，是非論定百年身。", "偶然不死由天地，尚可無慚對鬼神。", "敢問名垂漢唐史，蕭曹房杜本何人。"]'),
('a58de14f-2e33-4fa4-9fbb-b6fac31d02dd','贈方童子','方回','宋','宋诗','song-poetry','','[]','我年五十九，門弧子垂左。',288,'全唐诗/poet.song.232000.json','["我年五十九，門弧子垂左。", "我今年七十，見子雙髻鬌。", "腹僅椰子大，貯書一何夥。", "疾讀建瓴水，響應炙車輠。", "光怪蟠肺腸，不啻珠萬顆。", "小松三尺許，千丈氣磊砢。", "近笑韓氏子，瑟僩了細瑣。", "遠笑陶翁兒，但解覓梨果。", "我年如子時，記誦亦云頗。", "舉苕乃遺帚，一懶萬事墮。", "願子於心田，及時勇耕播。", "秋成斂精鑿，糠粃勤篩簸。", "子之名曰燧，此語本宰我。", "拾舊新是圖，學問甚改火。", "字之曰又新，進業幸勿惰。", "譬如萬里途，幸已餱糧裹。", "一旦輟于行，駿馬同鱉跛。", "近世文字繁，動輒百篋鎖。", "誰能發蠹魚，丹鉛拂埃堁。", "手之而口之，五夜孤燈坐。", "林下時思之，解衣盤薄臝。", "六經四書外，一一與探揣。", "鵬鯨大胾嘬，餘子或螟蠃。", "又新有如此，名世豈不可。"]'),
('4c6dd41f-a13f-4c66-bb2e-064c71ad48ab','元夕前雨不已二首  其一','方回','宋','宋诗','song-poetry','','[]','節屆燒燈奈若何，客樓三夜聽霶𩃱。',32,'全唐诗/poet.song.232000.json','["節屆燒燈奈若何，客樓三夜聽霶𩃱。", "春風有意催花信，小雨如酥不用多。"]'),
('0c7661f9-298d-45cb-bd4c-467acd2cd7cf','元夕前雨不已二首  其二','方回','宋','宋诗','song-poetry','','[]','蘭膏畫炬出貧民，寶馬香車屬貴人。',32,'全唐诗/poet.song.232000.json','["蘭膏畫炬出貧民，寶馬香車屬貴人。", "月姊雨師暗商榷，不須粧點上元春。"]'),
('4be9dda5-f6c6-4b54-9a70-9b5e06a99e3b','清湖早春  其一','方回','宋','宋诗','song-poetry','','[]','曉窗初起望春雲，天色陰晴未十分。',32,'全唐诗/poet.song.232000.json','["曉窗初起望春雲，天色陰晴未十分。", "小雨漫空渾不覺，平湖點點見圓紋。"]'),
('9831bcad-c1a2-4f55-9872-989b3308b4a3','清湖早春  其二','方回','宋','宋诗','song-poetry','','[]','岸邊老樹柳猶枯，紅入桃花果有無。',32,'全唐诗/poet.song.232000.json','["岸邊老樹柳猶枯，紅入桃花果有無。", "一夜綠從冰底起，誰將藍汁染晴湖。"]'),
('01dd1a08-2701-4eee-8ba1-65101d765d07','湖曲細嚼梅花嚥酒','方回','宋','宋诗','song-poetry','','[]','梅心微苦似梅仁，細嚼香鬚酒入唇。',32,'全唐诗/poet.song.232000.json','["梅心微苦似梅仁，細嚼香鬚酒入唇。", "笑指逋仙墳上土，一杯好與酹芳辛。"]'),
('65b669ab-85f9-47f7-8ffb-a652b534a0c6','飲孤山六一泉有感','方回','宋','宋诗','song-poetry','','[]','解后猶存石柱梁，周家九鼎尚淪亡。',32,'全唐诗/poet.song.232000.json','["解后猶存石柱梁，周家九鼎尚淪亡。", "此泉只是尋常水，爲有歐蘇姓字香。"]'),
('d30353ef-c9bd-4f57-a3db-5e9b23d0d166','兩鄰家一主人群姬歌飲至夜半一母妻哭官檢魘死者','方回','宋','宋诗','song-poetry','','[]','歌喉弦指粉紅腮，群擁山翁醉玉頹。',32,'全唐诗/poet.song.232000.json','["歌喉弦指粉紅腮，群擁山翁醉玉頹。", "政恐真歡猶是假，不如鄰婦哭真哀。"]'),
('2a0874c4-49cc-4662-92d8-044657b7c219','記正月二十五日西湖之遊十五首  其一','方回','宋','宋诗','song-poetry','','["\u897f\u6e56"]','來輿去馬禁城空，豐樂樓消一炬紅。',32,'全唐诗/poet.song.232000.json','["來輿去馬禁城空，豐樂樓消一炬紅。", "說與吳儂莫惆悵，龍墀猶化梵王宮。"]'),
('1de41585-0b70-4cd8-ae8f-fb4c12771d13','記正月二十五日西湖之遊十五首  其二','方回','宋','宋诗','song-poetry','','["\u897f\u6e56"]','情知太乙已西遊，築館焉能强挽留。',32,'全唐诗/poet.song.232000.json','["情知太乙已西遊，築館焉能强挽留。", "此老平生讓人者，佛來我去尚何求。"]'),
('6e7c2156-088b-406b-9f0b-5ee5f8e9b968','記正月二十五日西湖之遊十五首  其三','方回','宋','宋诗','song-poetry','','["\u897f\u6e56"]','一夜緇郎剗醮壇，三清四聖化泥團。',32,'全唐诗/poet.song.232000.json','["一夜緇郎剗醮壇，三清四聖化泥團。", "也曾輸與林靈素，頂上曾纓德士冠。"]'),
('bde7764e-f1e1-46aa-8a01-ba86f00b9701','記正月二十五日西湖之遊十五首  其四','方回','宋','宋诗','song-poetry','','["\u897f\u6e56"]','千樹梅花斫半無，有人更欲涸西湖。',32,'全唐诗/poet.song.232000.json','["千樹梅花斫半無，有人更欲涸西湖。", "曾思慎勿近前日，不看老彭觀井圖。"]'),
('6da03de9-cb1b-40c1-bd05-ed579eb22000','記正月二十五日西湖之遊十五首  其五','方回','宋','宋诗','song-poetry','','["\u897f\u6e56"]','石梁石柱石爲碑，山拔泉飛石可移。',32,'全唐诗/poet.song.232000.json','["石梁石柱石爲碑，山拔泉飛石可移。", "兩玉堂仙一髠叟，自應名字萬年垂。"]'),
('d23c549b-91ec-4e9a-a571-ed6b308a3b96','記正月二十五日西湖之遊十五首  其六','方回','宋','宋诗','song-poetry','','["\u897f\u6e56"]','空埋貞觀蘭亭字，再出文城玉枕書。',32,'全唐诗/poet.song.232000.json','["空埋貞觀蘭亭字，再出文城玉枕書。", "想見八梅塚無物，生前曾笑馬相如。"]'),
('884a2c61-5a24-403e-a506-c1e2b3d1cf43','記正月二十五日西湖之遊十五首  其七','方回','宋','宋诗','song-poetry','','["\u897f\u6e56"]','身爲帝傅辯章公，慎恤奇丸侈後宮。',32,'全唐诗/poet.song.232000.json','["身爲帝傅辯章公，慎恤奇丸侈後宮。", "更欲長生汲丹井，山中笑倒葛仙翁。"]'),
('eb5fb85e-788a-4cee-8a71-e5e7fbe7cd8b','記正月二十五日西湖之遊十五首  其八','方回','宋','宋诗','song-poetry','','["\u897f\u6e56"]','炎炎赫赫忽荒寒，敗瓦頹牆百頃寬。',32,'全唐诗/poet.song.232000.json','["炎炎赫赫忽荒寒，敗瓦頹牆百頃寬。", "誰識舊朝大丞相，手携紅妓倚闌干。"]'),
('218d23bb-d5bc-472c-a8f1-bc6af19f0534','記正月二十五日西湖之遊十五首  其九','方回','宋','宋诗','song-poetry','','["\u897f\u6e56"]','容堂何地可容人，一語忠規坐殺身。',32,'全唐诗/poet.song.232000.json','["容堂何地可容人，一語忠規坐殺身。", "母死明年爾亦死，盜名猶謂再庚申。"]'),
('f1017fb2-488e-49a4-8038-e2d5c30fac8d','記正月二十五日西湖之遊十五首  其一○','方回','宋','宋诗','song-poetry','','["\u897f\u6e56"]','一犁酥潤萬牛耕，飯碗人間係死生。',32,'全唐诗/poet.song.232000.json','["一犁酥潤萬牛耕，飯碗人間係死生。", "公子樓頭賞春雨，杏花樹上聽新鶑。"]'),
('22a1776d-b17f-45f5-9ec8-93436e06e6a3','記正月二十五日西湖之遊十五首  其一一','方回','宋','宋诗','song-poetry','','["\u897f\u6e56"]','千山斫入亞夫營，佳墅名園怕近城。',32,'全唐诗/poet.song.232000.json','["千山斫入亞夫營，佳墅名園怕近城。", "頼是白公資佛力，小留蒼翠作秋聲。"]'),
('d665f414-a84c-44b1-a85c-b996ce6ea442','記正月二十五日西湖之遊十五首  其一二','方回','宋','宋诗','song-poetry','','["\u897f\u6e56"]','業已通名敢退無，小爲性命忍須臾。',32,'全唐诗/poet.song.232000.json','["業已通名敢退無，小爲性命忍須臾。", "十年朝士知何限，不許遊湖許見湖。"]'),
('62364753-033e-459b-8650-f425f2d32abe','記正月二十五日西湖之遊十五首  其一三','方回','宋','宋诗','song-poetry','','["\u897f\u6e56"]','相逢劍客曳長巾，曾道西湖看盡人。',32,'全唐诗/poet.song.232000.json','["相逢劍客曳長巾，曾道西湖看盡人。", "石屋雨來春樹暗，人琴兩已作埃塵。"]'),
('44ae413e-0b68-4002-8bdf-56d323bd5f65','記正月二十五日西湖之遊十五首  其一四','方回','宋','宋诗','song-poetry','','["\u897f\u6e56"]','六橋簫鼓日喧天，誰料年來漸索然。',32,'全唐诗/poet.song.232000.json','["六橋簫鼓日喧天，誰料年來漸索然。", "興廢榮枯都不識，一家活計一漁船。"]'),
('72e1fcea-a28b-402d-a4eb-b5b92da535cf','記正月二十五日西湖之遊十五首  其一五','方回','宋','宋诗','song-poetry','','["\u897f\u6e56"]','蘇公堤畔水如天，又見侵疆築葑田。',32,'全唐诗/poet.song.232000.json','["蘇公堤畔水如天，又見侵疆築葑田。", "遥望橫斜似棋局，飛烏翹鷺自爭先。"]'),
('56f2b234-5fc8-4e21-967e-89d73c43b6ed','清湖春早二首  其一','方回','宋','宋诗','song-poetry','','[]','半河樓影半河天，未有行人趁早船。',32,'全唐诗/poet.song.232000.json','["半河樓影半河天，未有行人趁早船。", "閒聽賣花聲自好，可須多費買花錢。"]'),
('b1d738c1-5d35-4941-8871-af49574bf2a9','清湖春早二首  其二','方回','宋','宋诗','song-poetry','','[]','樓上春陰覆曉雲，一河天淨碧沄沄。',32,'全唐诗/poet.song.232000.json','["樓上春陰覆曉雲，一河天淨碧沄沄。", "雨宜不驟風宜細，閒倚闌干看水紋。"]'),
('fdc215f9-a56e-4f11-a724-811fce31dabd','二月十五日趙君實南山別墅俟主客俱不至','方回','宋','宋诗','song-poetry','','[]','籬落梅殘野菜青，田間閒看鶴梳翎。',32,'全唐诗/poet.song.232000.json','["籬落梅殘野菜青，田間閒看鶴梳翎。", "主人不到客且去，細雨南山暗畫屏。"]'),
('bd99073d-1868-4a6c-831e-9e7932a8dc87','垂欲歸主客皆至','方回','宋','宋诗','song-poetry','','[]','荒林野塚古原頭，倚樹何人識故侯。',32,'全唐诗/poet.song.232000.json','["荒林野塚古原頭，倚樹何人識故侯。", "幽僻閴寥變歡笑，針鋒芥子忽相投。"]'),
('de824f76-04ab-4b63-acb7-a830c3373646','三賢堂已無官賣其址','方回','宋','宋诗','song-poetry','','[]','三賢無像亦無堂，敗柳猶垂赤土牆。',32,'全唐诗/poet.song.232000.json','["三賢無像亦無堂，敗柳猶垂赤土牆。", "官賣神祠有前例，熙寧丞相起坊場。"]'),
('085b5b4b-2380-407a-bd61-5cb9234dea79','三賢堂移入西湖新書院','方回','宋','宋诗','song-poetry','','["\u897f\u6e56"]','湖邊莫怪舊祠荒，士女何曾炷瓣香。',32,'全唐诗/poet.song.232000.json','["湖邊莫怪舊祠荒，士女何曾炷瓣香。", "頼是人心猶未泯，深衣迎奉入書堂。"]'),
('1080cf86-16b1-402a-ac18-9080e07a0977','集賢堂已無','方回','宋','宋诗','song-poetry','','[]','舊日三賢又集賢，看人歌舞過湖船。',32,'全唐诗/poet.song.232000.json','["舊日三賢又集賢，看人歌舞過湖船。", "一時去取非公論，到底終難昧老天。"]'),
('3aa7cd69-2ad3-47a9-ba27-dcd29b566144','湖山堂再修僅有','方回','宋','宋诗','song-poetry','','[]','飛鳥穿堂柱半欹，春晴猶不似春時。',32,'全唐诗/poet.song.232000.json','["飛鳥穿堂柱半欹，春晴猶不似春時。", "上梁文記臨邛魏，天目洪家却立碑。"]'),
('b71dfddd-cdda-486a-8394-a4099ede5f87','南高峰至其下不高','方回','宋','宋诗','song-poetry','','[]','遠望生愁陟降勞，崢嶸窣堵據金鰲。',32,'全唐诗/poet.song.232000.json','["遠望生愁陟降勞，崢嶸窣堵據金鰲。", "今朝身到南山下，漸近元來總不高。"]'),
('61672240-5f06-4dde-8a85-7c7e636d3523','北高峰屢欲登而輟','方回','宋','宋诗','song-poetry','','[]','擬上高峰最上頭，籃輿已賃又還休。',32,'全唐诗/poet.song.232000.json','["擬上高峰最上頭，籃輿已賃又還休。", "舊來詩眼如今別，添與江南一段愁。"]'),
('2bee0304-aa87-4e36-bdc3-d1242e8a2684','左顧保叔塔右顧雷峰塔并南北高峰塔爲四','方回','宋','宋诗','song-poetry','','[]','四山角立四浮屠，絕似雙林競寶珠。',32,'全唐诗/poet.song.232000.json','["四山角立四浮屠，絕似雙林競寶珠。", "萬古一丸拏不去，夜深朗月浸澄湖。"]'),
('20ab7b03-1211-4ee3-a3a8-9f0add714d75','中望吳山下一汀是爲杭州','方回','宋','宋诗','song-poetry','','[]','秦皇繫纜北山頭，一抹江邊海變洲。',32,'全唐诗/poet.song.232000.json','["秦皇繫纜北山頭，一抹江邊海變洲。", "百萬生人無葬處，蝸爭蟻戰不如休。"]'),
('5ba44898-c0df-4dbd-ae63-49133f111a3e','哭鮑景翔魯齋  其一','方回','宋','宋诗','song-poetry','','[]','學從元字起，貞實已先元。',48,'全唐诗/poet.song.232000.json','["學從元字起，貞實已先元。", "密玩坤乾易，精探宇宙根。", "與公傳後世，有客踐前言。", "萬古立鼇極，惟思夜氣存。"]'),
('ad105fb6-1f11-4fde-8d1b-6d2c50d47e93','哭鮑景翔魯齋  其二','方回','宋','宋诗','song-poetry','','[]','高年開八袠，細字尚親抄。',48,'全唐诗/poet.song.232000.json','["高年開八袠，細字尚親抄。", "已矣蠅頭筆，誰其鳳觜膠。", "能傳言外意，始識畫前爻。", "此老埋黄壤，紛紛嘆面交。"]'),
('ec7a2ca5-7834-4084-978f-37a9b307e5b7','送孫君文還桐廬二首  其一','方回','宋','宋诗','song-poetry','','[]','談笑丁年取甲科，一官潦倒鬢今皤。',64,'全唐诗/poet.song.232000.json','["談笑丁年取甲科，一官潦倒鬢今皤。", "飛騰尚覺聲名在，枯槁其如骨相何。", "舌鼓風雷無與敵，胸吞海嶽未爲多。", "向來一紀桐江上，殊欠先生共切磨。"]'),
('ece82a7d-53f1-4b7b-969d-b69fc39c60f0','送孫君文還桐廬二首  其二','方回','宋','宋诗','song-poetry','','[]','時違運往豈無才，老氣崢嶸隘九垓。',64,'全唐诗/poet.song.232000.json','["時違運往豈無才，老氣崢嶸隘九垓。", "漫仕有聲徐偃國，賦歸不愧子陵臺。", "相逢苦雨泥雙屐，可及晴湖汎一杯。", "忽又趁潮上桐瀨，山中春笋正堪煨。"]'),
('aa59a086-bd4b-4dbc-87d2-223f2d9b1dea','種花','方回','宋','宋诗','song-poetry','','[]','平生無嗜好，有地種花看。',48,'全唐诗/poet.song.232000.json','["平生無嗜好，有地種花看。", "萬玉梅成列，千金菊作團。", "秋宜鴻後冷，春惜燕前寒。", "更喜薰風好，青青笋上竿。"]'),
('aa7b866e-7655-42ab-a05d-c5bad6ca78a0','買花','方回','宋','宋诗','song-poetry','','[]','客中無玩好，日喜買花看。',48,'全唐诗/poet.song.232000.json','["客中無玩好，日喜買花看。", "酒債千金易，春晴一刻難。", "擔驚紅杏過，案惜玉梅殘。", "蜂蝶知何處，猶應怯曉寒。"]'),
('82b5dd83-f848-43a4-aa36-28373cfbe012','題陳學正巨源萬竹','方回','宋','宋诗','song-poetry','','[]','種竹種竹，種愈多愈不俗，種至萬竿猶不足。',86,'全唐诗/poet.song.232000.json','["種竹種竹，種愈多愈不俗，種至萬竿猶不足。", "讀書讀書，讀愈多愈不愚，讀過萬卷非有餘。", "竹萬竿環我屋，書萬卷遮我目。", "書在竹中身書中，竹風吹書沃心胸。", "倚竹挾書送飛鴻，不識人間有王公。"]'),
('0ed67c46-0bff-4e15-ba2f-1037b5027d04','題一家清雅集送植芸胡直內','方回','宋','宋诗','song-poetry','','[]','累朝科第總名臣，四世能詩才二人。',64,'全唐诗/poet.song.232000.json','["累朝科第總名臣，四世能詩才二人。", "參透雄深兼雅健，鍛成俊逸更清新。", "馬班翁季羞前躅，王謝雲仍踵後塵。", "頗恨昔叨桐瀨守，未能繡梓勵儒紳。"]'),
('446482e8-a9c9-4bbf-bcbf-183566701efc','寄題雲屋趙資敬啟蒙亭風雩亭二首  其一','方回','宋','宋诗','song-poetry','','[]','坤三變艮山，天一生坎泉。',132,'全唐诗/poet.song.232000.json','["坤三變艮山，天一生坎泉。", "注谷未浩浩，滴石初涓涓。", "君子觀厥象，有若童穉然。", "更歷幾險阻，然後爲巨川。", "始教及齠齔，成功從心年。", "夫人可爲聖，往聖敢自專。", "果行誓必往，江海迷泝沿。", "育德滋無窮，晝夜鳴潺湲。", "雲屋有遺老，鑿渠玩清漣。", "時時汎羽觴，坐致蘭亭賢。", "曷時亦酌我，同賦臨流篇。"]'),
('adf5ea42-0c38-4514-8be4-01a54f17733b','寄題雲屋趙資敬啟蒙亭風雩亭二首  其二','方回','宋','宋诗','song-poetry','','[]','昔人築雩壇，群巫此歌舞。',144,'全唐诗/poet.song.232000.json','["昔人築雩壇，群巫此歌舞。", "驕陽煽藴隆，吁嘆以降雨。", "良辰歲時和，遺迹林壑古。", "枯枿換槁葉，芳荑抽宿莽。", "徜徉沂水上，童冠七或五。", "春袖風乎茲，繢繡無火黼。", "千載想佳人，不仕東國魯。", "異彼三子撰，聖師獨予取。", "吾友趙隠君，笑唾卿相組。", "猿鳥聽新詠，點瑟時一鼓。", "漢歌曾罔聞，楚臺未渠數。", "泠泠列禦寇，肯爾噲等伍。"]'),
('ad5b50a5-1c15-4b75-bb4c-51bad830f7e2','送鄭君舉宣城教諭','方回','宋','宋诗','song-poetry','','[]','宣城畫虎遍天下，葉公好龍龍之假，百儒願陶一真者。',72,'全唐诗/poet.song.232000.json','["宣城畫虎遍天下，葉公好龍龍之假，百儒願陶一真者。", "紅花木瓜銀杏園，年年包貢入中原，何如興賢起邱樊。", "學徒尚有老梅否，詩聲千古捋歐九，子其作人舉薦口。"]'),
('5955c573-1478-4f54-9691-bc965412f5e8','送劉叔有還古鼎  其一','方回','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','我嘗飛過洞庭湖，但有青天地欲無。',64,'全唐诗/poet.song.232000.json','["我嘗飛過洞庭湖，但有青天地欲無。", "出峽蜀人趨鼎澧，泝江荆閫救巴渝。", "飄零詩酒全如夢，流落兵戈剩此軀。", "今日昇平歸去好，汎洲應有橘千株。"]'),
('7373a719-97b5-4972-a26a-89a60fc92f5d','送劉叔有還古鼎  其二','方回','宋','宋诗','song-poetry','','[]','題詩曾到古桃川，回首驚嗟四十年。',64,'全唐诗/poet.song.232000.json','["題詩曾到古桃川，回首驚嗟四十年。", "畫省郎官領賓客，白鬚道士似神仙。", "合城圍解江流沸，鄂渚兵豗廣徼穿。", "此處與公已相識，時籌前事一茫然。"]'),
('e8e78c91-3bb7-411b-9467-92cc02298d12','題趙循老立齋','方回','宋','宋诗','song-poetry','','[]','是身猶厦屋，下棟乃上宇。',120,'全唐诗/poet.song.232000.json','["是身猶厦屋，下棟乃上宇。", "一旦賀燕雀，千關庇風雨。", "輪奐易翬飛，難致礎上柱。", "桓楹一以植，次第萬厥戶。", "尼父早志學，更加歲十五。", "生知幼至壯，始以此自許。", "父師宿培壅，忍作籧篨俯。", "貞固軀峙幹，幸不夷左股。", "立斯以行斯，萬里在接武。", "務本果焉頼，腸書飽撐拄。"]'),
('183c3506-0864-4fb5-8463-3b2253ab3408','題趙繼孫拙齋','方回','宋','宋诗','song-poetry','','[]','曾顔得聖傳，何謂魯與愚。',120,'全唐诗/poet.song.232000.json','["曾顔得聖傳，何謂魯與愚。", "外察若不足，內朗實有餘。", "擇樹鵲巢高，罥虫蛛網虛。", "曲士挾小智，豈不雄里閭。", "之子息機心，抱甕灌園蔬。", "晚食足當肉，賁趾寧舍車。", "九卿彼四至，惡名垂簡書。", "天孫夜乞靈，悔不伾文疏。", "衆人笑我拙，囊螢披蠹魚。", "我亦笑爾巧，技止黔之馿。"]'),
('8af764f6-8d23-4978-accb-ebceb69f5684','午困','方回','宋','宋诗','song-poetry','','[]','老人無所嗜，惟書尚喜讀。',168,'全唐诗/poet.song.232000.json','["老人無所嗜，惟書尚喜讀。", "矧又晝正長，聊此展卷軸。", "閲久困已極，端坐閉我目。", "稍稍收神明，內觀默往復。", "謂可略欹枕，童子致委曲。", "心懼聖師責，美材化朽木。", "倦憊不可奈，一偃寐輒熟。", "何事忽驚覺，客至義當速。", "與語了無味，退就一影獨。", "□□□□□，尚頼有脫粟。", "朱墨工未竟，點勘繼以燭。", "還將夜有餘，用補日不足。", "行年過七十，焉用强自勗。", "起倒不由人，曷不返空谷。"]'),
('48f8f581-d6d6-48e7-86a5-e526f44ddc36','三月二十日張君輗約飲王子由紫霞道院酒字爲韻','方回','宋','宋诗','song-poetry','','["\u897f\u6e56"]','城中殘春未識春，城外心賞無不有。',320,'全唐诗/poet.song.232000.json','["城中殘春未識春，城外心賞無不有。", "今年春寒晚乃暖，尚餘飛絮忘高柳。", "西湖孰謂西子老，雖老絕勝登徒醜。", "刺水乍見新荷翻，銜泥莫辨乳燕耦。", "兒曹惡陳爭喜新，好以玄鬢嘲白首。", "遮莫少年自得志，看人輕肥但袖手。", "今朝天色適可意，張丈殷兄總閒叟。", "此一禿翁許追隨，琳宮菊花問開否。", "主客十人人能詩，冥搜遠討心欲嘔。", "何如平易任天真，索紙便作龍蛇走。", "仇仙笑指臯亭山，橫塞武林當水口。", "不爾歌舞百萬家，焉能奕世長保守。", "我獨睥睨壽星寺，欺孤柄臣據其右。", "一朝擊死木棉庵，頭顱可朽臭不朽。", "向來世故未深識，折腰此人覬升斗。", "追憶謝傅小忍語，竊虞桓玄錫命九。", "山河變幻泗鼎沒，脫身萬死亦云偶。", "升沉得喪俱置之，天地古今一杯酒。", "乍聚忽散醉忽醒，浮生邂逅理難久。", "王侯皂隸浪分別，頃刻白衣化蒼狗。"]'),
('21d52500-c185-4135-a043-f228b5d28856','記遊自次前韻','方回','宋','宋诗','song-poetry','','[]','百歲十分過七分，僥倖古來所希有。',320,'全唐诗/poet.song.232000.json','["百歲十分過七分，僥倖古來所希有。", "尋壑經丘詎得知，揣謂偷閒問花柳。", "未暇扶杖支疲癃，每羞照鏡現老醜。", "商洛隠遁似輩行，幽并游俠豈朋耦。", "朝哦雅什諷騷些，夜玩易爻測玄首。", "焚膏空餘冰檗心，補衮不到犁鋤手。", "驚思此生如掣電，昨日黄童今白叟。", "炙眉折肱了不悔，愛評文字判是否。", "包藏彼且城府深，骾直我乃肺肝嘔。", "爾來何止師左次，三十六策上策走。", "况如韓子生之辰，牛奮其角箕張口。", "梯衝百道公輸攻，一默不答堅墨守。", "城西俊遊小不忍，焉能軒左復輊右。", "蘭亭梓澤座有人，足與德功參不朽。", "是日已嘗穀雨茶，是歲木星守南斗。", "是集舉杯各見釂，淺量可能一敵九。", "坐視喧譁醉愈恭，不記俎奇忘豆偶。", "麥熟在即麴糵富，更願所至可賒酒。", "情懷坦蕩尚真率，滋味淡薄保長久。", "寧從散人盟狎鷗，勿作功臣烹走狗。"]'),
('7be9b40d-7c40-4355-a5c9-a6e5a4cc007a','次韻全君玉和高士馬虛中道院','方回','宋','宋诗','song-poetry','','[]','古人無欲非引年，古無有欲之聖賢，曰無欲者無私欲。',272,'全唐诗/poet.song.232000.json','["古人無欲非引年，古無有欲之聖賢，曰無欲者無私欲。", "昊皇魯叟畫繫傳，柱下木子知止足。", "豈謂出神凌紫煙，驂鸞駕鶴事恍惚。", "別異道家分神仙，淺之又淺伯陽契，癡兒妄詫玄又玄。", "內丹水火一升降，髑髏立變童顔妍。", "三載告成奪天地，汝拖腸鼠能攀牽。", "私欲如此大莫大，破入寒獄赦倒懸。", "遨崑登閬謂不死，終然白骨埋黄泉。", "腐儒一笑了萬事，何謂赤明龍漢前。", "號召風師呼雨伯，杖劍叱喝急急律。", "四時飯噉百花香，萬間厦入一壺窄。", "洞天有天魂兮來，弱水元無跬步隔。", "拄杖化龍舄作鳬，意所不求忽自得。", "醉眼暫作如是觀，誰識詠歸暮春瑟。", "和同光塵亦一法，豈敢訑訑見顔色。", "爲問今生賀知章，孰兩杜甫雙李白。"]'),
('141629f9-df69-46e8-b03c-12ed24f7c988','寫心五首  其一','方回','宋','宋诗','song-poetry','','[]','見惡巷伯嫉，聞善臯陶都。',72,'全唐诗/poet.song.232000.json','["見惡巷伯嫉，聞善臯陶都。", "空言非衮撻，焉有賞與誅。", "君子定相忘，小人將見圖。", "口過信未免，心過吾實無。", "浪自作臧否，了不關生枯。", "龜殻愛鑽灼，何如伏泥途。"]'),
('7e9831ab-61ad-4d88-8683-e60bd0f381b2','寫心五首  其二','方回','宋','宋诗','song-poetry','','[]','今日忽不愁，脫然體無病。',48,'全唐诗/poet.song.232000.json','["今日忽不愁，脫然體無病。", "餬飾窗櫺明，整齊書冊正。", "生無快意事，適此悅我性。", "雨足明當晴，更喜天宇靚。"]'),
('0fa68002-cac9-4fec-96ef-238a821a88a6','寫心五首  其三','方回','宋','宋诗','song-poetry','','[]','世人好圖畫，山水及動植。',96,'全唐诗/poet.song.232000.json','["世人好圖畫，山水及動植。", "墨煤與粉繪，軸而掛之壁。", "畫豈有天趣，識假真不識。", "我有古盆瓶，清晨井自汲。", "時花簪數枝，悠漾泳金鯽。", "靜坐玩生意，默然若有得。", "此見亦淺狹，撫几忽起立。", "我家山水鄉，鶑啼春草碧。"]'),
('6e09517f-6ab7-4407-a8e7-0302079dd01b','寫心五首  其四','方回','宋','宋诗','song-poetry','','[]','我既不干世，人故不我知。',72,'全唐诗/poet.song.232000.json','["我既不干世，人故不我知。", "我能自不輕，人亦莫我欺。", "夏潦江湖溢，雲雨翔蛟螭。", "兩涯一以涸，豈無藏蟄時。", "外凍內不死，復雷潜地維。", "何必慕薺菜，竊借春風吹。"]'),
('c8a12d0f-cb90-44ec-8085-ecc75020f994','寫心五首  其五','方回','宋','宋诗','song-poetry','','[]','此身脩至此，尚恐玉有瑕。',96,'全唐诗/poet.song.232000.json','["此身脩至此，尚恐玉有瑕。", "自茲脩更脩，庶幾寬我涯。", "不然輪生角，豈不柅厥車。", "故無熊虎卜，亦未夢龍蛇。", "學不取臨川，文不取永嘉。", "詩不取晚唐，有正寧無葩。", "真魏吾所師，未覺朱程賒。", "此身脩至此，餒死曾何嗟。"]');
